/// Master "autopilot" flag. When MU_AUTOPILOT=0, all autonomous background
/// crons (blog compose, council brief, /you daily, prompt_performance, X
/// cross-post, NFT mint) early-return after logging. Per-task env vars
/// (e.g. MU_NFT_MINT_LIVE) still apply on top.
/// Default: enabled (auto-on). Operator flips to 0 for emergency halt.
fn autopilot_on() -> bool {
    env::var("MU_AUTOPILOT").map(|v| v.trim() != "0").unwrap_or(true)
}

/// Returns true if autopilot is off — caller should log and skip.
/// Used at the top of every autonomous cron task.
pub(crate) fn autopilot_skip(task: &str) -> bool {
    if !autopilot_on() {
        tracing::warn!("[autopilot:off] skipping {} (set MU_AUTOPILOT=1 to re-enable)", task);
        true
    } else {
        false
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// MU Constitution — machine-readable single source of truth.
// File is `store/static/constitution.md`, read at compile time via
// include_str! so a rebuild is required to change Vision / Type-1 list /
// budget caps. This is intentional: those changes are governance-level, not
// runtime tweakable. Operational toggles (per-agent kill / dry-run) are env
// vars, not Constitution. NB: lives under store/static/ because that's the
// Docker build context (see store/Dockerfile `COPY static static`).
// ─────────────────────────────────────────────────────────────────────────────
const CONSTITUTION_RAW: &str = include_str!("../static/constitution.md");
/// 12-article append-only foundation document (legal/philosophical anchor for
/// the next 100 years). Drafted 2026-05-21. Notarization filed at 浜松町公証役場
/// — see docs/constitution-notary-draft.md. The 12 articles are IMMUTABLE: any
/// future addition must be Art. 13+ appended at the end, per Art. 9.
const CONSTITUTION_HTML_RAW: &str = include_str!("../static/constitution.html");
const DAO_WHITEPAPER_RAW: &str = include_str!("../static/whitepaper_dao.md");
const DONATIONS_RAW: &str = include_str!("../static/donations.md");
const PROFIT_SPLIT_RAW: &str = include_str!("../static/profit_split.md");

/// §28 利益分配スキーム — 税引後 当期純利益 P を 6 セグメントに分配。
/// 全比率の合計が 1.0 になっていることはデバッグ assert で担保 (下記 test)。
/// 端数 ¥1 は reserve に寄せる ([profit_split.md §3.1]).
pub const PROFIT_SPLIT_DONATION: f64    = 0.50; // base — §29 累進で 50→90% に成長
pub const PROFIT_SPLIT_YUKI: f64        = 0.10; // P ≤ ¥10M 範囲のみ。超過分は ¥10M キャップ
pub const PROFIT_SPLIT_SHAREHOLDER: f64 = 0.10; // 株主全員 (持分比率配当、§29 で全帯維持)
pub const PROFIT_SPLIT_MA_HOLDER: f64   = 0.10; // MUGEN+stack ホルダー (MUクーポン)
pub const PROFIT_SPLIT_COMMUNITY: f64   = 0.10; // MU Community Fund (50% は grant 枠)
pub const PROFIT_SPLIT_RESERVE: f64     = 0.10; // 運転備金 (内部留保, 端数吸収)

/// §29 The Discipline of Silence — Progressive Donation 累進寄付率
/// P レンジに応じて寄付比率を 50% → 90% に増やす (Yuki 報酬は ¥10M キャップ固定)。
/// 超過分は寄付 (+ 一部 Community) に流す。"自分の取り分が比例で増えない" 設計。
pub const YUKI_CAP_JPY: i64 = 10_000_000; // ¥10M Yuki 報酬上限

#[cfg(test)]
mod profit_split_tests {
    use super::*;
    #[test]
    fn ratios_sum_to_one() {
        let sum = PROFIT_SPLIT_DONATION + PROFIT_SPLIT_YUKI + PROFIT_SPLIT_SHAREHOLDER
                + PROFIT_SPLIT_MA_HOLDER + PROFIT_SPLIT_COMMUNITY + PROFIT_SPLIT_RESERVE;
        assert!((sum - 1.0).abs() < 1e-9, "ratios must sum to 1.0, got {}", sum);
    }
    #[test]
    fn breakdown_segments_sum_to_p_with_fraction_in_reserve() {
        // P = 1,000,003 — 端数 ¥3 が reserve に寄せられることを確認
        let p = 1_000_003i64;
        let br = profit_split_breakdown(p);
        let segs = br["segments"].as_array().unwrap();
        let sum: i64 = segs.iter().map(|s| s["jpy"].as_i64().unwrap()).sum();
        assert_eq!(sum, p, "segments must sum exactly to P");
        // donation = 50%, yuki = 10%, shareholder = 10%, ma = 10%, community = 10%, reserve = 残り
        assert_eq!(segs[0]["jpy"].as_i64().unwrap(), 500_001);    // donation
        assert_eq!(segs[1]["jpy"].as_i64().unwrap(), 100_000);    // yuki (floor)
        assert_eq!(segs[5]["jpy"].as_i64().unwrap(), 100_002);    // reserve (端数吸収)
    }
    #[test]
    fn breakdown_handles_zero_p() {
        let br = profit_split_breakdown(0);
        let segs = br["segments"].as_array().unwrap();
        for s in segs {
            assert_eq!(s["jpy"].as_i64().unwrap(), 0);
        }
    }
    #[test]
    fn breakdown_clamps_negative_p_to_zero() {
        // 赤字 P を渡しても 全 segment = 0 (負配分を防ぐ)
        let br = profit_split_breakdown(-100_000);
        assert_eq!(br["net_after_tax_jpy"].as_i64().unwrap(), 0);
    }
}

/// Extract a top-level `## <name>` markdown section from the Constitution.
/// Matches the heading prefix (so `## Type 1 Doors — Irreversible / require human
/// approval` is found by `"Type 1 Doors"`), then returns the body up to the next
/// `## ` heading, trimmed. Returns "" if the section is missing.
fn constitution_section(name: &str) -> &'static str {
    let needle = format!("\n## {}", name);
    let Some(idx) = CONSTITUTION_RAW.find(&needle) else {
        return "";
    };
    // Skip to the end of the heading line.
    let after_heading_start = idx + needle.len();
    let rest = &CONSTITUTION_RAW[after_heading_start..];
    let body_start = rest.find('\n').map(|n| after_heading_start + n + 1)
        .unwrap_or(CONSTITUTION_RAW.len());
    let after = &CONSTITUTION_RAW[body_start..];
    let end = after.find("\n## ").unwrap_or(after.len());
    after[..end].trim_matches(|c: char| c == '\n' || c == ' ')
}

/// The 4-line brand vision. Sourced from Constitution `## Vision`.
fn mu_vision() -> &'static str {
    constitution_section("Vision")
}

/// Fail-fast at startup: if the Constitution is malformed or someone deleted
/// the Vision section, do not start MU. Better to crash on boot than to ship
/// agents with an empty vision string.
fn validate_constitution() {
    let v = mu_vision();
    if v.is_empty() || !v.contains("seasons") {
        panic!(
            "[constitution] store/static/constitution.md is missing or has no parseable '## Vision' section. \
             Fix and rebuild before deploying — refusing to start MU."
        );
    }
    for section in &["Operational Principles", "Type 1 Doors", "Type 2 Doors", "Budget Caps", "Kill Switches"] {
        if constitution_section(section).is_empty() {
            panic!("[constitution] required section '{}' missing", section);
        }
    }
    tracing::info!("[constitution] OK — Vision + 5 required sections present ({} bytes)", CONSTITUTION_RAW.len());
}

/// Check if a given agent is explicitly killed via env var.
/// Returns the env var name that triggered the kill (for audit), or None.
/// Honors `AGENT_KILL_ALL=1` and `AGENT_KILL_<UPPER_NAME>=1`.
fn agent_killed(name: &str) -> Option<String> {
    let truthy = |v: String| { let v = v.trim(); v == "1" || v.eq_ignore_ascii_case("true") || v.eq_ignore_ascii_case("yes") };
    if env::var("AGENT_KILL_ALL").map(&truthy).unwrap_or(false) {
        return Some("AGENT_KILL_ALL".to_string());
    }
    let var = format!("AGENT_KILL_{}", name.to_uppercase());
    if env::var(&var).map(&truthy).unwrap_or(false) {
        return Some(var);
    }
    None
}

/// Heuristic: is this email a fake/test address that no agent should send to?
/// Per Bezos critique: keep test data from polluting governance queue.
/// Errs on the side of skipping (better to under-act on a real edge-case than
/// to email-bomb noreply@ or burn Resend quota on test data).
fn is_test_email(email: &str) -> bool {
    let e = email.trim().to_lowercase();
    if e.is_empty() || !e.contains('@') { return true; }
    let bad_substrs = [
        "test@", "@test.", "test.com", "test.local",
        "@example.", "example.com", "example.org",
        "noreply@", "no-reply@", "donotreply@",
        "mailinator.com", "tempmail", "throwaway",
        "rate@", "burst-", "agent-test",
        "x@x.", "a@a.",
    ];
    bad_substrs.iter().any(|s| e.contains(s))
}

/// Check if a given agent should run in dry-run (log only, no side effects).
/// Honors `DRY_RUN_ALL=1` and `DRY_RUN_<UPPER_NAME>=1`.
fn dry_run_active(name: &str) -> bool {
    let truthy = |v: String| { let v = v.trim(); v == "1" || v.eq_ignore_ascii_case("true") || v.eq_ignore_ascii_case("yes") };
    if env::var("DRY_RUN_ALL").map(&truthy).unwrap_or(false) {
        return true;
    }
    let var = format!("DRY_RUN_{}", name.to_uppercase());
    env::var(&var).map(&truthy).unwrap_or(false)
}

/// Centralized admin token check. Fail-closed: if ADMIN_TOKEN env var
/// is missing or empty, every admin request is rejected with 503.
/// Never falls back to a default value (prevents the historical
/// "mu-admin" default-token vulnerability).
/// 包括的 admin 認可 — 推奨経路。
///
/// 確認順序:
///   1. `Authorization: Bearer <token>` ヘッダー (推奨、URL ログ漏れなし)
///   2. `X-Admin-Token: <token>` ヘッダー (代替)
///   3. `?token=<token>` クエリ (レガシー、後方互換のみ)
///
/// 副作用:
///   - admin_auth_log テーブルに毎回 1 行記録 (success/failure 両方)
///   - 直近 1 時間に同一 IP から失敗 30 回超で 429 (lockout 防止)
///
/// Extract the trusted client IP from request headers.
///
/// R1 fix: Fly.io's edge sets `fly-client-ip` to the validated client address
/// (not spoofable). When that header is absent (e.g. local dev, non-Fly
/// edge), fall back to the *last* element of `X-Forwarded-For` — that's the
/// hop closest to our edge, i.e. the only one our proxy added itself.
/// Taking the *first* XFF element was the bug: attackers can prepend any
/// value to spoof rate-limit identity.
pub fn client_ip(headers: &HeaderMap) -> String {
    if let Some(ip) = headers.get("fly-client-ip")
        .and_then(|v| v.to_str().ok())
        .map(|s| s.trim())
        .filter(|s| !s.is_empty())
    {
        return ip.to_string();
    }
    // Fallback: XFF last hop. If the chain is `attacker, real_proxy, edge`,
    // the LAST entry is the edge — strip our own proxy if present and take
    // the next-to-last, but in practice the last entry is the safest single
    // choice when fly-client-ip is unavailable. Operators behind a different
    // edge can override via env if needed; out of scope here.
    if let Some(xff) = headers.get("x-forwarded-for").and_then(|v| v.to_str().ok()) {
        if let Some(last) = xff.split(',').next_back().map(|s| s.trim()).filter(|s| !s.is_empty()) {
            return last.to_string();
        }
    }
    String::new()
}

/// 引数:
///   - headers : HeaderMap (リクエストヘッダー)
///   - q       : Query map (`?token=...` を抽出)
///   - db      : SQLite ハンドル (rate limit + ログ用)
///   - path    : リクエストパス (ログ用)
async fn admin_auth(
    headers: &HeaderMap,
    q: &std::collections::HashMap<String, String>,
    db: Db,
    path: &str,
) -> Result<(), Response> {
    // 1. クライアント IP (R1 fix: fly-client-ip 優先、XFF は LAST hop)
    let ip = client_ip(headers);

    // 2. レート制限: 同一 IP の失敗が直近 1h で 200 回超 → 429
    // (2026-05-17 bumped 30→200 — bulk admin operations like the jiufight
    // mockup regen flow can easily emit 30 mismatches just from one bash
    // off-by-one. 200 is still well below brute-force territory and Telegram
    // alerts fire on each individual mismatch via admin_token_mismatch_alert.)
    // /api/admin/unlock_self provides an escape hatch when this trips
    // anyway — it skips the rate-limit gate so a legit admin can recover.
    if !ip.is_empty() {
        let now_s: i64 = chrono_now().parse().unwrap_or(0);
        let h1 = now_s - 3600;
        let fails: i64 = {
            let conn = db.lock().unwrap();
            conn.query_row(
                "SELECT COUNT(*) FROM admin_auth_log
                 WHERE ip=? AND ok=0 AND CAST(at AS INTEGER) > ?",
                params![ip, h1], |r| r.get(0),
            ).unwrap_or(0)
        };
        if fails > 200 {
            eprintln!("[security] admin rate-limit blocked ip={} fails_1h={}", ip, fails);
            return Err((StatusCode::TOO_MANY_REQUESTS,
                "admin auth: too many failed attempts; locked for 1h. POST /api/admin/unlock_self?token=… to clear.").into_response());
        }
    }

    // 3. トークン抽出 (Authorization > X-Admin-Token > query)
    let (provided, via): (Option<String>, &'static str) = {
        let auth_h = headers.get("authorization")
            .and_then(|v| v.to_str().ok())
            .and_then(|s| s.strip_prefix("Bearer ").or_else(|| s.strip_prefix("bearer ")))
            .map(String::from);
        let xat = headers.get("x-admin-token")
            .and_then(|v| v.to_str().ok()).map(String::from);
        if let Some(t) = auth_h { (Some(t), "header") }
        else if let Some(t) = xat { (Some(t), "header") }
        else if let Some(t) = q.get("token") { (Some(t.clone()), "query") }
        else if let Some(t) = q.get("admin_token") { (Some(t.clone()), "query") }
        else { (None, "none") }
    };

    // 4a. Email-session admin (preferred — no token in URL). If a verified
    // session cookie matches ADMIN_EMAIL, accept and audit-log as `session`.
    if let Some(email) = is_admin_email_session(&db, headers) {
        let ua = headers.get("user-agent").and_then(|v| v.to_str().ok())
            .map(|s| s.chars().take(200).collect::<String>()).unwrap_or_default();
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "INSERT INTO admin_auth_log
                 (ip, path, method, user_agent, ok, token_prefix, via, at)
             VALUES (?,?,?,?,?,?,?,?)",
            params![ip, path, "?", ua, 1i64, email, "session", chrono_now()],
        );
        return Ok(());
    }
    // 4b. Token fallback (existing behavior — Authorization / X-Admin-Token / ?token).
    let result = require_admin_token(provided.as_ref());
    let ok = result.is_ok();
    let ua = headers.get("user-agent").and_then(|v| v.to_str().ok())
        .map(|s| s.chars().take(200).collect::<String>()).unwrap_or_default();
    let token_prefix = provided.as_deref()
        .map(|s| s.chars().take(4).collect::<String>()).unwrap_or_default();
    {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "INSERT INTO admin_auth_log
                 (ip, path, method, user_agent, ok, token_prefix, via, at)
             VALUES (?,?,?,?,?,?,?,?)",
            params![ip, path, "?", ua, ok as i64, token_prefix, via, chrono_now()],
        );
    }
    result
}

/// POST /api/admin/unlock_self?token=<ADMIN_TOKEN>
/// Clears admin_auth_log fails for the caller's IP. Crucially this endpoint
/// SKIPS the rate-limit gate in admin_auth so it works even when the calling
/// IP is currently locked out — that's the whole point.
/// Validates ADMIN_TOKEN directly via require_admin_token instead of going
/// through admin_auth.
async fn admin_unlock_self(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let provided: Option<String> = {
        let auth_h = headers.get("authorization").and_then(|v| v.to_str().ok())
            .and_then(|s| s.strip_prefix("Bearer ").or_else(|| s.strip_prefix("bearer ")))
            .map(String::from);
        let xat = headers.get("x-admin-token").and_then(|v| v.to_str().ok()).map(String::from);
        auth_h.or(xat)
            .or_else(|| q.get("token").cloned())
            .or_else(|| q.get("admin_token").cloned())
    };
    if let Err(r) = require_admin_token(provided.as_ref()) { return r; }
    let ip = client_ip(&headers);
    if ip.is_empty() {
        return (StatusCode::BAD_REQUEST,
            Json(serde_json::json!({"ok": false, "error": "no client IP"}))).into_response();
    }
    let cleared: usize = {
        let conn = db.lock().unwrap();
        conn.execute(
            "DELETE FROM admin_auth_log WHERE ip=? AND ok=0",
            params![ip],
        ).unwrap_or(0)
    };
    eprintln!("[security] unlock_self: ip={} cleared {} fail-logs", ip, cleared);
    Json(serde_json::json!({
        "ok": true, "ip": ip, "cleared_fails": cleared
    })).into_response()
}

/// Replace the values of secret-bearing query parameters (`token`,
/// `admin_token`, `key`, `api_key`, `secret`) with `***` so request-trace
/// log lines never contain a usable credential. Everything else is passed
/// through untouched.
fn redact_query_secrets(uri: &str) -> String {
    let Some((path, query)) = uri.split_once('?') else { return uri.to_string() };
    let redacted: Vec<String> = query.split('&').map(|pair| {
        match pair.split_once('=') {
            Some((name, _)) if matches!(
                name.to_ascii_lowercase().as_str(),
                "token" | "admin_token" | "key" | "api_key" | "secret"
            ) => format!("{}=***", name),
            _ => pair.to_string(),
        }
    }).collect();
    format!("{}?{}", path, redacted.join("&"))
}

fn require_admin_token(provided: Option<&String>) -> Result<(), Response> {
    let expected = match env::var("ADMIN_TOKEN") {
        Ok(v) if !v.is_empty() => v,
        _ => {
            eprintln!("[security] ADMIN_TOKEN env var is unset — rejecting admin request");
            return Err((
                StatusCode::SERVICE_UNAVAILABLE,
                "admin disabled (server misconfigured: ADMIN_TOKEN not set)",
            ).into_response());
        }
    };
    let provided_str = provided.map(String::as_str).unwrap_or("");
    // Constant-time comparison to prevent timing attacks
    let mismatch =
        provided_str.len() != expected.len()
        || {
            let mut diff: u8 = 0;
            for (a, b) in provided_str.bytes().zip(expected.bytes()) {
                diff |= a ^ b;
            }
            diff != 0
        };
    if mismatch {
        // Async-fire a Telegram alert (deduped) so admin-token-rotation
        // mismatches (Fly rotated, Actions secret stale → silent 401 chain)
        // surface immediately. 2026-05-12 incident: admin cron died for 24h
        // because we synced one side only.
        admin_token_mismatch_alert();
        return Err((StatusCode::UNAUTHORIZED, "unauthorized").into_response());
    }
    Ok(())
}

/// Telegram alert on admin-token mismatch. Deduped to 1 alert / 6h so a
/// brute-force attempt doesn't flood. Fires in a background tokio task so
/// the auth path stays fast.
fn admin_token_mismatch_alert() {
    use std::sync::atomic::{AtomicI64, Ordering};
    static LAST_ALERT: AtomicI64 = AtomicI64::new(0);
    let now: i64 = chrono_now().parse().unwrap_or(0);
    let last = LAST_ALERT.load(Ordering::Relaxed);
    if now - last < 6 * 3600 { return; }
    LAST_ALERT.store(now, Ordering::Relaxed);
    let tg_token = env::var("TELEGRAM_BOT_TOKEN").unwrap_or_default();
    let tg_chat  = env::var("TELEGRAM_CHAT_ID").unwrap_or_else(|_| "1136442501".into());
    if tg_token.is_empty() { return; }
    tokio::spawn(async move {
        let msg = "🔐 admin-token mismatch on wearmu.com — \
                   GH Actions secret or external caller is using a stale token. \
                   Check `fly ssh console -a mu-store -C 'printenv ADMIN_TOKEN'` vs \
                   `gh secret list --repo yukihamada/mu-brand`.";
        let _ = reqwest::Client::new()
            .post(format!("https://api.telegram.org/bot{}/sendMessage", tg_token))
            .json(&serde_json::json!({
                "chat_id": tg_chat, "text": msg, "disable_web_page_preview": true,
            }))
            .send().await;
    });
}

/// Add baseline security response headers to every reply.
async fn security_headers(req: Request<axum::body::Body>, next: Next) -> Response {
    // Embed iframe page is meant to be embedded cross-origin → skip the
    // X-Frame-Options/CSP frame-ancestors lockdown for that path only.
    let path = req.uri().path().to_string();
    let embed_frame = path.starts_with("/embed/");
    let mut resp = next.run(req).await;
    let h = resp.headers_mut();
    h.insert("X-Content-Type-Options", HeaderValue::from_static("nosniff"));
    if !embed_frame {
        h.insert("X-Frame-Options", HeaderValue::from_static("SAMEORIGIN"));
    } else {
        h.remove("X-Frame-Options");
        h.insert("Content-Security-Policy",
                 HeaderValue::from_static("frame-ancestors *"));
    }
    // /admin はクエリに ?token= を含むため、同一オリジン遷移でも Referrer に
    // フルURL(トークン込み)が残り analytics 経由で漏れる → 全面 no-referrer。
    // (2026-06-04 enabler-analytics の referrer に admin_token 平文が記録された実害の修正)
    if path.starts_with("/admin") || path.starts_with("/work") {
        h.insert("Referrer-Policy", HeaderValue::from_static("no-referrer"));
    } else {
        h.insert("Referrer-Policy", HeaderValue::from_static("strict-origin-when-cross-origin"));
    }
    h.insert("Strict-Transport-Security",
             HeaderValue::from_static("max-age=31536000; includeSubDomains"));
    h.insert("Permissions-Policy",
             HeaderValue::from_static("camera=(), microphone=(), geolocation=(), payment=(self \"https://js.stripe.com\")"));
    // 静的アセット (/static, /mockups) はビルド成果物・商品モックアップで
    // 内容が変わらない → 長期キャッシュ。従来 Cache-Control 無しで毎訪問
    // 再ダウンロードしていた (favicon 等) のを修正。HTML 等動的応答には付けない。
    if (path.starts_with("/static/") || path.starts_with("/mockups/"))
        && !h.contains_key(axum::http::header::CACHE_CONTROL)
    {
        h.insert(
            axum::http::header::CACHE_CONTROL,
            HeaderValue::from_static("public, max-age=604800, stale-while-revalidate=86400"),
        );
    }
    // ── Root-level static assets + SEO/PWA descriptors ────────────────────
    // Files served from the project root (icon-512.png, og.jpg, favicon.*,
    // robots.txt, sitemap.xml, manifest.json, …) go through serve_static_or_404
    // / the ServeDir fallback, none of which start with /static/, so they had
    // NO Cache-Control at all (every visit re-downloaded the favicon/og image).
    // Skip /api, /admin, /work (dynamic / secret-bearing) and any HTML.
    // Filenames are NOT content-hashed → conservative 1-day TTL for assets,
    // 1-hour for descriptors that the engine can regenerate.
    if !path.starts_with("/api")
        && !path.starts_with("/admin")
        && !path.starts_with("/work")
        && !h.contains_key(axum::http::header::CACHE_CONTROL)
    {
        // strip query string, lowercase, take the extension after the last '.'
        let lo = path.split('?').next().unwrap_or(&path).to_ascii_lowercase();
        let ext = lo.rsplit('.').next().unwrap_or("");
        let cache = match ext {
            // immutable-ish binary/static assets (no hashing → 1 day, safe)
            "png" | "jpg" | "jpeg" | "webp" | "gif" | "svg" | "ico"
            | "css" | "js" | "woff" | "woff2" | "ttf" | "otf" | "eot" => {
                Some("public, max-age=86400")
            }
            // SEO / PWA descriptors — short TTL so updates propagate fast
            "txt" | "xml" => {
                // robots.txt / sitemap.xml (and any other root .txt/.xml)
                Some("public, max-age=3600")
            }
            "json" => {
                // manifest.json etc. (but /api/* already excluded above)
                Some("public, max-age=3600")
            }
            _ => None, // HTML and extensionless routes: leave uncached
        };
        if let Some(c) = cache {
            h.insert(
                axum::http::header::CACHE_CONTROL,
                HeaderValue::from_static(c),
            );
        }
    }
    resp
}

type Db = Arc<Mutex<Connection>>;

#[derive(Serialize, Default)]
struct Product {
    id: i64,
    brand: String,
    drop_num: i64,
    name: String,
    /// YYYYMMDD-#NNN per-day-ordinal serial. NEW canonical product code.
    /// Computed at read time from created_at + ordinal within that JST day.
    serial_code: String,
    mockup_url: Option<String>,
    price_jpy: i64,
    inventory: i64,
    sold: i64,
    created_at: String,
    weather_data: Option<String>,
    prompt_hash: Option<String>,
    seed_data: Option<String>,
    nft_mint: Option<String>,
    auction_end: Option<String>,
    current_bid: i64,
    bid_count: i64,
    sold_out_at: Option<String>,
    /// Generated "person wearing this design" photo (Gemini image-to-image).
    /// Optional; falls back to mockup_url client-side.
    #[serde(skip_serializing_if = "Option::is_none")]
    lifestyle_url: Option<String>,
    /// Stripe Payment Link URL — when present, the PDP renders a
    /// "クイック購入" CTA that goes straight to Stripe-hosted checkout,
    /// skipping our /api/checkout roundtrip.
    #[serde(skip_serializing_if = "Option::is_none")]
    payment_link_url: Option<String>,
    /// SUZURI marketplace mirror URL — when present, JP customers can
    /// click "🇯🇵 SUZURI で買う" for domestic fulfillment via suzuri.jp.
    /// See [[wearmu_suzuri_mirror]] / Constitution §24-v2.
    #[serde(skip_serializing_if = "Option::is_none")]
    suzuri_url: Option<String>,
}

#[derive(Deserialize)]
struct CheckoutBody {
    product_id: i64,
    quantity: u32,
    /// Optional now (2026-05-13). Stripe Checkout collects email itself on
    /// the hosted page — requiring it client-side was duplicate friction.
    /// If provided, we prefill Stripe and also use it for KYC linkage.
    #[serde(default)]
    email: Option<String>,
    size: Option<String>,
    wallet: Option<String>,
    /// "jpy" (default, Stripe Checkout), "usdc", "sol", "eth"
    payment_method: Option<String>,
    /// Required when the final billed total (unit_price × quantity) is at or
    /// above `KYC_THRESHOLD_JPY` (¥300,000). Stored in `kyc_records`.
    kyc: Option<KycInfo>,
    /// Ad attribution. Client reads gclid + utm_* from URL params on the
    /// landing page, persists in sessionStorage, then echoes here on
    /// checkout POST so Stripe metadata carries them through to the order.
    /// All optional — absent values are simply not stored.
    #[serde(default)]
    gclid: Option<String>,
    #[serde(default)]
    utm_source: Option<String>,
    #[serde(default)]
    utm_medium: Option<String>,
    #[serde(default)]
    utm_campaign: Option<String>,
    #[serde(default)]
    utm_term: Option<String>,
    #[serde(default)]
    utm_content: Option<String>,
    /// Variant selector additions (2026-05-18). When both are present, the
    /// matrix in `product_variants_matrix()` overrides the bonding-curve
    /// dynamic price. Falls back to dynamic price when absent (preserves
    /// current /api/checkout behavior). Validated server-side so the client
    /// can't choose an unavailable combo.
    #[serde(default)]
    variant_type: Option<String>,    // tee | hoodie | longsleeve | tank | polo | tote | mug | sticker
    #[serde(default)]
    pod_provider: Option<String>,    // printful_eu | gelato_jp | suzuri_jp
}

