fn mockups_dir() -> std::path::PathBuf {
    std::path::PathBuf::from(env::var("MOCKUPS_DIR").unwrap_or_else(|_| "/data/mockups".into()))
}

/// Cloudflare R2 (S3-compatible) configuration. Active when all four envs
/// are present: R2_ENDPOINT, R2_BUCKET, R2_ACCESS_KEY_ID, R2_SECRET_ACCESS_KEY.
/// R2_PUBLIC_BASE defaults to https://mockups.wearmu.com.
pub(crate) struct R2Config {
    pub(crate) bucket: s3::Bucket,
    pub(crate) public_base: String,
}

pub(crate) fn r2_config() -> Option<R2Config> {
    let endpoint = env::var("R2_ENDPOINT").ok().filter(|s| !s.is_empty())?;
    let bucket_name = env::var("R2_BUCKET").ok().filter(|s| !s.is_empty())?;
    let access_key = env::var("R2_ACCESS_KEY_ID").ok().filter(|s| !s.is_empty())?;
    let secret_key = env::var("R2_SECRET_ACCESS_KEY").ok().filter(|s| !s.is_empty())?;
    let public_base = env::var("R2_PUBLIC_BASE")
        .unwrap_or_else(|_| "https://mockups.wearmu.com".into());
    let region = s3::Region::Custom { region: "auto".into(), endpoint };
    let creds = s3::creds::Credentials::new(
        Some(&access_key), Some(&secret_key), None, None, None,
    ).map_err(|e| eprintln!("[r2] credentials: {}", e)).ok()?;
    let bucket = s3::Bucket::new(&bucket_name, region, creds)
        .map_err(|e| eprintln!("[r2] bucket: {}", e)).ok()?
        .with_path_style();
    Some(R2Config { bucket, public_base })
}

/// Upload bytes to R2 under an arbitrary key (e.g. "catalog/SKU.png").
/// Returns the absolute public URL on success. Caller decides the
/// content-type. Falls back to None if R2 isn't configured (the local-
/// disk fallback in store_mockup_bytes is product-id-specific so we
/// don't use it here).
pub(crate) async fn store_r2_bytes(key: &str, bytes: &[u8], content_type: &str) -> Option<String> {
    let cfg = r2_config()?;
    match cfg.bucket.put_object_with_content_type(key, bytes, content_type).await {
        Ok(r) if r.status_code() == 200 => {
            Some(format!("{}/{}", cfg.public_base.trim_end_matches('/'), key))
        }
        Ok(r) => {
            eprintln!("[r2] put_object {} status {}: {}", key, r.status_code(),
                      String::from_utf8_lossy(r.bytes()));
            None
        }
        Err(e) => {
            eprintln!("[r2] put_object {} error: {}", key, e);
            None
        }
    }
}

/// Upload bytes to R2 if configured; otherwise write to local mockups dir.
/// Returns the URL (R2 public URL or `/mockups/<id>.jpg`) to store in DB.
async fn store_mockup_bytes(product_id: i64, bytes: &[u8]) -> Option<String> {
    let key = format!("{}.jpg", product_id);
    if let Some(cfg) = r2_config() {
        match cfg.bucket.put_object_with_content_type(&key, bytes, "image/jpeg").await {
            Ok(r) if r.status_code() == 200 => {
                return Some(format!("{}/{}", cfg.public_base.trim_end_matches('/'), key));
            }
            Ok(r) => {
                eprintln!("[r2] put_object {} status {}: {}", key, r.status_code(),
                          String::from_utf8_lossy(r.bytes()));
            }
            Err(e) => eprintln!("[r2] put_object {} error: {}", key, e),
        }
        // R2 configured but failed — don't silently fall back to local disk
        // (the local file would be inaccessible from the public DB URL anyway)
        return None;
    }
    // No R2 → fallback to Fly volume
    let dir = mockups_dir();
    if let Err(e) = tokio::fs::create_dir_all(&dir).await {
        eprintln!("[mockups] create_dir_all failed: {}", e);
        return None;
    }
    let path = dir.join(&key);
    if let Err(e) = tokio::fs::write(&path, bytes).await {
        eprintln!("[mockups] write {} failed: {}", path.display(), e);
        return None;
    }
    Some(format!("/mockups/{}", key))
}

/// Rasterize the moon-phase marker for a given (pid, pos) into an RGBA
/// buffer. White ink (255,255,255,a) on transparent background, designed
/// to be composited into the bottom-right of a 1024×1024 design PNG so
/// every Bella+Canvas 3001 DTG print carries a covert MU identifier.
///
/// Layout: 8 circles, radius=6, gap=4, stroke=1, total ~124×14 px.
/// First circle = MOON_MAGIC_DIGIT (=4, fully filled) so a HoughCircles
/// detection that doesn't see the magic byte can fast-reject as "not MU".
fn rasterize_moon_marker_rgba(pid: i64, pos: i64) -> (Vec<u8>, u32, u32) {
    let (digits, _) = moon_encode_marker(pid, pos);
    let radius: i32 = 6;
    let gap: i32 = 4;
    let stroke: i32 = 1;
    let cell: i32 = radius * 2 + stroke * 2;
    let n = MOON_CIRCLES as i32;
    let w: i32 = n * cell + (n - 1) * gap;
    let h: i32 = cell;
    let mut buf = vec![0u8; (w * h * 4) as usize];
    let set_px = |buf: &mut [u8], x: i32, y: i32, a: u8| {
        if x < 0 || x >= w || y < 0 || y >= h { return; }
        let idx = ((y * w + x) * 4) as usize;
        // White ink, alpha = a.  Composite via "max alpha" so overlapping
        // outline/fill regions don't darken each other.
        buf[idx]     = 255;
        buf[idx + 1] = 255;
        buf[idx + 2] = 255;
        if a > buf[idx + 3] { buf[idx + 3] = a; }
    };
    for (i, &d) in digits.iter().enumerate() {
        let cx = (i as i32) * (cell + gap) + cell / 2;
        let cy = h / 2;
        let frac = d as f32 / 4.0;
        let fill_right_from = cx as f32 - radius as f32 + (2.0 * radius as f32) * (1.0 - frac);
        for dy in -radius..=radius {
            for dx in -radius..=radius {
                let dist2 = dx * dx + dy * dy;
                let r_inner = (radius - stroke).max(1);
                if dist2 > radius * radius { continue; }
                let on_outline = dist2 > r_inner * r_inner;
                let in_fill = (d == 4)
                    || (d > 0 && (cx + dx) as f32 >= fill_right_from);
                let alpha: u8 = if d == 0 {
                    if on_outline { 255 } else { 0 }
                } else if in_fill {
                    255
                } else if on_outline {
                    255
                } else {
                    0
                };
                if alpha > 0 {
                    set_px(&mut buf, cx + dx, cy + dy, alpha);
                }
            }
        }
    }
    (buf, w as u32, h as u32)
}

/// Composite the moon marker into the bottom-right corner of a 1024×1024
/// (or any-size) design PNG. Returns the new PNG bytes. Pure-Rust path
/// using only the `png` crate — no heavy `image` dep.
///
/// White marker pixels are alpha-blended onto the design. If the design's
/// background is transparent (TYPE for all Gemini-generated MU designs),
/// the marker becomes part of the printable region for Printful DTG.
fn composite_marker_into_png(design_bytes: &[u8], pid: i64, pos: i64) -> Result<Vec<u8>, String> {
    let cursor = std::io::Cursor::new(design_bytes);
    let decoder = png::Decoder::new(cursor);
    let mut reader = decoder.read_info().map_err(|e| format!("png decode: {}", e))?;
    let info = reader.info().clone();
    let width = info.width;
    let height = info.height;
    let mut buf = vec![0u8; reader.output_buffer_size()];
    let frame_info = reader.next_frame(&mut buf).map_err(|e| format!("png frame: {}", e))?;
    // Normalize to RGBA8.
    let mut rgba: Vec<u8> = match frame_info.color_type {
        png::ColorType::Rgba => buf.clone(),
        png::ColorType::Rgb => {
            let mut out = Vec::with_capacity((width * height * 4) as usize);
            for chunk in buf.chunks_exact(3) {
                out.extend_from_slice(&[chunk[0], chunk[1], chunk[2], 255]);
            }
            out
        }
        png::ColorType::Grayscale => {
            let mut out = Vec::with_capacity((width * height * 4) as usize);
            for &g in &buf { out.extend_from_slice(&[g, g, g, 255]); }
            out
        }
        png::ColorType::GrayscaleAlpha => {
            let mut out = Vec::with_capacity((width * height * 4) as usize);
            for chunk in buf.chunks_exact(2) {
                out.extend_from_slice(&[chunk[0], chunk[0], chunk[0], chunk[1]]);
            }
            out
        }
        other => return Err(format!("unsupported PNG color type {:?}", other)),
    };
    let bit_depth = frame_info.bit_depth;
    if bit_depth != png::BitDepth::Eight {
        return Err(format!("unsupported bit depth {:?}", bit_depth));
    }
    // Rasterize marker.
    let (marker, mw, mh) = rasterize_moon_marker_rgba(pid, pos);
    // Place at bottom-right with 40 px padding (or 4% of width for smaller designs).
    let pad: u32 = (width / 25).max(16);
    let mx = width.saturating_sub(mw).saturating_sub(pad);
    let my = height.saturating_sub(mh).saturating_sub(pad);
    for y in 0..mh.min(height.saturating_sub(my)) {
        for x in 0..mw.min(width.saturating_sub(mx)) {
            let mi = ((y * mw + x) * 4) as usize;
            let ma = marker[mi + 3];
            if ma == 0 { continue; }
            let di = (((my + y) * width + (mx + x)) * 4) as usize;
            // Source-over blend: result = src*a + dst*(1-a)
            let sa = ma as u32;
            let da = rgba[di + 3] as u32;
            let inv = 255 - sa;
            rgba[di]     = ((marker[mi]     as u32 * sa + rgba[di]     as u32 * inv) / 255) as u8;
            rgba[di + 1] = ((marker[mi + 1] as u32 * sa + rgba[di + 1] as u32 * inv) / 255) as u8;
            rgba[di + 2] = ((marker[mi + 2] as u32 * sa + rgba[di + 2] as u32 * inv) / 255) as u8;
            rgba[di + 3] = (sa + (da * inv) / 255).min(255) as u8;
        }
    }
    // Re-encode as PNG (RGBA8).
    let mut out: Vec<u8> = Vec::with_capacity(design_bytes.len());
    {
        let mut encoder = png::Encoder::new(&mut out, width, height);
        encoder.set_color(png::ColorType::Rgba);
        encoder.set_depth(png::BitDepth::Eight);
        let mut writer = encoder.write_header().map_err(|e| format!("png header: {}", e))?;
        writer.write_image_data(&rgba).map_err(|e| format!("png write: {}", e))?;
    }
    Ok(out)
}

/// Fetch a design URL, composite the marker, upload to R2 (or fall back
/// to a local mockup dir), and return the new public URL. If R2/local
/// write fails, returns the original design_url unchanged — print still
/// works without the marker.
async fn marker_composite_url(original: &str, pid: i64, pos: i64) -> String {
    let original_owned = original.to_string();
    let bytes = match reqwest::get(original).await {
        Ok(r) if r.status().is_success() => match r.bytes().await {
            Ok(b) if !b.is_empty() => b,
            _ => return original_owned,
        },
        _ => return original_owned,
    };
    let composited = match composite_marker_into_png(&bytes, pid, pos) {
        Ok(v) => v,
        Err(e) => {
            eprintln!("[marker_composite] pid={} pos={} compose err: {}", pid, pos, e);
            return original_owned;
        }
    };
    let key = format!("marker/{}_{}.png", pid, pos);
    if let Some(cfg) = r2_config() {
        match cfg.bucket.put_object_with_content_type(&key, &composited, "image/png").await {
            Ok(r) if r.status_code() == 200 => {
                return format!("{}/{}", cfg.public_base.trim_end_matches('/'), key);
            }
            Ok(r) => eprintln!("[marker_composite] r2 status {}", r.status_code()),
            Err(e) => eprintln!("[marker_composite] r2 err: {}", e),
        }
    }
    // Fallback: write to /data/mockups/marker/.
    let dir = mockups_dir().join("marker");
    let _ = tokio::fs::create_dir_all(&dir).await;
    let path = dir.join(format!("{}_{}.png", pid, pos));
    if tokio::fs::write(&path, &composited).await.is_ok() {
        return format!("https://wearmu.com/mockups/marker/{}_{}.png", pid, pos);
    }
    original_owned
}

/// If the given URL is a Printful temporary upload (which expires), download
/// the bytes and persist them. Return the new permanent URL on success, or
/// None if the URL is already permanent / fetch failed.
async fn persist_mockup_if_temporary(product_id: i64, url: &str) -> Option<String> {
    let is_temp = url.starts_with("https://printful-upload.s3")
        || url.contains("/tmp/");
    if !is_temp {
        return None;
    }
    let bytes = match reqwest::get(url).await {
        Ok(r) if r.status().is_success() => match r.bytes().await {
            Ok(b) if !b.is_empty() => b,
            _ => return None,
        },
        _ => return None,
    };
    store_mockup_bytes(product_id, &bytes).await
}

/// Bonding-curve / progressive pricing.
/// Price starts at ¥5,000 (1st buyer) and steps up ¥250 per sold unit, capped at ¥30,000.
/// "Early buyer wins" — opposite of Dutch auction.
/// Special cases: MA starts at ¥30,000 (lowered from ¥120k on 2026-05-11
/// when MA moved from monthly to weekly 7-day auctions). MUGEN #108 = ¥30,000 fixed.
/// Price ceiling for the bonding curve. Final price (post-surcharge) is also
/// clamped to this value. Purchases at or above this threshold require KYC
/// (`KYC_THRESHOLD_JPY`).
const PRICE_CAP_JPY: i64 = 300_000;
const PRICE_BASE_JPY: i64 = 5_000;
const PRICE_STEP_JPY: i64 = 250;
const MUGEN_108_PRICE_JPY: i64 = 30_000;

// Constitution §24 — Stanley/Stella SATU001 fabric era.
// From mugen drop_num MU_FABRIC_SATU001_FIRST_DROP onward, every new
// MUGEN drop is on Stanley/Stella Ribbed Neck Creator 2.0 (Printful
// product 818, 180gsm, GOTS organic, EU made). Base bonding curve
// rises to ¥9,800 to cover the higher cost (~¥5,700 all-in vs ¥2,850
// Bella) while preserving ~42% margin at start.
//
// IMPORTANT: this constant gates pricing for FUTURE drops only. Drops
// 1-147 (Bella+Canvas 3001 era) retain their Bella-era base price as
// preserved by Constitution §21 (purchase path sacrosanct).
// Constitution §24 — Stanley/Stella SATU001 fabric era cutoffs per brand.
// Drop_num thresholds (drops at-or-above use the new fabric + new pricing).
// Bella+Canvas era drops below the cutoff are immutable per §21 (sacrosanct).
const MU_FABRIC_SATU001_FIRST_DROP: i64 = 148;       // MUGEN: next drop after 147
const MUON_FABRIC_SATU001_FIRST_DROP: i64 = 10;      // MUON: next drop after 9
const MA_FABRIC_SATU001_FIRST_DROP: i64 = 3;         // MA: next auction after 2

/// MUGEN base ¥7,800 / cap ¥35,000 (hits ¥34,800 at 108 sales — natural plateau)
const PRICE_BASE_SATU001_JPY: i64 = 7_800;
const PRICE_CAP_SATU001_JPY: i64 = 35_000;
/// MUON same fabric, daily drop → cap a bit lower since per-drop volume varies
const PRICE_BASE_MUON_SATU001_JPY: i64 = 7_800;
const PRICE_CAP_MUON_SATU001_JPY: i64 = 30_000;
/// MA 1-of-1 auction starting bid — lowered to ¥18,000 (Visvim Jumbo
/// equivalent) since fabric cost is the same as MUGEN now. Auctions go
/// up from here via bidding; cap remains the §21 ¥100,000 ceiling.
const PRICE_BASE_MA_SATU001_JPY: i64 = 18_000;

/// Stanley/Stella SATU001 Ribbed Neck Creator 2.0, BLACK, Printful variant
