/// SUZURI base wholesale prices (JPY). SUZURI's API doesn't return these
/// — the creator margin model means the creator picks the retail price
/// and SUZURI deducts a per-item base when settling. These are SUZURI's
/// published base prices (suzuri.jp/help/articles/...).
/// Update here if SUZURI changes their item base.
const SUZURI_BASE_PRICES_JPY: &[(&str, f64)] = &[
    ("148", 3500.0),   // ヘビーウェイトTシャツ — see SUZURI_CREATOR_MARGIN_JPY
    ("1",   1650.0),   // スタンダードTシャツ
    ("5",   3200.0),   // スウェット
    ("96",  4400.0),   // ビッグシルエットパーカー
    ("2",   1460.0),   // トートバッグ
    ("3",   1650.0),   // マグカップ
];

/// reqwest client with explicit 20s timeout. Fly→vendor network has
/// occasional long stalls; without a timeout a single slow probe can wedge
/// the entire sync loop.
fn pod_http_client() -> reqwest::Client {
    reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(20))
        .build()
        .unwrap_or_else(|_| reqwest::Client::new())
}

/// Probe Gelato `/v4/orders:quote` for live JP-delivered pricing.
/// Returns (price, currency, production_country, min_d, max_d).
async fn pod_probe_gelato(uid: &str) -> Result<(f64, String, String, i32, i32), String> {
    let key = env::var("GELATO_API_KEY").map_err(|_| "GELATO_API_KEY unset".to_string())?;
    let body = serde_json::json!({
        "orderReferenceId":   format!("mu-probe-{}", chrono_now()),
        "customerReferenceId":"mu-admin-probe",
        "currencyIsoCode":    "JPY",
        "recipient": {
            "country":"JP","firstName":"MU","lastName":"Admin",
            // Synthetic Tokyo Station address — Gelato logs the recipient
            // forever even on quote-only calls, so we deliberately avoid
            // exposing the company's real HQ on every price probe.
            "addressLine1":"丸の内1-9-1","city":"千代田区","postCode":"100-0005",
            "stateCode":"JP-13","email":"probe@wearmu.com"
        },
        "products": [{
            "itemReferenceId":"i1","quantity":1,"productUid":uid,"pageCount":1,
            "files":[{"type":"default","url":"https://wearmu.com/static/sample_design.png"}],
        }],
    });
    let resp = pod_http_client()
        .post("https://order.gelatoapis.com/v4/orders:quote")
        .header("X-API-KEY", &key)
        .header("Content-Type", "application/json")
        .json(&body).send().await.map_err(|e| format!("gelato POST: {}", e))?;
    let status = resp.status();
    let v: serde_json::Value = resp.json().await.map_err(|e| format!("gelato json: {}", e))?;
    if !status.is_success() {
        return Err(format!("gelato {} {}", status, v));
    }
    let q = &v["quotes"][0];
    let prod = &q["products"][0];
    let ship = &q["shipmentMethods"][0];
    let price = prod["price"].as_f64().ok_or_else(|| "no price".to_string())?;
    let currency = prod["currency"].as_str().unwrap_or("USD").to_string();
    let country = q["productionCountry"].as_str().unwrap_or("?").to_string();
    let min_d = ship["minDeliveryDays"].as_i64().unwrap_or(0) as i32;
    let max_d = ship["maxDeliveryDays"].as_i64().unwrap_or(0) as i32;
    Ok((price, currency, country, min_d, max_d))
}

/// Probe Printful `/products/{id}` for catalog info. We pick the M-black
/// variant when one exists, otherwise the cheapest. The `price` field
/// returned by Printful is the store's listed retail in the store's
/// configured currency — for MU's JP store this is JPY, but the API
/// doesn't echo a per-variant currency so we surface it as `JPY` here
/// (the admin UI lets you override per-vendor if a vendor changes default).
/// `availability_status` exposes regional stock — we pick the first
/// in-stock region as the production country surrogate. Delivery defaults
/// to Printful's documented 7-15d window since per-product timings are
/// not exposed without a full order.
async fn pod_probe_printful(uid: &str) -> Result<(f64, String, String, i32, i32), String> {
    let key = env::var("PRINTFUL_API_KEY").map_err(|_| "PRINTFUL_API_KEY unset".to_string())?;
    let pid: u64 = uid.parse().map_err(|_| format!("bad printful uid: {}", uid))?;
    let resp = pod_http_client()
        .get(format!("https://api.printful.com/products/{}", pid))
        .bearer_auth(&key)
        .send().await.map_err(|e| format!("printful GET: {}", e))?;
    let status = resp.status();
    let v: serde_json::Value = resp.json().await.map_err(|e| format!("printful json: {}", e))?;
    if !status.is_success() {
        return Err(format!("printful {} {}", status, v));
    }
    let variants = v["result"]["variants"].as_array().ok_or_else(|| "no variants".to_string())?;
    let chosen = variants.iter()
        .find(|v| v["color"].as_str().unwrap_or("").eq_ignore_ascii_case("black")
                && v["size"].as_str().unwrap_or("").eq_ignore_ascii_case("m"))
        .cloned()
        .or_else(|| {
            variants.iter().min_by(|a, b| {
                let pa = a["price"].as_str().unwrap_or("999").parse::<f64>().unwrap_or(999.0);
                let pb = b["price"].as_str().unwrap_or("999").parse::<f64>().unwrap_or(999.0);
                pa.partial_cmp(&pb).unwrap_or(std::cmp::Ordering::Equal)
            }).cloned()
        })
        .ok_or_else(|| "no variants found".to_string())?;
    let price = chosen["price"].as_str().and_then(|s| s.parse::<f64>().ok())
        .ok_or_else(|| "no price".to_string())?;
    let country = chosen["availability_status"].as_array()
        .and_then(|arr| arr.iter().find(|a| a["status"].as_str() == Some("in_stock"))
            .and_then(|a| a["region"].as_str()))
        .unwrap_or("US").to_string();
    Ok((price, "JPY".into(), country, 7, 15))
}

/// Probe SUZURI `/api/v1/items` to verify the item template exists, then
/// return the hardcoded wholesale price from SUZURI_BASE_PRICES_JPY (the
/// /items endpoint doesn't expose price — SUZURI's creator-margin model
/// means the API never returns a `wholesale` field). Country is always JP,
/// delivery is SUZURI's standard 2-4d domestic window.
async fn pod_probe_suzuri(uid: &str) -> Result<(f64, String, String, i32, i32), String> {
    let token = env::var("SUZURI_ACCESS_TOKEN").map_err(|_| "SUZURI_ACCESS_TOKEN unset".to_string())?;
    let item_id: u32 = uid.parse().map_err(|_| format!("bad suzuri uid: {}", uid))?;
    let resp = pod_http_client()
        .get("https://suzuri.jp/api/v1/items")
        .bearer_auth(&token)
        .send().await.map_err(|e| format!("suzuri GET: {}", e))?;
    let status = resp.status();
    let v: serde_json::Value = resp.json().await.map_err(|e| format!("suzuri json: {}", e))?;
    if !status.is_success() {
        return Err(format!("suzuri {} {}", status, v));
    }
    let items = v["items"].as_array().ok_or_else(|| "no items array".to_string())?;
    let _exists = items.iter().find(|it| it["id"].as_u64().unwrap_or(0) == item_id as u64)
        .ok_or_else(|| format!("suzuri item {} not found in /items", item_id))?;
    let price = SUZURI_BASE_PRICES_JPY.iter()
        .find(|(u, _)| *u == uid)
        .map(|(_, p)| *p)
        .ok_or_else(|| format!("suzuri item {} has no entry in SUZURI_BASE_PRICES_JPY — add wholesale price to the constant", uid))?;
    Ok((price, "JPY".into(), "JP".into(), 2, 4))
}

/// Dispatch probe by vendor.
async fn pod_probe(vendor: &str, uid: &str) -> Result<(f64, String, String, i32, i32), String> {
    match vendor {
        "gelato"   => pod_probe_gelato(uid).await,
        "printful" => pod_probe_printful(uid).await,
        "suzuri"   => pod_probe_suzuri(uid).await,
        _          => Err(format!("unknown vendor: {}", vendor)),
    }
}

// ───── Bulk catalog seed (per vendor) ───────────────────────────────
//
// SEED fetches each vendor's full product list and stores rows in
// pod_catalog with price_value=0 and last_priced_at='0'. SYNC then
// price-probes each entry on demand. Decoupling lets us pull thousands
// of SKUs without burning quota — pricing is fetched only for SKUs the
// user actually cares about (linked to MU products, or hit Refresh on).

/// Gelato catalogs we want to expose for MU. Excludes wallpaper /
/// stationery / blank-envelopes etc that we have no immediate use for.
const GELATO_SEED_CATALOGS: &[&str] = &[
    "apparel", "tote-bags", "mugs", "posters", "canvas",
    "phone-cases", "stickers", "hanging-posters", "framed-posters",
    "wood-prints", "fine-art", "framed-canvas", "mounted-fine-art",
    "fine-art-framed-poster", "mounted-framed-posters", "poster-hangers",
    "foam-print-product", "aprons", "baby-clothing", "beanies", "bottles",
];

/// Pretty-print a Gelato productUid like
/// `apparel_product_gca_t-shirt_gsc_crewneck_gcu_unisex_gqa_classic_gsi_m_gco_black_gpr_0-4_gildan_h000`
/// into something a human can read. Best-effort — falls back to the raw
/// uid if no underscore-segmented attributes are present.
fn gelato_label_from_uid(uid: &str) -> String {
    let mut parts: Vec<String> = Vec::new();
    let mut iter = uid.split('_').peekable();
    while let Some(seg) = iter.next() {
        match seg {
            // Apparel: gca=category, gsc=sub, gcu=cut, gqa=quality, gsi=size, gco=color
            "gca" | "gsc" | "gcu" | "gqa" | "gsi" | "gco" => {
                if let Some(val) = iter.next() {
                    parts.push(val.replace('-', " "));
                }
            }
            // Mug size, material; canvas size, frame type, etc — only meaningful tokens
            "msz" | "mmat" | "bsc" | "bqa" | "bsi" | "bco" => {
                if let Some(val) = iter.next() {
                    parts.push(val.replace('-', " "));
                }
            }
            _ => {}
        }
    }
    if parts.is_empty() { uid.to_string() } else {
        let mut s = parts.join(" · ");
        // Capitalize first letter for visual cleanliness.
        if let Some(c) = s.get_mut(0..1) { c.make_ascii_uppercase(); }
        s
    }
}

/// Insert a row into pod_catalog with price=0 (= "seeded, not priced yet").
/// Existing rows are left untouched so a re-seed doesn't clobber prices.
fn pod_catalog_upsert_unpriced(conn: &rusqlite::Connection, vendor: &str, uid: &str, title: &str, category: &str) -> rusqlite::Result<usize> {
    conn.execute(
        "INSERT INTO pod_catalog
           (vendor, product_uid, title, category, price_value, price_currency,
            production_country, min_delivery_days, max_delivery_days, last_priced_at)
         VALUES (?1, ?2, ?3, ?4, 0.0, '?', '?', 0, 0, '0')
         ON CONFLICT(vendor, product_uid) DO UPDATE SET
           title=excluded.title,
           category=excluded.category",
        params![vendor, uid, title, category],
    )
}

/// Seed Gelato — iterate target catalogs, save productUid + parsed label.
/// Returns (inserted_or_updated, errors).
async fn pod_seed_gelato(db: &Db) -> Result<(usize, Vec<String>), String> {
    let key = env::var("GELATO_API_KEY").map_err(|_| "GELATO_API_KEY unset".to_string())?;
    let client = pod_http_client();
    let mut count = 0usize;
    let mut errors: Vec<String> = Vec::new();
    for catalog in GELATO_SEED_CATALOGS {
        let url = format!("https://product.gelatoapis.com/v3/catalogs/{}/products:search", catalog);
        let body = serde_json::json!({"limit": 100});
        let resp = match client.post(&url).header("X-API-KEY", &key)
            .header("Content-Type", "application/json").json(&body).send().await {
            Ok(r) => r,
            Err(e) => { errors.push(format!("{}: {}", catalog, e)); continue; }
        };
        if !resp.status().is_success() {
            errors.push(format!("{}: HTTP {}", catalog, resp.status()));
            continue;
        }
        let v: serde_json::Value = match resp.json().await {
            Ok(j) => j,
            Err(e) => { errors.push(format!("{}: json {}", catalog, e)); continue; }
        };
        let prods = match v["products"].as_array() { Some(a) => a.clone(), None => continue };
        let cat_key: String = (*catalog).into();
        let conn = db.lock().unwrap();
        for p in &prods {
            let uid = match p["productUid"].as_str() { Some(s) => s.to_string(), None => continue };
            let label = gelato_label_from_uid(&uid);
            let category = if cat_key == "apparel" {
                // Refine: look at attributes for GarmentCategory
                p["attributes"].as_array().and_then(|arr| {
                    arr.iter().find(|a| a["productAttributeUid"].as_str() == Some("GarmentCategory"))
                        .and_then(|a| a["productAttributeValueUid"].as_str())
                        .map(|s| s.to_string())
                }).unwrap_or(cat_key.clone())
            } else { cat_key.clone() };
            if pod_catalog_upsert_unpriced(&conn, "gelato", &uid, &label, &category).is_ok() {
                count += 1;
            }
        }
    }
    Ok((count, errors))
}

/// Seed Printful — fetch /products (all top-level products) and store each
/// with the product_id as the uid and product.title as the title.
async fn pod_seed_printful(db: &Db) -> Result<(usize, Vec<String>), String> {
    let key = env::var("PRINTFUL_API_KEY").map_err(|_| "PRINTFUL_API_KEY unset".to_string())?;
    let resp = pod_http_client()
        .get("https://api.printful.com/products")
        .bearer_auth(&key)
        .send().await.map_err(|e| format!("printful GET: {}", e))?;
    if !resp.status().is_success() {
        return Err(format!("printful HTTP {}", resp.status()));
    }
    let v: serde_json::Value = resp.json().await.map_err(|e| format!("printful json: {}", e))?;
    let items = v["result"].as_array().ok_or_else(|| "no result array".to_string())?;
    let mut count = 0usize;
    let conn = db.lock().unwrap();
    for it in items {
        let pid = match it["id"].as_i64() { Some(n) => n, None => continue };
        let title = it["title"].as_str().unwrap_or("(untitled)").to_string();
        let cat = it["type_name"].as_str().or_else(|| it["type"].as_str()).unwrap_or("other").to_string();
        if pod_catalog_upsert_unpriced(&conn, "printful", &pid.to_string(), &title, &cat).is_ok() {
            count += 1;
        }
    }
    Ok((count, vec![]))
}

/// Seed SUZURI — fetch /api/v1/items (item templates), store all.
/// Wholesale prices come from SUZURI_BASE_PRICES_JPY at probe time;
/// items not in that map will show price=0 until added.
async fn pod_seed_suzuri(db: &Db) -> Result<(usize, Vec<String>), String> {
    let token = env::var("SUZURI_ACCESS_TOKEN").map_err(|_| "SUZURI_ACCESS_TOKEN unset".to_string())?;
    let resp = pod_http_client()
        .get("https://suzuri.jp/api/v1/items")
        .bearer_auth(&token)
        .send().await.map_err(|e| format!("suzuri GET: {}", e))?;
    if !resp.status().is_success() {
        return Err(format!("suzuri HTTP {}", resp.status()));
    }
    let v: serde_json::Value = resp.json().await.map_err(|e| format!("suzuri json: {}", e))?;
    let items = v["items"].as_array().ok_or_else(|| "no items array".to_string())?;
    let mut count = 0usize;
    let conn = db.lock().unwrap();
    for it in items {
        let id = match it["id"].as_u64() { Some(n) => n, None => continue };
        let title = it["humanizeName"].as_str()
            .or_else(|| it["name"].as_str())
            .unwrap_or("(untitled)").to_string();
        // Loose category from name keywords.
        let lower = title.to_lowercase();
        let cat = if title.contains("Tシャツ") || lower.contains("t-shirt") || lower.contains("tee") { "t-shirt" }
            else if title.contains("パーカー") || title.contains("フーディ") || lower.contains("hoodie") { "hoodie" }
            else if title.contains("スウェット") || lower.contains("sweat") { "sweatshirt" }
            else if title.contains("トート") || title.contains("バッグ") || lower.contains("bag") { "tote" }
            else if title.contains("マグ") || lower.contains("mug") { "mug" }
            else if title.contains("ステッカー") || lower.contains("sticker") { "sticker" }
            else if title.contains("ポスター") || lower.contains("poster") { "poster" }
            else if title.contains("ケース") || lower.contains("case") { "phone-case" }
            else { "other" };
        if pod_catalog_upsert_unpriced(&conn, "suzuri", &id.to_string(), &title, cat).is_ok() {
            count += 1;
        }
    }
    Ok((count, vec![]))
}

/// POST /api/admin/pod/seed?vendor=<gelato|printful|suzuri> — bulk catalog
/// ingest. Stores rows with price=0; later sync probes prices.
///
/// `vendor=all` is REJECTED because Gelato alone takes ~21 catalogs ×
/// up to 20s = ~420s, well past Fly's 60s edge proxy timeout. The UI
/// fires three sequential per-vendor requests instead. See the SEED ALL
/// button handler in admin-pod.html.
async fn admin_pod_seed(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/api/admin/pod/seed").await { return r; }
    let vendor = match q.get("vendor").map(|s| s.as_str()) {
        Some("gelato") | Some("printful") | Some("suzuri") => q.get("vendor").unwrap().clone(),
        Some("all") => return (StatusCode::BAD_REQUEST,
            Json(serde_json::json!({"error":"vendor=all is not allowed — call once per vendor (Fly proxy timeout)"}))).into_response(),
        _ => return (StatusCode::BAD_REQUEST,
            Json(serde_json::json!({"error":"vendor param required (gelato|printful|suzuri)"}))).into_response(),
    };
    let r = match vendor.as_str() {
        "gelato"   => pod_seed_gelato(&db).await,
        "printful" => pod_seed_printful(&db).await,
        "suzuri"   => pod_seed_suzuri(&db).await,
        _          => Err("?".into()),
    };
    let payload = match r {
        Ok((n, errs)) => serde_json::json!({"ok": true,  "vendor": vendor, "inserted": n, "errors": errs, "results": [{"vendor": vendor, "inserted": n, "errors": errs}]}),
        Err(e)        => serde_json::json!({"ok": false, "vendor": vendor, "error":    e, "results": [{"vendor": vendor, "error":    e}]}),
    };
    Json(payload).into_response()
}

/// GET /admin/pod — unified static admin page.
async fn admin_pod_page(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/admin/pod").await { return r; }
    Html(include_str!("../static/admin-pod.html")).into_response()
}

/// GET /api/admin/pod/catalog — return cached catalog (all vendors) + linked MU products.
async fn admin_pod_catalog(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/api/admin/pod/catalog").await { return r; }
    let conn = db.lock().unwrap();
    let rows: Vec<(String, String, String, Option<String>, f64, String, String, i64, i64, String)> = {
        let mut st = match conn.prepare(
            "SELECT vendor, product_uid, title, category, price_value, price_currency,
                    production_country, min_delivery_days, max_delivery_days, last_priced_at
               FROM pod_catalog
              ORDER BY vendor, (price_value=0) ASC, (production_country='JP') DESC, price_value ASC") {
            Ok(s) => s,
            Err(e) => return Json(serde_json::json!({"error": e.to_string()})).into_response(),
        };
        st.query_map([], |r| Ok((
            r.get::<_, String>(0)?,
            r.get::<_, String>(1)?,
            r.get::<_, String>(2).unwrap_or_default(),
            r.get::<_, Option<String>>(3).unwrap_or(None),
            r.get::<_, f64>(4).unwrap_or(0.0),
            r.get::<_, String>(5).unwrap_or_default(),
            r.get::<_, String>(6).unwrap_or_default(),
            r.get::<_, i64>(7).unwrap_or(0),
            r.get::<_, i64>(8).unwrap_or(0),
            r.get::<_, String>(9).unwrap_or_default(),
        ))).map(|it| it.flatten().collect()).unwrap_or_default()
    };
    let mut items: Vec<serde_json::Value> = Vec::new();
    for (vendor, uid, title, category, price, currency, country, min_d, max_d, when) in rows {
        let linked: Vec<serde_json::Value> = {
            let mut lst = match conn.prepare(
                "SELECT p.id, p.brand, p.drop_num, p.name, p.price_jpy, p.active
                   FROM product_pod_links l
                   JOIN products p ON p.id = l.product_id
                  WHERE l.vendor = ?1 AND l.pod_uid = ?2 ORDER BY p.id DESC") {
                Ok(s) => s,
                Err(_) => continue,
            };
            lst.query_map(params![&vendor, &uid], |r| Ok(serde_json::json!({
                "id":        r.get::<_, i64>(0)?,
                "brand":     r.get::<_, String>(1).unwrap_or_default(),
                "drop_num":  r.get::<_, i64>(2).unwrap_or(0),
                "name":      r.get::<_, String>(3).unwrap_or_default(),
                "price_jpy": r.get::<_, i64>(4).unwrap_or(0),
                "active":    r.get::<_, i64>(5).unwrap_or(0) != 0,
            }))).map(|it| it.flatten().collect()).unwrap_or_default()
        };
        items.push(serde_json::json!({
            "vendor": vendor, "uid": uid, "title": title, "category": category,
            "price_value": price, "price_currency": currency,
            "production_country": country,
            "min_delivery_days": min_d, "max_delivery_days": max_d,
            "last_priced_at": when,
            "linked_products": linked,
        }));
    }
    Json(serde_json::json!({"items": items, "total": items.len()})).into_response()
}

/// POST /api/admin/pod/sync?vendor=<gelato|printful|suzuri|all> — refresh curated SKUs.
async fn admin_pod_sync(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/api/admin/pod/sync").await { return r; }
    let vendor_filter = q.get("vendor").cloned().unwrap_or_else(|| "all".into());
    // Default 20 SKUs/call so even worst-case 20s probes total ≤400s. Typical
    // Gelato quote is ~1s, so 20 SKUs ≈ 20s — well under Fly's 60s edge proxy
    // timeout. User re-clicks PRICE until `remaining_stale` hits 0.
    let limit: i64 = q.get("limit").and_then(|s| s.parse().ok()).unwrap_or(20).clamp(1, 200);
    // `force=1` reprices everything; default skips rows with a fresh price (<24h).
    let force = matches!(q.get("force").map(|s| s.as_str()), Some("1") | Some("true"));
    // First-time bootstrap: if the catalog is empty for the requested vendor,
    // sync the legacy curated constants so the admin sees *something* even
    // before the user clicks SEED.
    {
        let conn = db.lock().unwrap();
        let n: i64 = if vendor_filter == "all" {
            conn.query_row("SELECT COUNT(*) FROM pod_catalog", [], |r| r.get(0)).unwrap_or(0)
        } else {
            conn.query_row("SELECT COUNT(*) FROM pod_catalog WHERE vendor=?1",
                params![vendor_filter.as_str()], |r| r.get(0)).unwrap_or(0)
        };
        if n == 0 {
            for sku in POD_CURATED_SKUS {
                if vendor_filter != "all" && vendor_filter != sku.vendor { continue; }
                let _ = pod_catalog_upsert_unpriced(&conn, sku.vendor, sku.uid, sku.label, sku.category);
            }
        }
    }
    // Pick rows to probe: stale (or all if force=1), limited.
    let now_sec: i64 = chrono_now().parse().unwrap_or(0);
    let stale_cutoff = now_sec - 24 * 3600;
    let rows: Vec<(String, String, String, String)> = {
        let conn = db.lock().unwrap();
        let sql = if vendor_filter == "all" {
            if force { "SELECT vendor, product_uid, title, COALESCE(category,'?') FROM pod_catalog ORDER BY CAST(last_priced_at AS INTEGER) ASC LIMIT ?1".to_string() }
            else     { "SELECT vendor, product_uid, title, COALESCE(category,'?') FROM pod_catalog WHERE CAST(last_priced_at AS INTEGER) < ?2 ORDER BY CAST(last_priced_at AS INTEGER) ASC LIMIT ?1".to_string() }
        } else {
            if force { "SELECT vendor, product_uid, title, COALESCE(category,'?') FROM pod_catalog WHERE vendor=?3 ORDER BY CAST(last_priced_at AS INTEGER) ASC LIMIT ?1".to_string() }
            else     { "SELECT vendor, product_uid, title, COALESCE(category,'?') FROM pod_catalog WHERE vendor=?3 AND CAST(last_priced_at AS INTEGER) < ?2 ORDER BY CAST(last_priced_at AS INTEGER) ASC LIMIT ?1".to_string() }
        };
        let mut st = match conn.prepare(&sql) { Ok(s) => s, Err(_) => return Json(serde_json::json!({"error":"prep"})).into_response() };
        let mapper = |r: &rusqlite::Row| Ok((
            r.get::<_, String>(0)?, r.get::<_, String>(1)?,
            r.get::<_, String>(2).unwrap_or_default(),
            r.get::<_, String>(3).unwrap_or_default(),
        ));
        let it_result = if vendor_filter == "all" {
            if force { st.query_map(params![limit], mapper) }
            else     { st.query_map(params![limit, stale_cutoff], mapper) }
        } else {
            if force { st.query_map(params![limit, vendor_filter.as_str()], mapper) }
            else     { st.query_map(params![limit, stale_cutoff, vendor_filter.as_str()], mapper) }
        };
        match it_result {
            Ok(it) => it.flatten().collect(),
            Err(_) => Vec::new(),
        }
    };
    let total_to_probe = rows.len();
    let mut synced: Vec<serde_json::Value> = Vec::new();
    let mut errors: Vec<serde_json::Value> = Vec::new();
    let mut rejected: Vec<serde_json::Value> = Vec::new();
    for (vendor, uid, _title, _cat) in rows {
        match pod_probe(&vendor, &uid).await {
            Ok((price, currency, country, min_d, max_d)) => {
                // Sanity guard: reject prices that diverge >2× from the
                // previous value. Defends against vendor APIs briefly
                // returning garbage (a single bad 1 ¥ would tank margins
                // until a human notices).
                let prev: Option<f64> = {
                    let conn = db.lock().unwrap();
                    conn.query_row(
                        "SELECT price_value FROM pod_catalog WHERE vendor=?1 AND product_uid=?2",
                        params![&vendor, &uid], |r| r.get::<_, f64>(0),
                    ).ok().filter(|p| *p > 0.0)
                };
                if let Some(p) = prev {
                    let ratio = if price > 0.0 { price / p } else { 0.0 };
                    if ratio > 2.0 || ratio < 0.5 {
                        eprintln!("[pod_sync] reject {} {}: new={} prev={} ratio={:.2}", vendor, uid, price, p, ratio);
                        rejected.push(serde_json::json!({
                            "vendor": vendor, "uid": uid,
                            "rejected_price": price, "currency": currency,
                            "previous_price": p,
                            "reason": format!("price diverged {:.2}x from previous (guard: 0.5-2.0)", ratio),
                        }));
                        continue;
                    }
                }
                let conn = db.lock().unwrap();
                let _ = conn.execute(
                    "UPDATE pod_catalog SET
                       price_value=?1, price_currency=?2, production_country=?3,
                       min_delivery_days=?4, max_delivery_days=?5, last_priced_at=?6
                     WHERE vendor=?7 AND product_uid=?8",
                    params![price, currency, country, min_d as i64, max_d as i64, chrono_now(), vendor, uid],
                );
                let _ = conn.execute(
                    "INSERT INTO pod_catalog_price_history
                       (vendor, product_uid, price_value, price_currency,
                        production_country, min_delivery_days, max_delivery_days, at, source)
                     VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8, 'sync')",
                    params![&vendor, &uid, price, &currency, &country, min_d as i64, max_d as i64, chrono_now()],
                );
                synced.push(serde_json::json!({
                    "vendor": vendor, "uid": uid,
                    "price": price, "currency": currency, "country": country
                }));
            }
            Err(e) => {
                errors.push(serde_json::json!({"vendor": vendor, "uid": uid, "error": e}));
            }
        }
    }
    // Count remaining stale rows so the UI can show "more to sync".
    let remaining_stale: i64 = {
        let conn = db.lock().unwrap();
        let sql = if vendor_filter == "all" {
            "SELECT COUNT(*) FROM pod_catalog WHERE CAST(last_priced_at AS INTEGER) < ?1".to_string()
        } else {
            "SELECT COUNT(*) FROM pod_catalog WHERE vendor=?2 AND CAST(last_priced_at AS INTEGER) < ?1".to_string()
        };
        if vendor_filter == "all" {
            conn.query_row(&sql, params![stale_cutoff], |r| r.get(0)).unwrap_or(0)
        } else {
            conn.query_row(&sql, params![stale_cutoff, vendor_filter.as_str()], |r| r.get(0)).unwrap_or(0)
        }
    };
    Json(serde_json::json!({
        "ok": true, "vendor": vendor_filter,
        "probed": total_to_probe, "limit": limit, "force": force,
        "remaining_stale": remaining_stale,
        "synced": synced, "errors": errors,
        "rejected": rejected,
    })).into_response()
}

#[derive(Deserialize)]
struct PodLinkReq {
    product_id: i64,
    vendor:     String,
    pod_uid:    String,
}

/// POST /api/admin/pod/link — bind a POD SKU to an MU product.
async fn admin_pod_link(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(req): Json<PodLinkReq>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/api/admin/pod/link").await { return r; }
    let conn = db.lock().unwrap();
    match conn.execute(
        "INSERT OR IGNORE INTO product_pod_links (product_id, vendor, pod_uid, created_at)
         VALUES (?1, ?2, ?3, ?4)",
        params![req.product_id, req.vendor, req.pod_uid, chrono_now()],
    ) {
        Ok(n) => Json(serde_json::json!({"ok": true, "inserted": n})).into_response(),
        Err(e) => (StatusCode::INTERNAL_SERVER_ERROR,
            Json(serde_json::json!({"error": e.to_string()}))).into_response(),
    }
}

/// POST /api/admin/pod/unlink — remove a POD↔MU link.
async fn admin_pod_unlink(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(req): Json<PodLinkReq>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/api/admin/pod/unlink").await { return r; }
    let conn = db.lock().unwrap();
    match conn.execute(
        "DELETE FROM product_pod_links WHERE product_id=?1 AND vendor=?2 AND pod_uid=?3",
        params![req.product_id, req.vendor, req.pod_uid],
    ) {
        Ok(n) => Json(serde_json::json!({"ok": true, "deleted": n})).into_response(),
        Err(e) => (StatusCode::INTERNAL_SERVER_ERROR,
            Json(serde_json::json!({"error": e.to_string()}))).into_response(),
    }
}

// ───── /admin/funnel — the drop-off diagnostic per Plan-agent W1 ──────
//
// Aggregates funnel_events over a 7-day window into the canonical sales
// funnel pageview → cta_click → checkout_start → checkout_paid. Shows
// the absolute count, the step-over-step conversion rate, and the
// biggest drop-off so the founder (Yuki) can fix one thing at a time.
//
// Why this matters today (2026-05-18): Google Ads burned ¥42K over 3
// days with 0 conversions. Without a per-step view we cannot tell if
// the loss was at landing, CTA, checkout init, or Stripe completion.
// Three-device manual testing is one diagnostic; this is the other.

async fn admin_funnel_page(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/admin/funnel").await { return r; }
    let days: i64 = q.get("days").and_then(|s| s.parse().ok()).unwrap_or(7).clamp(1, 90);
    let cutoff: i64 = chrono_now().parse::<i64>().unwrap_or(0) - days * 86_400;

    let conn = db.lock().unwrap();
    let count = |event: &str| -> i64 {
        conn.query_row(
            "SELECT COUNT(*) FROM funnel_events
             WHERE event=?1 AND CAST(COALESCE(created_at,'0') AS INTEGER) > ?2",
            params![event, cutoff], |r| r.get(0),
        ).unwrap_or(0)
    };
    let uniq = |event: &str| -> i64 {
        conn.query_row(
            "SELECT COUNT(DISTINCT visitor_id) FROM funnel_events
             WHERE event=?1 AND CAST(COALESCE(created_at,'0') AS INTEGER) > ?2",
            params![event, cutoff], |r| r.get(0),
        ).unwrap_or(0)
    };

    let pv      = count("pageview");
    let pv_u    = uniq("pageview");
    let cta     = count("cta_click");
    let cta_u   = uniq("cta_click");
    let st      = count("checkout_start");
    let st_u    = uniq("checkout_start");
    let paid    = count("checkout_paid");
    let paid_u  = uniq("checkout_paid");

    let pct = |a: i64, b: i64| -> String {
        if b <= 0 { return "—".into(); }
        format!("{:.1}%", 100.0 * a as f64 / b as f64)
    };
    let drop = |a: i64, b: i64| -> String {
        if b <= 0 { return "—".into(); }
        let d = b - a;
        format!("-{} ({:.1}%)", d, 100.0 * d as f64 / b as f64)
    };

    // Top paths by pageview (where traffic actually lands)
    let mut path_rows = String::new();
    {
        let mut st_ = match conn.prepare(
            "SELECT path, COUNT(*) AS pv, COUNT(DISTINCT visitor_id) AS uv
             FROM funnel_events
             WHERE event='pageview' AND CAST(COALESCE(created_at,'0') AS INTEGER) > ?1
             GROUP BY path ORDER BY pv DESC LIMIT 15"
        ) { Ok(s) => Some(s), Err(_) => None };
        if let Some(s) = st_.as_mut() {
            let rows: Vec<(String, i64, i64)> = s.query_map(params![cutoff], |r| {
                Ok((r.get::<_, String>(0).unwrap_or_default(),
                    r.get::<_, i64>(1).unwrap_or(0),
                    r.get::<_, i64>(2).unwrap_or(0)))
            }).map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default();
            for (p, pv_, uv) in &rows {
                let escaped = p.replace('<', "&lt;").replace('>', "&gt;");
                path_rows.push_str(&format!(
                    "<tr><td><code>{}</code></td><td class='num'>{}</td><td class='num'>{}</td></tr>",
                    escaped, pv_, uv
                ));
            }
        }
    }
    if path_rows.is_empty() {
        path_rows = "<tr><td colspan='3' style='text-align:center;color:#666;padding:40px'>まだ pageview なし</td></tr>".into();
    }

    let html = format!(r##"<!doctype html>
<html lang="ja"><head><meta charset="utf-8"><title>MU · funnel</title>
<meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="robots" content="noindex">
<style>
  body{{background:#0A0A0A;color:#F5F5F0;font-family:ui-monospace,Menlo,monospace;margin:0;padding:24px;font-size:13px;line-height:1.55}}
  .wrap{{max-width:1100px;margin:0 auto}}
  h1{{font-size:14px;letter-spacing:0.4em;margin:0 0 4px}}
  .sub{{color:#888;font-size:11px;letter-spacing:0.16em;margin-bottom:24px}}
  table{{width:100%;border-collapse:collapse;background:#101010;border:1px solid #1c1c1c;border-radius:6px;overflow:hidden;margin-bottom:24px}}
  th,td{{padding:10px 14px;text-align:left;border-bottom:1px solid #1c1c1c;font-size:12px}}
  th{{color:#888;font-size:10px;letter-spacing:0.22em;text-transform:uppercase;background:#080808}}
  td.num{{text-align:right;font-variant-numeric:tabular-nums}}
  td.step{{font-weight:600;color:#e6c449;letter-spacing:0.14em}}
  td.drop{{color:#ff4a3d;font-variant-numeric:tabular-nums;font-size:11px}}
  td.conv{{color:#7be57b;font-variant-numeric:tabular-nums}}
  code{{background:#050505;padding:2px 6px;border-radius:3px;color:#aaa;font-size:11px}}
  .note{{color:#666;font-size:11px;line-height:1.9;border-top:1px solid #1c1c1c;padding-top:16px}}
  a{{color:#e6c449}}
</style></head><body>
<div class="wrap">
  <h1>MU · FUNNEL ({days}d)</h1>
  <div class="sub">Plan agent W1 — drop-off を 数字 で 見る</div>
  <table>
    <thead><tr><th>step</th><th class='num'>events</th><th class='num'>uniq visitors</th><th class='num'>conv vs prev</th><th>drop-off</th></tr></thead>
    <tbody>
      <tr><td class='step'>1. PAGEVIEW</td><td class='num'>{pv}</td><td class='num'>{pv_u}</td><td class='num conv'>—</td><td>—</td></tr>
      <tr><td class='step'>2. CTA_CLICK</td><td class='num'>{cta}</td><td class='num'>{cta_u}</td><td class='num conv'>{cta_pct}</td><td class='drop'>{cta_drop}</td></tr>
      <tr><td class='step'>3. CHECKOUT_START</td><td class='num'>{st}</td><td class='num'>{st_u}</td><td class='num conv'>{st_pct}</td><td class='drop'>{st_drop}</td></tr>
      <tr><td class='step'>4. CHECKOUT_PAID</td><td class='num'>{paid}</td><td class='num'>{paid_u}</td><td class='num conv'>{paid_pct}</td><td class='drop'>{paid_drop}</td></tr>
      <tr><td class='step' style='color:#888'>TOTAL CVR</td><td colspan='4' class='num' style='color:#7be57b'>{total_cvr} (paid / pageview)</td></tr>
    </tbody>
  </table>
  <table>
    <thead><tr><th>top paths (pageview)</th><th class='num'>events</th><th class='num'>uniq</th></tr></thead>
    <tbody>{path_rows}</tbody>
  </table>
  <div class="note">
    drop-off が 一番 大きい step が <strong>修正 すべき #1 箇所</strong>。 普通の e-comm の 目安:
    <br>· pageview → cta_click: 5-15% 健康
    <br>· cta_click → checkout_start: 30-60% 健康 (低い と CTA UX 不調 か 価格 ショック)
    <br>· checkout_start → checkout_paid: 50-80% 健康 (低い と Stripe ページ で 落ちてる、 カード入力 失敗 / 3DS 失敗 等)
    <br><br>
    今回 の Google Ads ¥42K で 0 conv の 原因 は ここ で 見える はず。 step 2 or 3 で 100% drop なら CTA ボタン or checkout init 関数 (`/api/checkout/v2`) が 壊れてる。
    <br><br>
    <a href="/admin/retention">→ retention</a> · <a href="/admin/db">→ db</a> · <a href="/admin/costs">→ costs</a>
  </div>
</div></body></html>"##,
        days = days,
        pv = pv, pv_u = pv_u,
        cta = cta, cta_u = cta_u, cta_pct = pct(cta, pv), cta_drop = drop(cta, pv),
        st = st, st_u = st_u, st_pct = pct(st, cta), st_drop = drop(st, cta),
        paid = paid, paid_u = paid_u, paid_pct = pct(paid, st), paid_drop = drop(paid, st),
        total_cvr = pct(paid, pv),
        path_rows = path_rows,
    );
    Html(html).into_response()
}

// ───── /admin/retention — the only metric that proves §29 is real ─────
//
// Why this exists: Plan agent / 6-persona review identified that all the
// §30 spec work is downstream of "do customers come back?" — and we had
// no measurement. This view computes from mu_purchases:
//
//   - distinct buyer count
//   - repeat-buyer count (>= 2 distinct purchases)
//   - days-to-2nd-purchase per repeater
//   - weekly cohort table (week-of-first-purchase × cumulative repeats)
//
// Read-only, admin-gated. Refuses to over-render — if there's not enough
// data the page says so honestly instead of inventing percentages.

async fn admin_retention_page(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/admin/retention").await { return r; }
    let conn = db.lock().unwrap();

    let total_purchases: i64 = conn.query_row(
        "SELECT COUNT(*) FROM mu_purchases", [], |r| r.get(0),
    ).unwrap_or(0);
    let distinct_buyers: i64 = conn.query_row(
        "SELECT COUNT(DISTINCT email) FROM mu_purchases WHERE email != ''", [], |r| r.get(0),
    ).unwrap_or(0);
    let repeat_buyers: i64 = conn.query_row(
        "SELECT COUNT(*) FROM (
           SELECT email FROM mu_purchases WHERE email != ''
           GROUP BY email HAVING COUNT(*) >= 2
         )", [], |r| r.get(0),
    ).unwrap_or(0);

    // Per-buyer: first purchase ts, second purchase ts, days-between
    let rows: Vec<(String, String, i64, i64)> = {
        let mut st = match conn.prepare(
            "SELECT email,
                    MIN(created_at) AS first_ts,
                    COUNT(*)        AS purchase_count,
                    COALESCE(SUM(amount_jpy), 0) AS total_jpy
             FROM mu_purchases
             WHERE email != ''
             GROUP BY email
             ORDER BY first_ts ASC"
        ) {
            Ok(s) => s,
            Err(e) => return Html(format!("<p>schema err: {}</p>", e)).into_response(),
        };
        st.query_map([], |r| Ok((
            r.get::<_, String>(0)?,
            r.get::<_, String>(1).unwrap_or_default(),
            r.get::<_, i64>(2).unwrap_or(0),
            r.get::<_, i64>(3).unwrap_or(0),
        ))).map(|it| it.flatten().collect()).unwrap_or_default()
    };

    // Compute days-to-2nd for repeaters
    let mut days_to_second: Vec<i64> = Vec::new();
    for (email, _first_ts, count, _amt) in &rows {
        if *count < 2 { continue; }
        let second_row: Option<(String, String)> = conn.query_row(
            "SELECT MIN(created_at), MAX(created_at) FROM mu_purchases
             WHERE email=?1
             AND id NOT IN (SELECT id FROM mu_purchases WHERE email=?1 ORDER BY created_at ASC LIMIT 1)",
            params![email],
            |r| Ok((r.get::<_, String>(0).unwrap_or_default(), r.get::<_, String>(1).unwrap_or_default())),
        ).ok();
        if let Some((second_ts, _)) = second_row {
            let first_row = rows.iter().find(|x| x.0 == *email).map(|x| x.1.clone()).unwrap_or_default();
            let f: i64 = first_row.parse().unwrap_or(0);
            let s: i64 = second_ts.parse().unwrap_or(0);
            if f > 0 && s > f { days_to_second.push((s - f) / 86_400); }
        }
    }
    let avg_days: Option<f64> = if days_to_second.is_empty() { None } else {
        Some(days_to_second.iter().sum::<i64>() as f64 / days_to_second.len() as f64)
    };

    // Repeat rate (only meaningful with ≥10 buyers per Plan agent / buffett)
    let repeat_rate_str = if distinct_buyers >= 10 {
        format!("{:.1}%", (repeat_buyers as f64 / distinct_buyers as f64) * 100.0)
    } else {
        format!("— (まだ {} 人 だけ。 10 人 集まったら 表示)", distinct_buyers)
    };

    // Render
    let mut buyer_rows = String::new();
    for (email, first_ts, count, total_jpy) in &rows {
        let mask = if email.len() > 4 {
            let parts: Vec<&str> = email.splitn(2, '@').collect();
            if parts.len() == 2 {
                let p0 = parts[0];
                let v: Vec<char> = p0.chars().collect();
                format!("{}***@{}", v.iter().take(2).collect::<String>(), parts[1])
            } else { email.clone() }
        } else { email.clone() };
        let first_dt = {
            let f: i64 = first_ts.parse().unwrap_or(0);
            if f > 0 {
                let jst_secs = f + 9 * 3600;
                let days = jst_secs / 86_400;
                let z = days + 719_468;
                let era = if z >= 0 { z } else { z - 146_096 } / 146_097;
                let doe = z - era * 146_097;
                let yoe = (doe - doe / 1460 + doe / 36524 - doe / 146_096) / 365;
                let y = yoe + era * 400;
                let doy = doe - (365 * yoe + yoe / 4 - yoe / 100);
                let mp = (5 * doy + 2) / 153;
                let m = if mp < 10 { mp + 3 } else { mp - 9 };
                let d = doy - (153 * mp + 2) / 5 + 1;
                let yy = if m <= 2 { y + 1 } else { y };
                format!("{:04}-{:02}-{:02}", yy, m, d)
            } else { "-".into() }
        };
        let highlight = if *count >= 2 { " style='background:rgba(123,229,123,0.08)'" } else { "" };
        buyer_rows.push_str(&format!(
            "<tr{}><td>{}</td><td>{}</td><td class='num'>{}</td><td class='num'>¥{}</td></tr>",
            highlight, mask, first_dt, count, total_jpy.to_string(),
        ));
    }

    let avg_days_str = avg_days.map(|d| format!("{:.1} 日", d)).unwrap_or_else(|| "—".into());

    let html = format!(r##"<!doctype html>
<html lang="ja"><head><meta charset="utf-8"><title>MU · retention</title>
<meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="robots" content="noindex">
<style>
  body{{background:#0A0A0A;color:#F5F5F0;font-family:ui-monospace,Menlo,monospace;margin:0;padding:24px;font-size:13px;line-height:1.55}}
  .wrap{{max-width:1100px;margin:0 auto}}
  h1{{font-size:14px;letter-spacing:0.4em;margin:0 0 4px}}
  .sub{{color:#888;font-size:11px;letter-spacing:0.16em;margin-bottom:24px}}
  .kpis{{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;margin-bottom:24px}}
  .kpi{{background:#101010;border:1px solid #1c1c1c;border-radius:6px;padding:14px 16px}}
  .kpi .label{{color:#888;font-size:10px;letter-spacing:0.18em;text-transform:uppercase}}
  .kpi .value{{color:#e6c449;font-size:22px;margin-top:6px;font-variant-numeric:tabular-nums}}
  .kpi .meta{{color:#666;font-size:10px;margin-top:4px}}
  table{{width:100%;border-collapse:collapse;background:#101010;border:1px solid #1c1c1c;border-radius:6px;overflow:hidden}}
  th,td{{padding:9px 14px;text-align:left;border-bottom:1px solid #1c1c1c;font-size:12px}}
  th{{color:#888;font-size:10px;letter-spacing:0.22em;text-transform:uppercase;background:#080808}}
  td.num{{text-align:right;font-variant-numeric:tabular-nums}}
  .note{{margin-top:24px;color:#666;font-size:11px;line-height:1.9;border-top:1px solid #1c1c1c;padding-top:16px}}
  a{{color:#e6c449}}
</style></head><body>
<div class="wrap">
  <h1>MU · RETENTION</h1>
  <div class="sub">Plan agent Week 1 priority — the only metric that proves §29 is real.</div>
  <div class="kpis">
    <div class="kpi"><div class="label">Purchases</div><div class="value">{purchases}</div><div class="meta">cs_live_* 累計</div></div>
    <div class="kpi"><div class="label">Distinct buyers</div><div class="value">{buyers}</div><div class="meta">unique email</div></div>
    <div class="kpi"><div class="label">Repeat buyers</div><div class="value">{repeats}</div><div class="meta">≥2 purchases</div></div>
    <div class="kpi"><div class="label">Repeat rate</div><div class="value">{rate}</div><div class="meta">Plan W4 gate: ≥15%</div></div>
    <div class="kpi"><div class="label">Avg days to 2nd</div><div class="value">{avg_days}</div><div class="meta">N={n_repeats}</div></div>
  </div>
  <table>
    <thead><tr><th>buyer (masked)</th><th>first purchase</th><th>purchases</th><th>total ¥</th></tr></thead>
    <tbody>{rows}</tbody>
  </table>
  <div class="note">
    Plan agent W2 action: <strong>13 名 全員 に Yuki 名義 で ¥500 OFF メール を 個別送付</strong>, 14日 期限。 redemption が 2 件 出れば repeat_rate が 15.4% — Plan W4 gate に 到達。
    <br>Plan agent: 「§30 を 動かす 前 に この 数字 が 必要。 数字 が 出ない なら §30 は <strong>delete</strong> 候補。」
    <br><br>
    Updated 2026-05-18 / Plan agent recommendation #6.
  </div>
</div></body></html>"##,
        purchases = total_purchases,
        buyers = distinct_buyers,
        repeats = repeat_buyers,
        rate = repeat_rate_str,
        avg_days = avg_days_str,
        n_repeats = days_to_second.len(),
        rows = if buyer_rows.is_empty() {
            "<tr><td colspan='4' style='text-align:center;color:#666;padding:40px'>まだ 購入 が ありません</td></tr>".into()
        } else { buyer_rows },
    );
    Html(html).into_response()
}

// ───── §30-EX v3 circular exchange handlers ────────────────────────────
//
// Endpoints:
//   POST /api/pt/exchange/list   — owner lists their cert into the pool
//   POST /api/pt/exchange/claim  — another user claims for 30pt
//   GET  /api/pt/exchange/pool   — public read-only listing of pool
//   GET  /pt-exchange            — public HTML page
//
// Fulfillment (printing both sides) is deferred to agent_pt_swap_processor.

const PT_SWAP_COST: i64 = 30;
const PT_SWAP_LISTING_DAYS: i64 = 30;

#[derive(Deserialize)]
struct PtExchangeListReq {
    email: String,
    cert_id: String,
}

/// POST /api/pt/exchange/list — owner releases a cert into the swap pool.
/// No pt cost to list — the cert is given to MU as 黙示の贈与 (silent gift).
async fn pt_exchange_list_handler(
    State(db): State<Db>,
    Json(req): Json<PtExchangeListReq>,
) -> Response {
    let email = normalize_email(&req.email);
    if validate_email(&email).is_err() {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"error": "invalid email"}))).into_response();
    }
    let conn = db.lock().unwrap();
    let cert: Option<(i64, Option<String>)> = conn.query_row(
        "SELECT product_id, retired_at FROM pt_certificates
         WHERE cert_id=?1 AND owner_email=?2",
        params![&req.cert_id, &email],
        |r| Ok((r.get::<_, i64>(0)?, r.get::<_, Option<String>>(1)?)),
    ).ok();
    let (product_id, retired_at) = match cert {
        Some(c) => c,
        None => return (StatusCode::NOT_FOUND, Json(serde_json::json!({"error": "cert not found or not owned by this email"}))).into_response(),
    };
    if retired_at.is_some() {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"error": "cert already retired (swapped, redeemed, or expired)"}))).into_response();
    }
    let now_s: i64 = chrono_now().parse().unwrap_or(0);
    let expire_s = now_s + PT_SWAP_LISTING_DAYS * 86_400;
    // Atomically: retire cert + insert pool row.
    let _ = conn.execute(
        "UPDATE pt_certificates SET retired_at=?1, retire_reason='listed_for_exchange' WHERE cert_id=?2",
        params![chrono_now(), &req.cert_id],
    );
    let inserted = conn.execute(
        "INSERT INTO pt_swap_pool
           (owner_email, product_id, cert_id, listed_at, status, expire_at)
         VALUES (?1, ?2, ?3, ?4, 'listed', ?5)",
        params![&email, product_id, &req.cert_id, chrono_now(), expire_s.to_string()],
    );
    match inserted {
        Ok(_) => {
            let listing_id: i64 = conn.last_insert_rowid();
            Json(serde_json::json!({
                "ok": true,
                "listing_id": listing_id,
                "product_id": product_id,
                "expire_at": expire_s,
                "pt_cost_to_claim": PT_SWAP_COST,
            })).into_response()
        }
        Err(e) => (StatusCode::INTERNAL_SERVER_ERROR, Json(serde_json::json!({"error": e.to_string()}))).into_response(),
    }
}

#[derive(Deserialize)]
struct PtExchangeClaimReq {
    email: String,
    listing_id: i64,
}

/// POST /api/pt/exchange/claim — another MUer pays 30 pt to claim a listing.
/// The pt is deducted immediately; the actual Printful fulfillment runs
/// asynchronously via agent_pt_swap_processor.
async fn pt_exchange_claim_handler(
    State(db): State<Db>,
    Json(req): Json<PtExchangeClaimReq>,
) -> Response {
    let email = normalize_email(&req.email);
    if validate_email(&email).is_err() {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"error": "invalid email"}))).into_response();
    }
    let conn = db.lock().unwrap();
    let row: Option<(String, i64, String, String)> = conn.query_row(
        "SELECT owner_email, product_id, cert_id, status FROM pt_swap_pool WHERE id=?1",
        params![req.listing_id],
        |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?)),
    ).ok();
    let (owner_email, product_id, cert_id, status) = match row {
        Some(t) => t,
        None => return (StatusCode::NOT_FOUND, Json(serde_json::json!({"error": "listing not found"}))).into_response(),
    };
    if status != "listed" {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"error": format!("listing not claimable (status={})", status)}))).into_response();
    }
    if owner_email == email {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"error": "cannot claim your own listing"}))).into_response();
    }
    // Deduct pt — points_mutate enforces sufficient balance.
    let ref_str = format!("swap-{}", req.listing_id);
    match points_mutate(&conn, &email, -PT_SWAP_COST, "pt_swap_claim", Some(&ref_str), None) {
        Ok(new_bal) => {
            let _ = conn.execute(
                "UPDATE pt_swap_pool
                   SET claimed_by=?1, claimed_at=?2, status='claimed'
                 WHERE id=?3 AND status='listed'",
                params![&email, chrono_now(), req.listing_id],
            );
            Json(serde_json::json!({
                "ok": true,
                "listing_id": req.listing_id,
                "product_id": product_id,
                "cert_id": cert_id,
                "pt_balance_after": new_bal,
                "note": "fulfillment queued — agent_pt_swap_processor will print both items",
            })).into_response()
        }
        Err(e) => (StatusCode::BAD_REQUEST, Json(serde_json::json!({"error": e}))).into_response(),
    }
}

/// GET /api/pt/exchange/pool — public read of available listings (no auth).
/// Returns the first N unexpired, unclaimed listings with design preview.
async fn pt_exchange_pool_handler(
    State(db): State<Db>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let limit: i64 = q.get("limit").and_then(|s| s.parse().ok()).unwrap_or(50).clamp(1, 200);
    let now_s: i64 = chrono_now().parse().unwrap_or(0);
    let conn = db.lock().unwrap();
    let mut stmt = match conn.prepare(
        "SELECT s.id, s.product_id, s.listed_at, s.expire_at,
                p.brand, p.drop_num, p.name, p.design_url, p.mockup_url
         FROM pt_swap_pool s
         JOIN products p ON p.id = s.product_id
         WHERE s.status='listed' AND CAST(s.expire_at AS INTEGER) > ?1
         ORDER BY s.id DESC
         LIMIT ?2"
    ) {
        Ok(s) => s,
        Err(e) => return Json(serde_json::json!({"error": e.to_string()})).into_response(),
    };
    let items: Vec<serde_json::Value> = stmt.query_map(params![now_s, limit], |r| Ok(serde_json::json!({
        "listing_id": r.get::<_, i64>(0)?,
        "product_id": r.get::<_, i64>(1)?,
        "listed_at":  r.get::<_, String>(2).unwrap_or_default(),
        "expire_at":  r.get::<_, String>(3).unwrap_or_default(),
        "brand":      r.get::<_, String>(4).unwrap_or_default(),
        "drop_num":   r.get::<_, i64>(5).unwrap_or(0),
        "name":       r.get::<_, String>(6).unwrap_or_default(),
        "design_url": r.get::<_, Option<String>>(7).unwrap_or(None),
        "mockup_url": r.get::<_, Option<String>>(8).unwrap_or(None),
    }))).map(|it| it.flatten().collect()).unwrap_or_default();
    Json(serde_json::json!({
        "items": items,
        "pt_cost": PT_SWAP_COST,
        "policy": "§30-EX v3 (Constitution): list = release cert as silent gift, claim costs 30pt, both sides receive freshly printed items, no second-hand transfer between users",
    })).into_response()
}

#[derive(Deserialize)]
struct PtSpawnReq {
    email: String,
    seed_text: Option<String>,
}

/// POST /api/pt/spawn-mugen — 30 pt → new MUGEN drop request.
/// Enqueues; pt_spawn_processor agent runs Gemini asynchronously since
/// image generation is slow + costly + susceptible to upstream blips.
async fn pt_spawn_mugen_handler(
    State(db): State<Db>,
    Json(req): Json<PtSpawnReq>,
) -> Response {
    let email = normalize_email(&req.email);
    if validate_email(&email).is_err() {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"error": "invalid email"}))).into_response();
    }
    let seed = req.seed_text.as_deref().unwrap_or("").trim().to_string();
    if seed.len() > 400 {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"error": "seed_text too long (max 400 chars)"}))).into_response();
    }
    let conn = db.lock().unwrap();
    // Enqueue first so we get an id, then charge pt against that id for
    // idempotency. If pt fails we delete the queue row.
    let inserted = conn.execute(
        "INSERT INTO pt_spawn_queue (email, seed_text, requested_at, status)
         VALUES (?1, ?2, ?3, 'pending')",
        params![&email, &seed, chrono_now()],
    );
    let spawn_id = match inserted {
        Ok(_) => conn.last_insert_rowid(),
        Err(e) => return (StatusCode::INTERNAL_SERVER_ERROR, Json(serde_json::json!({"error": e.to_string()}))).into_response(),
    };
    let ref_str = format!("spawn-{}", spawn_id);
    match points_mutate(&conn, &email, -PT_SWAP_COST, "pt_spawn_mugen", Some(&ref_str), None) {
        Ok(bal) => Json(serde_json::json!({
            "ok": true, "spawn_id": spawn_id, "pt_balance_after": bal,
            "note": "queued — pt_spawn_processor agent will run Gemini and publish",
        })).into_response(),
        Err(e) => {
            // refund the queue row
            let _ = conn.execute("DELETE FROM pt_spawn_queue WHERE id=?1", params![spawn_id]);
            (StatusCode::BAD_REQUEST, Json(serde_json::json!({"error": e}))).into_response()
        }
    }
}

