/// Returns "era-1 (Bella+Canvas 3001)" or "era-2 (Stanley/Stella SATU001)"
/// for a given mugen drop_num. Other brands return their own era string.
fn fabric_era_for(brand: &str, drop_num: i64) -> &'static str {
    let cutoff = match brand {
        "mugen" => MU_FABRIC_SATU001_FIRST_DROP,
        "muon"  => MUON_FABRIC_SATU001_FIRST_DROP,
        "ma"    => MA_FABRIC_SATU001_FIRST_DROP,
        _       => return "collab / other",
    };
    if drop_num >= cutoff {
        "era-2 (Stanley/Stella SATU001, 180gsm organic, EU made, ribbed neck)"
    } else {
        "era-1 (Bella+Canvas 3001, 4.2oz cotton, US made)"
    }
}
/// MA auction starting bid. 2026-05-11: ¥120,000 → ¥30,000, monthly → weekly.
const MA_BASE_PRICE_JPY: i64 = 30_000;
/// MA auction duration in seconds. 2026-05-11: 30d → 7d.
/// Currently set by generate.py at row-insert time; this constant is the
/// single source of truth referenced by docs and admin tools.
#[allow(dead_code)]
const MA_AUCTION_DURATION_SECS: i64 = 7 * 24 * 60 * 60;
const KYC_THRESHOLD_JPY: i64 = 300_000;

/// Gemini model used for the daily Field log + customer feedback replies.
/// Pro tier — slower & costlier than Flash, but writes far better Japanese
/// and follows the brand-voice constraints (no seasonal cycle, numbers > adj)
/// more reliably. Other agents (vision_drift, x_brand, critic_check) stay
/// on Flash for cost reasons since their outputs are short.
const BLOG_GEMINI_MODEL: &str = "gemini-2.5-pro";

/// Gemini model used by the self_evolve agent (proposes code-level changes
/// to main.rs). Pro tier — the higher reasoning quality is worth the cost
/// for code patches that humans will review.
const SELF_EVOLVE_GEMINI_MODEL: &str = "gemini-2.5-pro";

/// Rough per-call JPY cost estimates for budget accounting. Pro is ~10x
/// the cost of Flash. These are intentionally conservative (upper bound)
/// so the budget hits the cap *before* real billing does.
fn estimated_call_cost_jpy(model: &str) -> i64 {
    match model {
        m if m.contains("2.5-pro") || m.contains("3-pro") => 15, // ¥15 per call (avg)
        m if m.contains("flash")    => 2,                        // ¥2 per call
        _                            => 5,
    }
}

/// Current month key (JST) — used as the bucket for `ai_budget_usage`.
fn yyyymm_jst() -> String {
    let secs = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs() as i64).unwrap_or(0);
    let jst = secs + 9 * 3600;
    // approx: days since unix epoch / 30
    let days = jst / 86400;
    // shift to civil-date via tegmen / Howard Hinnant algorithm
    let z = days + 719_468;
    let era = if z >= 0 { z } else { z - 146_096 } / 146_097;
    let doe = z - era * 146_097;
    let yoe = (doe - doe / 1460 + doe / 36524 - doe / 146_096) / 365;
    let y = yoe + era * 400;
    let doy = doe - (365 * yoe + yoe / 4 - yoe / 100);
    let mp = (5 * doy + 2) / 153;
    let m = if mp < 10 { mp + 3 } else { mp - 9 };
    let y_actual = if m <= 2 { y + 1 } else { y };
    format!("{:04}-{:02}", y_actual, m)
}

/// Returns (used_jpy, limit_jpy, remaining_jpy) for the current JST month.
fn budget_state_jpy(conn: &rusqlite::Connection) -> (i64, i64, i64) {
    let month = yyyymm_jst();
    let limit: i64 = conn.query_row(
        "SELECT monthly_limit_jpy FROM ai_budget_config WHERE id=1",
        [], |r| r.get(0),
    ).unwrap_or(30_000);
    let used: i64 = conn.query_row(
        "SELECT COALESCE(SUM(estimated_cost_jpy),0)
         FROM ai_budget_usage WHERE yyyymm=?",
        params![month], |r| r.get(0),
    ).unwrap_or(0);
    (used, limit, (limit - used).max(0))
}

/// Check budget before an AI call. Returns Err with a human-readable
/// reason if the monthly cap would be exceeded. The cap is a hard stop —
/// callers must propagate the error and skip the AI call.
fn budget_check(conn: &rusqlite::Connection, model: &str) -> Result<(), String> {
    let (used, limit, remaining) = budget_state_jpy(conn);
    let est = estimated_call_cost_jpy(model);
    if est > remaining {
        return Err(format!(
            "AI budget exceeded for {} (used ¥{} / cap ¥{}, this call est ¥{}). \
             Set AI_BUDGET_MONTHLY_JPY higher or wait for the next month.",
            yyyymm_jst(), used, limit, est));
    }
    Ok(())
}

/// Record an AI call in the budget ledger. Best-effort.
/// `paid_by`: 'card' | 'crypto' | 'pending' (None = pending).
fn budget_record(
    conn: &rusqlite::Connection,
    decision_type: &str,
    model: &str,
    in_tokens: i64,
    out_tokens: i64,
) -> i64 {
    let month = yyyymm_jst();
    let est = estimated_call_cost_jpy(model);
    // Default payment: card first, fall through to crypto. The actual
    // settlement is done in batch (see /admin/budget/settle).
    let paid_by: Option<String> = Some("card".into());
    match conn.execute(
        "INSERT INTO ai_budget_usage
            (yyyymm, decision_type, model, estimated_cost_jpy,
             in_tokens, out_tokens, paid_by, created_at)
         VALUES (?,?,?,?,?,?,?,?)",
        params![month, decision_type, model, est, in_tokens, out_tokens,
                paid_by, chrono_now()],
    ) {
        Ok(_) => conn.last_insert_rowid(),
        Err(e) => { eprintln!("[budget_record] {e}"); 0 }
    }
}

fn dynamic_price(brand: &str, drop_num: i64, sold: i64, name: &str) -> i64 {
    // Constitution §24 — Stanley/Stella SATU001 era per-brand cutoffs.
    // Era-1 drops (below cutoff) keep their Bella+Canvas pricing per §21.
    if brand == "ma" {
        if drop_num >= MA_FABRIC_SATU001_FIRST_DROP {
            return PRICE_BASE_MA_SATU001_JPY; // ¥18,000 starting bid (era-2)
        }
        return MA_BASE_PRICE_JPY; // ¥30,000 starting bid (era-1)
    }
    if brand == "nouns" {
        let nm = name.to_uppercase();
        if nm.contains("間") || nm.contains(" MA ") || nm.starts_with("MA ") || nm.ends_with(" MA") {
            return MA_BASE_PRICE_JPY;
        }
    }
    if brand == "mugen" && drop_num == 108 {
        return MUGEN_108_PRICE_JPY;
    }
    // 号外 (daily festival extra-edition): doubles as a 無音祭 ticket, so it is
    // a premium limited drop fixed at ¥22,500 (~$150). Checked before the
    // generic mugen bonding curve so it overrides the per-drop price.
    if brand == "mugen" && name.contains("号外") {
        return 22_500;
    }
    if brand == "mugen" && drop_num >= MU_FABRIC_SATU001_FIRST_DROP {
        return (PRICE_BASE_SATU001_JPY + sold.max(0) * PRICE_STEP_JPY).min(PRICE_CAP_SATU001_JPY);
    }
    if brand == "muon" && drop_num >= MUON_FABRIC_SATU001_FIRST_DROP {
        return (PRICE_BASE_MUON_SATU001_JPY + sold.max(0) * PRICE_STEP_JPY).min(PRICE_CAP_MUON_SATU001_JPY);
    }
    (PRICE_BASE_JPY + sold.max(0) * PRICE_STEP_JPY).min(PRICE_CAP_JPY)
}

/// Surcharge in basis points (1 bp = 0.01%) applied on top of the JPY price
/// for non-JPY payment methods. Covers processor fees, FX slip, oracle
/// volatility, and the additional accounting/KYC overhead.
fn payment_surcharge_bps(method: &str) -> i64 {
    match method.to_ascii_lowercase().as_str() {
        "eth" => 500,                                       // +5.0%
        "usdc" | "sol" | "solana" | "crypto" => 300,        // +3.0%
        "jpy" | "" => 0,
        _ => 0,                                             // unknown → safe default
    }
}

/// Apply the surcharge for the chosen payment method, then clamp to the
/// price cap. Result is rounded to the nearest yen.
fn apply_payment_surcharge(price_jpy: i64, method: &str) -> i64 {
    let bps = payment_surcharge_bps(method);
    if bps == 0 {
        return price_jpy.min(PRICE_CAP_JPY);
    }
    // Use 128-bit intermediate to be safe at extreme inputs.
    let surcharged = ((price_jpy as i128) * (10_000 + bps as i128) / 10_000) as i64;
    surcharged.min(PRICE_CAP_JPY)
}

/// Fields needed to build a Stripe Checkout Session form. Used by both the
/// MU clothing checkout (mode=payment) and the MA auction settlement.
/// New options should be added here so the JP CVR config stays unified.
pub struct StripeCheckoutFields<'a> {
    pub mode: &'a str,                  // "payment" / "subscription"
    pub base_url: &'a str,
    pub success_path: &'a str,          // e.g. "/success?sid={CHECKOUT_SESSION_ID}"
    pub cancel_path: &'a str,
    pub display_name: &'a str,
    pub unit_amount: i64,
    pub quantity: i64,
    pub customer_email: Option<&'a str>,
    /// Existing Stripe Customer ID (e.g. "cus_xxx"). When set, Stripe will
    /// reuse the customer's saved name + shipping addresses on the hosted
    /// page (auto-prefill). Overrides `customer_email` and disables the
    /// `customer_creation=always` toggle so we don't get a duplicate row.
    pub customer_id: Option<&'a str>,
    pub product_id: Option<i64>,
    pub size: Option<&'a str>,
    pub wallet: Option<&'a str>,
    pub payment_method: Option<&'a str>,
    pub base_price_jpy: Option<i64>,
    pub total_jpy: Option<i64>,
    pub kyc_required: bool,
    pub collect_shipping: bool,
    /// Ad attribution — captured from URL params on landing pages, stored in
    /// sessionStorage, and threaded into checkout so Stripe Dashboard exports
    /// can be reconciled with Google Ads Offline Conversion Imports.
    /// JiuFlow 2026-05-07/09 spent ¥42K with 0 trackable conversions because
    /// this chain wasn't wired through; this exists to not repeat that.
    pub gclid:        Option<&'a str>,
    pub utm_source:   Option<&'a str>,
    pub utm_medium:   Option<&'a str>,
    pub utm_campaign: Option<&'a str>,
    pub utm_term:     Option<&'a str>,
    pub utm_content:  Option<&'a str>,
    /// HTTPS URL to the product mockup. Surfaced on Stripe Checkout as
    /// `line_items[].price_data.product_data.images[0]`. Stripe accepts
    /// up to 8 images per product; we send 1. Must be publicly reachable
    /// (Stripe re-hosts on their CDN). Skipped when None or empty.
    pub image_url: Option<&'a str>,
}

/// Build the Stripe Checkout Session form payload tuned for the JP market.
///
/// Diagnosed 2026-05-11: ~88% of recent sessions (44/50) abandoned at the
/// Stripe page. Production sessions were going out with locale=null,
/// payment_method_types=["card","wechat_pay"], no konbini, no Apple/Google
/// Pay, no phone collection. This helper produces the corrected payload.
///
/// Each addition is gated by an env flag so the canonical config can be
/// rolled back per-field without redeploying — set the corresponding
/// `STRIPE_*_ENABLED` secret to "0" to disable that field.
fn stripe_checkout_form_jp(f: StripeCheckoutFields) -> Vec<(String, String)> {
    let mut form: Vec<(String, String)> = Vec::with_capacity(48);
    let push = |form: &mut Vec<(String, String)>, k: &str, v: String| {
        form.push((k.to_string(), v));
    };

    push(&mut form, "mode", f.mode.to_string());
    push(&mut form, "currency", "jpy".into());
    push(&mut form, "line_items[0][price_data][currency]", "jpy".into());
    push(&mut form, "line_items[0][price_data][product_data][name]", f.display_name.to_string());
    // Surface the product mockup on the Stripe Checkout page so buyers see
    // what they're paying for at the very last step. HTTPS-only, skipped when
    // absent or blank.
    if let Some(img) = f.image_url.map(|s| s.trim()).filter(|s| s.starts_with("https://")) {
        push(&mut form, "line_items[0][price_data][product_data][images][0]", img.to_string());
    }
    push(&mut form, "line_items[0][price_data][unit_amount]", f.unit_amount.to_string());
    push(&mut form, "line_items[0][quantity]", f.quantity.to_string());
    push(&mut form, "success_url", format!("{}{}", f.base_url, f.success_path));
    push(&mut form, "cancel_url",  format!("{}{}", f.base_url, f.cancel_path));
    // Returning-customer path: when we found an existing Stripe Customer,
    // pass `customer=cus_xxx` so Stripe auto-prefills name + shipping +
    // saved payment methods. Customer-creation must NOT be set in that case
    // (would create a second duplicate customer). When absent, fall back to
    // customer_email + customer_creation=always (legacy behaviour).
    if let Some(cid) = f.customer_id.filter(|s| s.starts_with("cus_")) {
        push(&mut form, "customer", cid.to_string());
    } else if let Some(em) = f.customer_email {
        push(&mut form, "customer_email", em.to_string());
    }

    // ── JP CVR repair: locale=ja (was null → users saw English page) ──
    if env_flag_enabled("STRIPE_LOCALE_JA", true) {
        push(&mut form, "locale", "ja".into());
    }

    // ── JP payment methods: card + konbini (+ apple_pay/google_pay are
    //    automatic for card on supported devices, but we explicitly include
    //    them so Stripe doesn't omit them via locale negotiation).
    //    NOTE: konbini requires "Konbini" payment method to be enabled in the
    //    Stripe dashboard for the account. If the account hasn't enabled it,
    //    Stripe returns 400 — runtime auto-detect flips KONBINI_DISABLED_RUNTIME
    //    on first failure so subsequent calls skip konbini. Env override:
    //    STRIPE_KONBINI_ENABLED=0 to force off.
    if konbini_currently_enabled() {
        push(&mut form, "payment_method_types[0]", "card".into());
        push(&mut form, "payment_method_types[1]", "konbini".into());
        // payment_method_options[konbini][expires_after_days] — give buyers
        // 3 days to walk to a conbini. Default = 3 if omitted, set explicit.
        push(&mut form, "payment_method_options[konbini][expires_after_days]", "3".into());
    }
    // Apple Pay / Google Pay surface automatically on supported devices when
    // 'card' is in payment_method_types; no separate flag needed (per Stripe
    // docs as of 2026). We leave that auto-handling on.

    // ── Phone collection (Stripe-recommended for JP for shipping reachability). ──
    if env_flag_enabled("STRIPE_PHONE_COLLECTION", true) {
        push(&mut form, "phone_number_collection[enabled]", "true".into());
    }

    // ── Submit type: "pay" instead of default "auto" so the button is
    //    explicitly labelled "支払う" (avoids "Subscribe" mis-translations
    //    that auto picks for some JP locales).
    if f.mode == "payment" && env_flag_enabled("STRIPE_SUBMIT_TYPE_PAY", true) {
        push(&mut form, "submit_type", "pay".into());
    }

    // ── Always create a customer object so receipts + Customer Portal work,
    //    even for the one-shot clothing buys (some MUer becomes MA bidder
    //    later — we want one Stripe customer per email).
    // Skipped when reusing an existing customer (`customer=cus_xxx`) — Stripe
    // rejects the combination "customer + customer_creation".
    if f.customer_id.is_none() {
        push(&mut form, "customer_creation", "always".into());
    }

    // ── Shipping address collection: physical MU/MA pieces always ship.
    //    Subscription-mode (/you 3-mo pack and monthly) doesn't ship → caller
    //    can opt out via collect_shipping=false.
    if f.collect_shipping {
        let countries = ["JP","US","GB","FR","DE","AU","KR","TW","HK","SG","CA","CN","IT","ES","NL","SE","CH","NZ","TH","ID","PH","MY","VN","IN","MX","BR"];
        for (i, c) in countries.iter().enumerate() {
            push(&mut form,
                &format!("shipping_address_collection[allowed_countries][{}]", i),
                c.to_string());
        }
    }

    // ── allow_promotion_codes is always on; we explicitly mint coupons via
    //    the thank-you flow and the exit-intent discount funnel.
    push(&mut form, "allow_promotion_codes", "true".into());

    // ── Metadata (audit + webhook lookup) ──
    if let Some(pid)  = f.product_id      { push(&mut form, "metadata[product_id]",      pid.to_string()); }
    if let Some(s)    = f.size            { push(&mut form, "metadata[size]",            s.to_string()); }
    if let Some(w)    = f.wallet          { push(&mut form, "metadata[wallet]",          w.to_string()); }
    if let Some(p)    = f.payment_method  { push(&mut form, "metadata[payment_method]",  p.to_string()); }
    if let Some(bp)   = f.base_price_jpy  { push(&mut form, "metadata[base_price_jpy]",  bp.to_string()); }
    push(&mut form, "metadata[unit_price_jpy]", f.unit_amount.to_string());
    if let Some(tot)  = f.total_jpy       { push(&mut form, "metadata[total_price_jpy]", tot.to_string()); }
    // Ad attribution — only push non-empty values so we don't pollute metadata
    // with empty keys that hurt readability in the Stripe Dashboard exports.
    let push_attr = |form: &mut Vec<(String, String)>, key: &str, val: Option<&str>| {
        if let Some(v) = val.map(|s| s.trim()).filter(|s| !s.is_empty()) {
            // Stripe metadata values capped at 500 chars; gclid/utm are well under.
            let truncated = if v.len() > 500 { &v[..500] } else { v };
            form.push((format!("metadata[{}]", key), truncated.to_string()));
        }
    };
    push_attr(&mut form, "gclid",        f.gclid);
    push_attr(&mut form, "utm_source",   f.utm_source);
    push_attr(&mut form, "utm_medium",   f.utm_medium);
    push_attr(&mut form, "utm_campaign", f.utm_campaign);
    push_attr(&mut form, "utm_term",     f.utm_term);
    push_attr(&mut form, "utm_content",  f.utm_content);
    push(&mut form, "metadata[kyc_required]",
        if f.kyc_required { "true".into() } else { "false".into() });

    form
}

/// Returns true if the named env var is set to a truthy value, OR (when unset)
/// falls back to `default_on`. Truthy = "1" / "true" / "yes" (case-insensitive).
/// Explicitly "0" / "false" / "no" disables.
fn env_flag_enabled(var: &str, default_on: bool) -> bool {
    match env::var(var).ok().map(|s| s.trim().to_ascii_lowercase()) {
        Some(s) if s == "1" || s == "true" || s == "yes" || s == "on" => true,
        Some(s) if s == "0" || s == "false" || s == "no" || s == "off" => false,
        _ => default_on,
    }
}

/// Convert a Unix epoch (seconds, UTC) into "YYYY-MM-DD HH:MM JST" without
/// dragging in the chrono crate. Good enough for human-readable reminder
/// emails. Handles 1970..2099 via the proleptic Gregorian calendar.
fn format_jst_yyyy_mm_dd_hhmm(unix_utc: i64) -> String {
    let jst = unix_utc + 9 * 3600;
    let days_since_epoch = jst.div_euclid(86_400);
    let secs = jst.rem_euclid(86_400);
    let hour = (secs / 3_600) as u32;
    let minute = ((secs % 3_600) / 60) as u32;
    // Civil-from-days (Howard Hinnant's algorithm).
    let z = days_since_epoch + 719_468;
    let era = if z >= 0 { z } else { z - 146_096 } / 146_097;
    let doe = (z - era * 146_097) as u64;
    let yoe = (doe - doe / 1460 + doe / 36524 - doe / 146096) / 365;
    let y = yoe as i64 + era * 400;
    let doy = doe - (365 * yoe + yoe / 4 - yoe / 100);
    let mp = (5 * doy + 2) / 153;
    let d = (doy - (153 * mp + 2) / 5 + 1) as u32;
    let m = (if mp < 10 { mp + 3 } else { mp - 9 }) as u32;
    let y = y + if m <= 2 { 1 } else { 0 };
    format!("{:04}-{:02}-{:02} {:02}:{:02} JST", y, m, d, hour, minute)
}

/// POST /api/checkout/embedded — return a `client_secret` for Stripe's
/// embedded Checkout Session.
///
/// Why embedded over hosted: the embedded form mounts directly in the modal,
/// shows the native Apple Pay / Google Pay button without a page redirect,
/// and reuses the existing `checkout.session.completed` webhook for
/// fulfillment (no new server handlers required). The buyer never leaves
/// wearmu.com — fastest path from "Add" to "Paid."
async fn checkout_embedded(
    State(db): State<Db>,
    Json(body): Json<CheckoutBody>,
) -> impl IntoResponse {
    let stripe_key = env::var("STRIPE_SECRET_KEY").unwrap_or_default();
    if stripe_key.is_empty() {
        return (StatusCode::SERVICE_UNAVAILABLE,
            Json(serde_json::json!({"ok":false,"error":"stripe key not configured"}))).into_response();
    }

    // Product lookup mirrors /api/checkout — same pricing + KYC threshold rules.
    // mockup_url is surfaced on the Stripe checkout page (product image).
    let (brand_str, drop_num, inventory, sold, product_name, mockup_url) = {
        let conn = db.lock().unwrap();
        match conn.query_row(
            "SELECT brand, drop_num, inventory, sold, name, mockup_url FROM products WHERE id=? AND active=1",
            params![body.product_id],
            |row| Ok((
                row.get::<_,String>(0)?, row.get::<_,i64>(1)?,
                row.get::<_,i64>(2)?, row.get::<_,i64>(3)?,
                row.get::<_,String>(4)?,
                row.get::<_,Option<String>>(5)?,
            )),
        ) {
            Ok(r) => r,
            Err(_) => return (StatusCode::NOT_FOUND,
                Json(serde_json::json!({"ok":false,"error":"product not found"}))).into_response(),
        }
    };
    // Stripe requires HTTPS URLs and accepts the existing R2/CDN-served mockup.
    let stripe_image_url = mockup_url.as_deref()
        .filter(|u| u.starts_with("https://"))
        .or_else(|| Some(""))
        .filter(|s| !s.is_empty())
        .map(String::from)
        .or_else(|| Some(format!("https://mockups.wearmu.com/{}.jpg", body.product_id)));
    if inventory - sold < body.quantity as i64 {
        return (StatusCode::CONFLICT,
            Json(serde_json::json!({"ok":false,"error":"sold out"}))).into_response();
    }

    let base_price_jpy = dynamic_price(&brand_str, drop_num, sold, &product_name);
    let pm = body.payment_method.clone().unwrap_or_else(|| "jpy".into()).to_ascii_lowercase();
    let price_jpy = apply_payment_surcharge(base_price_jpy, &pm);
    let total_jpy = price_jpy.saturating_mul(body.quantity as i64);

    if pm != "jpy" {
        return (StatusCode::BAD_REQUEST,
            Json(serde_json::json!({"ok":false,"error":"embedded checkout supports jpy only"}))).into_response();
    }

    let base_url = env::var("BASE_URL").unwrap_or_else(|_| "http://localhost:3000".into());
    let size_label = body.size.clone().unwrap_or_else(|| "M".into());
    let display_name = format!("{} ({})", product_name, size_label);
    let wallet = body.wallet.clone().unwrap_or_default();

    let reuse_customer_id: Option<String> = if let Some(em) = body.email.as_deref().filter(|s| !s.is_empty()) {
        find_stripe_customer_by_email(&stripe_key, em).await
    } else { None };

    let build_form = || {
        let mut f = stripe_checkout_form_jp(StripeCheckoutFields {
            mode: "payment",
            base_url: &base_url,
            success_path: "/success?sid={CHECKOUT_SESSION_ID}",
            cancel_path: "/",
            display_name: &display_name,
            unit_amount: price_jpy,
            quantity: body.quantity as i64,
            customer_email: body.email.as_deref().filter(|s| !s.is_empty()),
            customer_id: reuse_customer_id.as_deref(),
            product_id: Some(body.product_id),
            size: Some(&size_label),
            wallet: Some(&wallet),
            payment_method: Some(&pm),
            base_price_jpy: Some(base_price_jpy),
            total_jpy: Some(total_jpy),
            kyc_required: total_jpy >= KYC_THRESHOLD_JPY,
            collect_shipping: true,
            gclid:        body.gclid.as_deref(),
            utm_source:   body.utm_source.as_deref(),
            utm_medium:   body.utm_medium.as_deref(),
            utm_campaign: body.utm_campaign.as_deref(),
            utm_term:     body.utm_term.as_deref(),
            utm_content:  body.utm_content.as_deref(),
            image_url:    stripe_image_url.as_deref(),
        });
        f.push(("ui_mode".into(), "embedded".into()));
        f.push(("return_url".into(),
            format!("{}/success?sid={{CHECKOUT_SESSION_ID}}&from=embedded", base_url)));
        // success_url / cancel_url are invalid in embedded mode — strip them.
        f.retain(|(k, _)| k != "success_url" && k != "cancel_url");
        f
    };

    let client = reqwest::Client::new();
    let send_one = |form: Vec<(String, String)>| {
        let c = client.clone();
        let k = stripe_key.clone();
        async move {
            c.post("https://api.stripe.com/v1/checkout/sessions")
                .basic_auth(&k, None::<&str>).form(&form).send().await
        }
    };

    // First attempt. If Stripe rejects konbini as inactive, auto-disable +
    // retry without it — mirrors the legacy /api/checkout path.
    let first = send_one(build_form()).await;
    let resp = match first {
        Ok(r) if r.status().is_success() => Ok(r),
        Ok(r) => {
            let s = r.status();
            let body_text = r.text().await.unwrap_or_default();
            if maybe_disable_konbini(&body_text) {
                tracing::warn!("[embedded-checkout] retrying without konbini after runtime auto-disable");
                send_one(build_form()).await
            } else {
                tracing::error!("[embedded-checkout] stripe {}: {}", s, body_text.chars().take(300).collect::<String>());
                return (StatusCode::BAD_GATEWAY,
                    Json(serde_json::json!({"ok":false,"error":format!("stripe {}: {}", s, &body_text[..body_text.len().min(200)])}))).into_response();
            }
        }
        Err(e) => Err(e),
    };

    match resp {
        Ok(r) if r.status().is_success() => {
            let j: serde_json::Value = r.json().await.unwrap_or_default();
            let client_secret = j["client_secret"].as_str().unwrap_or("").to_string();
            let session_id    = j["id"].as_str().unwrap_or("").to_string();
            if client_secret.is_empty() {
                return (StatusCode::BAD_GATEWAY,
                    Json(serde_json::json!({"ok":false,"error":"stripe returned no client_secret"}))).into_response();
            }
            // Funnel: server-side checkout_start event.
            funnel_track_server(&db, "checkout_start",
                &format!("/products/{}", body.product_id),
                Some(body.product_id),
                serde_json::json!({"amount_jpy": total_jpy, "session": session_id})).await;
            Json(serde_json::json!({
                "ok": true,
                "client_secret": client_secret,
                "session_id": session_id,
                "amount_jpy": total_jpy,
            })).into_response()
        }
        Ok(r) => {
            let s = r.status();
            let t = r.text().await.unwrap_or_default();
            tracing::error!("[embedded-checkout] stripe retry {}: {}", s, t.chars().take(300).collect::<String>());
            (StatusCode::BAD_GATEWAY,
             Json(serde_json::json!({"ok":false,"error":format!("stripe {}: {}", s, &t[..t.len().min(200)])}))).into_response()
        }
        Err(e) => (StatusCode::BAD_GATEWAY,
            Json(serde_json::json!({"ok":false,"error":format!("network: {}", e)}))).into_response(),
    }
}

/// GET /api/stripe/pubkey — exposes the Stripe publishable key so the
/// embedded Checkout Element on the PDP can initialise Stripe.js without
/// hard-coding the key in the static HTML.
async fn stripe_pubkey() -> impl IntoResponse {
    let pk = env::var("STRIPE_PUBLISHABLE_KEY").unwrap_or_default();
    if pk.is_empty() {
        return (StatusCode::SERVICE_UNAVAILABLE,
            Json(serde_json::json!({"ok":false,"error":"STRIPE_PUBLISHABLE_KEY unset"}))).into_response();
    }
    Json(serde_json::json!({"ok": true, "publishable_key": pk})).into_response()
}

/// POST /api/admin/products/:id/payment-link — create (or refresh) a Stripe
/// Payment Link for a product. Persists the URL + Stripe Price ID on
/// products.payment_link_url so the PDP renders a "クイック購入" button.
///
/// Idempotent: returns the existing link if already created. Set ?refresh=1
/// to force-recreate (e.g. after price changes — old link auto-deactivated).
///
/// Limited to 1 completed session per Payment Link (suits MUGEN 1/1).
async fn admin_create_payment_link(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Path(id): axum::extract::Path<i64>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/admin/products/payment-link").await { return r; }
    let stripe_key = env::var("STRIPE_SECRET_KEY").unwrap_or_default();
    if stripe_key.is_empty() {
        return (StatusCode::SERVICE_UNAVAILABLE,
            Json(serde_json::json!({"ok":false,"error":"stripe key not configured"}))).into_response();
    }
    let force = matches!(q.get("refresh").map(String::as_str), Some("1") | Some("true"));

    // 1. Load product (and any existing link / price).
    struct ProdRow {
        brand: String, drop_num: i64, name: String, price_jpy: i64,
        inventory: i64, sold: i64,
        link_url: Option<String>, link_id: Option<String>, price_id: Option<String>,
    }
    let prod: Result<ProdRow, rusqlite::Error> = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT brand, drop_num, name, price_jpy, inventory, sold,
                    payment_link_url, payment_link_id, stripe_price_id
             FROM products WHERE id=?",
            params![id],
            |r| Ok(ProdRow{
                brand: r.get(0)?, drop_num: r.get(1)?, name: r.get(2)?,
                price_jpy: r.get(3)?, inventory: r.get(4)?, sold: r.get(5)?,
                link_url: r.get(6)?, link_id: r.get(7)?, price_id: r.get(8)?,
            }),
        )
    };
    let prod = match prod {
        Ok(p) => p,
        Err(_) => return (StatusCode::NOT_FOUND,
            Json(serde_json::json!({"ok":false,"error":"product not found"}))).into_response(),
    };

    if !force {
        if let (Some(url), Some(lid)) = (prod.link_url.as_ref().filter(|s| !s.is_empty()),
                                         prod.link_id.as_ref().filter(|s| !s.is_empty())) {
            return Json(serde_json::json!({
                "ok": true, "already": true,
                "url": url, "payment_link_id": lid, "stripe_price_id": prod.price_id,
            })).into_response();
        }
    }

    let display_name = format!("{} — {}", prod.brand.to_uppercase(), prod.name);
    let client = reqwest::Client::new();

    // 2. If force-refresh, deactivate the old link first (best-effort).
    if force {
        if let Some(lid) = prod.link_id.as_ref().filter(|s| !s.is_empty()) {
            let _ = client.post(format!("https://api.stripe.com/v1/payment_links/{}", lid))
                .basic_auth(&stripe_key, None::<&str>)
                .form(&[("active", "false")])
                .send().await;
        }
    }

    // 3. Create (or reuse) a Stripe Price object for this product.
    let price_id: String = if let (false, Some(pid)) = (force, prod.price_id.as_ref().filter(|s| !s.is_empty())) {
        pid.clone()
    } else {
        let resp = client.post("https://api.stripe.com/v1/prices")
            .basic_auth(&stripe_key, None::<&str>)
            .form(&[
                ("unit_amount", prod.price_jpy.to_string().as_str()),
                ("currency", "jpy"),
                ("product_data[name]", &display_name),
                ("product_data[metadata][product_id]", &id.to_string()),
                ("product_data[metadata][brand]", &prod.brand),
                ("product_data[metadata][drop_num]", &prod.drop_num.to_string()),
            ])
            .send().await;
        match resp {
            Ok(r) if r.status().is_success() => {
                let j: serde_json::Value = r.json().await.unwrap_or_default();
                let pid = j["id"].as_str().unwrap_or("").to_string();
                if pid.is_empty() {
                    return (StatusCode::BAD_GATEWAY,
                        Json(serde_json::json!({"ok":false,"error":"stripe returned no price id"}))).into_response();
                }
                pid
            }
            Ok(r) => {
                let s = r.status();
                let t = r.text().await.unwrap_or_default();
                tracing::error!("[payment-link] price create {}: {}", s, t.chars().take(200).collect::<String>());
                return (StatusCode::BAD_GATEWAY,
                    Json(serde_json::json!({"ok":false,"error":format!("stripe price {}", s)}))).into_response();
            }
            Err(e) => return (StatusCode::BAD_GATEWAY,
                Json(serde_json::json!({"ok":false,"error":format!("network: {}", e)}))).into_response(),
        }
    };

    // 4. Create the Payment Link itself.
    let base_url = env::var("BASE_URL").unwrap_or_else(|_| "https://wearmu.com".into());
    let success_url = format!("{}/success?from=payment_link", base_url);
    // For 1/1 MUGEN: cap at inventory-sold so we don't overshoot. For
    // multi-quantity drops (MUON / NOUNS), let buyers choose 1..rem on the link.
    let remaining = (prod.inventory - prod.sold).max(0);
    let pmt_link_form: Vec<(&str, String)> = vec![
        ("line_items[0][price]", price_id.clone()),
        ("line_items[0][quantity]", "1".into()),
        ("line_items[0][adjustable_quantity][enabled]", "false".into()),
        ("after_completion[type]", "redirect".into()),
        ("after_completion[redirect][url]", success_url.clone()),
        ("allow_promotion_codes", "true".into()),
        // Stripe Payment Links use restrictions to cap total successful
        // checkouts. 1 keeps MUGEN safe; for MUON we cap to remaining.
        ("restrictions[completed_sessions][limit]",
            if prod.brand == "mugen" || prod.brand == "ma" { "1".to_string() }
            else { remaining.max(1).to_string() }),
        ("shipping_address_collection[allowed_countries][0]", "JP".into()),
        ("phone_number_collection[enabled]", "true".into()),
        ("metadata[product_id]", id.to_string()),
        ("metadata[brand]", prod.brand.clone()),
        ("metadata[drop_num]", prod.drop_num.to_string()),
    ];
    let resp = client.post("https://api.stripe.com/v1/payment_links")
        .basic_auth(&stripe_key, None::<&str>)
        .form(&pmt_link_form)
        .send().await;
    let (url, link_id): (String, String) = match resp {
        Ok(r) if r.status().is_success() => {
            let j: serde_json::Value = r.json().await.unwrap_or_default();
            (j["url"].as_str().unwrap_or("").to_string(),
             j["id"].as_str().unwrap_or("").to_string())
        }
        Ok(r) => {
            let s = r.status();
            let t = r.text().await.unwrap_or_default();
            tracing::error!("[payment-link] create {}: {}", s, t.chars().take(300).collect::<String>());
            return (StatusCode::BAD_GATEWAY,
                Json(serde_json::json!({"ok":false,"error":format!("stripe link {}: {}", s, &t[..t.len().min(200)])}))).into_response();
        }
        Err(e) => return (StatusCode::BAD_GATEWAY,
            Json(serde_json::json!({"ok":false,"error":format!("network: {}", e)}))).into_response(),
    };
    if url.is_empty() || link_id.is_empty() {
        return (StatusCode::BAD_GATEWAY,
            Json(serde_json::json!({"ok":false,"error":"stripe returned incomplete link"}))).into_response();
    }

    // 5. Persist.
    {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "UPDATE products
             SET payment_link_url=?, payment_link_id=?, stripe_price_id=?
             WHERE id=?",
            params![url, link_id, price_id, id],
        );
    }

    Json(serde_json::json!({
        "ok": true, "already": false,
        "url": url, "payment_link_id": link_id, "stripe_price_id": price_id,
    })).into_response()
}

/// POST /api/admin/cron/konbini-reminder — scheduled cron that finds open
/// Konbini checkout sessions and emails the buyer a reminder.
///
/// Two reminder buckets, both idempotent (won't double-send):
///   - "24h": session was created ≥24h ago, ≥24h until konbini expiry → ping
///   - "48h": session was created ≥48h ago, ~24h before expiry → "明日まで"
async fn cron_konbini_reminder(
    State(db): State<Db>,
    Json(body): Json<serde_json::Value>,
) -> impl IntoResponse {
    let admin_token = body["admin_token"].as_str().unwrap_or("").to_string();
    if let Err(r) = require_admin_token(Some(&admin_token)) { return r; }

    let stripe_key = env::var("STRIPE_SECRET_KEY").unwrap_or_default();
    let resend_key = env::var("RESEND_API_KEY").unwrap_or_default();
    if stripe_key.is_empty() {
        return (StatusCode::SERVICE_UNAVAILABLE, "stripe key not configured").into_response();
    }

    let now_unix: i64 = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs() as i64).unwrap_or(0);
    let since_unix = now_unix - 4 * 86_400;
    let url = format!(
        "https://api.stripe.com/v1/checkout/sessions?limit=100&created[gte]={}",
        since_unix,
    );
    let resp = match reqwest::Client::new()
        .get(&url).basic_auth(&stripe_key, None::<&str>)
        .timeout(std::time::Duration::from_secs(20))
        .send().await {
        Ok(r) => r,
        Err(e) => {
            tracing::error!("[konbini-reminder] stripe list err: {}", e);
            return Json(serde_json::json!({"ok":false,"error":"stripe network"})).into_response();
        }
    };
    if !resp.status().is_success() {
        let s = resp.status();
        let t = resp.text().await.unwrap_or_default();
        return Json(serde_json::json!({"ok":false,"error":format!("stripe {} {}", s, &t[..t.len().min(200)])})).into_response();
    }
    let j: serde_json::Value = match resp.json().await {
        Ok(v) => v,
        Err(_) => return Json(serde_json::json!({"ok":false,"error":"bad stripe json"})).into_response(),
    };
    let sessions = j["data"].as_array().cloned().unwrap_or_default();

    let mut considered = 0usize;
    let mut sent_24h   = 0usize;
    let mut sent_48h   = 0usize;
    let mut skipped    = 0usize;

    for sess in sessions {
        considered += 1;
        let status = sess["status"].as_str().unwrap_or("");
        if status != "open" { skipped += 1; continue; }
        let payment_status = sess["payment_status"].as_str().unwrap_or("");
        if payment_status == "paid" { skipped += 1; continue; }
        let pmt = sess["payment_method_types"].as_array().cloned().unwrap_or_default();
        let has_konbini = pmt.iter().any(|v| v.as_str() == Some("konbini"));
        if !has_konbini { skipped += 1; continue; }

        let session_id = sess["id"].as_str().unwrap_or("").to_string();
        if session_id.is_empty() { skipped += 1; continue; }
        let created    = sess["created"].as_i64().unwrap_or(0);
        let expires_at = sess["expires_at"].as_i64().unwrap_or(0);
        if created == 0 || expires_at == 0 || expires_at <= now_unix {
            skipped += 1; continue;
        }
        let age = now_unix - created;
        let time_left = expires_at - now_unix;

        let bucket: &'static str = if time_left <= 24 * 3_600 + 7_200 && age >= 36 * 3_600 {
            "48h"
        } else if age >= 24 * 3_600 && time_left >= 24 * 3_600 {
            "24h"
        } else {
            skipped += 1; continue;
        };

        let already_sent: bool = {
            let conn = db.lock().unwrap();
            conn.query_row(
                "SELECT 1 FROM konbini_reminders WHERE session_id=? AND bucket=?",
                params![session_id, bucket], |_| Ok(true),
            ).unwrap_or(false)
        };
        if already_sent { skipped += 1; continue; }

        let email = sess["customer_details"]["email"].as_str()
            .or_else(|| sess["customer_email"].as_str())
            .unwrap_or("").to_string();
        if email.is_empty() || !email.contains('@') { skipped += 1; continue; }

        let amount_total = sess["amount_total"].as_i64().unwrap_or(0);
        let item_name = sess["metadata"]["display_name"].as_str()
            .or_else(|| sess["metadata"]["product_id"].as_str())
            .unwrap_or("MU 商品").to_string();
        // Format expiry as JST without a chrono dep.
        let exp_str = format_jst_yyyy_mm_dd_hhmm(expires_at);
        let session_url = sess["url"].as_str().unwrap_or("").to_string();
        let (subject, html) = if bucket == "48h" {
            (format!("【明日まで】コンビニ払込番号 — ご注文 {}", item_name),
             format!(
                 "<p>こんにちは,</p>\
                  <p>MU でのご注文 <b>{name}</b> (¥{amt}) のコンビニ払込番号の <b>有効期限が明日 ({exp})</b> までです。お近くのコンビニでお早めにお支払いください。</p>\
                  <p>払込番号がお手元にない場合は、下記のリンクから再表示できます:<br><a href=\"{url}\">{url}</a></p>\
                  <p>期限を過ぎるとご注文はキャンセルとなります。<br>— MU / 株式会社イネブラ</p>",
                 name = html_escape(&item_name), amt = fmt_jpy(amount_total),
                 exp = html_escape(&exp_str), url = html_attr_escape(&session_url),
             ))
        } else {
            (format!("コンビニ払込番号のご案内 — {}", item_name),
             format!(
                 "<p>こんにちは,</p>\
                  <p>MU でのご注文 <b>{name}</b> (¥{amt}) のコンビニ払込番号をお送りします。</p>\
                  <p>有効期限: <b>{exp}</b><br><a href=\"{url}\">こちら</a> から払込番号を表示し、お近くのコンビニ (ローソン / ファミマ / セイコーマート / ミニストップ) でお支払いください。</p>\
                  <p>ご質問は本メールへの返信、または info@wearmu.com まで。<br>— MU / 株式会社イネブラ</p>",
                 name = html_escape(&item_name), amt = fmt_jpy(amount_total),
                 exp = html_escape(&exp_str), url = html_attr_escape(&session_url),
             ))
        };

        let send_ok = if !resend_key.is_empty() {
            let r = reqwest::Client::new()
                .post("https://api.resend.com/emails")
                .bearer_auth(&resend_key)
                .json(&serde_json::json!({
                    "from": "━◯━ MU <info@wearmu.com>",
                    "to": [email.clone()],
                    "subject": subject,
                    "html": html,
                    "reply_to": "info@wearmu.com",
                }))
                .timeout(std::time::Duration::from_secs(15))
                .send().await;
            matches!(r, Ok(rr) if rr.status().is_success())
        } else {
            tracing::warn!("[konbini-reminder] RESEND_API_KEY unset — skipping send (would notify {} for session {})", email, session_id);
            false
        };

        if send_ok {
            let now_iso = chrono_now();
            {
                let conn = db.lock().unwrap();
                let _ = conn.execute(
                    "INSERT OR REPLACE INTO konbini_reminders (session_id, bucket, email, sent_at)
                     VALUES (?,?,?,?)",
                    params![session_id, bucket, email, now_iso],
                );
            }
            if bucket == "48h" { sent_48h += 1; } else { sent_24h += 1; }
        }
    }

    Json(serde_json::json!({
        "ok": true,
        "considered": considered,
        "sent_24h": sent_24h,
        "sent_48h": sent_48h,
        "skipped": skipped,
    })).into_response()
}

/// Search Stripe for an existing customer with this email and return
/// `cus_xxx` if found. Best-effort: any error / timeout returns None so
/// the caller falls back to creating a fresh customer. Single API call,
/// limit=1, ~150ms typical. Used by /api/checkout to auto-prefill the
/// returning buyer's name + shipping on the Stripe Checkout page.
pub async fn find_stripe_customer_by_email(stripe_key: &str, email: &str) -> Option<String> {
    if stripe_key.is_empty() || email.is_empty() || !email.contains('@') { return None; }
    let url = format!(
        "https://api.stripe.com/v1/customers?email={}&limit=1",
        urlencoding::encode(email),
    );
    let resp = reqwest::Client::new()
        .get(&url)
        .basic_auth(stripe_key, None::<&str>)
        .timeout(std::time::Duration::from_millis(2_500))
        .send().await.ok()?;
    if !resp.status().is_success() { return None; }
    let j: serde_json::Value = resp.json().await.ok()?;
    j["data"][0]["id"].as_str().filter(|s| s.starts_with("cus_")).map(String::from)
}

/// Runtime auto-disable for Konbini. Set to true once Stripe responds with
/// "konbini is invalid" — happens when ops hasn't activated Konbini in the
/// dashboard yet (capabilities API can't enable own-account features).
/// Process-lifetime cache; resets on deploy. Once flipped, subsequent
/// checkouts skip konbini without making a doomed Stripe call.
static KONBINI_DISABLED_RUNTIME: std::sync::atomic::AtomicBool =
    std::sync::atomic::AtomicBool::new(false);

fn konbini_currently_enabled() -> bool {
    if KONBINI_DISABLED_RUNTIME.load(std::sync::atomic::Ordering::Relaxed) {
        return false;
    }
    env_flag_enabled("STRIPE_KONBINI_ENABLED", true)
}

/// Inspect a Stripe error body and disable konbini at runtime if Stripe
/// is telling us the account doesn't have konbini enabled. Called from
/// the checkout error path so the next checkout call works without ops
/// intervention.
fn maybe_disable_konbini(stripe_error_body: &str) -> bool {
    if stripe_error_body.contains("konbini")
        && (stripe_error_body.contains("invalid") || stripe_error_body.contains("not activated"))
    {
        let was_enabled = !KONBINI_DISABLED_RUNTIME.swap(true, std::sync::atomic::Ordering::Relaxed);
        if was_enabled {
            tracing::warn!("[stripe] auto-disabling konbini at runtime — Stripe says it's not activated. \
                            Enable it at https://dashboard.stripe.com/account/payments/settings then restart \
                            (or `fly secrets set STRIPE_KONBINI_RESET=$(date +%s) -a mu-store` to force re-enable).");
        }
        true
    } else {
        false
    }
}

#[cfg(test)]
mod stripe_cvr_tests {
    use super::*;

    // Tests in this module mutate process-global env vars
    // (STRIPE_KONBINI_ENABLED etc.). cargo runs tests in parallel threads, so
    // without serialization two tests race on the same var and fail flakily
    // (seen in CI 2026-06-07: default_includes_konbini_payment_method vs
    // konbini_flag_can_be_disabled — different one each run). Every test that
    // touches env MUST take this lock first.
    static ENV_LOCK: std::sync::Mutex<()> = std::sync::Mutex::new(());

    fn base() -> StripeCheckoutFields<'static> {
        StripeCheckoutFields {
            mode: "payment",
            base_url: "https://wearmu.com",
            success_path: "/success?sid={CHECKOUT_SESSION_ID}",
            cancel_path: "/",
            display_name: "MU MUGEN-001 (M)",
            unit_amount: 5_000,
            quantity: 1,
            customer_email: Some("buyer@example.com"),
            customer_id: None,
            product_id: Some(42),
            size: Some("M"),
            wallet: Some(""),
            payment_method: Some("jpy"),
            base_price_jpy: Some(5_000),
            total_jpy: Some(5_000),
            kyc_required: false,
            collect_shipping: true,
            gclid: None,
            utm_source: None,
            utm_medium: None,
            utm_campaign: None,
            utm_term: None,
            utm_content: None,
            image_url: None,
        }
    }

    fn has(form: &[(String, String)], key: &str, value: &str) -> bool {
        form.iter().any(|(k, v)| k == key && v == value)
    }
    fn has_key(form: &[(String, String)], key: &str) -> bool {
        form.iter().any(|(k, _)| k == key)
    }

    #[test]
    fn default_includes_jp_locale() {
        let _env_guard = ENV_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        // Default flags ON → locale=ja must be present.
        std::env::remove_var("STRIPE_LOCALE_JA");
        let form = stripe_checkout_form_jp(base());
        assert!(has(&form, "locale", "ja"),
            "locale=ja missing — JP buyers were seeing English Stripe page");
    }

    #[test]
    fn default_includes_konbini_payment_method() {
        let _env_guard = ENV_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        std::env::remove_var("STRIPE_KONBINI_ENABLED");
        let form = stripe_checkout_form_jp(base());
        assert!(has(&form, "payment_method_types[0]", "card"));
        assert!(has(&form, "payment_method_types[1]", "konbini"),
            "konbini missing — ~30% of JP e-commerce uses convenience-store payment");
        assert!(has(&form, "payment_method_options[konbini][expires_after_days]", "3"));
    }

    #[test]
    fn default_includes_phone_collection_and_submit_pay() {
        let _env_guard = ENV_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        std::env::remove_var("STRIPE_PHONE_COLLECTION");
        std::env::remove_var("STRIPE_SUBMIT_TYPE_PAY");
        let form = stripe_checkout_form_jp(base());
        assert!(has(&form, "phone_number_collection[enabled]", "true"));
        assert!(has(&form, "submit_type", "pay"));
        assert!(has(&form, "customer_creation", "always"));
    }

    #[test]
    fn shipping_collection_optional() {
        let _env_guard = ENV_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        let mut f = base();
        f.collect_shipping = false;
        let form = stripe_checkout_form_jp(f);
        assert!(!has_key(&form, "shipping_address_collection[allowed_countries][0]"));

        let f2 = base();
        let form2 = stripe_checkout_form_jp(f2);
        assert!(has(&form2, "shipping_address_collection[allowed_countries][0]", "JP"));
    }

    #[test]
    fn konbini_flag_can_be_disabled() {
        let _env_guard = ENV_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        std::env::set_var("STRIPE_KONBINI_ENABLED", "0");
        let form = stripe_checkout_form_jp(base());
        assert!(!has(&form, "payment_method_types[1]", "konbini"),
            "STRIPE_KONBINI_ENABLED=0 should disable konbini");
        std::env::remove_var("STRIPE_KONBINI_ENABLED");
    }

    #[test]
    fn metadata_preserved() {
        let _env_guard = ENV_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        let form = stripe_checkout_form_jp(base());
        assert!(has(&form, "metadata[product_id]", "42"));
        assert!(has(&form, "metadata[size]", "M"));
        assert!(has(&form, "metadata[unit_price_jpy]", "5000"));
        assert!(has(&form, "metadata[kyc_required]", "false"));
    }
}

#[cfg(test)]
mod price_tests {
    use super::*;

    #[test]
    fn cap_is_three_hundred_thousand() {
        // Far above the cap with normal step.
        let p = dynamic_price("mugen", 1, 10_000, "x");
        assert_eq!(p, PRICE_CAP_JPY);
        assert_eq!(p, 300_000);
    }

    #[test]
    fn surcharge_three_percent_for_crypto() {
        assert_eq!(apply_payment_surcharge(5_000, "usdc"), 5_150);
        assert_eq!(apply_payment_surcharge(5_000, "sol"), 5_150);
        assert_eq!(apply_payment_surcharge(120_000, "usdc"), 123_600);
    }

    #[test]
    fn surcharge_five_percent_for_eth() {
        assert_eq!(apply_payment_surcharge(5_000, "eth"), 5_250);
        assert_eq!(apply_payment_surcharge(120_000, "eth"), 126_000);
    }

    #[test]
    fn surcharge_clamps_to_cap() {
        // Base already at cap; ETH surcharge cannot push it past cap.
        assert_eq!(apply_payment_surcharge(PRICE_CAP_JPY, "eth"), PRICE_CAP_JPY);
        // Base just below cap; small surcharge pushed past would clamp.
        assert_eq!(apply_payment_surcharge(295_000, "eth"), PRICE_CAP_JPY);
    }

    #[test]
    fn jpy_is_passthrough() {
        assert_eq!(apply_payment_surcharge(5_000, "jpy"), 5_000);
        assert_eq!(apply_payment_surcharge(5_000, ""), 5_000);
    }
}

/// Normalize a `created_at` value (which may be a unix epoch string OR an ISO
/// timestamp like "2026-05-05T12:21:44.522054") into a consistent ISO-8601 UTC
/// string `"YYYY-MM-DDTHH:MM:SSZ"`. Lets clients sort/compare deterministically.
fn normalize_created_at_iso(raw: &str) -> String {
    if let Ok(secs) = raw.parse::<i64>() {
        if secs > 0 {
            let days = secs.div_euclid(86_400);
            let rem  = secs.rem_euclid(86_400);
            let (y, m, d) = civil_from_days(days);
            let hh = rem / 3600;
            let mm = (rem % 3600) / 60;
            let ss = rem % 60;
            return format!("{:04}-{:02}-{:02}T{:02}:{:02}:{:02}Z", y, m, d, hh, mm, ss);
        }
    }
    // Already ISO-ish — trim fractional seconds + ensure trailing Z.
    let trimmed = raw.split('.').next().unwrap_or(raw);
    if trimmed.contains('T') {
        return if trimmed.ends_with('Z') { trimmed.to_string() } else { format!("{trimmed}Z") };
    }
    raw.to_string()
}

fn read_product(row: &rusqlite::Row) -> rusqlite::Result<Product> {
    let brand:    String = row.get(1)?;
    let drop_num: i64    = row.get(2)?;
    let name:     String = row.get(3)?;
    let db_price: i64    = row.get(5)?;
    let sold:     i64    = row.get(7)?;
    let created_at_raw: String = row.get(8)?;
    // Pricing rule:
    //   - MA: respect the per-piece DB floor (so legacy monthly pieces created
    //     at ¥120k stay ¥120k even after the cadence change lowered the constant
    //     to ¥30k; admin update-price calls also persist correctly).
    //   - MUGEN/MUON/NOUNS: recompute from the bonding curve so each read
    //     reflects current `sold` count.
    let price_jpy = if brand == "ma" && db_price > 0 {
        db_price
    } else {
        dynamic_price(&brand, drop_num, sold, &name)
    };
    let serial_code = serial_code_for(&created_at_raw, drop_num);
    let created_at = normalize_created_at_iso(&created_at_raw);
    Ok(Product {
        id:           row.get(0)?,
        brand,
        drop_num,
        name,
        serial_code,
        mockup_url:   row.get(4)?,
        price_jpy,
        inventory:    row.get(6)?,
        sold,
        created_at,
        weather_data: row.get(9)?,
        prompt_hash:  row.get(10)?,
        seed_data:    row.get(11)?,
        nft_mint:     row.get(12)?,
        auction_end:  row.get(13)?,
        current_bid:  row.get(14).unwrap_or(0),
        bid_count:    row.get(15).unwrap_or(0),
        sold_out_at:  row.get(16).unwrap_or(None),
        lifestyle_url: row.get(17).unwrap_or(None),
        // Try-get because not every SELECT pulls the new column. When the
        // column index is out-of-range (small SELECT), this falls back to None.
        payment_link_url: row.get(18).unwrap_or(None),
        suzuri_url: row.get(19).unwrap_or(None),
    })
}

/// Build a YYYYMMDD-#NNN serial code from the row's created_at and a stable
/// per-day ordinal. We use drop_num modulo a per-day estimate when no explicit
/// per-day index is stored. For MUGEN at most 24 drops/day (one per hour), so
/// the ordinal is `((drop_num - 1) % 24) + 1`. For other brands we fall back
/// to drop_num itself since they're already 1-indexed within their cycle.
fn serial_code_for(created_at_raw: &str, drop_num: i64) -> String {
    // created_at is either a Unix epoch as TEXT or an ISO-ish stamp
    let unix_secs: i64 = if let Ok(v) = created_at_raw.parse::<i64>() {
        v
    } else {
        // Try "YYYY-MM-DDTHH:MM:SS..." — use only the date portion
        if let Some(date) = created_at_raw.split('T').next() {
            let parts: Vec<&str> = date.split('-').collect();
            if parts.len() == 3 {
                let y: i64 = parts[0].parse().unwrap_or(2026);
                let m: i64 = parts[1].parse().unwrap_or(1);
                let d: i64 = parts[2].parse().unwrap_or(1);
                return format!("{:04}{:02}{:02}-#{:03}", y, m, d, drop_num.max(1));
            }
        }
        0
    };
    if unix_secs <= 0 {
        return format!("00000000-#{:03}", drop_num.max(1));
    }
    // JST date = epoch + 9h, then break into Y/M/D
    let days_since_epoch = (unix_secs + 9 * 3600) / 86400;
    let (y, m, d) = civil_from_days(days_since_epoch);
    // Per-day ordinal: drop_num is 1-108 for mugen, mostly sequential by hour
    let ord = ((drop_num.max(1) - 1) % 99) + 1; // keep within #001-#099
    format!("{:04}{:02}{:02}-#{:03}", y, m, d, ord)
}

async fn list_products(
    Path(brand): Path<String>,
    State(db): State<Db>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> impl IntoResponse {
    let limit: i64 = q.get("limit").and_then(|s| s.parse().ok()).unwrap_or(500).clamp(1, 1000);
    let conn = db.lock().unwrap();
    let mut stmt = conn.prepare(
        // Printful S3 temp URLs (printful-upload.s3-accelerate.amazonaws.com)
        // expire ~24h after upload. When that happens we fall back to the raw
        // design_url (stable imgur/R2 URL) so the image never disappears.
        "SELECT id, brand, drop_num, name,
                CASE
                  WHEN mockup_url LIKE 'https://printful-upload.s3%'
                       OR mockup_url LIKE 'https://files.cdn.printful.com/upload%'
                  THEN COALESCE(NULLIF(design_url,''), mockup_url)
                  ELSE mockup_url
                END AS mockup_url,
                price_jpy, inventory, sold, created_at,
                weather_data, prompt_hash, seed_data, nft_mint, auction_end,
                COALESCE(current_bid,0), COALESCE(bid_count,0), sold_out_at, lifestyle_url,
                payment_link_url, suzuri_url
         FROM products WHERE brand=? AND active=1 ORDER BY drop_num DESC LIMIT ?"
    ).unwrap();
    let products: Vec<Product> = stmt.query_map(params![brand, limit], |row| read_product(row))
        .unwrap().filter_map(|r| r.ok()).collect();
    Json(products)
}

/// GET /api/v1/embed/products?brand=mugen&limit=12&available=1
///
/// CORS-enabled, embed-friendly product listing for external EC sites.
/// Returns a minimal, stable schema with explicit `checkout_url`, `share_url`,
/// `available`, and `image_url`. Use from /embed.js or fetch() directly.
///
/// Query params:
///   brand     — mugen | muon | ma | nouns | sweep (default: all)
///   limit     — 1..50 (default 12)
///   available — "1" to filter inventory>sold (default: all)
async fn embed_products(
    State(db): State<Db>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> impl IntoResponse {
    let limit: i64 = q.get("limit").and_then(|s| s.parse().ok()).unwrap_or(12).clamp(1, 50);
    let available_only = q.get("available").map(|s| s == "1").unwrap_or(false);

    // Build query — if `brand` is set, filter; otherwise include all main brands.
    // Kichinan_* brands are allow-listed by prefix so the 36-SKU collab line
    // (each SKU is its own brand: kichinan_tee_sample, kichinan_cap_sample…)
    // is queryable via /api/v1/embed/products?brand=kichinan_tee_sample
    // once the kichinan_approval gate has flipped them to active=1.
    let allowed = ["mugen","muon","ma","nouns"];
    let conn = db.lock().unwrap();
    let brand_filter = q.get("brand")
        .map(String::as_str)
        .filter(|b| allowed.contains(b) || is_proposal_brand(&conn, b));
    let sql = if brand_filter.is_some() {
        "SELECT id, brand, drop_num, name,
                CASE
                  WHEN mockup_url LIKE 'https://printful-upload.s3%'
                  THEN COALESCE(NULLIF(design_url,''), mockup_url)
                  ELSE mockup_url
                END AS img,
                price_jpy, inventory, sold, created_at, auction_end
         FROM products WHERE brand=? AND active=1
         ORDER BY drop_num DESC LIMIT ?"
    } else {
        "SELECT id, brand, drop_num, name,
                CASE
                  WHEN mockup_url LIKE 'https://printful-upload.s3%'
                  THEN COALESCE(NULLIF(design_url,''), mockup_url)
                  ELSE mockup_url
                END AS img,
                price_jpy, inventory, sold, created_at, auction_end
         FROM products WHERE active=1
         ORDER BY id DESC LIMIT ?"
    };
    let mut stmt = match conn.prepare(sql) {
        Ok(s) => s,
        Err(_) => return (StatusCode::INTERNAL_SERVER_ERROR, "db").into_response(),
    };
    let mapper = |row: &rusqlite::Row| -> rusqlite::Result<serde_json::Value> {
        let id: i64 = row.get(0)?;
        let brand: String = row.get(1)?;
        let drop_num: i64 = row.get(2)?;
        let name: String = row.get(3)?;
        let img: Option<String> = row.get(4)?;
        let price: i64 = row.get(5)?;
        let inv: i64 = row.get(6)?;
        let sold: i64 = row.get(7)?;
        let auction_end: Option<String> = row.get(9)?;
        // Absolute-URL the image: embedded sites on other origins cannot
        // resolve relative paths like /mockups/121.jpg → expand to wearmu.com.
        let image_abs: Option<String> = img.map(|u| {
            if u.starts_with("http://") || u.starts_with("https://") {
                u
            } else if u.starts_with('/') {
                format!("https://wearmu.com{}", u)
            } else {
                format!("https://wearmu.com/{}", u)
            }
        });
        Ok(serde_json::json!({
            "id": id,
            "brand": brand,
            "drop_num": drop_num,
            "name": name,
            "image_url": image_abs,
            "price_jpy": price,
            "inventory": inv,
            "sold": sold,
            "available": (inv - sold) > 0,
            "is_auction": auction_end.is_some(),
            "checkout_url": format!("https://wearmu.com/products/{}/{}", brand, drop_num),
            "share_url":    format!("https://wearmu.com/products/{}/{}", brand, drop_num),
        }))
    };
    let products: Vec<serde_json::Value> = if let Some(b) = brand_filter {
        stmt.query_map(params![b, limit], mapper)
    } else {
        stmt.query_map(params![limit], mapper)
    }.map(|it| it.filter_map(|r| r.ok())
        .filter(|p| !available_only || p["available"].as_bool().unwrap_or(false))
        .collect()).unwrap_or_default();

    Json(serde_json::json!({
        "products": products,
        "count":    products.len(),
        "source":   "https://wearmu.com",
        "docs":     "https://wearmu.com/developers",
    })).into_response()
}

/// GET /embed.js — Drop-in widget. Renders MU products inside any HTML element
/// on any domain. Usage:
///
///   <div id="mu-mount"></div>
///   <script src="https://wearmu.com/embed.js" defer></script>
///   <script>
///     window.addEventListener('load', () => MU.mount({
///       brand:    'mugen',     // mugen | muon | ma | nouns (or omit for mixed)
///       count:    6,
///       container:'#mu-mount',
///       theme:    'dark',      // 'dark' | 'light' (default: dark)
///       available: true,       // only in-stock items
///       lang:     'ja',        // ja | en
///       onClick:  (p) => window.open(p.checkout_url, '_blank'),
///     }));
///   </script>
async fn embed_js() -> impl IntoResponse {
    let body = include_str!("../static/embed.js");
    (
        [
            (axum::http::header::CONTENT_TYPE, "application/javascript; charset=utf-8"),
            (axum::http::header::CACHE_CONTROL, "public, max-age=300"),
        ],
        body,
    )
}

