/// POST /api/bounty/claim/:token — consume the token, record shipping +
/// cash-payout target, kick off Printful fulfillment.
#[derive(Deserialize)]
struct BountyClaimBody {
    #[serde(default)] choice: String,
    #[serde(default)] product_id: Option<i64>,
    #[serde(default)] size: String,
    #[serde(default)] ship_name: String,
    #[serde(default)] ship_email: String,
    #[serde(default)] ship_phone: String,
    #[serde(default)] ship_line1: String,
    #[serde(default)] ship_line2: String,
    #[serde(default)] ship_city: String,
    #[serde(default)] ship_state: String,
    #[serde(default)] ship_zip: String,
    #[serde(default)] ship_country: String,
    // Cash-payout. Only one of solana_wallet / stripe_connect_account_id /
    // paypay_handle is used, depending on payout_method.
    #[serde(default)] payout_method: String,
    #[serde(default)] solana_wallet: String,
    #[serde(default)] stripe_connect_account_id: String,
    #[serde(default)] paypay_handle: String,
}
async fn bounty_claim(
    State(db): State<Db>,
    axum::extract::Path(token): axum::extract::Path<String>,
    Json(body): Json<BountyClaimBody>,
) -> Response {
    if token.len() < 32 || token.len() > 128 || !token.chars().all(|c| c.is_ascii_alphanumeric()) {
        return (StatusCode::NOT_FOUND, Json(serde_json::json!({"ok":false,"error":"invalid token"}))).into_response();
    }
    let choice = body.choice.trim().to_string();
    if choice != "existing" && choice != "original" {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok":false,"error":"choice must be 'existing' or 'original'"}))).into_response();
    }
    let size = body.size.trim().to_uppercase();
    if !["S","M","L","XL","XXL","2XL"].contains(&size.as_str()) {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok":false,"error":"invalid size"}))).into_response();
    }
    let ship_email = body.ship_email.trim().to_lowercase();
    if !ship_email.contains('@') || ship_email.len() < 5 || ship_email.len() > 254 {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok":false,"error":"invalid ship_email"}))).into_response();
    }
    let ship_name = body.ship_name.trim().chars().take(120).collect::<String>();
    let ship_line1 = body.ship_line1.trim().chars().take(200).collect::<String>();
    let ship_line2 = body.ship_line2.trim().chars().take(200).collect::<String>();
    let ship_city = body.ship_city.trim().chars().take(80).collect::<String>();
    let ship_state = body.ship_state.trim().chars().take(80).collect::<String>();
    let ship_zip = body.ship_zip.trim().chars().take(20).collect::<String>();
    let ship_country = body.ship_country.trim().to_uppercase().chars().take(2).collect::<String>();
    let ship_phone = body.ship_phone.trim().chars().take(40).collect::<String>();
    if ship_name.is_empty() || ship_line1.is_empty() || ship_city.is_empty()
        || ship_zip.is_empty() || ship_country.len() != 2 {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok":false,"error":"shipping required (name, line1, city, zip, country)"}))).into_response();
    }

    // ── Payout validation ─────────────────────────────────────────────
    let payout_method = body.payout_method.trim().to_lowercase();
    let solana_wallet = body.solana_wallet.trim().chars().take(64).collect::<String>();
    let stripe_account_id = body.stripe_connect_account_id.trim().chars().take(64).collect::<String>();
    let paypay_handle = body.paypay_handle.trim().chars().take(60).collect::<String>();
    // Only require a payout target if there's actually cash on the reward.
    // (For tee-only rewards, payout_method may be blank.)
    let need_cash_payout = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT cash_amount_jpy FROM bounty_rewards WHERE token=?",
            params![token], |r| r.get::<_, i64>(0),
        ).unwrap_or(0) > 0
    };
    if need_cash_payout {
        if !["solana", "stripe_connect", "paypay"].contains(&payout_method.as_str()) {
            return (StatusCode::BAD_REQUEST,
                Json(serde_json::json!({"ok":false,"error":"payout_method must be 'solana', 'stripe_connect', or 'paypay'"}))).into_response();
        }
        match payout_method.as_str() {
            "solana" => {
                // Solana addresses are base58-encoded ed25519 pubkeys,
                // typically 43–44 chars. Validate length + base58 alphabet.
                if !is_plausible_solana_wallet(&solana_wallet) {
                    return (StatusCode::BAD_REQUEST,
                        Json(serde_json::json!({"ok":false,"error":"invalid Solana wallet address"}))).into_response();
                }
            }
            "stripe_connect" => {
                if !stripe_account_id.starts_with("acct_") || stripe_account_id.len() < 12 {
                    return (StatusCode::BAD_REQUEST,
                        Json(serde_json::json!({"ok":false,"error":"please complete Stripe Connect onboarding first"}))).into_response();
                }
            }
            "paypay" => {
                if paypay_handle.is_empty() || paypay_handle.len() > 60 {
                    return (StatusCode::BAD_REQUEST,
                        Json(serde_json::json!({"ok":false,"error":"PayPay ID required"}))).into_response();
                }
            }
            _ => unreachable!(),
        }
    }

    let now_int: i64 = chrono_now().parse().unwrap_or(0);

    // Atomic check-and-claim in one critical section.
    struct TxResult { reward_id: i64, bounty_id: i64, cash_amount_jpy: i64, design_url: String }
    let outcome: Result<TxResult, Response> = (|| -> Result<TxResult, Response> {
        let conn = db.lock().unwrap();
        let row: Result<(i64, i64, i64, String, i64), rusqlite::Error> = conn.query_row(
            "SELECT id, bounty_id, cash_amount_jpy, status, CAST(expires_at AS INTEGER)
             FROM bounty_rewards WHERE token=?",
            params![token],
            |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?, r.get(4)?)),
        );
        let (reward_id, bounty_id, cash_amount_jpy, status, expires_at) = match row {
            Ok(t) => t,
            Err(_) => return Err((StatusCode::NOT_FOUND,
                Json(serde_json::json!({"ok":false,"error":"token not found"}))).into_response()),
        };
        if status != "issued" {
            return Err((StatusCode::GONE,
                Json(serde_json::json!({"ok":false,"error":"token already used"}))).into_response());
        }
        if expires_at <= now_int {
            return Err((StatusCode::GONE,
                Json(serde_json::json!({"ok":false,"error":"token expired"}))).into_response());
        }
        let design_url = if choice == "original" {
            bounty_original_tee_design_url()
        } else {
            let pid = match body.product_id {
                Some(p) if p > 0 => p,
                _ => return Err((StatusCode::BAD_REQUEST,
                    Json(serde_json::json!({"ok":false,"error":"product_id required for choice=existing"}))).into_response()),
            };
            let url: Result<String, rusqlite::Error> = conn.query_row(
                "SELECT COALESCE(design_url, mockup_url, '')
                 FROM products WHERE id=? AND active=1",
                params![pid], |r| r.get(0),
            );
            match url {
                Ok(u) if !u.is_empty() => u,
                _ => return Err((StatusCode::BAD_REQUEST,
                    Json(serde_json::json!({"ok":false,"error":"selected product has no artwork"}))).into_response()),
            }
        };
        // Persist payout target only if relevant; otherwise leave NULL so
        // the admin payout queue ignores tee-only rewards.
        let (pm_db, sol_db, stp_db, pp_db): (Option<&str>, Option<&str>, Option<&str>, Option<&str>) =
            if cash_amount_jpy > 0 {
                (Some(payout_method.as_str()),
                 if !solana_wallet.is_empty() { Some(solana_wallet.as_str()) } else { None },
                 if !stripe_account_id.is_empty() { Some(stripe_account_id.as_str()) } else { None },
                 if !paypay_handle.is_empty() { Some(paypay_handle.as_str()) } else { None })
            } else { (None, None, None, None) };
        let updated = conn.execute(
            "UPDATE bounty_rewards
             SET choice=?, chosen_product_id=?, chosen_size=?,
                 ship_name=?, ship_line1=?, ship_line2=?, ship_city=?, ship_state=?,
                 ship_zip=?, ship_country=?, ship_phone=?, ship_email=?,
                 payout_method=?, solana_wallet=?, stripe_connect_account_id=?, paypay_handle=?,
                 payout_status=CASE WHEN ?>0 THEN 'pending' ELSE NULL END,
                 status='claimed', claimed_at=?
             WHERE id=? AND status='issued'",
            params![
                choice, body.product_id, size,
                ship_name, ship_line1, ship_line2, ship_city, ship_state,
                ship_zip, ship_country, ship_phone, ship_email,
                pm_db, sol_db, stp_db, pp_db,
                cash_amount_jpy,
                now_int.to_string(), reward_id,
            ],
        ).unwrap_or(0);
        if updated == 0 {
            return Err((StatusCode::CONFLICT,
                Json(serde_json::json!({"ok":false,"error":"race: token already consumed"}))).into_response());
        }
        Ok(TxResult { reward_id, bounty_id, cash_amount_jpy, design_url })
    })();
    let r = match outcome { Ok(t) => t, Err(resp) => return resp };

    let payout_summary = if r.cash_amount_jpy > 0 {
        match payout_method.as_str() {
            "solana"          => format!("solana → {}", solana_wallet),
            "stripe_connect"  => format!("stripe_connect → {}", stripe_account_id),
            "paypay"          => format!("paypay → {}", paypay_handle),
            _                 => "未指定".into(),
        }
    } else { "—".into() };

    let tg = format!(
        "🎁 *Bounty reward claimed* #{} (bounty #{})\nchoice: {}\nproduct_id: {:?}\nsize: {}\ncash: ¥{}\npayout: {}\nship: {} <{}>\nto: {} {} {} {} {} {}",
        r.reward_id, r.bounty_id, choice, body.product_id, size, fmt_jpy(r.cash_amount_jpy),
        payout_summary,
        ship_name, ship_email,
        ship_line1, ship_line2, ship_city, ship_state, ship_zip, ship_country,
    );
    let _ = send_telegram_message(&tg).await;

    let printful_key = env::var("PRINTFUL_API_KEY").unwrap_or_default();
    if !printful_key.is_empty() {
        let db_clone = db.clone();
        let r_id = r.reward_id;
        let r_size = size.clone();
        let r_design = r.design_url.clone();
        let r_email = ship_email.clone();
        let r_name = ship_name.clone();
        let r_l1 = ship_line1.clone();
        let r_l2 = ship_line2.clone();
        let r_c = ship_city.clone();
        let r_s = ship_state.clone();
        let r_z = ship_zip.clone();
        let r_cc = ship_country.clone();
        let r_p = ship_phone.clone();
        tokio::spawn(async move {
            bounty_printful_fulfill(
                printful_key, db_clone, r_id, &r_size, &r_design,
                &r_email, &r_name, &r_l1, &r_l2, &r_c, &r_s, &r_z, &r_cc, &r_p,
            ).await;
        });
    } else {
        tracing::warn!("[bounty/claim] PRINTFUL_API_KEY unset — order will be fulfilled manually");
    }

    Json(serde_json::json!({
        "ok": true,
        "reward_id": r.reward_id,
        "bounty_id": r.bounty_id,
        "choice": choice,
        "size": size,
        "cash_amount_jpy": r.cash_amount_jpy,
        "payout_method": if r.cash_amount_jpy > 0 { Some(payout_method.clone()) } else { None },
    })).into_response()
}

/// GET /api/bounty/claim/:token/prefill — find a past shipping address for
/// the bounty reporter's email and return it so the claim page can offer
/// "前回のお届け先に送る" pre-fill.
///
/// Sources, in priority order (most-recent within each):
///   1. previously claimed bounty_rewards (same email, fully filled)
///   2. pending_crypto_payments (crypto checkout with shipping)
///   3. gi_preorders.shipping_json (Stripe shipping_details JSON)
///
/// Returns `{ found, source, masked, fields }`. We expose the unmasked
/// fields too because the token is single-use and only the email recipient
/// holds the URL — the masked label is just for the UI confirmation banner.
async fn bounty_claim_prefill(
    State(db): State<Db>,
    axum::extract::Path(token): axum::extract::Path<String>,
) -> Response {
    if token.len() < 32 || token.len() > 128 || !token.chars().all(|c| c.is_ascii_alphanumeric()) {
        return (StatusCode::NOT_FOUND, Json(serde_json::json!({"found": false}))).into_response();
    }
    let now_int: i64 = chrono_now().parse().unwrap_or(0);

    // 1. Resolve the bounty reporter's email via the token.
    let email: Option<String> = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT b.reporter_email
             FROM bounty_rewards r
             JOIN bounty_submissions b ON b.id = r.bounty_id
             WHERE r.token = ? AND r.status = 'issued'
               AND CAST(r.expires_at AS INTEGER) > ?",
            params![token, now_int],
            |r| r.get::<_, String>(0),
        ).ok()
    };
    let Some(email) = email.filter(|s| s.contains('@')) else {
        return Json(serde_json::json!({"found": false})).into_response();
    };

    #[derive(Default)]
    struct Ship {
        name: String, line1: String, line2: String, city: String,
        state: String, zip: String, country: String, phone: String,
    }
    fn nonempty(s: &Ship) -> bool { !s.line1.is_empty() && !s.city.is_empty() && !s.zip.is_empty() }

    let mut source: &'static str = "";
    let mut ship = Ship::default();

    let conn = db.lock().unwrap();

    // 1a. Past claimed bounty_rewards for this email.
    if let Ok(s) = conn.query_row(
        "SELECT COALESCE(ship_name,''), COALESCE(ship_line1,''), COALESCE(ship_line2,''),
                COALESCE(ship_city,''), COALESCE(ship_state,''), COALESCE(ship_zip,''),
                COALESCE(ship_country,''), COALESCE(ship_phone,'')
         FROM bounty_rewards
         WHERE ship_email = ? AND ship_line1 IS NOT NULL AND ship_line1 != ''
         ORDER BY claimed_at DESC LIMIT 1",
        params![email],
        |r| Ok(Ship{
            name: r.get(0)?, line1: r.get(1)?, line2: r.get(2)?, city: r.get(3)?,
            state: r.get(4)?, zip: r.get(5)?, country: r.get(6)?, phone: r.get(7)?,
        })) {
        if nonempty(&s) { ship = s; source = "prior_bounty"; }
    }

    // 1b. Crypto checkout history.
    if source.is_empty() {
        if let Ok(s) = conn.query_row(
            "SELECT COALESCE(ship_name,''), COALESCE(ship_line1,''), COALESCE(ship_line2,''),
                    COALESCE(ship_city,''), COALESCE(ship_state,''), COALESCE(ship_zip,''),
                    COALESCE(ship_country,''), COALESCE(ship_phone,'')
             FROM pending_crypto_payments
             WHERE email = ? AND ship_line1 IS NOT NULL AND ship_line1 != ''
             ORDER BY created_at DESC LIMIT 1",
            params![email],
            |r| Ok(Ship{
                name: r.get(0)?, line1: r.get(1)?, line2: r.get(2)?, city: r.get(3)?,
                state: r.get(4)?, zip: r.get(5)?, country: r.get(6)?, phone: r.get(7)?,
            })) {
            if nonempty(&s) { ship = s; source = "crypto_checkout"; }
        }
    }

    // 1c. Gi preorder Stripe shipping_json fallback.
    if source.is_empty() {
        let row: Option<(String, String, String)> = conn.query_row(
            "SELECT COALESCE(shipping_json,''), COALESCE(name,''), COALESCE(phone,'')
             FROM gi_preorders
             WHERE email = ? AND shipping_json IS NOT NULL AND shipping_json != ''
             ORDER BY paid_at DESC LIMIT 1",
            params![email],
            |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?)),
        ).ok();
        if let Some((js, name, phone)) = row {
            if let Ok(v) = serde_json::from_str::<serde_json::Value>(&js) {
                let a = &v["address"];
                let s = Ship{
                    name:    if !name.is_empty() { name } else { v["name"].as_str().unwrap_or("").to_string() },
                    line1:   a["line1"].as_str().unwrap_or("").to_string(),
                    line2:   a["line2"].as_str().unwrap_or("").to_string(),
                    city:    a["city"].as_str().unwrap_or("").to_string(),
                    state:   a["state"].as_str().unwrap_or("").to_string(),
                    zip:     a["postal_code"].as_str().unwrap_or("").to_string(),
                    country: a["country"].as_str().unwrap_or("").to_string(),
                    phone,
                };
                if nonempty(&s) { ship = s; source = "gi_preorder"; }
            }
        }
    }

    if source.is_empty() {
        return Json(serde_json::json!({"found": false})).into_response();
    }

    // Build a human-readable masked label for the UI banner. Show city +
    // first ~3 chars of the postal code; hide street.
    let masked = format!(
        "{country} · {state} {city} · 〒{zip_head}…",
        country = if ship.country == "JP" { "日本" } else { ship.country.as_str() },
        state = ship.state,
        city = ship.city,
        zip_head = ship.zip.chars().take(3).collect::<String>(),
    );

    Json(serde_json::json!({
        "found": true,
        "source": source,
        "masked": masked,
        "fields": {
            "ship_name":    ship.name,
            "ship_line1":   ship.line1,
            "ship_line2":   ship.line2,
            "ship_city":    ship.city,
            "ship_state":   ship.state,
            "ship_zip":     ship.zip,
            "ship_country": ship.country,
            "ship_phone":   ship.phone,
        },
    })).into_response()
}

/// Basic shape check for a Solana wallet address. Real Solana pubkeys
/// are 32-byte base58 strings (32-44 chars typically), but we don't link
/// libsodium just to ed25519-validate. This is a "looks plausible" guard.
fn is_plausible_solana_wallet(s: &str) -> bool {
    if !(32..=44).contains(&s.len()) { return false; }
    s.chars().all(|c| {
        // Base58 alphabet (Bitcoin / Solana): excludes 0, O, I, l.
        matches!(c,
            '1'..='9' |
            'A'..='H' | 'J'..='N' | 'P'..='Z' |
            'a'..='k' | 'm'..='z')
    })
}

/// POST /api/bounty/claim/:token/stripe-connect — create a Stripe Connect
/// Express account + onboarding link for the bounty reward recipient.
/// Returns `{ url, account_id, expires_at }`.
///
/// The account is created once per claim token (idempotent: if the row
/// already has a stripe_connect_account_id, re-uses it and returns a fresh
/// account_link).
async fn bounty_claim_stripe_connect(
    State(db): State<Db>,
    axum::extract::Path(token): axum::extract::Path<String>,
) -> Response {
    if token.len() < 32 || token.len() > 128 || !token.chars().all(|c| c.is_ascii_alphanumeric()) {
        return (StatusCode::NOT_FOUND, Json(serde_json::json!({"ok":false,"error":"invalid token"}))).into_response();
    }
    let stripe_key = env::var("STRIPE_SECRET_KEY").unwrap_or_default();
    if stripe_key.is_empty() {
        return (StatusCode::SERVICE_UNAVAILABLE,
            Json(serde_json::json!({"ok":false,"error":"stripe key not configured"}))).into_response();
    }

    // Verify token is live + read existing state.
    let now_int: i64 = chrono_now().parse().unwrap_or(0);
    struct R { reward_id: i64, cash_amount_jpy: i64, status: String, expires_at: i64,
               existing_account: Option<String> }
    let r: Option<R> = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT id, cash_amount_jpy, status, CAST(expires_at AS INTEGER),
                    stripe_connect_account_id
             FROM bounty_rewards WHERE token=?",
            params![token],
            |r| Ok(R{
                reward_id: r.get(0)?, cash_amount_jpy: r.get(1)?,
                status: r.get(2)?, expires_at: r.get(3)?,
                existing_account: r.get(4)?,
            }),
        ).ok()
    };
    let Some(r) = r else {
        return (StatusCode::NOT_FOUND, Json(serde_json::json!({"ok":false,"error":"token not found"}))).into_response();
    };
    if r.status != "issued" && r.status != "claimed" {
        return (StatusCode::GONE, Json(serde_json::json!({"ok":false,"error":"reward not active"}))).into_response();
    }
    if r.expires_at <= now_int {
        return (StatusCode::GONE, Json(serde_json::json!({"ok":false,"error":"token expired"}))).into_response();
    }
    if r.cash_amount_jpy <= 0 {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok":false,"error":"no cash on this reward"}))).into_response();
    }

    let client = reqwest::Client::new();

    // 1. Re-use or create the connected account.
    let account_id: String = if let Some(a) = r.existing_account.as_ref()
        .filter(|s| s.starts_with("acct_") && s.len() > 10) {
        a.clone()
    } else {
        let resp = client.post("https://api.stripe.com/v1/accounts")
            .basic_auth(&stripe_key, None::<&str>)
            .form(&[
                ("type", "express"),
                ("country", "JP"),
                ("capabilities[transfers][requested]", "true"),
                ("metadata[bounty_reward_id]", &r.reward_id.to_string()),
            ])
            .send().await;
        match resp {
            Ok(r2) if r2.status().is_success() => {
                let j: serde_json::Value = r2.json().await.unwrap_or_default();
                let id = j["id"].as_str().unwrap_or("").to_string();
                if id.is_empty() {
                    return (StatusCode::BAD_GATEWAY,
                        Json(serde_json::json!({"ok":false,"error":"stripe returned no account id"}))).into_response();
                }
                // Persist before generating link so a partial onboard still
                // re-uses the same account next attempt.
                {
                    let conn = db.lock().unwrap();
                    let _ = conn.execute(
                        "UPDATE bounty_rewards SET stripe_connect_account_id=? WHERE id=?",
                        params![id, r.reward_id],
                    );
                }
                id
            }
            Ok(r2) => {
                let st = r2.status();
                let t  = r2.text().await.unwrap_or_default();
                tracing::error!("[bounty/stripe-connect] account create {}: {}", st, t.chars().take(400).collect::<String>());
                let user_msg = if t.contains("signed up for Connect") || t.contains("Connect platform") {
                    "Stripe Connect is not enabled on this account. Choose Solana or PayPay instead."
                } else {
                    "Stripe account creation failed. Try again or pick another method."
                };
                return (StatusCode::BAD_GATEWAY,
                    Json(serde_json::json!({"ok":false,"error":user_msg}))).into_response();
            }
            Err(e) => {
                tracing::error!("[bounty/stripe-connect] account network: {}", e);
                return (StatusCode::BAD_GATEWAY,
                    Json(serde_json::json!({"ok":false,"error":"stripe network error"}))).into_response();
            }
        }
    };

    // 2. Generate a fresh onboarding link (these expire after a few minutes).
    let base_url = env::var("BASE_URL").unwrap_or_else(|_| "https://wearmu.com".into());
    let return_url = format!("{}/bounty/claim/{}#stripe-return", base_url, token);
    let refresh_url = format!("{}/bounty/claim/{}#stripe-refresh", base_url, token);
    let link_resp = client.post("https://api.stripe.com/v1/account_links")
        .basic_auth(&stripe_key, None::<&str>)
        .form(&[
            ("account", account_id.as_str()),
            ("type", "account_onboarding"),
            ("refresh_url", refresh_url.as_str()),
            ("return_url", return_url.as_str()),
        ])
        .send().await;
    match link_resp {
        Ok(r2) if r2.status().is_success() => {
            let j: serde_json::Value = r2.json().await.unwrap_or_default();
            let url = j["url"].as_str().unwrap_or("").to_string();
            let expires_at = j["expires_at"].as_i64().unwrap_or(0);
            if url.is_empty() {
                return (StatusCode::BAD_GATEWAY,
                    Json(serde_json::json!({"ok":false,"error":"stripe returned no link"}))).into_response();
            }
            Json(serde_json::json!({
                "ok": true, "url": url, "account_id": account_id, "expires_at": expires_at,
            })).into_response()
        }
        Ok(r2) => {
            let st = r2.status();
            let t  = r2.text().await.unwrap_or_default();
            tracing::error!("[bounty/stripe-connect] account_links {}: {}", st, t.chars().take(400).collect::<String>());
            (StatusCode::BAD_GATEWAY,
             Json(serde_json::json!({"ok":false,"error":"stripe link creation failed"}))).into_response()
        }
        Err(e) => {
            tracing::error!("[bounty/stripe-connect] account_links network: {}", e);
            (StatusCode::BAD_GATEWAY,
             Json(serde_json::json!({"ok":false,"error":"stripe network error"}))).into_response()
        }
    }
}

/// Background task: create a Printful order for a bounty reward claim and
/// stamp the printful_order_id back onto the row.
async fn bounty_printful_fulfill(
    key: String, db: Db, reward_id: i64,
    size: &str, design_url: &str,
    email: &str, name: &str, line1: &str, line2: &str,
    city: &str, state: &str, zip: &str, country: &str, phone: &str,
) {
    let variant_id = bounty_variant_id_for_size(size);
    // Printful rejects raw JP prefecture names ("東京都"/"東京") — normalize
    // to ISO 3166-2 ("JP-13"); non-JP values pass through unchanged.
    let state = jp_prefecture_to_iso(state).unwrap_or(state);
    let order = serde_json::json!({
        "recipient": {
            "name": name, "address1": line1, "address2": line2,
            "city": city, "state_code": state, "country_code": country,
            "zip": zip, "phone": phone, "email": email,
        },
        "items": [{
            "variant_id": variant_id,
            "quantity": 1,
            "files": [{"url": design_url, "placement": "front"}],
        }],
        "confirm": true,
    });
    let resp = reqwest::Client::new()
        .post("https://api.printful.com/orders")
        .bearer_auth(&key).json(&order).send().await;
    let now_int = chrono_now();
    match resp {
        Ok(r) if r.status().is_success() => {
            let j: serde_json::Value = r.json().await.unwrap_or_default();
            let order_id = j["result"]["id"].as_i64()
                .map(|n| n.to_string())
                .or_else(|| j["result"]["id"].as_str().map(String::from))
                .unwrap_or_default();
            let conn = db.lock().unwrap();
            let _ = conn.execute(
                "UPDATE bounty_rewards SET printful_order_id=?, status='shipped', shipped_at=? WHERE id=?",
                params![order_id, now_int, reward_id],
            );
            tracing::info!("[bounty/printful] reward_id={} printful_order_id={}", reward_id, order_id);
        }
        Ok(r) => {
            let s = r.status();
            let t = r.text().await.unwrap_or_default();
            tracing::error!("[bounty/printful] reward_id={} status={} body={}",
                reward_id, s, t.chars().take(400).collect::<String>());
        }
        Err(e) => tracing::error!("[bounty/printful] reward_id={} network: {}", reward_id, e),
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// MU PAY — customer-facing store credit.
//
// MU PAY is a thin, branded surface over the existing `mu_credits` balance
// (email-keyed, audited by mu_credit_ledger). A customer reaches their balance
// through a deterministic magic link /pay/<token> and redeems it for MUGEN
// tees: balance is decremented, shipping is collected on the page, and Printful
// auto-fulfils. Cash-out is intentionally "coming soon" — for now MU PAY only
// buys shirts. Bounty rewards are the first credit source
// (POST /admin/bounty/:id/grant-mupay). No new wallet/order tables: a
// redemption is just a negative mu_credit_ledger row.

/// Apology block shown on /bounty-adjacent surfaces (no reporter name).
const MUPAY_APOLOGY_HTML: &str = r#"<div style="max-width:780px;margin:24px auto;padding:18px 22px;border:1px solid rgba(230,196,73,0.3);background:rgba(230,196,73,0.06);border-radius:6px;color:#d8d4c8;font-size:13.5px;line-height:1.9">
<b style="color:#e6c449">お詫びと改善のご報告</b><br>
先日のバグ報酬対応で、受領確認メールの遅延と、引き換えリンクが正しく開けない不具合がありました。ご報告くださった方に大変ご不便をおかけしました。心よりお詫び申し上げます。<br>
現在は (1) 受領・判定メールの送信監視を強化し、(2) 引き換えは壊れにくい <code>/pay</code> リンクに統一、(3) 報酬は <b>MU PAY</b>（T シャツに使えるストアクレジット）でお渡しできるようにしました。現金へのお引き換えは準備中です（Coming soon）。引き続きよろしくお願いいたします。
</div>"#;

/// Deterministic per-email MU PAY access token (stable across re-grants).
fn mupay_token_for_email(email: &str) -> String {
    use sha2::{Sha256, Digest};
    let secret = env::var("ADMIN_TOKEN").unwrap_or_else(|_| "mupay-fallback-secret".into());
    let mut h = Sha256::new();
    h.update(b"mupay:");
    h.update(email.to_lowercase().as_bytes());
    h.update(b"|");
    h.update(secret.as_bytes());
    format!("{:x}", h.finalize())[..40].to_string()
}

/// Resolve a /pay/<token> back to the account email.
fn mupay_email_for_token(conn: &rusqlite::Connection, token: &str) -> Option<String> {
    conn.query_row(
        "SELECT email FROM mu_credits WHERE pay_token=?",
        params![token], |r| r.get::<_, String>(0),
    ).ok()
}

/// Credit MU PAY for an email, persist the access token, return the token.
/// Idempotent on `ref_id` (won't double-credit the same bounty).
fn mupay_grant(conn: &rusqlite::Connection, email: &str, amount_jpy: i64, reason: &str, ref_id: &str) -> Option<String> {
    if email.trim().is_empty() || amount_jpy <= 0 { return None; }
    let email_lc = email.trim().to_lowercase();
    let already: i64 = conn.query_row(
        "SELECT COUNT(*) FROM mu_credit_ledger WHERE email=? AND ref_id=?",
        params![email_lc, ref_id], |r| r.get(0),
    ).unwrap_or(0);
    if already == 0 {
        let _ = mu_credit_apply(conn, &email_lc, amount_jpy, reason, Some(ref_id));
    }
    let token = mupay_token_for_email(&email_lc);
    let _ = conn.execute(
        "UPDATE mu_credits SET pay_token=? WHERE email=? AND COALESCE(pay_token,'')=''",
        params![token, email_lc],
    );
    Some(token)
}

/// Best-effort Resend send with the verified info@ sender + failure logging.
async fn mupay_send_email(resend_key: &str, to: &str, subject: &str, html: &str) {
    match reqwest::Client::new()
        .post("https://api.resend.com/emails")
        .bearer_auth(resend_key)
        .json(&serde_json::json!({
            "from": "MU PAY <info@wearmu.com>",
            "to": [to],
            "subject": subject,
            "html": html,
            "reply_to": "info@wearmu.com",
        }))
        .send().await
    {
        Ok(resp) => {
            let code = resp.status().as_u16();
            if code >= 400 {
                let b = resp.text().await.unwrap_or_default();
                eprintln!("[mupay email] resend FAIL {} → {} : {}", code, to, b.chars().take(300).collect::<String>());
            }
        }
        Err(e) => eprintln!("[mupay email] resend HTTP ERROR → {} : {}", to, e),
    }
}

/// Place a Printful order for one MU tee. Returns the order id on success.
async fn mupay_place_printful_order(
    key: &str, variant_id: u64, design_url: &str,
    email: &str, name: &str, line1: &str, line2: &str,
    city: &str, state: &str, zip: &str, country: &str, phone: &str,
) -> Result<String, String> {
    // Printful rejects raw JP prefecture names — normalize to ISO 3166-2.
    let state = jp_prefecture_to_iso(state).unwrap_or(state);
    let order = serde_json::json!({
        "recipient": {
            "name": name, "address1": line1, "address2": line2,
            "city": city, "state_code": state, "country_code": country,
            "zip": zip, "phone": phone, "email": email,
        },
        "items": [{
            "variant_id": variant_id,
            "quantity": 1,
            "files": [{"url": design_url, "placement": "front"}],
        }],
        "confirm": true,
    });
    match reqwest::Client::new()
        .post("https://api.printful.com/orders")
        .bearer_auth(key).json(&order).send().await
    {
        Ok(r) if r.status().is_success() => {
            let j: serde_json::Value = r.json().await.unwrap_or_default();
            Ok(j["result"]["id"].as_i64().map(|n| n.to_string())
                .or_else(|| j["result"]["id"].as_str().map(String::from))
                .unwrap_or_default())
        }
        Ok(r) => {
            let s = r.status();
            let t = r.text().await.unwrap_or_default();
            Err(format!("printful {} {}", s, t.chars().take(300).collect::<String>()))
        }
        Err(e) => Err(format!("printful network: {}", e)),
    }
}

