/// Unix-epoch-seconds 30 days from now, as a string (matches you_users.trial_end_at format).
pub(crate) fn trial_end_seconds_from_now() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let secs = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();
    format!("{}", secs + 30 * 86400)
}

/// Days since signup (created_at). Positive integer, 1 on day 0.
fn days_since_signup_secs(created_at_secs: u64) -> i64 {
    use std::time::{SystemTime, UNIX_EPOCH};
    let now = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();
    if now <= created_at_secs { return 1; }
    1 + ((now - created_at_secs) / 86400) as i64
}

/// Whether a /you account is currently allowed to receive daily designs.
/// Active when ANY of:
///   - lifetime_free is set (bought a MU shirt → forever)
///   - trial_end_at is in the future
///   - subscription_until is in the future (¥980/月 paid plan)
fn you_user_active(trial_end_at: Option<&str>, lifetime_free: bool) -> bool {
    you_user_active_full(trial_end_at, lifetime_free, None)
}

fn you_user_active_full(
    trial_end_at: Option<&str>,
    lifetime_free: bool,
    subscription_until: Option<&str>,
) -> bool {
    if lifetime_free { return true; }
    use std::time::{SystemTime, UNIX_EPOCH};
    let now = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();
    let trial_end: u64 = trial_end_at.and_then(|s| s.parse().ok()).unwrap_or(0);
    if now < trial_end { return true; }
    let sub_end: u64 = subscription_until.and_then(|s| s.parse().ok()).unwrap_or(0);
    now < sub_end
}

/// Subscription state shown to the client (and stamped on emails).
fn you_user_state(trial_end_at: Option<&str>, lifetime_free: bool) -> serde_json::Value {
    you_user_state_full(trial_end_at, lifetime_free, None, None)
}

fn you_user_state_full(
    trial_end_at: Option<&str>,
    lifetime_free: bool,
    subscription_status: Option<&str>,
    subscription_until: Option<&str>,
) -> serde_json::Value {
    use std::time::{SystemTime, UNIX_EPOCH};
    let now = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();
    let trial_end: u64 = trial_end_at.and_then(|s| s.parse().ok()).unwrap_or(0);
    let sub_end: u64   = subscription_until.and_then(|s| s.parse().ok()).unwrap_or(0);
    let on_paid = subscription_status.map(|s| s == "active" || s == "trialing").unwrap_or(false)
                  && sub_end > now;
    let days_left: i64 = if lifetime_free {
        -1
    } else if on_paid {
        ((sub_end - now) / 86400) as i64
    } else if trial_end > now {
        ((trial_end - now) / 86400) as i64
    } else {
        0
    };
    let status = if lifetime_free {
        "lifetime"
    } else if on_paid {
        "subscribed"
    } else if trial_end > now {
        "trial"
    } else {
        "expired"
    };
    serde_json::json!({
        "status": status,
        "trial_end_at": trial_end_at,
        "subscription_status": subscription_status,
        "subscription_until": subscription_until,
        "days_left": days_left,
        "lifetime_free": lifetime_free,
    })
}

/// GET /api/you/featured_buy — latest active SKU surfaced as the /you hero
/// Buy CTA. /you receives ~70% of pageviews but historically had no direct
/// Buy action, contributing to the pageview→cta_click -91.8% drop in the
/// admin funnel. Returns a single SKU the hero links to as
/// `/p/<serial_code>?buy=1&utm_source=you_hero`. Cached 60 s.
async fn you_featured_buy(State(db): State<Db>) -> impl IntoResponse {
    let row: Option<(i64, String, i64, String, String, i64, Option<String>)> = {
        let conn = db.lock().unwrap();
        // Prefer products with non-zero sold (proven sellers); fall back to
        // the latest active SKU. retired_at IS NULL excludes pulled drops.
        conn.query_row(
            "SELECT id, brand, drop_num, name, serial_code, price_jpy, mockup_url
             FROM products
             WHERE active=1
               AND serial_code IS NOT NULL AND serial_code <> ''
               AND mockup_url IS NOT NULL AND mockup_url <> ''
               AND retired_at IS NULL
             ORDER BY (sold > 0) DESC, sold DESC, id DESC
             LIMIT 1",
            [], |r| Ok((
                r.get::<_, i64>(0)?,
                r.get::<_, String>(1)?,
                r.get::<_, i64>(2)?,
                r.get::<_, String>(3)?,
                r.get::<_, String>(4)?,
                r.get::<_, i64>(5)?,
                r.get::<_, Option<String>>(6).ok().flatten(),
            )),
        ).ok()
    };
    let mut headers = HeaderMap::new();
    headers.insert("Cache-Control", HeaderValue::from_static("public, max-age=60"));
    let body = match row {
        Some((id, brand, drop_num, name, serial_code, price_jpy, mockup_url)) => {
            serde_json::json!({
                "id": id,
                "brand": brand,
                "drop_num": drop_num,
                "name": name,
                "serial_code": serial_code,
                "price_jpy": price_jpy,
                "mockup_url": mockup_url,
                "buy_href": format!("/p/{}?buy=1&utm_source=you_hero", serial_code),
            })
        }
        None => serde_json::json!({ "id": null }),
    };
    (headers, Json(body)).into_response()
}

/// Total active /you subscribers — used for social-proof badge on the LP.
/// Cached for 60 seconds to avoid hammering the DB on every page load.
async fn you_active_count(State(db): State<Db>) -> impl IntoResponse {
    let total: i64 = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT COUNT(*) FROM you_users WHERE unsubscribed_at IS NULL",
            [], |r| r.get(0),
        ).unwrap_or(0)
    };
    let lifetime: i64 = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT COUNT(*) FROM you_users WHERE unsubscribed_at IS NULL AND lifetime_free=1",
            [], |r| r.get(0),
        ).unwrap_or(0)
    };
    let designs_total: i64 = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT COUNT(*) FROM you_designs WHERE gen_status='ready'",
            [], |r| r.get(0),
        ).unwrap_or(0)
    };
    // Cache 60s on the CDN
    let mut headers = HeaderMap::new();
    headers.insert("Cache-Control", HeaderValue::from_static("public, max-age=60"));
    (headers, Json(serde_json::json!({
        "active_subscribers": total,
        "lifetime_members":   lifetime,
        "designs_generated":  designs_total,
    }))).into_response()
}

/// GET / — 人間には HTML、`Accept: text/markdown` を明示する AI エージェント
/// には正準ドキュメント /llms.txt の本文をそのまま返す（既存挙動への影響ゼロ）。
async fn home(
    State(db): State<Db>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    headers: HeaderMap,
) -> Response {
    let wants_md = headers
        .get("accept")
        .and_then(|v| v.to_str().ok())
        .map(|a| a.contains("text/markdown"))
        .unwrap_or(false);
    if wants_md {
        return agent_api::llms_txt().await;
    }
    // ── language selection (?lang=en wins; else Accept-Language) ──
    // The page is JA by default; only an explicit `?lang=en` OR an
    // Accept-Language that prefers en (with no ja) renders the English
    // copy. This keeps <html lang> / hreflang / og:locale honest — they
    // now match the body that ships, instead of declaring en while
    // rendering ja. ?lang=ja always forces JA (lets en-locale users opt back).
    let lang_q = q.get("lang").map(|s| s.as_str()).unwrap_or("");
    let is_en = if lang_q.eq_ignore_ascii_case("en") {
        true
    } else if lang_q.eq_ignore_ascii_case("ja") {
        false
    } else {
        let al = headers
            .get("accept-language")
            .and_then(|v| v.to_str().ok())
            .unwrap_or("")
            .to_ascii_lowercase();
        // Prefer en only when the client clearly wants en and not ja.
        al.contains("en") && !al.contains("ja")
    };
    index(State(db), is_en).await.into_response()
}

async fn index(State(db): State<Db>, is_en: bool) -> Html<String> {
    let raw = include_str!("../static/index.html");

    // ── SSR fill: pre-fill the dynamic placeholders so the page never
    // ── renders "—°C / —着 / —:— / #—" during the JS fetch window.
    //
    // Sources (best-effort, falls back to "—" if missing):
    //   - mugen latest drop_num     → products WHERE brand='mugen' ORDER BY drop_num DESC
    //   - muon remaining today      → products WHERE brand='muon' (latest row)
    //   - weather temp_c            → cv_config('weather_temp_c') populated by /api/weather
    //   - mugen-timer mm:ss         → seconds-to-next-hour computed server-side

    let (mugen_drop, mugen_cycle, muon_qty, temp_c, lifestyle_tiles): (Option<i64>, Option<i64>, Option<i64>, Option<i64>, Vec<(i64, String, String)>) = {
        let conn = db.lock().unwrap();
        let mugen = conn.query_row(
            "SELECT drop_num FROM products WHERE brand='mugen' AND active=1
             ORDER BY drop_num DESC LIMIT 1",
            [], |r| r.get::<_, i64>(0),
        ).ok();
        let muon = conn.query_row(
            "SELECT MAX(0, inventory - sold) FROM products WHERE brand='muon' AND active=1
             ORDER BY id DESC LIMIT 1",
            [], |r| r.get::<_, i64>(0),
        ).ok();
        let cycle = mugen.map(|d| ((d - 1).rem_euclid(108)) + 1);
        // Weather: only trust if cached within 60 min (else stale; let JS retry)
        let temp = {
            let raw = cv_get(&conn, "weather_temp_c", "");
            let at_str = cv_get(&conn, "weather_cached_at", "0");
            let at: i64 = at_str.parse().unwrap_or(0);
            let now_s: i64 = chrono_now().parse().unwrap_or(0);
            if !raw.is_empty() && (now_s - at).abs() < 3600 {
                raw.parse::<i64>().ok()
            } else { None }
        };
        // people-wearing-MU tiles: pull up to 6 mugen products with lifestyle_url.
        let tiles: Vec<(i64, String, String)> = {
            let mut stmt = match conn.prepare(
                "SELECT drop_num, name, lifestyle_url FROM products
                 WHERE active=1 AND lifestyle_url IS NOT NULL AND lifestyle_url != ''
                 ORDER BY id DESC LIMIT 6"
            ) { Ok(s) => s, Err(_) => return Html(String::new()) };
            stmt.query_map([], |r| Ok((r.get::<_,i64>(0)?, r.get::<_,String>(1)?, r.get::<_,String>(2)?)))
                .map(|it| it.filter_map(|r| r.ok()).collect())
                .unwrap_or_default()
        };
        (mugen, cycle, muon, temp, tiles)
    };

    // Homepage discovery strip (2026-05-30): the hero sells only "今日の一着"
    // (MUGEN/MUON); the 745-SKU catalog across collab brands was invisible
    // below the nav. Surface up to 8 live apparel SKUs with real POD mockups
    // to lift the visit→buy-click rate. Reuses /shop/:sku (proven buy flow);
    // does NOT touch pricing or checkout. Falls back to empty (placeholder
    // replaced with "") when no qualifying rows exist.
    let shop_picks: Vec<(String, String, String, i64)> = {
        let conn = db.lock().unwrap();
        conn.prepare(
            "SELECT sku, description_ja, mockup_url_external, retail_price_jpy
             FROM catalog_products
             WHERE is_active=1 AND status='live'
               AND mockup_url_external IS NOT NULL AND mockup_url_external != ''
               AND ( mockup_url_external LIKE '%printful%'
                     OR mockup_url_external LIKE '%r2.dev%'
                     OR mockup_url_external LIKE '%r2.cloudflarestorage%'
                     OR mockup_url_external LIKE '%mockups.wearmu.com%' )
               -- Exclude Printful *temporary* upload URLs (expire → 403 → blank
               -- tiles). Mirrors persist_mockup_if_temporary()'s is_temp check:
               -- printful-upload.s3… and any /tmp/ path are ephemeral.
               AND mockup_url_external NOT LIKE 'https://printful-upload.s3%'
               AND mockup_url_external NOT LIKE '%/tmp/%'
               AND retail_price_jpy >= 3000
               AND sku NOT LIKE 'PROPOSAL-%'
             ORDER BY RANDOM()
             LIMIT 8",
        )
        .ok()
        .and_then(|mut s| {
            s.query_map([], |r| {
                Ok((
                    r.get::<_, String>(0)?,
                    r.get::<_, String>(1)?,
                    r.get::<_, String>(2)?,
                    r.get::<_, i64>(3)?,
                ))
            })
            .ok()
            .map(|it| it.filter_map(|r| r.ok()).collect())
        })
        .unwrap_or_default()
    };

    // Timer: seconds to next whole hour (UTC, mirrors JS implementation).
    let timer_str: String = {
        let now_s: i64 = chrono_now().parse().unwrap_or(0);
        let secs_into_hour = now_s.rem_euclid(3600);
        let remaining = 3600 - secs_into_hour;
        let m = remaining / 60;
        let s = remaining % 60;
        format!("{:02}:{:02}", m, s)
    };

    // (Removed 2026-05-20: t100-banner SSR fill (T100_SOLD / T100_DAYS_LEFT).
    //  Banner removed from homepage; /100 page handler computes inline.)

    let drop_str   = mugen_drop.map(|d| format!("#{}", d)).unwrap_or_else(|| "—".into());
    let cycle_str  = mugen_cycle.map(|c| format!("{}/108", c)).unwrap_or_else(|| "—/108".into());
    let temp_str   = temp_c.map(|t| t.to_string()).unwrap_or_else(|| "—".into());
    let qty_from_temp = temp_c.map(|t| t.unsigned_abs().max(1) as i64);
    let qty_str    = qty_from_temp.map(|q| q.to_string()).unwrap_or_else(|| "—".into());
    let muon_qty_str = muon_qty.map(|q| q.to_string()).unwrap_or_else(|| "—".into());
    let temp_deg_str = temp_c.map(|t| format!("{}°", t)).unwrap_or_else(|| "—".into());
    // For hero stat that displays "MUON Today", prefer the live MUON inventory
    // if present, fall back to temp-derived qty (the original JS behavior).
    let hero_qty_str = if muon_qty.is_some() { muon_qty_str.clone() } else { qty_str.clone() };

    // Substitute placeholder spans. Each replace targets the exact static markup
    // shipped in static/index.html — adding new placeholders is safe (becomes no-op).
    let html = raw
        // Ticker: drop number (2 occurrences)
        .replace(
            r#"<span class="ticker-item">MUGEN 無限 — AIが毎時間デザインを生成中 <span id="t-drop">—</span></span>"#,
            &format!(r#"<span class="ticker-item">MUGEN 無限 — AIが毎時間デザインを生成中 <span id="t-drop">{}</span></span>"#, drop_str),
        )
        .replace(
            r#"<span class="ticker-item">MUGEN 無限 — AIが毎時間デザインを生成中 <span id="t-drop2">—</span></span>"#,
            &format!(r#"<span class="ticker-item">MUGEN 無限 — AIが毎時間デザインを生成中 <span id="t-drop2">{}</span></span>"#, drop_str),
        )
        // Ticker: temp + qty
        .replace(
            r#"<span class="ticker-item">MUON 無音 — 今日の気温 <span id="t-temp">—</span>°C → <span id="t-qty">—</span>着</span>"#,
            &format!(r#"<span class="ticker-item">MUON 無音 — 今日の気温 <span id="t-temp">{}</span>°C → <span id="t-qty">{}</span>着</span>"#, temp_str, qty_str),
        )
        .replace(
            r#"<span class="ticker-item">MUON 無音 — 今日の気温 <span id="t-temp2">—</span>°C → <span id="t-qty2">—</span>着</span>"#,
            &format!(r#"<span class="ticker-item">MUON 無音 — 今日の気温 <span id="t-temp2">{}</span>°C → <span id="t-qty2">{}</span>着</span>"#, temp_str, qty_str),
        )
        // Ticker: next-drop timer
        .replace(
            r#"<span class="ticker-item">次のMUGENドロップまで <span id="t-timer">—</span></span>"#,
            &format!(r#"<span class="ticker-item">次のMUGENドロップまで <span id="t-timer">{}</span></span>"#, timer_str),
        )
        .replace(
            r#"<span class="ticker-item">次のMUGENドロップまで <span id="t-timer2">—</span></span>"#,
            &format!(r#"<span class="ticker-item">次のMUGENドロップまで <span id="t-timer2">{}</span></span>"#, timer_str),
        )
        // Hero stats — strip loading-shimmer + data-loading when SSR fills the value
        .replace(
            r#"<div class="hero-stat-num loading-shimmer" id="stat-mugen" data-loading="true" aria-label="MUGEN drop number, loading">···</div>"#,
            &format!(r#"<div class="hero-stat-num" id="stat-mugen" aria-label="MUGEN drop number">{}</div>"#, drop_str),
        )
        .replace(
            r#"<div class="hero-stat-num loading-shimmer" id="stat-temp" data-loading="true" aria-label="Today's temperature in Hokkaido, loading">···</div>"#,
            &format!(r#"<div class="hero-stat-num" id="stat-temp" aria-label="Today's temperature in Hokkaido">{}</div>"#, temp_deg_str),
        )
        .replace(
            r#"<div class="hero-stat-num loading-shimmer" id="stat-qty" data-loading="true" aria-label="MUON pieces today, loading">···</div>"#,
            &format!(r#"<div class="hero-stat-num" id="stat-qty" aria-label="MUON pieces today">{}</div>"#, hero_qty_str),
        )
        // MUON section live-info
        .replace(
            r#"<span id="weather-temp">—</span>°C"#,
            &format!(r#"<span id="weather-temp">{}</span>°C"#, temp_str),
        )
        .replace(
            r#"今日の発行枚数 <span id="weather-qty">—</span>着"#,
            &format!(r#"今日の発行枚数 <span id="weather-qty">{}</span>着"#, hero_qty_str),
        )
        // MUGEN section
        .replace(
            r#"<div class="drop-counter" id="mugen-drop-num">#—</div>"#,
            &format!(r#"<div class="drop-counter" id="mugen-drop-num">{}</div>"#, drop_str),
        )
        .replace(
            r#"<div class="drop-sub" id="mugen-cycle">—/108</div>"#,
            &format!(r#"<div class="drop-sub" id="mugen-cycle">{}</div>"#, cycle_str),
        )
        .replace(
            r#"<div class="drop-counter next-drop-timer" id="mugen-timer">—:—</div>"#,
            &format!(r#"<div class="drop-counter next-drop-timer" id="mugen-timer">{}</div>"#, timer_str),
        );

    // Fill the `#hero-lifestyle` "people wearing MU" grid with up to 6 cards.
    // Empty fallback: keep the original placeholder (CSS hides it via display:none).
    let html = if !lifestyle_tiles.is_empty() {
        let cards: String = lifestyle_tiles.iter().map(|(drop, name, url)| {
            let name_esc = html_attr_escape(name);
            let url_esc  = html_attr_escape(url);
            format!(
                r#"<a href="/mugen" title="{name_esc}" style="display:block;aspect-ratio:4/5;overflow:hidden;border:1px solid rgba(255,255,255,0.08);transition:border-color 0.2s ease"><img src="{url_esc}" alt="MUGEN #{drop} lifestyle" loading="lazy" style="width:100%;height:100%;object-fit:cover;display:block"></a>"#,
                drop = drop, name_esc = name_esc, url_esc = url_esc,
            )
        }).collect();
        let new_grid = format!(
            r#"<div id="hero-lifestyle" style="margin-top:28px;width:100%;max-width:880px;display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:6px;padding:0 12px"><div style="grid-column:1/-1;text-align:center;font-size:9px;letter-spacing:0.3em;opacity:0.45;text-transform:uppercase;margin-bottom:4px">people wearing MU · live</div>{}</div>"#,
            cards,
        );
        // Match the static placeholder. The CSS rule `#hero-lifestyle{{display:none}}`
        // hides the empty grid; once filled by JS or SSR, JS clears it. Here we
        // also add an inline display:grid override so SSR wins over the rule.
        let new_grid = new_grid.replacen(
            r#"id="hero-lifestyle" style=""#,
            r#"id="hero-lifestyle" style="display:grid !important;"#, 1,
        );
        html.replace(
            r#"<div id="hero-lifestyle" style="margin-top:28px;width:100%;max-width:880px;display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:6px;padding:0 12px">
    <div style="grid-column:1/-1;text-align:center;font-size:9px;letter-spacing:0.3em;opacity:0.35;text-transform:uppercase">people wearing MU</div>
  </div>"#,
            &new_grid,
        )
    } else {
        html
    };

    // Hero T-shirt card SSR-fill: latest mugen drop label (#N or fallback).
    let hero_drop_label = mugen_drop.map(|d| format!("#{:04}", d)).unwrap_or_else(|| "今日 の 一着".into());
    let html = html.replace("{HERO_DROP_LABEL}", &hero_drop_label);

    // Fill the homepage discovery strip ({BEST_SELLERS_STRIP}). Tasteful dark
    // section matching the hero; links each card to its /shop/:sku PDP and a
    // "全商品を見る" CTA to /shop. Empty when no qualifying SKUs (token → "").
    let shop_strip = if shop_picks.is_empty() {
        String::new()
    } else {
        let cards: String = shop_picks.iter().map(|(sku, name, img, price)| {
            let sku_e   = html_attr_escape(sku);
            let name_e  = html_attr_escape(name);
            let img_e   = html_attr_escape(img);
            format!(
                r#"<a href="/shop/{sku_e}" data-funnel="cta_click" data-funnel-cta="home_shop_pick" style="display:block;text-decoration:none;color:inherit;background:#0d0d0d;border:1px solid rgba(255,255,255,0.07);border-radius:4px;overflow:hidden;transition:border-color 0.2s ease" onmouseover="this.style.borderColor='rgba(230,196,73,0.5)'" onmouseout="this.style.borderColor='rgba(255,255,255,0.07)'"><div style="width:100%;aspect-ratio:1/1;background:#fff;overflow:hidden"><img src="{img_e}" alt="{name_e}" loading="lazy" style="width:100%;height:100%;object-fit:cover;display:block"></div><div style="padding:9px 10px"><div style="font-size:11px;color:#F5F5F0;line-height:1.4;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">{name_e}</div><div style="font-size:12px;font-weight:600;color:#e6c449;margin-top:3px;font-variant-numeric:tabular-nums">¥{price_fmt}</div></div></a>"#,
                sku_e = sku_e, name_e = name_e, img_e = img_e, price_fmt = format_jpy(*price),
            )
        }).collect();
        format!(
            r#"<section style="width:100%;max-width:880px;margin:44px auto 0;padding:0 12px">
  <div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:14px">
    <div style="font-size:10px;letter-spacing:0.3em;text-transform:uppercase;opacity:0.55">MU &amp; コラボ — コレクション</div>
    <a href="/shop" data-funnel="cta_click" data-funnel-cta="home_shop_all" style="font-size:10px;letter-spacing:0.18em;text-transform:uppercase;color:#e6c449;text-decoration:none">全商品を見る →</a>
  </div>
  <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:10px">{cards}</div>
</section>"#,
            cards = cards,
        )
    };
    let html = html.replace("{BEST_SELLERS_STRIP}", &shop_strip);

    // ── English rendering (?lang=en / Accept-Language: en) ──
    // The static index.html ships JA and *declares* ja+en (hreflang,
    // og:locale:alternate, JSON-LD inLanguage). Until now the body stayed
    // JA even for ?lang=en — the declaration lied. This swaps <html lang>,
    // the meta/og/twitter copy, and the visible hero + nav + CTAs to real
    // English so the declared language matches the rendered language.
    // Scope (per task): top page only — hero, nav, meta, buy CTA, and the
    // BIM section heading. Deeper sections (tab-toggled MA/MUON/MUGEN) stay
    // JA for now; they are not visible above the fold. Checkout links
    // (/buy, /shop/:sku, /make) are NOT touched — only their button text.
    let html = if is_en {
        html
            // ── <html lang> + locale (the core honesty fix) ──
            .replace(r#"<html lang="ja">"#, r#"<html lang="en">"#)
            .replace(
                r#"<meta property="og:locale" content="ja_JP">"#,
                r#"<meta property="og:locale" content="en_US">"#,
            )
            .replace(
                r#"<meta property="og:locale:alternate" content="en_US">"#,
                r#"<meta property="og:locale:alternate" content="ja_JP">"#,
            )
            // canonical points at the en variant so search engines index it as en
            .replace(
                r#"<link rel="canonical" href="https://wearmu.com/">"#,
                r#"<link rel="canonical" href="https://wearmu.com/?lang=en">"#,
            )
            // ── <title> / meta description ──
            .replace(
                r#"<title>MU — 今日も、 一つの絵が生まれた。| AIが毎日描く受注生産オリジナルTシャツ · wearmu.com</title>"#,
                r#"<title>MU — Today, one more drawing was born. | An AI that paints a new made-to-order tee every day · wearmu.com</title>"#,
            )
            .replace(
                r#"<meta name="description" content="¥7,800 — 原価 ¥5,700 公開。北海道弟子屈町の気温と月相を、AI が読む。同じ絵は二度と生まれない。— 私が死んでも、明日も一つの絵が生まれる。(MUGEN は同じ絵を最大 108 枚、MA は世界に 1 枚)">"#,
                r#"<meta name="description" content="¥7,800 — cost ¥5,700, made public. An AI reads the temperature and moon phase of Teshikaga, Hokkaido. No two drawings are ever the same. Even after I'm gone, one more drawing is born each day. (MUGEN prints one design up to 108 times; MA is 1-of-1 worldwide.)">"#,
            )
            // ── Open Graph / Twitter copy ──
            .replace(
                r#"<meta property="og:title" content="MU — 今日も、 一つの絵が生まれた。">"#,
                r#"<meta property="og:title" content="MU — Today, one more drawing was born.">"#,
            )
            .replace(
                r#"<meta property="og:description" content="¥7,800 — 原価 ¥5,700 公開。北海道弟子屈町の気温と月相を、AI が読む。同じ絵は二度と生まれない。私が死んでも、明日も一つの絵が生まれる。">"#,
                r#"<meta property="og:description" content="¥7,800 — cost ¥5,700, made public. An AI reads the temperature and moon phase of Teshikaga, Hokkaido. No two drawings are ever the same. Even after I'm gone, one more drawing is born each day.">"#,
            )
            .replace(
                r#"<meta name="twitter:title" content="MU — 今日も、 一つの絵が生まれた。">"#,
                r#"<meta name="twitter:title" content="MU — Today, one more drawing was born.">"#,
            )
            .replace(
                r#"<meta name="twitter:description" content="¥7,800 — 原価 ¥5,700 公開。毎日、 一つの絵が生まれる。私が死んでも、 明日も一つの絵が生まれる。">"#,
                r#"<meta name="twitter:description" content="¥7,800 — cost ¥5,700, made public. One drawing is born every day. Even after I'm gone, one more drawing is born each day.">"#,
            )
            // ── nav ──
            .replace(
                r#"aria-label="ブランド一覧 — MU と各パートナーのコラボブランド">ブランド一覧</a>"#,
                r#"aria-label="Brands — MU and partner collab brands">Brands</a>"#,
            )
            .replace(
                r#"aria-label="運営公開ノート">運営ノート</a>"#,
                r#"aria-label="Operator's public notes">Notes</a>"#,
            )
            // ── footer 読みもの (journal) internal links ──
            .replace(
                r#"<span class="footer-readmore-h">読みもの</span>"#,
                r#"<span class="footer-readmore-h">Journal</span>"#,
            )
            .replace(
                r#"seo-original-tshirt-1mai">オリジナルTシャツを1枚から作る方法</a>"#,
                r#"seo-original-tshirt-1mai">Make a custom tee from just one (JA)</a>"#,
            )
            .replace(
                r#"seo-bjj-rashguard-order">柔術ラッシュガード・BJJ Tシャツのオーダーメイド</a>"#,
                r#"seo-bjj-rashguard-order">Custom BJJ rashguards &amp; tees (JA)</a>"#,
            )
            .replace(
                r#"seo-pod-honest-cost">受注生産アパレルの原価、全部見せます</a>"#,
                r#"seo-pod-honest-cost">The honest economics of print-on-demand (JA)</a>"#,
            )
            .replace(
                r#"<a href="/blog/">すべての記事 →</a>"#,
                r#"<a href="/blog/">All notes →</a>"#,
            )
            // ── promo strip (today's tee card) ──
            .replace(
                r#"今日 の Tシャツ · MUGEN {HERO_DROP_LABEL} · ベーシック生地"#,
                r#"TODAY'S TEE · MUGEN {HERO_DROP_LABEL} · basic fabric"#,
            )
            .replace(
                r#"<div style="font-size:18px;font-weight:600;color:#fff;margin-bottom:3px">¥4,900 <span style="font-size:12px;opacity:0.55;font-weight:400">≈ $33</span> · 国内 5-8 日 <span style="font-size:11px;opacity:0.5;font-weight:400">(下のオーガニック版は ¥7,800)</span></div>"#,
                r#"<div style="font-size:18px;font-weight:600;color:#fff;margin-bottom:3px">¥4,900 <span style="font-size:12px;opacity:0.55;font-weight:400">≈ $33</span> · ships worldwide <span style="font-size:11px;opacity:0.5;font-weight:400">(organic version below is ¥7,800)</span></div>"#,
            )
            .replace(
                r#"気温seed · AI生成 · 1時間に1着 · 同じ柄は2度と作られない · <strong style="color:#e6c449">+ MSA</strong> (21リポDL付)"#,
                r#"temperature seed · AI-generated · 1 tee per hour · the same design is never made twice · <strong style="color:#e6c449">+ MSA</strong> (21-repo download)"#,
            )
            // ── hero number line + tagline + sub-copy ──
            .replace(
                r#"オーガニック版 · 原価 ¥5,700 公開"#,
                r#"organic version · cost ¥5,700, public"#,
            )
            .replace("今日も、 一つの絵が生まれた。", "Today, one more drawing was born.")
            .replace(
                r#"弟子屈町の気温と月相を、AI が読む。<br>
    人間は介在しない。同じ絵は、二度と生まれない。"#,
                r#"An AI reads the temperature and moon phase of Teshikaga.<br>
    No human is involved. No two drawings are ever the same."#,
            )
            .replace("私が死んでも、明日も一つの絵が生まれる。", "Even after I'm gone, one more drawing is born each day.")
            .replace(
                r#"なぜ ¥7,800</a>"#,
                r#"why ¥7,800</a>"#,
            )
            // ── /make CTA ──
            .replace(
                r#"✦ ひとこと言うだけで、自分のTシャツをAIが作る → /make"#,
                r#"✦ Say one line, and AI makes your own tee → /make"#,
            )
            .replace(
                r#"ログイン不要・在庫ゼロ。約 10〜20 秒でデザイン → その場で並んで買える (公開前に人が一度確認)。<br>下の「今日の一着」は、AI が毎時間ひとりで生む既製の柄です。"#,
                r#"No login, zero inventory. ~10–20s to a design → buy it right there (a human reviews before it goes public).<br>"Today's one piece" below is a ready-made design the AI generates on its own every hour."#,
            )
            // ── MU Pass entry ──
            .replace(
                r#"🌀 買った 1 着が、永久メンバー証 (NFT) になる → /pass"#,
                r#"🌀 The tee you buy becomes a permanent membership (NFT) → /pass"#,
            )
            // ── "today's one piece" buy card ──
            .replace("▶ 今日の一着", "▶ TODAY'S ONE PIECE")
            .replace("MUGEN — 今日 ━◯━", "MUGEN — today ━◯━")
            // ── buy buttons (text only; href untouched) ──
            .replace(
                r#"font-weight:800;white-space:nowrap;flex-shrink:0">買う →</div>"#,
                r#"font-weight:800;white-space:nowrap;flex-shrink:0">BUY →</div>"#,
            )
            .replace(
                r#"font-weight:700;white-space:nowrap">買う →</span>"#,
                r#"font-weight:700;white-space:nowrap">BUY →</span>"#,
            )
            // ── BIM section heading + lede (main visible section heading) ──
            .replace("— BIM 設計 · 北海道 弟子屈", "— BIM design · Teshikaga, Hokkaido")
            .replace(
                r#"無人の店を、<br>BIM で設計した。"#,
                r#"We designed an<br>unstaffed store in BIM."#,
            )
            .replace(
                r#"MU の T シャツを見る →"#,
                r#"See MU's tees →"#,
            )
    } else {
        html
    };

    // トップA/B/C: 勝者確定済みなら全員その案をサーバが焼く（JS割当を上書き）。
    // 未確定なら __SERVER_VARIANT__ を空にし、クライアントJSが visitor で3分割。
    let home_winner = {
        let conn = db.lock().unwrap();
        conn.query_row("SELECT value FROM cv_config WHERE key='home_winner'", [], |r| r.get::<_, String>(0))
            .ok()
            .filter(|v| v == "a" || v == "b" || v == "c")
            .unwrap_or_default()
    };
    let html = html.replace("__SERVER_VARIANT__", &home_winner);

    Html(html)
}

async fn blog_index(State(db): State<Db>) -> Html<String> {
    let base = include_str!("../static/blog/index.html");
    // Fetch most recent 30 AI auto-blog posts and render a section.
    let posts: Vec<(String, String, String)> = {
        let conn = db.lock().unwrap();
        // created_at is stored as unix-epoch string (chrono_now()). Convert to
        // JST date for display. Fallback to SUBSTR for legacy ISO rows.
        let result = match conn.prepare(
            "SELECT slug, title, COALESCE(
                CASE WHEN created_at GLOB '[0-9]*' AND LENGTH(created_at) <= 11
                     THEN date(CAST(created_at AS INTEGER), 'unixepoch', '+9 hours')
                     ELSE SUBSTR(created_at,1,10) END, '')
             FROM auto_blog_posts WHERE published=1
             ORDER BY created_at DESC LIMIT 30"
        ) {
            Ok(mut stmt) => stmt.query_map([], |r| Ok((
                r.get::<_, String>(0)?, r.get::<_, String>(1)?, r.get::<_, String>(2)?
            ))).map(|it| it.filter_map(|r| r.ok()).collect::<Vec<_>>())
              .unwrap_or_default(),
            Err(_) => Vec::new(),
        };
        result
    };
    let auto_html = if posts.is_empty() {
        String::new()
    } else {
        let mut s = String::from(
            r#"<section style="max-width:760px;margin:48px auto 0;padding:0 32px">
<div class="eyebrow">AI Field log — 毎朝 9:10 JST</div>
<h2 style="font-size:22px;font-weight:300;letter-spacing:0.02em;margin:14px 0 8px">
Gemini が書く運営日誌
</h2>
<p style="color:var(--mute);font-size:13px;line-height:1.85;margin-bottom:6px">
人手版のノートとは別系列。AI が毎朝、その日の天気・売上・在庫・お客様の声を見て自分の言葉で書く。
</p>
</section>
<ul class="list">"#);
        for (slug, title, date) in &posts {
            // ISO 8601 (YYYY-MM-DD) — keep machine-tone consistent across surfaces.
            s.push_str(&format!(
                r#"<li>
<div class="date">{date} · AI auto-blog</div>
<h2><a href="/blog/auto/{slug}">{title}</a></h2>
</li>"#,
                date = html_escape(date),
                slug = html_attr_escape(slug),
                title = html_escape(title),
            ));
        }
        s.push_str("</ul>");
        s
    };
    // Inject the new section right before <footer>
    let injected = if let Some(footer_idx) = base.find("<footer>") {
        let (head, tail) = base.split_at(footer_idx);
        format!("{head}{auto_html}{tail}")
    } else {
        format!("{base}{auto_html}")
    };
    Html(injected)
}

