/// Return (ISO-ish JST string, human JP label) for the next Founder Edition
/// drop (春分・夏至・秋分・冬至 21:00 JST after now). Skips past dates.
/// Dates are the JMA astronomical approximations for 2026–2030; refresh
/// the table once it's lived through a year.
fn founder_next_drop_label() -> (String, String) {
    // (month, day, jp_kanji)
    let candidates: [(u32, u32, &str); 4] = [
        (3, 20, "春分"),
        (6, 21, "夏至"),
        (9, 23, "秋分"),
        (12, 22, "冬至"),
    ];
    let secs = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs() as i64;
    // JST = UTC + 9h
    let jst_secs = secs + 9 * 3600;
    let (year, month, day) = unix_to_ymd(jst_secs);
    let now_md = (month, day);
    let pick = |yr: i32| -> Option<(i32, u32, u32, &'static str)> {
        for (m, d, jp) in candidates {
            // pick the first solstice/equinox strictly after today (compare yyyy-mm-dd)
            if yr > year || (yr == year && (m, d) > now_md) {
                return Some((yr, m, d, jp));
            }
        }
        None
    };
    let (yr, m, d, jp) = pick(year)
        .or_else(|| pick(year + 1))
        .unwrap_or((year + 1, 3, 20, "春分"));
    let iso = format!("{:04}-{:02}-{:02}T21:00:00+09:00", yr, m, d);
    let label = format!("{yr}年{m}月{d}日 ({jp}) 21:00", yr = yr, m = m, d = d, jp = jp);
    (iso, label)
}

/// Civil-calendar conversion (proleptic Gregorian) for a unix timestamp
/// already shifted to the target timezone. Returns (year, month, day).
/// Avoids pulling chrono (main.rs intentionally doesn't depend on it).
fn unix_to_ymd(secs: i64) -> (i32, u32, u32) {
    let days_since_epoch = secs.div_euclid(86_400);
    // Convert days-since-1970-01-01 to (y, m, d) using Howard Hinnant's algorithm.
    let z = days_since_epoch + 719_468;
    let era = z.div_euclid(146_097);
    let doe = (z - era * 146_097) as u64;
    let yoe = (doe - doe / 1460 + doe / 36_524 - doe / 146_096) / 365;
    let y = yoe as i64 + era * 400;
    let doy = doe - (365 * yoe + yoe / 4 - yoe / 100);
    let mp = (5 * doy + 2) / 153;
    let d = (doy - (153 * mp + 2) / 5 + 1) as u32;
    let m = (if mp < 10 { mp + 3 } else { mp - 9 }) as u32;
    let y = if m <= 2 { y + 1 } else { y } as i32;
    (y, m, d)
}

/// POST /api/checkout/founder — open a Stripe Checkout session for the
/// Founder Edition. ¥48,000 fixed price, 1着, ships at next solstice/equinox.
async fn founder_checkout(
    State(_db): State<Db>,
    Json(body): Json<serde_json::Value>,
) -> Response {
    let stripe_key = env::var("STRIPE_SECRET_KEY").unwrap_or_default();
    if stripe_key.is_empty() {
        return (StatusCode::SERVICE_UNAVAILABLE,
            Json(serde_json::json!({"error":"checkout disabled (STRIPE_SECRET_KEY not set)"})))
            .into_response();
    }
    let size = body.get("size").and_then(|v| v.as_str())
        .map(|s| s.to_uppercase())
        .filter(|s| ["XS","S","M","L","XL","XXL"].contains(&s.as_str()))
        .unwrap_or_else(|| "M".to_string());

    let base_url = env::var("BASE_URL").unwrap_or_else(|_| "https://wearmu.com".into());
    let price_jpy: i64 = 48_000;
    let display = format!("MUGEN #∞ Founder Edition (size {size}) — 先行予約");
    let price_str = price_jpy.to_string();
    let success_url = format!("{}/success?sid={{CHECKOUT_SESSION_ID}}&edition=founder", base_url);
    let cancel_url  = format!("{}/buy/founder", base_url);
    let image_url   = format!("{}/static/founder/hero-on-model.png", base_url);
    let (drop_iso, _label) = founder_next_drop_label();

    let resp = reqwest::Client::new()
        .post("https://api.stripe.com/v1/checkout/sessions")
        .basic_auth(&stripe_key, None::<&str>)
        .form(&[
            ("mode", "payment"),
            ("currency", "jpy"),
            ("locale", "ja"),
            // 先行予約: authorize only, capture confirmed manually after
            // manufacturing is complete. Stripe holds the auth for 7 days for
            // cards; we re-auth before each drop's actual capture.
            ("payment_intent_data[capture_method]", "manual"),
            ("payment_intent_data[description]",
             "MUGEN #∞ Founder Edition — 先行予約 (オーソリのみ、課金は製造完了後)"),
            ("line_items[0][price_data][currency]", "jpy"),
            ("line_items[0][price_data][product_data][name]", display.as_str()),
            ("line_items[0][price_data][product_data][description]",
             "Loopwheel 14oz · 弟子屈 鉱物染色 · NFC 革ラベル。先行予約 (課金確定 = 製造完了後、遅延・中止時は全額返金)。"),
            ("line_items[0][price_data][product_data][images][0]", image_url.as_str()),
            ("line_items[0][price_data][unit_amount]", price_str.as_str()),
            ("line_items[0][quantity]", "1"),
            ("success_url", success_url.as_str()),
            ("cancel_url", cancel_url.as_str()),
            ("billing_address_collection", "required"),
            ("shipping_address_collection[allowed_countries][0]", "JP"),
            ("shipping_address_collection[allowed_countries][1]", "US"),
            ("shipping_address_collection[allowed_countries][2]", "GB"),
            ("shipping_address_collection[allowed_countries][3]", "FR"),
            ("shipping_address_collection[allowed_countries][4]", "DE"),
            ("shipping_address_collection[allowed_countries][5]", "AU"),
            ("shipping_address_collection[allowed_countries][6]", "KR"),
            ("shipping_address_collection[allowed_countries][7]", "TW"),
            ("shipping_address_collection[allowed_countries][8]", "HK"),
            ("phone_number_collection[enabled]", "true"),
            ("allow_promotion_codes", "true"),
            ("metadata[edition]", "founder"),
            ("metadata[size]", size.as_str()),
            ("metadata[next_drop_iso]", drop_iso.as_str()),
            ("metadata[product]", "MUGEN_FOUNDER_INFINITY"),
            ("metadata[reservation]", "true"),
        ])
        .send().await;

    match resp {
        Ok(r) if r.status().is_success() => {
            let json: serde_json::Value = r.json().await.unwrap_or_default();
            let url = json["url"].as_str().unwrap_or("/buy/founder").to_string();
            Json(serde_json::json!({
                "url": url,
                "edition": "founder",
                "size": size,
                "next_drop": drop_iso,
            })).into_response()
        }
        Ok(r) => {
            let status = r.status();
            let txt = r.text().await.unwrap_or_default();
            eprintln!("[founder] stripe error {}: {}", status, txt);
            (StatusCode::INTERNAL_SERVER_ERROR,
                Json(serde_json::json!({
                    "error": format!("stripe: {}", &txt[..txt.len().min(240)])
                }))).into_response()
        }
        Err(e) => {
            eprintln!("[founder] stripe request error: {}", e);
            (StatusCode::INTERNAL_SERVER_ERROR,
                Json(serde_json::json!({"error":"stripe connection error"}))).into_response()
        }
    }
}

/// /collections/:brand — gallery page listing every active product of a brand.
/// Each card links to /buy/:id. Useful for kawanabe_personal (10 candidates)
/// and the ads_* niche bundles. Falls back to "no products" message.
async fn collection_page(
    State(db): State<Db>,
    axum::extract::Path(brand): axum::extract::Path<String>,
) -> Response {
    let rows: Vec<(i64, i64, String, Option<String>, i64, i64, i64)> = {
        let conn = db.lock().unwrap();
        let mut stmt = match conn.prepare(
            "SELECT id, drop_num, name, mockup_url, price_jpy, inventory, sold
             FROM products WHERE brand = ? AND active = 1
             ORDER BY drop_num ASC"
        ) { Ok(s) => s, Err(e) => return (StatusCode::INTERNAL_SERVER_ERROR, format!("db: {}", e)).into_response() };
        stmt.query_map(params![brand], |r| Ok((
            r.get(0)?, r.get(1)?, r.get(2)?, r.get::<_, Option<String>>(3)?,
            r.get(4)?, r.get(5)?, r.get(6)?
        ))).map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default()
    };
    let brand_label = brand.to_uppercase().replace("ADS_", "").replace("_", " ");

    let mut cards = String::new();
    if rows.is_empty() {
        cards.push_str(r#"<div class="empty">商品が見つかりません</div>"#);
    } else {
        for (id, drop, name, mockup, price, inventory, sold) in &rows {
            let img = mockup.as_deref().unwrap_or("https://mockups.wearmu.com/hero.png");
            let remaining: i64 = inventory - sold;
            let stock = if remaining <= 0 { "<span class=\"sold\">SOLD</span>".to_string() }
                       else { format!("のこり {}/{}", remaining, inventory) };
            cards.push_str(&format!(
                r#"<a class="card" href="/buy/{id}">
                  <div class="thumb"><img src="{img}" alt="{name_esc}" loading="lazy"></div>
                  <div class="meta">
                    <div class="num">#{drop:03}</div>
                    <div class="name">{name_esc}</div>
                    <div class="row"><span class="price">¥{price}</span><span class="stock">{stock}</span></div>
                  </div>
                </a>"#,
                id=id, img=html_attr_escape(img), name_esc=html_escape(name),
                drop=drop, price=format_jpy(*price), stock=stock));
        }
    }

    // Cross-link to bim.house for the bimhouse-goods collection. MU と
    // bim.house は既に相互に導線を張っている (bim.house 側に「🏠この家に
    // 置くもの — MU」)。ここは押し売りせず、静かに一行で出自を示す。
    // 日本語+英語併記 (このページに i18n フレームワークは無いため短文併記)。
    let note = if brand == "bimhouse-goods" {
        r#"<div class="note">
      この意匠の家は <a href="https://bim.house" target="_blank" rel="noopener">bim.house</a> で建っている。言葉から、建築 BIM へ。
      <span class="en">The houses behind this collection are built on <a href="https://bim.house" target="_blank" rel="noopener">bim.house</a> — from words to architecture.</span>
    </div>"#
    } else {
        ""
    };

    let canonical_url = format!("https://wearmu.com/collections/{}", brand);
    let html = format!(r#"<!doctype html><html lang="ja"><head>
<meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1"/>
<title>{label} — MU</title>
<link rel="canonical" href="{canonical_url}"/>
<meta property="og:type" content="website">
<meta property="og:title" content="{label} — MU">
<meta property="og:description" content="{label} コレクション · MU">
<meta property="og:url" content="{canonical_url}">
<meta property="og:image" content="https://wearmu.com/static/og.png">
<meta property="og:site_name" content="MU">
<meta name="twitter:card" content="summary_large_image">
<meta name="twitter:image" content="https://wearmu.com/static/og.png">
<style>{css}
  .wrap{{max-width:1100px;margin:0 auto;padding:32px 22px 0}}
  .kicker{{font-size:10.5px;letter-spacing:0.22em;color:#666;text-transform:uppercase}}
  h1{{font-size:32px;font-weight:300;margin:8px 0 6px;letter-spacing:0.01em}}
  h1 em{{color:#e6c449;font-style:normal}}
  .sub{{color:#888;font-size:13.5px;margin-bottom:30px}}
  .grid{{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:14px}}
  .card{{background:#0a0a0a;border:1px solid #1f1f1f;border-radius:6px;overflow:hidden;text-decoration:none;color:inherit;display:block;transition:border-color 0.15s,transform 0.15s}}
  .card:hover{{border-color:#e6c449;transform:translateY(-2px)}}
  .card .thumb{{aspect-ratio:1/1;background:#000;display:flex;align-items:center;justify-content:center}}
  .card .thumb img{{width:100%;height:100%;object-fit:cover;display:block}}
  .card .meta{{padding:14px 16px}}
  .card .num{{font-size:10.5px;letter-spacing:0.2em;color:#e6c449;font-family:ui-monospace,Menlo,monospace}}
  .card .name{{font-size:14px;font-weight:500;margin:4px 0 10px;line-height:1.4;color:#f5f5f0}}
  .card .row{{display:flex;justify-content:space-between;align-items:baseline;font-size:12.5px}}
  .card .price{{color:#e6c449;font-weight:500}}
  .card .stock{{color:#888}}
  .card .sold{{color:#e07b7b;font-weight:600;letter-spacing:0.08em}}
  .empty{{color:#888;text-align:center;padding:80px 0;grid-column:1/-1}}
  .note{{margin:-12px 0 30px;padding:14px 16px;border:1px solid #1f1f1f;border-radius:6px;background:#0a0a0a;color:#aaa;font-size:13px;line-height:1.7}}
  .note a{{color:#e6c449;text-decoration:none;border-bottom:1px solid #3a3a2a}}
  .note a:hover{{border-bottom-color:#e6c449}}
  .note .en{{display:block;margin-top:5px;color:#666;font-size:12px}}
</style></head><body>
  {header}
  <div class="wrap">
    <div class="kicker">COLLECTION</div>
    <h1><em>{label}</em></h1>
    <div class="sub">{count} 着のデザイン。クリックで個別購入ページへ。</div>
    {note}
    <div class="grid">{cards}</div>
  </div>
  {footer}
</body></html>"#,
        css=vault_chrome_css(),
        header=vault_header_html("home", None),
        footer=vault_footer_html(),
        label=html_escape(&brand_label),
        canonical_url=html_attr_escape(&canonical_url),
        count=rows.len(),
        note=note,
        cards=cards);
    (StatusCode::OK, [("content-type", "text/html; charset=utf-8")], html).into_response()
}

/// Top-level merch categories. Each category aggregates several
/// sub-brands (drops, partner collabs, product-type sample lines)
/// into a single SEO landing under /merch/<category>. The mapping is
/// static because brands are added rarely; if a brand is missing add
/// it here. `like_prefixes` is matched via `brand LIKE 'prefix%'` so
/// the auto-generated `<brand>_<product>_sample` lines are picked up
/// without enumerating every one.
struct MerchCategory {
    slug: &'static str,
    label: &'static str,
    tagline: &'static str,
    exact_brands: &'static [&'static str],
    like_prefixes: &'static [&'static str],
}

