#[derive(Deserialize)]
struct KichinanSampleBody {
    design: String,    // "a" | "b" | "c" | "d" | "e"
    size: Option<String>, // S/M/L/XL — defaults to M
    price_jpy: i64,
}


/// Idempotent: ensures one products row per kichinan design so Printful
/// fulfillment piggybacks on the existing MUGEN/MA pipeline. design_url is
/// the print-ready transparent PNG, mockup_url is the photoreal Gemini
/// product shot for OG / receipt thumbnails.
fn kichinan_brand_for_kind(kind: &str) -> &'static str {
    match kind {
        "cap"             => "kichinan_cap_sample",
        "tote"            => "kichinan_tote_sample",
        "hoodie"          => "kichinan_hoodie_sample",
        "mug"             => "kichinan_mug_sample",
        "beanie"          => "kichinan_beanie_sample",
        "longsleeve"      => "kichinan_longsleeve_sample",
        "sticker"         => "kichinan_sticker_sample",
        "kids_hoodie"     => "kichinan_kids_hoodie_sample",
        "kids_longsleeve" => "kichinan_kids_longsleeve_sample",
        "kids_sweat"      => "kichinan_kids_sweat_sample",
        "baby_onesie"     => "kichinan_baby_onesie_sample",
        "baby_bib"        => "kichinan_baby_bib_sample",
        "mousepad"        => "kichinan_mousepad_sample",
        "phonecase"       => "kichinan_phonecase_sample",
        "notebook"        => "kichinan_notebook_sample",
        "puzzle"          => "kichinan_puzzle_sample",
        "pillow"          => "kichinan_pillow_sample",
        "blanket"         => "kichinan_blanket_sample",
        "pin"             => "kichinan_pin_sample",
        "magnet"          => "kichinan_magnet_sample",
        "postcard"        => "kichinan_postcard_sample",
        "poster"          => "kichinan_poster_sample",
        "canvas"          => "kichinan_canvas_sample",
        "socks"           => "kichinan_socks_sample",
        "bandana"         => "kichinan_bandana_sample",
        "kids_tote"       => "kichinan_kids_tote_sample",
        "plush"           => "kichinan_plush_sample",
        "acrylic_charm"   => "kichinan_acrylic_charm_sample",
        "kids_tee"        => "kichinan_kids_tee_sample",
        "drawstring"      => "kichinan_drawstring_sample",
        _                 => "kichinan_sample",
    }
}

/// One-size Kichinan SKU brands — size selection is hidden in the LP and
/// metadata is forced to "ONESIZE" so the webhook variant lookup uses the
/// one-size Printful variant.
fn kichinan_brand_is_onesize(brand: &str) -> bool {
    matches!(brand,
        "kichinan_cap_sample" | "kichinan_tote_sample" | "kichinan_mug_sample" |
        "kichinan_beanie_sample" | "kichinan_sticker_sample" |
        "kichinan_mousepad_sample" | "kichinan_phonecase_sample" |
        "kichinan_notebook_sample" | "kichinan_puzzle_sample" |
        "kichinan_pillow_sample" | "kichinan_blanket_sample" |
        "kichinan_pin_sample" | "kichinan_magnet_sample" |
        "kichinan_postcard_sample" | "kichinan_poster_sample" |
        "kichinan_canvas_sample" | "kichinan_socks_sample" |
        "kichinan_bandana_sample" | "kichinan_kids_tote_sample" |
        "kichinan_baby_bib_sample" |
        "kichinan_plush_sample" | "kichinan_acrylic_charm_sample" |
        "kichinan_drawstring_sample"
    )
}

/// POST /api/proposals/kichinan/sample — issues a Stripe Payment Link for
/// a real T-shirt with the chosen design + size. Fulfillment is the standard
/// MU webhook flow (checkout.session.completed → create_printful_order)
/// because we seed products with brand=kichinan_sample at startup.
async fn proposal_kichinan_sample(
    State(db): State<Db>,
    Json(body): Json<KichinanSampleBody>,
) -> Response {
    let design_lower = body.design.to_lowercase();
    let (drop_num, default_price, label, kind): (i64, i64, String, String) = {
        let conn = db.lock().unwrap();
        match conn.query_row(
            "SELECT drop_num, price_jpy, label, kind FROM proposal_skus WHERE slug='kichinan' AND letter=?",
            params![design_lower],
            |r| Ok((r.get::<_, i64>(0)?, r.get::<_, i64>(1)?,
                    r.get::<_, String>(2)?, r.get::<_, String>(3)?)),
        ) { Ok(v) => v, Err(_) => return (StatusCode::BAD_REQUEST, "unknown design id").into_response() }
    };
    let price_jpy = if (400..=12000).contains(&body.price_jpy) { body.price_jpy } else { default_price };
    let brand = kichinan_brand_for_kind(&kind);
    let size = if kichinan_brand_is_onesize(brand) {
        "ONESIZE".to_string()
    } else {
        // Kids size labels accepted: S/M/L/XL or 110/120/130/140/150.
        let s = body.size.as_deref().unwrap_or("M").to_uppercase();
        let kids_sizes = ["110","120","130","140","150"];
        if !["S","M","L","XL"].contains(&s.as_str()) && !kids_sizes.contains(&s.as_str()) {
            return (StatusCode::BAD_REQUEST, "size must be S/M/L/XL or 110-150").into_response();
        }
        s
    };
    let stripe_key = env::var("STRIPE_SECRET_KEY").unwrap_or_default();
    if stripe_key.is_empty() {
        return (StatusCode::SERVICE_UNAVAILABLE, "stripe key missing").into_response();
    }
    let product_id: i64 = {
        let conn = db.lock().unwrap();
        match conn.query_row(
            "SELECT id FROM products WHERE brand=? AND drop_num=? LIMIT 1",
            params![brand, drop_num], |r| r.get(0),
        ) {
            Ok(id) => id,
            Err(_) => return (StatusCode::SERVICE_UNAVAILABLE, "kichinan products not seeded").into_response(),
        }
    };
    let client = reqwest::Client::new();
    // ASCII-only name to avoid any Stripe form-encoding edge cases with
    // multi-byte chars (━◯━ × · …). Localized label still rides in metadata.
    // NB: /v1/prices does NOT accept product_data[images] — that's a /v1/products
    // parameter. Stripe surfaces the parameter via PaymentLink line_items later.
    let product_name = format!("MU x KICHINAN sample - {} - {} - {}",
        design_lower.to_uppercase(), label, size);
    let price_form: Vec<(&str, String)> = vec![
        ("currency", "jpy".into()),
        ("unit_amount", price_jpy.to_string()),
        ("product_data[name]", product_name),
    ];
    let raw_resp = match client.post("https://api.stripe.com/v1/prices")
        .basic_auth(&stripe_key, Some("")).form(&price_form).send().await {
        Ok(r) => {
            let status = r.status();
            let body = r.text().await.unwrap_or_default();
            if !status.is_success() {
                eprintln!("[kichinan_sample] stripe price {} → {}", status, body.chars().take(500).collect::<String>());
                return (StatusCode::BAD_GATEWAY, format!("stripe {}: {}", status, body.chars().take(300).collect::<String>())).into_response();
            }
            body
        }
        Err(e) => return (StatusCode::BAD_GATEWAY, format!("stripe price http: {}", e)).into_response(),
    };
    let price_id: String = serde_json::from_str::<serde_json::Value>(&raw_resp)
        .ok()
        .and_then(|v| v.get("id").and_then(|x| x.as_str()).map(String::from))
        .unwrap_or_default();
    if price_id.is_empty() {
        eprintln!("[kichinan_sample] stripe 200 but no id in body: {}", raw_resp.chars().take(500).collect::<String>());
        return (StatusCode::BAD_GATEWAY, "stripe returned no price id").into_response();
    }
    let pl_form: Vec<(&str, String)> = vec![
        ("line_items[0][price]", price_id),
        ("line_items[0][quantity]", "1".into()),
        ("shipping_address_collection[allowed_countries][0]", "JP".into()),
        ("allow_promotion_codes", "true".into()),
        ("after_completion[type]", "redirect".into()),
        ("after_completion[redirect][url]", "https://wearmu.com/proposals/kichinan?sample=ok".into()),
        ("metadata[kind]", "kichinan_sample".into()),
        ("metadata[design]", design_lower.clone()),
        ("metadata[size]", size.clone()),
        ("metadata[product_id]", product_id.to_string()),
        ("metadata[license_status]", "pending".into()),
        ("metadata[ip_owner]", "Kichinan Group".into()),
    ];
    match client.post("https://api.stripe.com/v1/payment_links")
        .basic_auth(&stripe_key, Some("")).form(&pl_form).send().await {
        Ok(r) => {
            let v: serde_json::Value = r.json().await.unwrap_or(serde_json::Value::Null);
            if let Some(u) = v.get("url").and_then(|x| x.as_str()) {
                return Json(serde_json::json!({
                    "ok": true, "url": u, "design": design_lower, "size": size,
                    "price_jpy": price_jpy, "product_id": product_id,
                })).into_response();
            }
            (StatusCode::BAD_GATEWAY, format!("payment_link: {}", v.to_string().chars().take(300).collect::<String>())).into_response()
        }
        Err(e) => (StatusCode::BAD_GATEWAY, format!("stripe: {}", e)).into_response(),
    }
}

// ── Kichinan approval gate ────────────────────────────────────────────────
// Workflow:
//   1. /proposals/kichinan is seeded with active=0 (proposal only). Public
//      catalog endpoints filter active=1 so no kichinan SKU is publicly
//      buyable at this stage.
//   2. After the kichinan group signs off (verbal/email OK), the admin POSTs
//      /api/proposals/kichinan/approve with ADMIN_TOKEN and the approver's
//      name + email + tier. All kichinan_* products flip to active=1 and a
//      permanent contract record lands in the `kichinan_approval` table.
//   3. The LP polls /api/proposals/kichinan/status to swap banner + button
//      copy from "proposal" to "公式販売中" and "今すぐ購入".
//   4. /api/proposals/kichinan/revoke (admin-gated) undoes the activation
//      if the agreement is later cancelled — kept reversible by design.

fn ensure_kichinan_approval_table(db: &Db) {
    let conn = db.lock().unwrap();
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS kichinan_approval (
            id            INTEGER PRIMARY KEY,
            approved_at   TEXT,
            approver_name TEXT,
            approver_email TEXT,
            approver_ip   TEXT,
            plan_tier     TEXT,
            note          TEXT,
            revoked_at    TEXT
         )",
        [],
    );
}

fn kichinan_approval_row(conn: &rusqlite::Connection) -> Option<(String, String, String, String, Option<String>)> {
    conn.query_row(
        "SELECT approved_at, approver_name, approver_email, COALESCE(plan_tier,''), revoked_at
         FROM kichinan_approval WHERE id=1 AND approved_at IS NOT NULL",
        [],
        |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?, r.get(4)?)),
    ).ok()
}

fn kichinan_is_approved(conn: &rusqlite::Connection) -> bool {
    kichinan_approval_row(conn).map(|t| t.4.is_none()).unwrap_or(false)
}

/// GET /api/proposals/kichinan/status — public. Used by the LP JS to
/// swap banner + button copy. No PII (returns first name only).
async fn proposal_kichinan_status(State(db): State<Db>) -> impl IntoResponse {
    let conn = db.lock().unwrap();
    let row = kichinan_approval_row(&conn);
    let approved = row.as_ref().map(|t| t.4.is_none()).unwrap_or(false);
    let (approved_at, approver_name, plan_tier) = match &row {
        Some((at, n, _e, p, _r)) => (
            Some(at.clone()),
            // First name only — never leak full identity on a public endpoint.
            Some(n.split_whitespace().next().unwrap_or("—").to_string()),
            Some(p.clone()),
        ),
        None => (None, None, None),
    };
    let active_count: i64 = conn.query_row(
        "SELECT COUNT(*) FROM products WHERE brand LIKE 'kichinan_%' AND active=1",
        [], |r| r.get(0),
    ).unwrap_or(0);
    Json(serde_json::json!({
        "approved": approved,
        "approved_at": approved_at,
        "approver_first_name": approver_name,
        "plan_tier": plan_tier,
        "products_active": active_count,
        "products_total": proposal_skus_for(&conn, "kichinan").len(),
    }))
}

#[derive(Deserialize)]
struct KichinanApproveBody {
    approver_name: String,
    approver_email: String,
    #[serde(default)]
    plan_tier: String, // "starter" | "growth" | "enterprise"
    #[serde(default)]
    note: String,
}

/// POST /api/proposals/kichinan/approve — admin-gated. Flips every kichinan_*
/// product to active=1 and lands a permanent approval record. Idempotent —
/// a second call updates the row in place without unsetting active=1.
async fn proposal_kichinan_approve(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(body): Json<KichinanApproveBody>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/api/proposals/kichinan/approve").await {
        return r;
    }
    let name = body.approver_name.trim();
    let email = body.approver_email.trim().to_lowercase();
    if name.is_empty() || !email.contains('@') {
        return (StatusCode::BAD_REQUEST, "approver_name + valid approver_email required").into_response();
    }
    let plan = match body.plan_tier.trim().to_lowercase().as_str() {
        "starter" | "growth" | "enterprise" => body.plan_tier.trim().to_lowercase(),
        _ => "starter".into(),
    };
    let ip = client_ip(&headers);
    let now = chrono_now();
    let (activated, products_total): (usize, usize) = {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "INSERT INTO kichinan_approval
                (id, approved_at, approver_name, approver_email, approver_ip, plan_tier, note, revoked_at)
             VALUES (1, ?, ?, ?, ?, ?, ?, NULL)
             ON CONFLICT(id) DO UPDATE SET
                approved_at=excluded.approved_at,
                approver_name=excluded.approver_name,
                approver_email=excluded.approver_email,
                approver_ip=excluded.approver_ip,
                plan_tier=excluded.plan_tier,
                note=excluded.note,
                revoked_at=NULL",
            params![now, name, email, ip, plan, body.note.trim()],
        );
        let act = conn.execute(
            "UPDATE products SET active=1 WHERE brand LIKE 'kichinan_%' AND active=0",
            [],
        ).unwrap_or(0);
        let tot = proposal_skus_for(&conn, "kichinan").len();
        (act, tot)
    };
    eprintln!("[kichinan] approved by {} <{}> plan={} activated_rows={}", name, email, plan, activated);
    let alert = format!(
        "━◯━ kichinan collab APPROVED\n\
         approver: {} <{}>\n\
         plan: {}\n\
         products activated: {}/{}\n\
         at: {}\n\
         next: 全 SKU が公式販売中 (https://wearmu.com/proposals/kichinan)",
        name, email, plan, activated, products_total, now,
    );
    tokio::spawn(async move { send_telegram_message(&alert).await; });
    Json(serde_json::json!({
        "ok": true,
        "approved_at": now,
        "products_activated": activated,
        "products_total": products_total,
        "plan_tier": plan,
    })).into_response()
}

/// POST /api/proposals/kichinan/revoke — admin-gated. Sets revoked_at and
/// flips active=0 on every kichinan_* product so the LP reverts to proposal
/// mode and the catalog hides them.
async fn proposal_kichinan_revoke(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/api/proposals/kichinan/revoke").await {
        return r;
    }
    let now = chrono_now();
    let deactivated: usize = {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "UPDATE kichinan_approval SET revoked_at=? WHERE id=1",
            params![now],
        );
        conn.execute(
            "UPDATE products SET active=0 WHERE brand LIKE 'kichinan_%' AND active=1",
            [],
        ).unwrap_or(0)
    };
    eprintln!("[kichinan] revoked at {} products_deactivated={}", now, deactivated);
    Json(serde_json::json!({
        "ok": true, "revoked_at": now, "products_deactivated": deactivated,
    })).into_response()
}

// ── Asoview approval gate ─────────────────────────────────────────────────
// Parallel to the kichinan flow but for アソビュー株式会社 (山野智久 CEO,
// 体験予約 platform). Once approved, https://wearmu.com/asoview becomes a
// public LP — until then /asoview 404s. The proposal LP at /proposals/asoview
// is always reachable for internal review + approval form.

