fn proposal_brand_for_kind(slug_prefix: &str, kind: &str) -> String {
    // Mirrors kichinan_brand_for_kind but parametrized on slug.
    // Any "<kind>" here must also exist in the create_printful_order match.
    // Kichinan has its own historical naming (tee → kichinan_sample, not
    // kichinan_tee_sample), so delegate to its dedicated mapper for that slug.
    if slug_prefix == "kichinan" {
        return kichinan_brand_for_kind(kind).to_string();
    }
    match kind {
        "tee"            => format!("{}_tee_sample",            slug_prefix),
        "polo"           => format!("{}_polo_sample",           slug_prefix),
        "cap"            => format!("{}_cap_sample",            slug_prefix),
        "dad_hat"        => format!("{}_dad_hat_sample",        slug_prefix),
        "bucket_hat"     => format!("{}_bucket_hat_sample",     slug_prefix),
        "tote"           => format!("{}_tote_sample",           slug_prefix),
        "hoodie"         => format!("{}_hoodie_sample",         slug_prefix),
        "mug"            => format!("{}_mug_sample",            slug_prefix),
        "beanie"         => format!("{}_beanie_sample",         slug_prefix),
        "longsleeve"     => format!("{}_longsleeve_sample",     slug_prefix),
        "sticker"        => format!("{}_sticker_sample",        slug_prefix),
        "kids_tee"       => format!("{}_kids_tee_sample",       slug_prefix),
        "pin"            => format!("{}_pin_sample",            slug_prefix),
        "pillow"         => format!("{}_pillow_sample",         slug_prefix),
        "drawstring"     => format!("{}_drawstring_sample",     slug_prefix),
        "socks"          => format!("{}_socks_sample",          slug_prefix),
        // mode-Y3 / BJJ extensions (NOJIMAHAL)
        "rashguard_ls"   => format!("{}_rashguard_ls_sample",   slug_prefix),
        "athletic_tee"   => format!("{}_athletic_tee_sample",   slug_prefix),
        "fight_shorts"   => format!("{}_fight_shorts_sample",   slug_prefix),
        "spats"          => format!("{}_spats_sample",          slug_prefix),
        "bomber_jacket"  => format!("{}_bomber_jacket_sample",  slug_prefix),
        "windbreaker"    => format!("{}_windbreaker_sample",    slug_prefix),
        "track_pants"    => format!("{}_track_pants_sample",    slug_prefix),
        "sweatpants"     => format!("{}_sweatpants_sample",     slug_prefix),
        "crewneck"       => format!("{}_crewneck_sample",       slug_prefix),
        // RYOZO TOP TEAM additions
        "joggers"        => format!("{}_joggers_sample",        slug_prefix),
        "zip_hoodie"     => format!("{}_zip_hoodie_sample",     slug_prefix),
        "quarter_zip"    => format!("{}_quarter_zip_sample",    slug_prefix),
        "water_bottle"   => format!("{}_water_bottle_sample",   slug_prefix),
        "beach_towel"    => format!("{}_beach_towel_sample",    slug_prefix),
        "patch"          => format!("{}_patch_sample",          slug_prefix),
        "apron"          => format!("{}_apron_sample",          slug_prefix),
        "tank_top"       => format!("{}_tank_top_sample",       slug_prefix),
        "crossbody"      => format!("{}_crossbody_sample",      slug_prefix),
        "mug_team"       => format!("{}_mug_team_sample",       slug_prefix),
        // Spectator / cheering kit
        "bandana"        => format!("{}_bandana_sample",        slug_prefix),
        "fan"            => format!("{}_fan_sample",            slug_prefix),
        "wristband"      => format!("{}_wristband_sample",      slug_prefix),
        "lanyard"        => format!("{}_lanyard_sample",        slug_prefix),
        "flag"           => format!("{}_flag_sample",           slug_prefix),
        // Lifestyle / desk / wall / home (added so atsume etc. land on the
        // right brand row instead of the _tee_sample catch-all).
        "magnet"         => format!("{}_magnet_sample",         slug_prefix),
        "postcard"       => format!("{}_postcard_sample",       slug_prefix),
        "notebook"       => format!("{}_notebook_sample",       slug_prefix),
        "mousepad"       => format!("{}_mousepad_sample",       slug_prefix),
        "phonecase"      => format!("{}_phonecase_sample",      slug_prefix),
        "poster"         => format!("{}_poster_sample",         slug_prefix),
        "canvas"         => format!("{}_canvas_sample",         slug_prefix),
        "blanket"        => format!("{}_blanket_sample",        slug_prefix),
        "kids_hoodie"    => format!("{}_kids_hoodie_sample",    slug_prefix),
        "kids_longsleeve"=> format!("{}_kids_longsleeve_sample",slug_prefix),
        "kids_sweat"     => format!("{}_kids_sweat_sample",     slug_prefix),
        "kids_tote"      => format!("{}_kids_tote_sample",      slug_prefix),
        "baby_onesie"    => format!("{}_baby_onesie_sample",    slug_prefix),
        "baby_bib"       => format!("{}_baby_bib_sample",       slug_prefix),
        "plush"          => format!("{}_plush_sample",          slug_prefix),
        "acrylic_charm"  => format!("{}_acrylic_charm_sample",  slug_prefix),
        "puzzle"         => format!("{}_puzzle_sample",         slug_prefix),
        _                => format!("{}_{}_sample",             slug_prefix, kind),
    }
}

fn proposal_brand_is_onesize(brand: &str) -> bool {
    brand.ends_with("_cap_sample") || brand.ends_with("_tote_sample")
        || brand.ends_with("_mug_sample") || brand.ends_with("_beanie_sample")
        || brand.ends_with("_sticker_sample") || brand.ends_with("_pin_sample")
        || brand.ends_with("_pillow_sample")
        || brand.ends_with("_dad_hat_sample") || brand.ends_with("_bucket_hat_sample")
        || brand.ends_with("_drawstring_sample") || brand.ends_with("_socks_sample")
        || brand.ends_with("_water_bottle_sample") || brand.ends_with("_beach_towel_sample")
        || brand.ends_with("_patch_sample") || brand.ends_with("_apron_sample")
        || brand.ends_with("_crossbody_sample") || brand.ends_with("_mug_team_sample")
        // Spectator kit (one-size all)
        || brand.ends_with("_bandana_sample") || brand.ends_with("_fan_sample")
        || brand.ends_with("_wristband_sample") || brand.ends_with("_lanyard_sample")
        || brand.ends_with("_flag_sample")
}

#[derive(Deserialize)]
struct ProposalSampleBody {
    design: String,
    size: Option<String>,
    price_jpy: i64,
}

async fn issue_proposal_sample_link(
    db: Db, slug_prefix: &str,
    body: ProposalSampleBody,
) -> Response {
    let design_lower = body.design.to_lowercase();
    let (drop_num, default_price, label, kind): (i64, i64, String, String) = {
        let conn = db.lock().unwrap();
        match conn.query_row(
            "SELECT drop_num, price_jpy, label, kind FROM proposal_skus WHERE slug=? AND letter=?",
            params![slug_prefix, design_lower],
            |r| Ok((r.get::<_, i64>(0)?, r.get::<_, i64>(1)?,
                    r.get::<_, String>(2)?, r.get::<_, String>(3)?)),
        ) { Ok(v) => v, Err(_) => return (StatusCode::BAD_REQUEST, "unknown design id").into_response() }
    };
    let price_jpy = if (400..=12000).contains(&body.price_jpy) { body.price_jpy } else { default_price };
    let brand = proposal_brand_for_kind(slug_prefix, &kind);
    let size = if proposal_brand_is_onesize(&brand) {
        "ONESIZE".to_string()
    } else {
        let s = body.size.as_deref().unwrap_or("M").to_uppercase();
        let kids = ["110","120","130","140","150"];
        if !["S","M","L","XL"].contains(&s.as_str()) && !kids.contains(&s.as_str()) {
            return (StatusCode::BAD_REQUEST, "size must be S/M/L/XL or 110-150").into_response();
        }
        s
    };
    let stripe_key = env::var("STRIPE_SECRET_KEY").unwrap_or_default();
    if stripe_key.is_empty() { return (StatusCode::SERVICE_UNAVAILABLE, "stripe key missing").into_response(); }
    let product_id: i64 = {
        let conn = db.lock().unwrap();
        match conn.query_row(
            "SELECT id FROM products WHERE brand=? AND drop_num=? LIMIT 1",
            params![brand, drop_num], |r| r.get(0),
        ) { Ok(id) => id, Err(_) => return (StatusCode::SERVICE_UNAVAILABLE, "products not seeded").into_response() }
    };
    let client = reqwest::Client::new();
    let product_name = format!("MU x {} - {} - {} - {}",
        slug_prefix.to_uppercase(), design_lower.to_uppercase(), label, size);
    let price_form: Vec<(&str, String)> = vec![
        ("currency", "jpy".into()),
        ("unit_amount", price_jpy.to_string()),
        ("product_data[name]", product_name),
    ];
    let raw_resp = match client.post("https://api.stripe.com/v1/prices")
        .basic_auth(&stripe_key, Some("")).form(&price_form).send().await {
        Ok(r) => {
            let status = r.status();
            let body = r.text().await.unwrap_or_default();
            if !status.is_success() {
                eprintln!("[{}_sample] stripe price {} → {}", slug_prefix, status, body.chars().take(500).collect::<String>());
                return (StatusCode::BAD_GATEWAY, format!("stripe {}: {}", status, body.chars().take(300).collect::<String>())).into_response();
            }
            body
        }
        Err(e) => return (StatusCode::BAD_GATEWAY, format!("stripe price http: {}", e)).into_response(),
    };
    let price_id: String = serde_json::from_str::<serde_json::Value>(&raw_resp)
        .ok().and_then(|v| v.get("id").and_then(|x| x.as_str()).map(String::from)).unwrap_or_default();
    if price_id.is_empty() { return (StatusCode::BAD_GATEWAY, "stripe returned no price id").into_response(); }
    let redirect_url = format!("https://wearmu.com/{}?sample=ok", slug_prefix);
    let pl_form: Vec<(&str, String)> = vec![
        ("line_items[0][price]", price_id),
        ("line_items[0][quantity]", "1".into()),
        ("shipping_address_collection[allowed_countries][0]", "JP".into()),
        ("allow_promotion_codes", "true".into()),
        ("after_completion[type]", "redirect".into()),
        ("after_completion[redirect][url]", redirect_url),
        ("metadata[kind]", format!("{}_sample", slug_prefix)),
        ("metadata[design]", design_lower.clone()),
        ("metadata[size]", size.clone()),
        ("metadata[product_id]", product_id.to_string()),
    ];
    match client.post("https://api.stripe.com/v1/payment_links")
        .basic_auth(&stripe_key, Some("")).form(&pl_form).send().await {
        Ok(r) => {
            let v: serde_json::Value = r.json().await.unwrap_or(serde_json::Value::Null);
            if let Some(u) = v.get("url").and_then(|x| x.as_str()) {
                Json(serde_json::json!({
                    "ok": true, "url": u, "design": design_lower, "size": size,
                    "price_jpy": price_jpy, "product_id": product_id,
                })).into_response()
            } else {
                (StatusCode::BAD_GATEWAY, format!("payment_link: {}", v.to_string().chars().take(300).collect::<String>())).into_response()
            }
        }
        Err(e) => (StatusCode::BAD_GATEWAY, format!("stripe: {}", e)).into_response(),
    }
}

