fn gate_collab_login_prompt() -> Response {
    let extra = r#"
      .wrap{max-width:460px;margin:0 auto;padding:60px 22px;text-align:center}
      .kicker{font-size:10.5px;letter-spacing:.22em;color:#666;text-transform:uppercase;margin-bottom:14px}
      h1{font-size:28px;font-weight:300;margin:0 0 12px;color:#fff}
      p{color:#999;font-size:14px;line-height:1.8;margin:0 0 22px}
      input{width:100%;background:#000;border:1px solid #242424;color:#fff;padding:13px;border-radius:4px;font-size:15px;box-sizing:border-box;margin-bottom:12px}
      button{width:100%;background:#e6c449;color:#000;border:0;padding:13px;font-weight:600;border-radius:4px;cursor:pointer}
      .msg{font-size:13px;color:#9bd97a;margin-top:14px;min-height:18px}
    "#;
    let inner = r#"<div class="wrap">
    <div class="kicker">PARTNER LOGIN</div>
    <h1>パートナーログイン</h1>
    <p>ホルダー限定ゲートを作るにはログインが必要です。メールアドレスにログインリンクをお送りします。</p>
    <input type="email" id="le" placeholder="you@example.com" autocomplete="email">
    <button onclick="startLogin()">ログインリンクを送る</button>
    <div id="lmsg" class="msg"></div>
    <script>
    async function startLogin(){
      const e=document.getElementById('le').value.trim(); const m=document.getElementById('lmsg');
      if(!e){m.style.color='#e07b7b';m.textContent='メールを入力してください';return;}
      m.style.color='#9a9a90'; m.textContent='送信中…';
      const r=await fetch('/api/collab/auth/start',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({email:e})});
      if(r.ok){m.style.color='#9bd97a';m.textContent='メールのリンクを開いてから、このページを再読み込みしてください。';}
      else{m.style.color='#e07b7b';m.textContent='エラーが発生しました。';}
    }
    </script>
  </div>"#;
    gate_page_shell("パートナーログイン · GATE · MU", false, None, extra, inner)
}

/// GET /collab/gates — partner self-serve management (create + edit own gates).
async fn collab_gates_page(State(db): State<Db>, headers: HeaderMap) -> Response {
    let email = match collab_session_email(&db, &headers) {
        Some(s) => s.0,
        None => return gate_collab_login_prompt(),
    };
    let masked = mask_email_public(&email);

    let gates: Vec<GateRow> = {
        let conn = db.lock().unwrap();
        let mut stmt = match conn.prepare(
            "SELECT slug, owner_email, title, teaser, body_md, approved_at, revoked_at, view_count, unlock_count
             FROM holder_gates WHERE owner_email=? ORDER BY created_at DESC"
        ) { Ok(s) => s, Err(_) => return (StatusCode::INTERNAL_SERVER_ERROR, "db error").into_response() };
        let it = stmt.query_map(params![email], |r| Ok(GateRow {
            slug: r.get(0)?, owner_email: r.get(1)?, title: r.get(2)?, teaser: r.get(3)?,
            body_md: r.get(4)?, approved_at: r.get(5)?, revoked_at: r.get(6)?,
            view_count: r.get(7)?, unlock_count: r.get(8)?,
        }));
        match it { Ok(rows) => rows.filter_map(|x| x.ok()).collect(), Err(_) => Vec::new() }
    };

    let mut rows_html = String::new();
    if gates.is_empty() {
        rows_html.push_str(r#"<div class="panel" style="color:#777;font-size:13px">まだゲートがありません。上のフォームから作成してください。</div>"#);
    }
    for g in &gates {
        let badge = if g.revoked_at.is_some() { r#"<span class="badge rev">停止中</span>"# }
            else if g.approved_at.is_some() { r#"<span class="badge live">公開中</span>"# }
            else { r#"<span class="badge pend">承認待ち</span>"# };
        rows_html.push_str(&format!(r#"<div class="panel gate" data-slug="{slug_attr}">
<div class="ghead"><a href="/gate/{slug}" target="_blank">/gate/{slug}</a> {badge}<span class="stat">{views} 表示 · {unlocks} 開封</span></div>
<label>タイトル<input class="e_title" value="{title}"></label>
<label>ティザー（公開）<textarea class="e_teaser" rows="2">{teaser}</textarea></label>
<label>本文（ホルダー限定）<textarea class="e_body" rows="6">{body}</textarea></label>
<button onclick="saveGate(this)">保存（再承認が必要）</button><div class="msg emsg"></div></div>"#,
            slug_attr = html_attr_escape(&g.slug),
            slug = html_escape(&g.slug),
            badge = badge,
            views = g.view_count,
            unlocks = g.unlock_count,
            title = html_attr_escape(&g.title),
            teaser = html_escape(&g.teaser),
            body = html_escape(&g.body_md)));
    }

    let mut inner = String::new();
    inner.push_str(r#"<div class="wrap"><div class="kicker">PARTNER · MU HOLDER GATE</div><h1>ホルダー限定ゲート</h1>"#);
    inner.push_str(&format!(r#"<p class="intro">本文は <strong>MU を買ったホルダー</strong>だけに表示されます。作成後、運営の承認で公開されます。ログイン中: {}</p>"#, html_escape(&masked)));
    inner.push_str(r#"<div class="panel"><h2>新規ゲートを作る</h2>
<label>URL slug（半角英数・ハイフン, 2〜64文字）<input id="c_slug" placeholder="atsume-secret"></label>
<label>タイトル<input id="c_title" placeholder="ATSUME × MU 特典"></label>
<label>ティザー（公開・Markdown可）<textarea id="c_teaser" rows="3" placeholder="誰でも見える紹介文"></textarea></label>
<label>本文（ホルダー限定・Markdown）<textarea id="c_body" rows="8" placeholder="限定Discord招待や特典など"></textarea></label>
<button onclick="createGate()">作成する</button><div id="c_msg" class="msg"></div></div>
<h2>あなたのゲート</h2>"#);
    inner.push_str(&rows_html);
    inner.push_str(GATE_MGMT_JS);
    inner.push_str("</div>");

    gate_page_shell("ホルダー限定ゲート · MU", false, Some(&masked), GATE_MGMT_CSS, &inner)
}

#[derive(Deserialize)]
struct GateCreateBody { slug: String, title: String, #[serde(default)] teaser: String, #[serde(default)] body_md: String }

/// POST /api/collab/gates — create a gate owned by the verified partner.
async fn collab_gate_create(State(db): State<Db>, headers: HeaderMap, Json(body): Json<GateCreateBody>) -> Response {
    let email = match collab_session_email(&db, &headers) {
        Some(s) => s.0,
        None => return (StatusCode::UNAUTHORIZED, Json(serde_json::json!({
            "error": "verify email first", "verify_endpoint": "/api/collab/auth/start"
        }))).into_response(),
    };
    let slug = match gate_slugify(&body.slug) {
        Some(s) => s,
        None => return (StatusCode::BAD_REQUEST, Json(serde_json::json!({
            "error": "invalid slug — 2〜64 chars of a-z 0-9 -, starting alnum"
        }))).into_response(),
    };
    let title = body.title.trim().to_string();
    if title.is_empty() {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"error": "title required"}))).into_response();
    }
    let now = chrono_now();
    let outcome: Result<(), (StatusCode, &'static str)> = {
        let conn = db.lock().unwrap();
        if gate_row(&conn, &slug).is_some() {
            Err((StatusCode::CONFLICT, "slug already taken"))
        } else {
            conn.execute(
                "INSERT INTO holder_gates (slug, owner_email, title, teaser, body_md, criterion, approved_at, revoked_at, created_at, updated_at)
                 VALUES (?,?,?,?,?, 'mu_holder', NULL, NULL, ?, ?)",
                params![slug, email, title, body.teaser.trim(), body.body_md, now, now],
            ).map(|_| ()).map_err(|_| (StatusCode::INTERNAL_SERVER_ERROR, "db error"))
        }
    };
    match outcome {
        Ok(()) => {
            let gate_url = format!("/gate/{}", slug);
            Json(serde_json::json!({"ok": true, "slug": slug, "gate_url": gate_url, "manage_url": "/collab/gates"})).into_response()
        }
        Err((code, msg)) => (code, Json(serde_json::json!({"error": msg}))).into_response(),
    }
}

#[derive(Deserialize)]
struct GateUpdateBody { title: String, #[serde(default)] teaser: String, #[serde(default)] body_md: String }

/// POST /api/collab/gates/:slug — edit own gate. Editing content resets the
/// approval (approved_at=NULL) so the owner can't swap content post-approval.
async fn collab_gate_update(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Path(slug): axum::extract::Path<String>,
    Json(body): Json<GateUpdateBody>,
) -> Response {
    let email = match collab_session_email(&db, &headers) {
        Some(s) => s.0,
        None => return (StatusCode::UNAUTHORIZED, Json(serde_json::json!({
            "error": "verify email first", "verify_endpoint": "/api/collab/auth/start"
        }))).into_response(),
    };
    let slug = slug.to_lowercase();
    let title = body.title.trim().to_string();
    if title.is_empty() {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"error": "title required"}))).into_response();
    }
    let now = chrono_now();
    let n = {
        let conn = db.lock().unwrap();
        conn.execute(
            "UPDATE holder_gates SET title=?, teaser=?, body_md=?, approved_at=NULL, updated_at=?
             WHERE slug=? AND owner_email=?",
            params![title, body.teaser.trim(), body.body_md, now, slug, email],
        ).unwrap_or(0)
    };
    if n == 0 {
        return (StatusCode::NOT_FOUND, Json(serde_json::json!({"error": "gate not found or not yours"}))).into_response();
    }
    Json(serde_json::json!({"ok": true, "slug": slug, "note": "編集したので再承認が必要です", "gate_url": format!("/gate/{}", slug)})).into_response()
}

#[derive(Deserialize)]
struct GateApproveBody { #[serde(default)] #[allow(dead_code)] note: String }

/// POST /api/gate/:slug/approve — admin-gated. Mirrors proposal approve.
async fn gate_approve(
    State(db): State<Db>,
    axum::extract::Path(slug): axum::extract::Path<String>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(_body): Json<GateApproveBody>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), &format!("/api/gate/{}/approve", slug)).await { return r; }
    let slug = slug.to_lowercase();
    let now = chrono_now();
    let info = {
        let conn = db.lock().unwrap();
        match gate_row(&conn, &slug) {
            None => None,
            Some(g) => {
                let _ = conn.execute(
                    "UPDATE holder_gates SET approved_at=?, revoked_at=NULL, updated_at=? WHERE slug=?",
                    params![now, now, slug],
                );
                Some((g.owner_email, g.title))
            }
        }
    };
    let (owner, title) = match info {
        Some(x) => x,
        None => return (StatusCode::NOT_FOUND, "unknown gate slug").into_response(),
    };
    let alert = format!(
        "━◯━ gate {} APPROVED\ntitle: {}\nowner: {}\nat: {}\n→ https://wearmu.com/gate/{}",
        slug, title, owner, now, slug,
    );
    tokio::spawn(async move { send_telegram_message(&alert).await; });
    Json(serde_json::json!({"ok": true, "slug": slug, "approved_at": now})).into_response()
}

/// POST /api/gate/:slug/revoke — admin-gated. Mirrors proposal revoke.
async fn gate_revoke(
    State(db): State<Db>,
    axum::extract::Path(slug): axum::extract::Path<String>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), &format!("/api/gate/{}/revoke", slug)).await { return r; }
    let slug = slug.to_lowercase();
    let now = chrono_now();
    let found = {
        let conn = db.lock().unwrap();
        if gate_row(&conn, &slug).is_none() {
            false
        } else {
            let _ = conn.execute(
                "UPDATE holder_gates SET revoked_at=?, updated_at=? WHERE slug=?",
                params![now, now, slug],
            );
            true
        }
    };
    if !found {
        return (StatusCode::NOT_FOUND, "unknown gate slug").into_response();
    }
    Json(serde_json::json!({"ok": true, "slug": slug, "revoked_at": now})).into_response()
}

fn ensure_proposal_tables(db: &Db) {
    let conn = db.lock().unwrap();
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS proposals (
            slug TEXT PRIMARY KEY,
            name TEXT NOT NULL,
            ip_owner TEXT NOT NULL,
            approved_at TEXT,
            approver_name TEXT,
            approver_email TEXT,
            approver_ip TEXT,
            plan_tier TEXT,
            note TEXT,
            revoked_at TEXT,
            created_at TEXT NOT NULL,
            meta_json TEXT,
            owner_email TEXT
         )", [],
    );
    // Backfill for older volumes.
    let _ = conn.execute("ALTER TABLE proposals ADD COLUMN meta_json TEXT", []);
    let _ = conn.execute("ALTER TABLE proposals ADD COLUMN owner_email TEXT", []);
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS proposal_skus (
            slug TEXT NOT NULL,
            letter TEXT NOT NULL,
            drop_num INTEGER NOT NULL,
            price_jpy INTEGER NOT NULL,
            label TEXT NOT NULL,
            kind TEXT NOT NULL,
            design_slug TEXT NOT NULL,
            design_url TEXT,
            published INTEGER NOT NULL DEFAULT 1,
            PRIMARY KEY (slug, letter)
         )", [],
    );
    // Backfill `published` for volumes created before this column existed.
    let _ = conn.execute("ALTER TABLE proposal_skus ADD COLUMN published INTEGER NOT NULL DEFAULT 1", []);
    // Admin user roster — supplemental to the global ADMIN_TOKEN, lets the
    // owner add/remove named operators without rotating the master token.
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS admin_users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email TEXT NOT NULL UNIQUE,
            name TEXT,
            role TEXT NOT NULL DEFAULT 'admin',
            active INTEGER NOT NULL DEFAULT 1,
            created_at TEXT NOT NULL,
            created_by TEXT
         )", [],
    );
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS proposal_feedback (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            slug TEXT NOT NULL,
            design_letter TEXT NOT NULL,
            action TEXT NOT NULL,           -- 'like' | 'dislike' | 'comment'
            comment TEXT,
            voter_email TEXT,
            voter_ip TEXT,
            voter_pseudonym TEXT,           -- anonymous device hash for rate-limit
            created_at TEXT NOT NULL
         )", [],
    );
    let _ = conn.execute("CREATE INDEX IF NOT EXISTS idx_proposal_feedback_slug ON proposal_feedback(slug, created_at DESC)", []);

    // ── Proposal Extras (Points + AI SKU generation) ─────────────────────
    // Email-keyed points wallet. Earned via MUGEN-tee purchase (+1000 pt)
    // and sample purchases (+10% of yen amount). Spent on /api/proposal/:slug
    // /extras/order to AI-generate N extra SKUs (10 pt per SKU). First 30
    // SKUs are free *once per email* (free_30_used=1 after first claim).
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS proposal_points (
            email                 TEXT PRIMARY KEY,
            balance               INTEGER NOT NULL DEFAULT 0,
            free_30_used          INTEGER NOT NULL DEFAULT 0,
            updated_at            TEXT NOT NULL,
            -- Inactivity reminder bookkeeping. Points themselves NEVER
            -- expire (deliberate B2B trust choice). We just nudge wallets
            -- that have been idle for 90+ days with a non-pushy email.
            last_activity_at      TEXT,
            last_reminder_sent_at TEXT
         )", [],
    );
    let _ = conn.execute("ALTER TABLE proposal_points ADD COLUMN last_activity_at TEXT", []);
    let _ = conn.execute("ALTER TABLE proposal_points ADD COLUMN last_reminder_sent_at TEXT", []);
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS proposal_point_events (
            id          INTEGER PRIMARY KEY AUTOINCREMENT,
            email       TEXT NOT NULL,
            delta       INTEGER NOT NULL,        -- positive=credit, negative=charge
            reason      TEXT NOT NULL,           -- 'sample_back'|'mugen_claim'|'extras_order'|'extras_refund'|'admin_grant'
            ref         TEXT,                    -- order id / job id / partner slug / etc.
            slug        TEXT,                    -- partner slug if applicable
            balance_after INTEGER NOT NULL,
            created_at  TEXT NOT NULL
         )", [],
    );
    let _ = conn.execute("CREATE INDEX IF NOT EXISTS idx_point_events_email ON proposal_point_events(email, created_at DESC)", []);
    // pt_gate unlocks (universal "もっと見るには30pt" pattern).
    // Persists which (email, target) pairs have spent points to unlock a content gate
    // so revisits stay unlocked without re-charging.
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS proposal_points_unlocks (
            email       TEXT NOT NULL,
            target      TEXT NOT NULL,           -- gate id, e.g. 'kokon:section-2', 'jiuflow:deep-dive'
            cost        INTEGER NOT NULL,
            free_used   INTEGER NOT NULL DEFAULT 0,
            created_at  TEXT NOT NULL,
            PRIMARY KEY (email, target)
         )", [],
    );
    let _ = conn.execute("CREATE INDEX IF NOT EXISTS idx_points_unlocks_email ON proposal_points_unlocks(email, created_at DESC)", []);

    // MU Pass — every T-shirt sold = one membership pass.
    // edition is a globally monotonic number (#001, #002, …) assigned in
    // chronological purchase order. mint_status tracks on-chain state without
    // blocking the visible "you are a member" UX: a pass is valid the moment
    // the row exists, even if the Solana mint is still pending.
    //   mint_status: 'pending' | 'minting' | 'minted' | 'failed' | 'skipped'
    //   claimed_wallet: NULL until holder claims/exports to their own wallet.
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS mu_passes (
            id              INTEGER PRIMARY KEY AUTOINCREMENT,
            edition         INTEGER NOT NULL UNIQUE,
            email           TEXT NOT NULL,
            brand           TEXT NOT NULL,          -- 'mugen' | 'muon' | 'ma' | 'jiufight' | …
            sku_id          TEXT,                   -- printful/suzuri sku reference
            order_ref       TEXT,                   -- stripe checkout session id or printful order id
            mint_status     TEXT NOT NULL DEFAULT 'pending',
            mint_tx         TEXT,                   -- Solana tx signature once minted
            mint_asset      TEXT,                   -- cNFT asset id (Metaplex Core)
            claimed_wallet  TEXT,                   -- holder's own wallet after export
            transferred_at  TEXT,                   -- if non-null, residual revshare cutoff = + 90d
            created_at      TEXT NOT NULL
         )", [],
    );
    let _ = conn.execute("CREATE INDEX IF NOT EXISTS idx_mu_passes_email ON mu_passes(email, edition)", []);
    let _ = conn.execute("CREATE INDEX IF NOT EXISTS idx_mu_passes_status ON mu_passes(mint_status, created_at)", []);

    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS proposal_extras_jobs (
            id           INTEGER PRIMARY KEY AUTOINCREMENT,
            slug         TEXT NOT NULL,
            email        TEXT NOT NULL,
            qty          INTEGER NOT NULL,
            free_applied INTEGER NOT NULL DEFAULT 0,
            points_charged INTEGER NOT NULL DEFAULT 0,
            status       TEXT NOT NULL DEFAULT 'pending', -- 'pending'|'processing'|'cancelling'|'cancelled'|'completed'|'partial'|'failed'
            done_count   INTEGER NOT NULL DEFAULT 0,
            last_error   TEXT,
            notify_email INTEGER NOT NULL DEFAULT 0,
            created_at   TEXT NOT NULL,
            started_at   TEXT,
            completed_at TEXT
         )", [],
    );
    // ALTER for already-deployed jobs table — ignored when column exists.
    let _ = conn.execute("ALTER TABLE proposal_extras_jobs ADD COLUMN notify_email INTEGER NOT NULL DEFAULT 0", []);
    let _ = conn.execute("CREATE INDEX IF NOT EXISTS idx_extras_jobs_status ON proposal_extras_jobs(status, created_at)", []);
    let _ = conn.execute("CREATE INDEX IF NOT EXISTS idx_extras_jobs_slug   ON proposal_extras_jobs(slug, created_at DESC)", []);
    // Each generated SKU lives here. Mirrored to proposal_skus so it shows
    // on the LP; this table is the canonical record for the extras workflow
    // (audit + display order + image URL).
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS proposal_extras_skus (
            id         INTEGER PRIMARY KEY AUTOINCREMENT,
            job_id     INTEGER NOT NULL,
            slug       TEXT NOT NULL,
            letter     TEXT NOT NULL,        -- e.g. 'x031', 'x032' (proposal_skus PK piece)
            label      TEXT NOT NULL,
            kind       TEXT NOT NULL,        -- 'tee'|'hoodie'|'cap'|...
            price_jpy  INTEGER NOT NULL,
            image_url  TEXT,
            prompt     TEXT,
            -- Approval gate: every generated SKU is 'pending' until the
            -- partner reviews it. Only 'approved' rows are mirrored into
            -- proposal_skus so we never publish an unreviewed AI image on
            -- the partner's LP.
            approval_status TEXT NOT NULL DEFAULT 'pending', -- 'pending'|'approved'|'rejected'
            reviewed_at TEXT,
            created_at TEXT NOT NULL
         )", [],
    );
    let _ = conn.execute("CREATE INDEX IF NOT EXISTS idx_extras_skus_job ON proposal_extras_skus(job_id)", []);
    let _ = conn.execute("CREATE INDEX IF NOT EXISTS idx_extras_skus_approval ON proposal_extras_skus(slug, approval_status)", []);
    // ALTER for already-deployed tables — ignored when columns exist.
    let _ = conn.execute("ALTER TABLE proposal_extras_skus ADD COLUMN approval_status TEXT NOT NULL DEFAULT 'pending'", []);
    let _ = conn.execute("ALTER TABLE proposal_extras_skus ADD COLUMN reviewed_at TEXT", []);
    // Prevent double-claim of the same MUGEN purchase.
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS proposal_mugen_claims (
            mu_purchase_id INTEGER PRIMARY KEY,
            email          TEXT NOT NULL,
            slug           TEXT,
            points_added   INTEGER NOT NULL,
            claimed_at     TEXT NOT NULL
         )", [],
    );
    let _ = conn.execute("CREATE INDEX IF NOT EXISTS idx_mugen_claims_email ON proposal_mugen_claims(email)", []);

    // ── NL → product instant-preview jobs ─────────────────────────────────
    // POST /api/admin/create/start INSERTs a row, scripts/nl_product_creator.py
    // updates status from `parsing` → `preview_ready` → `generating` → `done`.
    // GET /api/admin/create/status/<id> returns the row. UI polls at 1s.
    let _ = conn.execute(
        "CREATE TABLE IF NOT EXISTS nl_jobs (
            id          TEXT PRIMARY KEY,
            status      TEXT NOT NULL,
            text        TEXT NOT NULL,
            spec_json   TEXT,
            preview_url TEXT,
            mockup_url  TEXT,
            design_url  TEXT,
            product_id  INTEGER,
            error       TEXT,
            created_at  TEXT NOT NULL,
            updated_at  TEXT NOT NULL
         )", [],
    );
    let _ = conn.execute(
        "CREATE INDEX IF NOT EXISTS idx_nl_jobs_status ON nl_jobs(status, created_at DESC)", [],
    );
}

// ── Points wallet helpers ────────────────────────────────────────────────
// All operations are best-effort; failures are logged and silently swallowed
// because the points economy is non-financial (no money refund obligation).

/// 1 pt = ¥1 throughout. 1 SKU generation costs EXTRAS_POINTS_PER_SKU pt.
/// Sized to signal premium output (vs ¥10 = "AI slop" perception). With
/// Gemini cost ~¥6/image, ¥30 leaves comfortable margin for the OS work
/// (brand-spec prompts, R2 hosting, approve gate, Stripe wiring).
const EXTRAS_POINTS_PER_SKU: i64 = 30;
/// First 30 SKUs are free per email (consumed only on full 30/30 success).
const EXTRAS_FREE_SKUS: i64 = 30;
/// MUGEN tee purchase grants 100% of *actual yen paid* as pt. Looked up
/// dynamically from products.price_jpy at claim time. Range follows the
/// MUGEN bonding curve (¥7,800 base → ¥34,800 at 108 sales; #108 is fixed
/// ¥30,000). One full early-cycle MUGEN at ¥7,800 → 260 SKUs at ¥30 each.
/// A late-cycle MUGEN at ¥30,000 → 1,000 SKUs.
/// This constant is the *displayed-floor* used by /balance for UI hints.
const EXTRAS_POINTS_PER_MUGEN_FLOOR: i64 = 7_800;

/// Direct pt purchase tiers. (yen, pt, bonus_pct).
/// Larger packs get a graduated bonus so big partners feel rewarded.
const EXTRAS_POINT_PACKS: &[(i64, i64, i64)] = &[
    (1_000,  1_000,  0),   // ¥1k    = 1,000 pt   = 33 SKU
    (3_000,  3_300,  10),  // ¥3k    = 3,300 pt   = 110 SKU
    (10_000, 11_500, 15),  // ¥10k   = 11,500 pt  = 383 SKU
    (30_000, 36_000, 20),  // ¥30k   = 36,000 pt  = 1,200 SKU
];

fn normalize_email(e: &str) -> String {
    e.trim().to_ascii_lowercase()
}

fn points_balance(conn: &rusqlite::Connection, email: &str) -> (i64, bool) {
    let em = normalize_email(email);
    conn.query_row(
        "SELECT balance, free_30_used FROM proposal_points WHERE email=?",
        params![em],
        |r| Ok((r.get::<_, i64>(0)?, r.get::<_, i64>(1)? != 0)),
    ).unwrap_or((0, false))
}

/// Credit (positive delta) or charge (negative delta) `email`'s wallet.
/// Returns the new balance, or Err if charging would overdraw.
fn points_mutate(
    conn: &rusqlite::Connection,
    email: &str, delta: i64, reason: &str,
    ref_: Option<&str>, slug: Option<&str>,
) -> Result<i64, String> {
    if delta == 0 { return Ok(points_balance(conn, email).0); }
    let em = normalize_email(email);
    let now = chrono_now();
    let _ = conn.execute(
        "INSERT OR IGNORE INTO proposal_points (email, balance, free_30_used, updated_at, last_activity_at)
         VALUES (?, 0, 0, ?, ?)",
        params![em, now, now],
    );
    let cur: i64 = conn.query_row(
        "SELECT balance FROM proposal_points WHERE email=?",
        params![em], |r| r.get(0),
    ).unwrap_or(0);
    let new_bal = cur + delta;
    if new_bal < 0 {
        return Err(format!("insufficient points (have {}, need {})", cur, -delta));
    }
    conn.execute(
        "UPDATE proposal_points SET balance=?, updated_at=?, last_activity_at=? WHERE email=?",
        params![new_bal, now, now, em],
    ).map_err(|e| e.to_string())?;
    let _ = conn.execute(
        "INSERT INTO proposal_point_events (email, delta, reason, ref, slug, balance_after, created_at)
         VALUES (?,?,?,?,?,?,?)",
        params![em, delta, reason, ref_, slug, new_bal, now],
    );
    Ok(new_bal)
}

fn mark_free_30_used(conn: &rusqlite::Connection, email: &str) {
    let em = normalize_email(email);
    let now = chrono_now();
    let _ = conn.execute(
        "INSERT OR IGNORE INTO proposal_points (email, balance, free_30_used, updated_at)
         VALUES (?, 0, 1, ?)",
        params![em, now],
    );
    let _ = conn.execute(
        "UPDATE proposal_points SET free_30_used=1, updated_at=? WHERE email=?",
        params![now, em],
    );
}

/// Mirror approval state from legacy `<brand>_approval` tables into the
/// unified `proposals` row. The spec.json loader handles SKU seeding;
/// this only carries forward approval state for the 6 brands that have a
/// legacy *_approval table.
fn migrate_legacy_approval_into_proposals(db: &Db) {
    let conn = db.lock().unwrap();
    let pairs: &[(&str, &str)] = &[
        ("kichinan",  "kichinan_approval"),
        ("asoview",   "asoview_approval"),
        ("elsoul",    "elsoul_approval"),
        ("ele",       "ele_approval"),
        ("nojimahal", "nojimahal_approval"),
        ("ryozo",     "ryozo_approval"),
    ];
    for (slug, approval_table) in pairs {
        let migrated = conn.query_row(
            &format!("SELECT approved_at, approver_name, approver_email, approver_ip, COALESCE(plan_tier,''), COALESCE(note,''), revoked_at FROM {} WHERE id=1", approval_table),
            [],
            |r| Ok((
                r.get::<_, Option<String>>(0)?, r.get::<_, Option<String>>(1)?,
                r.get::<_, Option<String>>(2)?, r.get::<_, Option<String>>(3)?,
                r.get::<_, String>(4)?,        r.get::<_, String>(5)?,
                r.get::<_, Option<String>>(6)?,
            )),
        ).ok();
        if let Some((at, n, e, ip, plan, note, rev)) = migrated {
            let _ = conn.execute(
                "UPDATE proposals SET
                    approved_at=?, approver_name=?, approver_email=?, approver_ip=?,
                    plan_tier=?, note=?, revoked_at=?
                 WHERE slug=?",
                params![at, n, e, ip, plan, note, rev, slug],
            );
        }
    }
}

fn proposal_row(conn: &rusqlite::Connection, slug: &str)
    -> Option<(String, String, Option<String>, Option<String>, Option<String>, Option<String>, Option<String>)> {
    conn.query_row(
        "SELECT name, ip_owner, approved_at, approver_name, approver_email, plan_tier, revoked_at
         FROM proposals WHERE slug=?",
        params![slug],
        |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?, r.get(4)?, r.get(5)?, r.get(6)?)),
    ).ok()
}

fn proposal_is_approved(conn: &rusqlite::Connection, slug: &str) -> bool {
    conn.query_row(
        "SELECT approved_at IS NOT NULL AND revoked_at IS NULL FROM proposals WHERE slug=?",
        params![slug], |r| r.get::<_, bool>(0),
    ).unwrap_or(false)
}

/// Per-slug preview key check. Allows an unapproved proposal to accept Stripe
/// checkout if the request carries `?key=<expected>` AND the env var
/// PROPOSAL_PREVIEW_KEY_<SLUG_UPPERCASE> is set to that same value. Used to
/// share a previewable buyable URL with the partner before final approve,
/// without flipping the brand public-buyable for the whole internet.
fn proposal_preview_key_ok(
    slug: &str,
    q: &std::collections::HashMap<String, String>,
) -> bool {
    let provided = q.get("key").map(|s| s.trim()).unwrap_or("");
    if provided.is_empty() { return false; }
    let env_name = format!("PROPOSAL_PREVIEW_KEY_{}", slug.to_uppercase());
    // Default keys for DRAFT brands that need a preview URL before sending
    // their pitch deck. Rotate by setting the matching Fly secret to override.
    let fallback: &'static str = match slug {
        "charfilm" => "7fc131d3eac02496704af91af506827f",
        _ => "",
    };
    let expected = std::env::var(&env_name).unwrap_or_else(|_| fallback.to_string());
    if expected.is_empty() { return false; }
    // Constant-time compare to avoid timing-based key probing.
    let a = provided.as_bytes();
    let b = expected.as_bytes();
    if a.len() != b.len() { return false; }
    let mut diff: u8 = 0;
    for i in 0..a.len() { diff |= a[i] ^ b[i]; }
    diff == 0
}

fn proposal_skus_for(conn: &rusqlite::Connection, slug: &str)
    -> Vec<(String, i64, i64, String, String, String)> {
    let mut out = Vec::new();
    if let Ok(mut stmt) = conn.prepare(
        "SELECT letter, drop_num, price_jpy, label, kind, design_slug
         FROM proposal_skus WHERE slug=? ORDER BY drop_num ASC",
    ) {
        if let Ok(rows) = stmt.query_map(params![slug], |r| {
            Ok((
                r.get::<_, String>(0)?, r.get::<_, i64>(1)?, r.get::<_, i64>(2)?,
                r.get::<_, String>(3)?, r.get::<_, String>(4)?, r.get::<_, String>(5)?,
            ))
        }) {
            for row in rows.flatten() { out.push(row); }
        }
    }
    out
}

/// Same as proposal_skus_for but includes the `published` flag. Used by the
/// `/api/proposal/:slug/skus` endpoint so admin manage pages can render
/// public/private state without a second query.
fn proposal_skus_for_with_published(conn: &rusqlite::Connection, slug: &str)
    -> Vec<(String, i64, i64, String, String, String, Option<String>, i64)> {
    let mut out = Vec::new();
    if let Ok(mut stmt) = conn.prepare(
        "SELECT letter, drop_num, price_jpy, label, kind, design_slug, design_url, COALESCE(published, 1)
         FROM proposal_skus WHERE slug=? ORDER BY drop_num ASC",
    ) {
        if let Ok(rows) = stmt.query_map(params![slug], |r| {
            Ok((
                r.get::<_, String>(0)?, r.get::<_, i64>(1)?, r.get::<_, i64>(2)?,
                r.get::<_, String>(3)?, r.get::<_, String>(4)?, r.get::<_, String>(5)?,
                r.get::<_, Option<String>>(6)?, r.get::<_, i64>(7)?,
            ))
        }) {
            for row in rows.flatten() { out.push(row); }
        }
    }
    out
}

/// GET /api/proposal/:slug/meta — public read of the full meta_json blob
/// that drives the LP template. Combined with /skus this is enough for a
/// single generic HTML template to render any partner's proposal LP.
async fn proposal_generic_meta(
    State(db): State<Db>,
    axum::extract::Path(slug): axum::extract::Path<String>,
) -> Response {
    let conn = db.lock().unwrap();
    let row: Option<(String, String, Option<String>, Option<String>, Option<String>, Option<String>)> =
        conn.query_row(
            "SELECT slug, name, ip_owner, meta_json, approved_at, revoked_at
             FROM proposals WHERE slug=?",
            params![slug.to_lowercase()],
            |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?, r.get(4)?, r.get(5)?)),
        ).ok();
    let (s, name, ip_owner, meta_json, approved_at, revoked_at) = match row {
        Some(r) => r,
        None => return (StatusCode::NOT_FOUND,
            Json(serde_json::json!({"error": "proposal not found", "slug": slug}))).into_response(),
    };
    let meta: serde_json::Value = meta_json
        .and_then(|s| serde_json::from_str(&s).ok())
        .unwrap_or(serde_json::Value::Null);
    let approved = approved_at.is_some() && revoked_at.is_none();
    Json(serde_json::json!({
        "slug": s, "name": name,
        "ip_owner": ip_owner.unwrap_or_default(),
        "approved": approved,
        "approved_at": approved_at,
        "revoked_at": revoked_at,
        "meta": meta,
    })).into_response()
}

/// PATCH /api/admin/proposal/:slug/meta — admin-gated meta_json update.
/// Body: a JSON object that is merged into the existing meta_json. Top-
/// level keys in the request replace the existing top-level keys (shallow
/// merge), so an admin can add `sections: [...]` without resending the
/// rest. Returns the merged result.
async fn api_admin_proposal_meta_patch(
    State(db): State<Db>, headers: HeaderMap,
    axum::extract::Path(slug): axum::extract::Path<String>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(patch): Json<serde_json::Value>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(),
        &format!("/api/admin/proposal/{}/meta", slug)).await { return r; }
    let slug = slug.to_lowercase();
    let conn = db.lock().unwrap();
    let existing: Option<String> = conn.query_row(
        "SELECT meta_json FROM proposals WHERE slug=?",
        params![slug], |r| r.get(0)).ok().flatten();
    let mut merged: serde_json::Map<String, serde_json::Value> = existing
        .and_then(|s| serde_json::from_str::<serde_json::Map<String, serde_json::Value>>(&s).ok())
        .unwrap_or_default();
    if let serde_json::Value::Object(p) = patch {
        for (k, v) in p { merged.insert(k, v); }
    } else {
        return (StatusCode::BAD_REQUEST, "patch must be a JSON object").into_response();
    }
    let merged_str = serde_json::to_string(&merged).unwrap_or_default();
    let n = conn.execute(
        "UPDATE proposals SET meta_json=? WHERE slug=?",
        params![merged_str, slug],
    ).unwrap_or(0);
    Json(serde_json::json!({
        "ok": n > 0, "slug": slug,
        "meta": serde_json::Value::Object(merged),
    })).into_response()
}

/// GET /api/proposal/:slug/state — generic public state endpoint.
async fn proposal_generic_state(
    State(db): State<Db>,
    axum::extract::Path(slug): axum::extract::Path<String>,
) -> Response {
    let conn = db.lock().unwrap();
    let row = match proposal_row(&conn, &slug) {
        Some(r) => r,
        None => return (StatusCode::NOT_FOUND, "unknown proposal slug").into_response(),
    };
    let approved = row.2.is_some() && row.6.is_none();
    let active_count: i64 = conn.query_row(
        "SELECT COUNT(*) FROM products WHERE brand LIKE ?||'%' AND active=1",
        params![format!("{}_", slug)], |r| r.get(0),
    ).unwrap_or(0);
    let total: i64 = conn.query_row(
        "SELECT COUNT(*) FROM proposal_skus WHERE slug=?",
        params![slug], |r| r.get(0),
    ).unwrap_or(0);
    Json(serde_json::json!({
        "slug": slug,
        "name": row.0,
        "approved": approved,
        "approved_at": row.2,
        "approver_first_name": row.3.as_ref().map(|n| n.split_whitespace().next().unwrap_or("—").to_string()),
        "plan_tier": row.5,
        "products_active": active_count,
        "products_total": total,
    })).into_response()
}

/// Try to render an approved proposal LP from DB, for the /:slug catch-all.
/// Returns Some(html) ONLY when the proposal exists, has `approved_at`, and
/// has not been revoked. Unapproved / revoked / non-existent → None (caller
/// falls through to the static-or-404 path so the brand is invisible).
///
/// `as_admin_preview = true` bypasses the approval gate so the admin /ls
/// dashboard can show every brand (with a PREVIEW banner). Public callers
/// must pass `false`.
///
/// All inputs (name, ip_owner, meta, SKUs) come from the DB. No file or
/// embedded asset is read at request time.
fn try_render_approved_proposal_lp(slug: &str, db: &Db) -> Option<String> {
    try_render_proposal_lp_inner(slug, db, false, "ja")
}

/// Public approved LP with explicit language. ?lang=en → swaps the page lang
/// attribute + a small bilingual layer (status banner, "buy" pill text, og:
/// locale). Per-proposal meta can also carry `<key>_en` overrides — those
/// win over the default JP `<key>` when lang=en. Falls back to JP when an
/// `_en` override is missing.
fn try_render_approved_proposal_lp_with_lang(slug: &str, db: &Db, lang: &str) -> Option<String> {
    try_render_proposal_lp_inner(slug, db, false, lang)
}

fn try_render_proposal_lp_inner(slug: &str, db: &Db, as_admin_preview: bool, lang: &str) -> Option<String> {
    let (name, ip_owner, plan_tier, meta_json_str, skus, approved) = {
        let conn = db.lock().unwrap();
        let row = proposal_row(&conn, slug)?;
        let approved = row.2.is_some() && row.6.is_none();
        // Public: gate strictly on approval. Admin preview: always render.
        if !approved && !as_admin_preview { return None; }
        let plan = row.5.clone().unwrap_or_default();
        let meta: Option<String> = conn.query_row(
            "SELECT meta_json FROM proposals WHERE slug=?",
            params![slug], |r| r.get(0),
        ).ok().flatten();
        // Inline query so we can pull design_url too AND join in products.mockup_url
        // (the Printful-generated mockup, when available — that's the per-SKU,
        // design-overlaid product photo we actually want to show).
        // We also pull `products.id` so the Buy button can POST a real product_id
        // to /api/checkout, and a separate design_url column so we can fall back
        // independently when the mockup is missing but a design preview exists.
        let mut skus: Vec<(
            String, i64, i64, String, String, String, // letter, drop, price, label, kind, design_slug
            Option<String>,  // img_url (mockup or design)
            Option<i64>,     // product_id (for Buy CTA)
            i64,             // active (for "sold-out" gating)
        )> = Vec::new();
        if let Ok(mut stmt) = conn.prepare(
            "SELECT ps.letter, ps.drop_num, ps.price_jpy, ps.label, ps.kind, ps.design_slug,
                    COALESCE(
                        NULLIF(p.mockup_url, ''),
                        NULLIF(ps.design_url, ''),
                        NULLIF(p.design_url,  '')
                    ) AS img_url,
                    p.id   AS product_id,
                    COALESCE(p.active, 0) AS active
             FROM proposal_skus ps
             LEFT JOIN products p
                    ON p.brand = ps.slug || '_' || ps.kind || '_sample'
                   AND p.drop_num = ps.drop_num
             WHERE ps.slug = ?
             ORDER BY ps.drop_num ASC",
        ) {
            if let Ok(rows) = stmt.query_map(params![slug], |r| {
                Ok((
                    r.get::<_, String>(0)?, r.get::<_, i64>(1)?, r.get::<_, i64>(2)?,
                    r.get::<_, String>(3)?, r.get::<_, String>(4)?, r.get::<_, String>(5)?,
                    r.get::<_, Option<String>>(6)?,
                    r.get::<_, Option<i64>>(7)?,
                    r.get::<_, i64>(8)?,
                ))
            }) {
                for row in rows.flatten() { skus.push(row); }
            }
        }
        (row.0, row.1, plan, meta.unwrap_or_default(), skus, approved)
    };
    let meta_json: serde_json::Value = serde_json::from_str(&meta_json_str)
        .unwrap_or(serde_json::json!({}));
    Some(render_proposal_lp(slug, &name, &ip_owner, approved, &plan_tier, &skus, &meta_json, lang))
}

#[allow(clippy::type_complexity)]
fn render_proposal_lp(
    slug: &str,
    name: &str,
    ip_owner: &str,
    approved: bool,
    plan_tier: &str,
    skus: &[(
        String, i64, i64, String, String, String,
        Option<String>, Option<i64>, i64,
    )],
    meta: &serde_json::Value,
    lang: &str,
) -> String {
    // ?lang=en path: any `<key>_en` in the proposal meta wins over `<key>`.
    // Falls back to the JP value when an `_en` override is missing, so we
    // never blank-out unlocalised fields. JP path ignores `_en` keys.
    let is_en = lang.eq_ignore_ascii_case("en");
    let m = |k: &str| -> String {
        if is_en {
            let en_key = format!("{}_en", k);
            if let Some(s) = meta.get(&en_key).and_then(|v| v.as_str()) {
                return s.to_string();
            }
        }
        meta.get(k).and_then(|v| v.as_str()).unwrap_or("").to_string()
    };
    let display_name = if !m("display_name").is_empty() { m("display_name") } else { name.to_string() };
    let tagline      = m("tagline");
    let h1           = if !m("h1").is_empty() { m("h1") } else { html_escape(&display_name) };
    let subtitle     = m("subtitle");
    let lede         = m("lede");
    let why_md       = m("why_md");
    let accent       = if !m("accent_hex").is_empty() { m("accent_hex") } else { "#7be57b".into() };

    let accent_rgba = {
        let h = accent.trim_start_matches('#');
        let r = u8::from_str_radix(h.get(0..2).unwrap_or("7b"), 16).unwrap_or(0x7b);
        let g = u8::from_str_radix(h.get(2..4).unwrap_or("e5"), 16).unwrap_or(0xe5);
        let b = u8::from_str_radix(h.get(4..6).unwrap_or("7b"), 16).unwrap_or(0x7b);
        format!("rgba({},{},{},0.10)", r, g, b)
    };

    let hero_kv_html: String = meta.get("hero_kv")
        .and_then(|v| v.as_array())
        .map(|arr| arr.iter().filter_map(|p| {
            let pair = p.as_array()?;
            let k = pair.first()?.as_str()?;
            let v = pair.get(1)?.as_str()?;
            Some(format!(
                "<hr><div class=\"k\">{}</div><div class=\"v\">{}</div>",
                html_escape(k), html_escape(v)
            ))
        }).collect::<Vec<_>>().join(""))
        .unwrap_or_default();

    let use_cases_html: String = meta.get("use_cases")
        .and_then(|v| v.as_array())
        .map(|arr| arr.iter().filter_map(|u| u.as_str())
            .map(|u| format!("<li>{}</li>", html_escape(u)))
            .collect::<Vec<_>>().join(""))
        .unwrap_or_default();

    let n_sku = skus.len();
    let total_jpy: i64 = skus.iter().map(|s| s.2).sum();
    // ── SKU cards: image (5-level fallback) + Buy button ──
    // Image priority: img_url from DB (mockup_url / design_url) →
    //   /static/proposals/<slug>-mockup-<letter>.png →
    //   /static/proposals/<slug>-pf-<letter>.jpg →
    //   /static/proposals/<slug>-design-<design_slug>.png →
    //   placeholder SVG circle.
    // <img> with onerror chain walks the fallbacks until one loads. JS hidden
    // here — we use srcset-style `data-fallback` so the chain is declarative
    // and works without JS for SEO crawlers.
    let cards_html: String = skus.iter().map(|sku| {
        let (letter, _drop, price, label, kind, design_slug, img_url, product_id, active) = sku;
        let letter_lo = letter.to_ascii_lowercase();
        // Build fallback chain (declarative — onerror walks the list)
        let primary = img_url.clone().filter(|s| !s.is_empty()).unwrap_or_else(|| {
            format!("/static/proposals/{}-mockup-{}.png", slug, letter_lo)
        });
        let fb1 = format!("/static/proposals/{}-mockup-{}.png", slug, letter_lo);
        let fb2 = format!("/static/proposals/{}-pf-{}.jpg", slug, letter_lo);
        let fb3 = format!("/static/proposals/{}-design-{}.png", slug, design_slug);
        // Final placeholder: inline SVG with the MU mark ━◯━
        let placeholder = "data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 200 200'><rect width='200' height='200' fill='%230a0a0a'/><circle cx='100' cy='100' r='34' fill='none' stroke='%237be57b' stroke-width='2'/><rect x='30' y='99' width='40' height='2' fill='%237be57b'/><rect x='130' y='99' width='40' height='2' fill='%237be57b'/></svg>";
        // The onerror chain: each step swaps to the next fallback and clears
        // its own handler so it only fires once per level.
        let onerror = format!(
            "if(this.dataset.s==='0'){{this.dataset.s='1';this.src='{}';}}\
             else if(this.dataset.s==='1'){{this.dataset.s='2';this.src='{}';}}\
             else if(this.dataset.s==='2'){{this.dataset.s='3';this.src='{}';}}\
             else if(this.dataset.s==='3'){{this.dataset.s='4';this.src=\"{}\";}}\
             else{{this.onerror=null;}}",
            html_attr_escape(&fb1), html_attr_escape(&fb2),
            html_attr_escape(&fb3), placeholder,
        );
        // Buy button: real product_id present + active=1 → enabled. Otherwise
        // show a disabled "準備中" pill. Clicking the enabled button opens the
        // shared <dialog id="buy-modal"> at the bottom of the page where the
        // buyer picks provider × fabric × size × qty + email. The modal then
        // POSTs {product_id, variant_type, pod_provider, size, quantity, email}
        // to /api/checkout — see VARIANT_PRICES table in the trailing <script>
        // for the price matrix that drives the dynamic total.
        let buy_label_active = if is_en {
            format!("Buy now · ¥{}", format_jpy(*price))
        } else {
            format!("今すぐ買う · ¥{}", format_jpy(*price))
        };
        let buy_label_inactive = if is_en {
            "Coming soon".to_string()
        } else {
            "準備中 · coming soon".to_string()
        };
        let buy_html = match (product_id, *active) {
            (Some(pid), 1) => format!(
                "<button type=\"button\" class=\"buy\" \
                   data-action=\"open-modal\" \
                   data-product-id=\"{pid}\" \
                   data-kind=\"{kind_attr}\" \
                   data-default-price=\"{price}\" \
                   data-name=\"{name_attr}\" \
                   data-img=\"{img_attr}\">\
                   {buy_label}\
                 </button>",
                pid = pid,
                kind_attr = html_attr_escape(kind),
                price = price,
                name_attr = html_attr_escape(label),
                img_attr = html_attr_escape(&primary),
                buy_label = html_escape(&buy_label_active),
            ),
            _ => format!(
                "<button type=\"button\" class=\"buy disabled\" disabled>{}</button>",
                html_escape(&buy_label_inactive)
            ),
        };
        format!(
            "<div class=\"card\">\
               <div class=\"thumb\">\
                 <img src=\"{img}\" alt=\"{alt}\" loading=\"lazy\" data-s=\"0\" onerror=\"{onerror}\">\
               </div>\
               <div class=\"id\">{letter}</div>\
               <h4>{label}</h4>\
               <div class=\"kind\">{kind} · design {design_slug}</div>\
               <div class=\"price\">¥{price_fmt}</div>\
               {buy}\
             </div>",
            img = html_attr_escape(&primary),
            alt = html_attr_escape(label),
            onerror = onerror,
            letter = html_escape(&letter.to_uppercase()),
            label = html_escape(label),
            kind = html_escape(kind),
            design_slug = html_escape(design_slug),
            price_fmt = format_jpy(*price),
            buy = buy_html,
        )
    }).collect::<Vec<_>>().join("\n");

    let status_label = if approved {
        if is_en {
            format!("LIVE / on sale ({})", html_escape(plan_tier))
        } else {
            format!("LIVE / 公開販売中 ({})", html_escape(plan_tier))
        }
    } else if is_en {
        "Confidential · pitch deck (gated)".to_string()
    } else {
        "社外秘 · pitch deck (gated)".to_string()
    };

    // ── mu_intro (core_truth / philosophy / proof_points / operator / founder) ──
    let mu_intro_html: String = meta.get("mu_intro").and_then(|v| v.as_object()).map(|obj| {
        let truth = obj.get("core_truth").and_then(|v| v.as_str()).unwrap_or("");
        let phil  = obj.get("philosophy").and_then(|v| v.as_str()).unwrap_or("");
        let proof: String = obj.get("proof_points").and_then(|v| v.as_array())
            .map(|arr| arr.iter().filter_map(|u| u.as_str())
                 .map(|u| format!("<li>{}</li>", html_escape(u)))
                 .collect::<Vec<_>>().join(""))
            .unwrap_or_default();
        let operator = obj.get("operator").and_then(|v| v.as_str()).unwrap_or("");
        let founder  = obj.get("founder").and_then(|v| v.as_str()).unwrap_or("");
        let mut out = String::new();
        out.push_str("<div class=\"mu-intro\">");
        out.push_str("<h3>About MU ━◯━ 静かなレーベル</h3>");
        if !truth.is_empty() {
            out.push_str(&format!("<div class=\"truth\">{}</div>", html_escape(truth)));
        }
        if !phil.is_empty() {
            out.push_str(&format!("<div class=\"phil\">{}</div>", html_escape(phil)));
        }
        if !proof.is_empty() {
            out.push_str("<h4>Proof points</h4>");
            out.push_str(&format!("<ul>{}</ul>", proof));
        }
        if !operator.is_empty() || !founder.is_empty() {
            out.push_str("<div class=\"who\">");
            if !operator.is_empty() {
                out.push_str(&format!(
                    "<div class=\"col\"><div class=\"role\">運営</div><div class=\"desc\">{}</div></div>",
                    html_escape(operator)
                ));
            }
            if !founder.is_empty() {
                out.push_str(&format!(
                    "<div class=\"col\"><div class=\"role\">代表</div><div class=\"desc\">{}</div></div>",
                    html_escape(founder)
                ));
            }
            out.push_str("</div>");
        }
        out.push_str("</div>");
        out
    }).unwrap_or_default();

    // ── mechanism (numbered cards: no/title/body) ──
    // body may contain inline HTML (e.g. <b>, <code>, <strong>) so we don't escape it.
    let mechanism_html: String = meta.get("mechanism").and_then(|v| v.as_array()).map(|arr| {
        arr.iter().filter_map(|m| {
            let no   = m.get("no").and_then(|v| v.as_i64()).unwrap_or(0);
            let title = m.get("title").and_then(|v| v.as_str())?;
            let body  = m.get("body").and_then(|v| v.as_str())?;
            Some(format!(
                "<div class=\"mech-item\">\
                   <div class=\"mech-no\">{:02}</div>\
                   <div class=\"mech-body\">\
                     <h4>{}</h4>\
                     <p>{}</p>\
                   </div>\
                 </div>",
                no, html_escape(title), body
            ))
        }).collect::<Vec<_>>().join("")
    }).unwrap_or_default();

    // ── options (3 plans: letter / title / body / image / drop_label / price_label) ──
    let options_html: String = meta.get("options").and_then(|v| v.as_array()).map(|arr| {
        arr.iter().filter_map(|o| {
            let letter      = o.get("letter").and_then(|v| v.as_str()).unwrap_or("");
            let title       = o.get("title").and_then(|v| v.as_str())?;
            let body        = o.get("body").and_then(|v| v.as_str())?;
            let image       = o.get("image").and_then(|v| v.as_str()).unwrap_or("");
            let drop_label  = o.get("drop_label").and_then(|v| v.as_str()).unwrap_or("");
            let price_label = o.get("price_label").and_then(|v| v.as_str()).unwrap_or("");
            let shot = if image.is_empty() {
                "<div class=\"shot empty\">image —</div>".to_string()
            } else {
                format!("<div class=\"shot\"><img src=\"{}\" alt=\"\" loading=\"lazy\"></div>",
                    html_attr_escape(image))
            };
            Some(format!(
                "<div class=\"option\">\
                   {shot}\
                   <div class=\"copy\">\
                     <div class=\"badge\">{badge}</div>\
                     <h3>{title}</h3>\
                     <p>{body}</p>\
                     <div class=\"price\">{price}</div>\
                   </div>\
                 </div>",
                shot = shot,
                badge = html_escape(&format!("{}{}{}",
                    letter,
                    if !letter.is_empty() && !drop_label.is_empty() { " · " } else { "" },
                    drop_label)),
                title = html_escape(title),
                body = body,
                price = html_escape(price_label),
            ))
        }).collect::<Vec<_>>().join("")
    }).unwrap_or_default();

    // ── terms (key / value table) ──
    let terms_html: String = meta.get("terms").and_then(|v| v.as_array()).map(|arr| {
        arr.iter().filter_map(|t| {
            let pair = t.as_array()?;
            let k = pair.first()?.as_str()?;
            let v = pair.get(1)?.as_str()?;
            // value may contain inline HTML (e.g. <b>無在庫</b>) — don't escape.
            Some(format!("<tr><td>{}</td><td>{}</td></tr>", html_escape(k), v))
        }).collect::<Vec<_>>().join("")
    }).unwrap_or_default();

    // ── timeline (Day X / description) ──
    let timeline_html: String = meta.get("timeline").and_then(|v| v.as_array()).map(|arr| {
        arr.iter().filter_map(|t| {
            let pair = t.as_array()?;
            let d = pair.first()?.as_str()?;
            let b = pair.get(1)?.as_str()?;
            Some(format!(
                "<div class=\"tr\"><div class=\"d\">{}</div><div class=\"b\">{}</div></div>",
                html_escape(d), html_escape(b)
            ))
        }).collect::<Vec<_>>().join("")
    }).unwrap_or_default();

    // ── canonical / og / robots ──
    // 2026-05-21: approved collab LPs are public landing pages and need full
    // SEO/social meta. Unapproved drafts stay noindex (admin preview only).
    // canonical = /<slug> per spec (the public, shareable URL form).
    let canonical_url_lp = format!("https://wearmu.com/{}", slug);
    let robots_meta = if approved {
        r#"<meta name="robots" content="index,follow">"#
    } else {
        r#"<meta name="robots" content="noindex,nofollow">"#
    };
    let og_image_lp = {
        // Use the first SKU's image when available; otherwise fall back to
        // the brand default. Never emit a 404 path — placeholder served by
        // /static/og.png keeps Twitter/FB cards rendering.
        let first_img = skus.iter().find_map(|s| s.6.clone().filter(|u| !u.is_empty()));
        match first_img {
            Some(u) if u.starts_with("http") => u,
            Some(u) => format!("https://wearmu.com{}", u),
            None    => "https://wearmu.com/static/og.png".to_string(),
        }
    };
    let og_desc_lp = if !tagline.is_empty() {
        tagline.clone()
    } else if !lede.is_empty() {
        let truncated: String = lede.chars().take(160).collect();
        truncated
    } else {
        format!("{} × MU — autonomous collab line.", display_name)
    };

    // ── lang-aware HTML head bits (?lang=en swaps these) ──
    let html_lang_attr = if is_en { "en" } else { "ja" };
    let og_locale_primary = if is_en { "en_US" } else { "ja_JP" };
    let og_locale_alt     = if is_en { "ja_JP" } else { "en_US" };
    let meta_desc_text = if is_en {
        format!("{} × MU — collab landing. {} SKUs, made-to-order via Printful EU, ships worldwide.", display_name, n_sku)
    } else {
        format!("社外秘 — {} 様への collab pitch deck (株式会社イネブラ / MU)。{} SKU、 拡張・リブランド相談用。", display_name, n_sku)
    };
    let title_suffix = if is_en { "collab landing" } else { "collab pitch" };
    let canonical_url_localized = if is_en {
        format!("{}?lang=en", canonical_url_lp)
    } else {
        canonical_url_lp.clone()
    };
    let hreflang_links = format!(
        r#"<link rel="alternate" hreflang="ja" href="{base}">
<link rel="alternate" hreflang="en" href="{base}?lang=en">
<link rel="alternate" hreflang="x-default" href="{base}">"#,
        base = canonical_url_lp,
    );

    format!(r#"<!doctype html>
<html lang="{html_lang_attr}"><head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>{display_name} × MU — {title_suffix}</title>
{robots_meta}
<link rel="canonical" href="{canonical_url_localized}">
{hreflang_links}
<meta name="description" content="{meta_desc_text_esc}">
<meta property="og:type" content="website">
<meta property="og:title" content="{display_name} × MU">
<meta property="og:description" content="{og_desc_lp_esc}">
<meta property="og:url" content="{canonical_url_localized}">
<meta property="og:image" content="{og_image_lp_esc}">
<meta property="og:site_name" content="MU">
<meta property="og:locale" content="{og_locale_primary}">
<meta property="og:locale:alternate" content="{og_locale_alt}">
<meta name="twitter:card" content="summary_large_image">
<meta name="twitter:title" content="{display_name} × MU">
<meta name="twitter:description" content="{og_desc_lp_esc}">
<meta name="twitter:image" content="{og_image_lp_esc}">
<style>
:root{{--bg:#0a0a0a;--fg:#f5f5f5;--mute:#888;--line:#222;--accent:{accent};--accent-rgba:{accent_rgba}}}
*{{box-sizing:border-box}}
body{{background:var(--bg);color:var(--fg);font-family:'Helvetica Neue',Arial,sans-serif;margin:0;line-height:1.7;-webkit-font-smoothing:antialiased}}
.wrap{{max-width:980px;margin:0 auto;padding:48px 24px}}
.status-banner{{background:var(--accent-rgba);border:1px solid var(--accent);border-left:4px solid var(--accent);padding:14px 20px;margin-bottom:32px;display:flex;align-items:center;gap:16px;font-size:12px;letter-spacing:0.04em;flex-wrap:wrap}}
.status-banner .label{{color:var(--accent);font-weight:700;text-transform:uppercase}}
.status-banner .meta{{color:var(--mute);font-size:11px;margin-left:auto;text-align:right}}
.tagline{{color:var(--accent);font-weight:600;font-size:12px;letter-spacing:0.20em;text-transform:uppercase;margin-bottom:12px}}
h1{{font-size:48px;line-height:1.15;letter-spacing:-0.02em;margin:0 0 16px;font-weight:800}}
.subtitle{{color:var(--mute);font-size:13px;letter-spacing:0.18em;text-transform:uppercase;margin-bottom:48px}}
.hero{{display:grid;grid-template-columns:1fr 320px;gap:48px;margin-bottom:64px;align-items:start}}
@media(max-width:760px){{.hero{{grid-template-columns:1fr}} h1{{font-size:36px}}}}
.lede{{font-size:16px;line-height:1.95;color:#ddd}}
.hero-card{{background:#111;border:1px solid var(--line);padding:24px;border-radius:4px}}
.hero-card .k{{font-size:9px;letter-spacing:0.32em;text-transform:uppercase;color:var(--mute);font-weight:700;margin-bottom:6px}}
.hero-card .v{{font-size:13px;color:var(--fg)}}
.hero-card hr{{border:0;border-top:1px solid var(--line);margin:14px 0}}
.hero-card hr:first-child{{display:none}}
h2{{font-size:22px;letter-spacing:-0.01em;margin:48px 0 16px;font-weight:700}}
.why{{font-size:15px;line-height:2;color:#ccc;margin-bottom:32px}}
ul.use-cases{{margin:0 0 32px;padding:0;list-style:none}}
ul.use-cases li{{padding:10px 0;border-bottom:1px solid var(--line);color:#ccc;font-size:14px}}
ul.use-cases li:before{{content:'━◯━ ';color:var(--accent);font-weight:700;margin-right:8px}}
.grid{{display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:14px;margin-top:24px}}
.card{{background:#111;border:1px solid var(--line);padding:0;border-radius:6px;transition:border-color 0.2s;overflow:hidden;display:flex;flex-direction:column}}
.card:hover{{border-color:var(--accent)}}
.card .thumb{{aspect-ratio:1/1;background:#0a0a0a;border-bottom:1px solid var(--line);overflow:hidden;display:flex;align-items:center;justify-content:center}}
.card .thumb img{{display:block;width:100%;height:100%;object-fit:cover}}
.card > .id,.card > h4,.card > .kind,.card > .price,.card > .buy{{margin-left:14px;margin-right:14px}}
.card .id{{font-size:10px;letter-spacing:0.3em;color:var(--accent);font-weight:700;margin-top:12px;margin-bottom:4px}}
.card h4{{margin:0 14px 6px;font-size:13px;line-height:1.45;font-weight:600}}
.card .kind{{font-size:10px;color:var(--mute);letter-spacing:0.16em;text-transform:uppercase;margin-bottom:8px}}
.card .price{{font-size:15px;font-weight:700;color:var(--fg);margin-bottom:10px}}
.card .buy{{background:var(--accent);color:#000;border:0;font-weight:700;padding:10px 12px;font-size:12px;letter-spacing:0.05em;cursor:pointer;border-radius:4px;font-family:inherit;margin-bottom:14px;text-align:center;transition:opacity 0.15s}}
.card .buy:hover:not(:disabled){{opacity:0.85}}
.card .buy.disabled,.card .buy:disabled{{background:#222;color:var(--mute);cursor:not-allowed}}
.extras-cta{{margin-top:48px;padding:24px;border:1px solid var(--line);background:#111;border-radius:6px}}
.extras-cta h3{{margin:0 0 8px;font-size:18px;font-weight:700;color:var(--accent)}}
.extras-cta p{{margin:0 0 16px;color:#ccc;font-size:13px;line-height:1.8}}
.extras-cta form{{display:flex;gap:8px;flex-wrap:wrap;align-items:center}}
.extras-cta input[type=email]{{flex:1;min-width:220px;background:#0a0a0a;border:1px solid var(--line);color:var(--fg);padding:10px 12px;font-family:inherit;font-size:14px;border-radius:4px}}
.extras-cta input[type=email]:focus{{border-color:var(--accent);outline:none}}
.extras-cta button{{background:var(--accent);color:#000;border:0;font-weight:700;padding:10px 18px;font-size:13px;letter-spacing:0.04em;cursor:pointer;border-radius:4px;font-family:inherit}}
.extras-cta button:disabled{{opacity:0.5;cursor:not-allowed}}
.extras-cta .result{{margin-top:14px;font-size:12px;color:var(--mute);line-height:1.7;font-family:'SF Mono',monospace}}
.extras-cta .result.ok{{color:var(--accent)}}
.extras-cta .result.err{{color:#ff6464}}
footer{{margin-top:96px;padding-top:24px;border-top:1px solid var(--line);color:var(--mute);font-size:12px;line-height:1.8}}
footer code{{background:#111;border:1px solid var(--line);padding:1px 6px;border-radius:3px;font-size:11px}}
footer a{{color:var(--accent);text-decoration:none}}
/* ── mu-intro ── */
.mu-intro{{margin:24px 0 32px;border:1px solid var(--accent);background:var(--accent-rgba);padding:28px 24px;border-radius:6px}}
.mu-intro h3{{color:var(--accent);font-size:10px;letter-spacing:0.28em;text-transform:uppercase;margin:0 0 12px;font-weight:700}}
.mu-intro .truth{{font-size:18px;line-height:1.7;color:var(--fg);margin-bottom:10px;font-weight:500}}
.mu-intro .phil{{font-size:13px;color:var(--mute);letter-spacing:0.14em;margin-bottom:20px}}
.mu-intro h4{{font-size:10px;color:var(--accent);letter-spacing:0.22em;text-transform:uppercase;margin:22px 0 10px;font-weight:700}}
.mu-intro ul{{list-style:none;padding:0;margin:0}}
.mu-intro ul li{{position:relative;padding:8px 0 8px 18px;color:#ddd;font-size:13px;line-height:1.85;border-bottom:1px solid var(--line)}}
.mu-intro ul li:last-child{{border-bottom:none}}
.mu-intro ul li::before{{content:'●';color:var(--accent);position:absolute;left:0;top:8px;font-size:10px}}
.mu-intro .who{{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:18px}}
@media(max-width:680px){{.mu-intro .who{{grid-template-columns:1fr}}}}
.mu-intro .who .col{{background:#0a0a0a;border:1px solid var(--line);padding:14px 16px;border-radius:4px}}
.mu-intro .who .role{{font-size:10px;color:var(--accent);letter-spacing:0.22em;text-transform:uppercase;margin-bottom:6px;font-weight:700}}
.mu-intro .who .desc{{font-size:12.5px;color:#ccc;line-height:1.7}}
/* ── mechanism ── */
.mech{{margin:24px 0 32px}}
.mech-item{{display:grid;grid-template-columns:48px 1fr;gap:18px;padding:18px 0;border-bottom:1px solid var(--line)}}
.mech-item:last-child{{border-bottom:none}}
.mech-no{{color:var(--accent);font-size:14px;font-weight:700;letter-spacing:0.08em;font-variant-numeric:tabular-nums;padding-top:2px}}
.mech-body h4{{font-size:14px;font-weight:700;margin:0 0 6px;color:var(--fg)}}
.mech-body p{{font-size:13px;color:#ccc;line-height:1.85;margin:0}}
.mech-body p code{{background:#111;border:1px solid var(--line);padding:1px 6px;border-radius:3px;font-size:11.5px;color:var(--accent)}}
/* ── options ── */
.options{{margin:24px 0 32px}}
.option{{display:grid;grid-template-columns:1fr 1.1fr;gap:20px;align-items:start;margin:0 0 32px;background:#111;border:1px solid var(--line);padding:20px;border-radius:6px}}
.option:nth-child(even){{grid-template-columns:1.1fr 1fr}}
.option:nth-child(even) .copy{{order:2}}
.option:nth-child(even) .shot{{order:1}}
@media(max-width:680px){{.option,.option:nth-child(even){{grid-template-columns:1fr}}.option:nth-child(even) .copy,.option:nth-child(even) .shot{{order:initial}}}}
.option .shot{{border:1px solid var(--line);background:#0a0a0a;aspect-ratio:1/1;display:flex;align-items:center;justify-content:center;overflow:hidden;border-radius:4px}}
.option .shot img{{display:block;width:100%;height:100%;object-fit:cover}}
.option .shot.empty{{color:var(--mute);font-size:11px;letter-spacing:0.16em}}
.option .copy .badge{{font-size:10px;color:var(--accent);letter-spacing:0.28em;text-transform:uppercase;margin-bottom:8px;font-weight:700}}
.option .copy h3{{font-size:18px;font-weight:700;line-height:1.3;margin:0 0 10px;color:var(--fg)}}
.option .copy p{{font-size:13px;color:#ccc;line-height:1.85;margin:0 0 10px}}
.option .copy p strong{{color:var(--fg);font-weight:600}}
.option .copy .price{{font-size:11px;color:var(--accent);letter-spacing:0.14em;margin-top:14px;border-top:1px solid var(--line);padding-top:12px;font-weight:600}}
/* ── terms ── */
.terms{{width:100%;border:1px solid var(--line);font-size:13px;border-collapse:collapse;margin:24px 0 16px;background:#111;border-radius:6px;overflow:hidden}}
.terms td{{padding:11px 16px;border-bottom:1px solid var(--line);color:#ccc;line-height:1.7;vertical-align:top}}
.terms td:first-child{{color:var(--accent);letter-spacing:0.12em;font-size:11px;text-transform:uppercase;width:32%;font-weight:700}}
.terms td b{{color:var(--fg);font-weight:600}}
.terms tr:last-child td{{border-bottom:none}}
/* ── timeline ── */
.timeline{{margin:24px 0 16px;background:#111;border:1px solid var(--line);border-radius:6px;padding:8px 18px}}
.timeline .tr{{display:grid;grid-template-columns:90px 1fr;gap:16px;padding:12px 0;border-bottom:1px solid var(--line);align-items:baseline}}
.timeline .tr:last-child{{border-bottom:none}}
.timeline .tr .d{{color:var(--accent);font-size:12px;font-weight:700;letter-spacing:0.08em;font-variant-numeric:tabular-nums}}
.timeline .tr .b{{color:#ddd;font-size:13.5px;line-height:1.7}}
/* ── buy modal (shared, single instance per page) ── */
#buy-modal{{border:1px solid var(--line);background:#0a0a0a;color:var(--fg);padding:0;border-radius:8px;max-width:520px;width:92vw;box-shadow:0 24px 64px rgba(0,0,0,0.55)}}
#buy-modal::backdrop{{background:rgba(0,0,0,0.72)}}
#buy-modal .bm-hd{{display:flex;align-items:center;gap:12px;padding:16px 20px;border-bottom:1px solid var(--line)}}
#buy-modal .bm-img{{width:64px;height:64px;background:#111;border:1px solid var(--line);border-radius:4px;object-fit:cover;flex:0 0 auto}}
#buy-modal .bm-title{{font-size:14px;font-weight:700;line-height:1.4;color:var(--fg);margin:0 0 4px}}
#buy-modal .bm-sub{{font-size:10px;color:var(--mute);letter-spacing:0.18em;text-transform:uppercase}}
#buy-modal .bm-close{{margin-left:auto;background:none;border:1px solid var(--line);color:var(--mute);width:28px;height:28px;border-radius:4px;cursor:pointer;font-family:inherit;font-size:14px;line-height:1}}
#buy-modal .bm-close:hover{{color:var(--fg);border-color:var(--accent)}}
#buy-modal .bm-body{{padding:18px 20px;display:flex;flex-direction:column;gap:14px;max-height:70vh;overflow-y:auto}}
#buy-modal .bm-sec{{display:flex;flex-direction:column;gap:6px}}
#buy-modal .bm-lbl{{font-size:10px;color:var(--accent);letter-spacing:0.22em;text-transform:uppercase;font-weight:700}}
#buy-modal .bm-provs{{display:grid;grid-template-columns:repeat(3,1fr);gap:6px}}
#buy-modal .bm-prov{{position:relative;border:1px solid var(--line);background:#111;padding:10px 8px;border-radius:4px;cursor:pointer;text-align:center;transition:border-color 0.15s,background 0.15s}}
#buy-modal .bm-prov:hover{{border-color:var(--accent)}}
#buy-modal .bm-prov input{{position:absolute;opacity:0;pointer-events:none}}
#buy-modal .bm-prov.selected{{border-color:var(--accent);background:var(--accent-rgba)}}
#buy-modal .bm-prov .p-name{{font-size:11px;font-weight:700;color:var(--fg);margin-bottom:3px}}
#buy-modal .bm-prov .p-meta{{font-size:9.5px;color:var(--mute);letter-spacing:0.06em;line-height:1.4}}
#buy-modal .bm-prov.disabled{{opacity:0.32;cursor:not-allowed}}
#buy-modal select,#buy-modal input[type=email],#buy-modal input[type=number]{{background:#0a0a0a;border:1px solid var(--line);color:var(--fg);padding:9px 11px;font-family:inherit;font-size:13px;border-radius:4px;width:100%;box-sizing:border-box}}
#buy-modal select:focus,#buy-modal input:focus{{outline:none;border-color:var(--accent)}}
#buy-modal .bm-row{{display:grid;grid-template-columns:1fr 1fr;gap:10px}}
#buy-modal .bm-sizes{{display:flex;flex-wrap:wrap;gap:6px}}
#buy-modal .bm-size{{flex:1;min-width:48px;border:1px solid var(--line);background:#111;color:var(--fg);padding:8px 4px;border-radius:4px;cursor:pointer;font-family:inherit;font-size:12px;font-weight:600;text-align:center}}
#buy-modal .bm-size.selected{{border-color:var(--accent);background:var(--accent-rgba);color:var(--accent)}}
#buy-modal .bm-total{{display:flex;align-items:baseline;justify-content:space-between;border-top:1px solid var(--line);padding-top:12px;margin-top:4px}}
#buy-modal .bm-total .tl{{font-size:10px;color:var(--mute);letter-spacing:0.2em;text-transform:uppercase}}
#buy-modal .bm-total .tv{{font-size:22px;font-weight:700;color:var(--fg);font-variant-numeric:tabular-nums}}
#buy-modal .bm-cta{{background:var(--accent);color:#000;border:0;font-weight:700;padding:14px;font-size:13px;letter-spacing:0.08em;cursor:pointer;border-radius:4px;font-family:inherit;text-align:center;transition:opacity 0.15s}}
#buy-modal .bm-cta:hover:not(:disabled){{opacity:0.85}}
#buy-modal .bm-cta:disabled{{opacity:0.5;cursor:not-allowed}}
#buy-modal .bm-err{{font-size:11px;color:#ff6464;line-height:1.6;display:none}}
#buy-modal .bm-err.show{{display:block}}
#buy-modal .bm-note{{font-size:10px;color:var(--mute);line-height:1.6}}
</style>
</head><body>
<div class="wrap">
  <div class="status-banner">
    <span class="label">━◯━ {status_label}</span>
    <span style="color:var(--fg);font-weight:600">{display_name} × MU</span>
    <span class="meta">{n_sku} SKUs · ¥{total_jpy} catalog</span>
  </div>
  <div class="tagline">{tagline}</div>
  <h1>{h1}</h1>
  <div class="subtitle">{subtitle}</div>
  <div class="hero">
    <div class="lede">{lede}</div>
    <div class="hero-card">{hero_kv_html}</div>
  </div>
  <h2>Why ━◯━ {display_name}</h2>
  <div class="why">{why_md}</div>
  {mu_intro_html}
  <h2>想定ユースケース</h2>
  <ul class="use-cases">{use_cases_html}</ul>
  <h2>仕組み (mechanism)</h2>
  <div class="mech">{mechanism_html}</div>
  <h2>3 つの始め方 (options)</h2>
  <div class="options">{options_html}</div>
  <h2>条件 (terms)</h2>
  <table class="terms"><tbody>{terms_html}</tbody></table>
  <h2>立ち上げスケジュール (timeline)</h2>
  <div class="timeline">{timeline_html}</div>
  <h2>カタログ {n_sku} SKU</h2>
  <div class="grid">{cards_html}</div>
  <div class="extras-cta">
    <h3>+30 SKU 追加</h3>
    <p>初回 30 SKU は無料 (10 pt/SKU、首回エミルで free_30 適用)。AI 自動生成 → 個別承認後に <code>proposal_skus</code> へ追記されます。</p>
    <form id="extras-form-{slug}" onsubmit="return false">
      <input type="email" id="extras-email-{slug}" placeholder="email — 初回 30 SKU 無料アクセス用" required autocomplete="email">
      <button type="submit" id="extras-submit-{slug}">+30 SKU 生成キューに投入</button>
    </form>
    <div class="result" id="extras-result-{slug}">qty=30 固定 · 50 / 100 は <code>POST /api/proposal/{slug}/extras/order</code> 直叩きで指定可。job 状況は <code>GET /api/proposal/extras/job/&lt;job_id&gt;</code>。</div>
  </div>

  <!-- ── shared buy modal (1 instance per page) ──
       Opens when any .card .buy[data-action="open-modal"] is clicked. The
       handler reads data-product-id / data-kind / data-default-price / data-name
       / data-img off the trigger, hydrates the modal, and on submit POSTs
       {{product_id, quantity, email, size, variant_type, pod_provider}} to
       /api/checkout. The server's lookup_variant_price() then overrides the
       bonding-curve price with the matrix value for that (type, pod) combo. -->
  <dialog id="buy-modal" aria-labelledby="bm-title">
    <div class="bm-hd">
      <img class="bm-img" id="bm-img" src="" alt="">
      <div>
        <div class="bm-title" id="bm-title">—</div>
        <div class="bm-sub" id="bm-sub">SKU</div>
      </div>
      <button type="button" class="bm-close" id="bm-close" aria-label="close">×</button>
    </div>
    <form class="bm-body" id="bm-form" method="dialog">
      <div class="bm-sec">
        <div class="bm-lbl">配送元 / Provider</div>
        <div class="bm-provs" id="bm-provs"></div>
      </div>
      <div class="bm-sec" id="bm-fabric-sec">
        <div class="bm-lbl">生地 / Fabric</div>
        <select id="bm-fabric"></select>
      </div>
      <div class="bm-sec" id="bm-size-sec">
        <div class="bm-lbl">サイズ / Size</div>
        <div class="bm-sizes" id="bm-sizes"></div>
      </div>
      <div class="bm-row">
        <div class="bm-sec">
          <div class="bm-lbl">数量 / Qty</div>
          <input type="number" id="bm-qty" min="1" max="5" value="1">
        </div>
        <div class="bm-sec">
          <div class="bm-lbl">メアド (任意)</div>
          <input type="email" id="bm-email" placeholder="you@example.com" autocomplete="email">
        </div>
      </div>
      <div class="bm-total"><div class="tl">合計 / Total</div><div class="tv" id="bm-total">¥—</div></div>
      <div class="bm-err" id="bm-err"></div>
      <button type="submit" class="bm-cta" id="bm-cta">Stripe で買う →</button>
      <div class="bm-note">配送元と生地は <code>/api/checkout</code> が <code>variant_type × pod_provider</code> 行列で照合 → 価格を確定します。 メアドは Stripe にも入力できますが、 ここに入れておくと購入後のサポート連絡が早くなります。</div>
    </form>
  </dialog>

  <script>
  // ── VARIANT_PRICES: client-side mirror of product_variants_matrix() ──
  // Kept in sync with store/src/main.rs::product_variants_matrix() so the
  // total updates without a round-trip. The server still re-checks via
  // lookup_variant_price() so a stale client cannot order an unavailable
  // combo. fabrics list is curated per (kind, pod) — names follow the
  // memory notes (gelato_api.md, wearmu_suzuri_mirror.md).
  var VARIANT_PRICES = {{
    tee: {{
      printful_eu: [
        {{ id:'bella_canvas',     label:'Bella+Canvas 4.2oz (Premium)',  price: 5000 }},
        {{ id:'gildan_5000',      label:'Gildan 5000 6oz (Heavyweight)', price: 5000 }},
        {{ id:'triblend',         label:'Triblend 4.2oz (Lightweight)',  price: 5000 }}
      ],
      gelato_jp: [
        {{ id:'gildan_h000',      label:'Gildan H000 6oz (Heavyweight 🇯🇵)', price: 4500 }},
        {{ id:'american_apparel', label:'American Apparel 5oz (Premium 🇯🇵)', price: 4500 }}
      ],
      suzuri_jp: [
        {{ id:'printstar_5_6oz',  label:'Printstar 5.6oz (Standard 🇯🇵)',     price: 4900 }},
        {{ id:'heavyweight_7oz',  label:'Heavyweight 7oz (Premium 🇯🇵)',      price: 4900 }}
      ]
    }},
    hoodie: {{
      printful_eu: [
        {{ id:'premium_9oz',      label:'Premium 9oz (Heavyweight)',     price: 9800 }},
        {{ id:'gildan_18500',     label:'Gildan 18500 8oz (Standard)',   price: 9800 }}
      ],
      gelato_jp: [
        {{ id:'standard_8oz',     label:'Standard 8oz 🇯🇵',                price: 8500 }}
      ],
      suzuri_jp: [
        {{ id:'standard',         label:'Standard pullover 🇯🇵',           price: 7800 }}
      ]
    }},
    longsleeve: {{
      printful_eu: [
        {{ id:'standard_5oz',     label:'Standard 5oz long sleeve',      price: 6800 }}
      ],
      suzuri_jp: [
        {{ id:'standard_6oz',     label:'Standard 6oz long sleeve 🇯🇵',    price: 6500 }}
      ]
    }},
    tank: {{
      printful_eu: [
        {{ id:'standard_4oz',     label:'Standard 4oz tank',             price: 5500 }}
      ]
    }},
    polo: {{
      printful_eu: [
        {{ id:'standard_polo',    label:'Standard pique polo',           price: 9800 }}
      ]
    }},
    tote: {{
      printful_eu: [
        {{ id:'organic_canvas',   label:'Organic canvas tote',           price: 3800 }}
      ],
      gelato_jp: [
        {{ id:'standard_tote',    label:'Standard 12oz tote 🇯🇵',          price: 3200 }}
      ],
      suzuri_jp: [
        {{ id:'natural_tote',     label:'Natural canvas tote 🇯🇵',         price: 3500 }}
      ]
    }},
    mug: {{
      gelato_jp: [
        {{ id:'ceramic_11oz',     label:'Ceramic 11oz mug 🇯🇵',            price: 2800 }}
      ],
      suzuri_jp: [
        {{ id:'standard_mug',     label:'Standard 11oz mug 🇯🇵',           price: 2500 }}
      ]
    }},
    sticker: {{
      suzuri_jp: [
        {{ id:'die_cut',          label:'Die-cut vinyl sticker 🇯🇵',       price:  800 }}
      ]
    }}
  }};
  var PROVIDERS = [
    {{ id:'printful_eu', name:'Printful',  region:'EU → JP', ship:'14-21d' }},
    {{ id:'gelato_jp',   name:'Gelato',    region:'国内印刷',  ship:'5-10d'  }},
    {{ id:'suzuri_jp',   name:'SUZURI',    region:'国内印刷',  ship:'5-8d'   }}
  ];
  // wearable kinds get size pickers; non-wear (tote/mug/sticker) skip.
  var WEAR_KINDS  = ['tee','hoodie','longsleeve','tank','polo'];
  var SIZE_LIST   = ['S','M','L','XL'];

  function fmtJPY(n){{ return '¥' + Number(n||0).toLocaleString('ja-JP'); }}

  // ── Buy buttons → open modal ──
  // Each .card .buy[data-action=open-modal] hydrates and opens the shared
  // <dialog id=buy-modal>. The trailing submit handler POSTs to /api/checkout.
  (function(){{
    var dlg   = document.getElementById('buy-modal');
    if (!dlg) return;
    var img   = document.getElementById('bm-img');
    var title = document.getElementById('bm-title');
    var sub   = document.getElementById('bm-sub');
    var provs = document.getElementById('bm-provs');
    var fabricSec = document.getElementById('bm-fabric-sec');
    var fabricSel = document.getElementById('bm-fabric');
    var sizeSec   = document.getElementById('bm-size-sec');
    var sizes     = document.getElementById('bm-sizes');
    var qty       = document.getElementById('bm-qty');
    var email     = document.getElementById('bm-email');
    var totalEl   = document.getElementById('bm-total');
    var err       = document.getElementById('bm-err');
    var cta       = document.getElementById('bm-cta');
    var form      = document.getElementById('bm-form');
    var closeBtn  = document.getElementById('bm-close');

    var state = {{ product_id:null, kind:'tee', provider:null, fabric:null, size:'M', name:'', img:'' }};

    function pickInitialProvider(kind){{
      var map = VARIANT_PRICES[kind] || {{}};
      // Preference: gelato_jp → printful_eu → suzuri_jp → first available.
      if (map.gelato_jp)  return 'gelato_jp';
      if (map.printful_eu) return 'printful_eu';
      if (map.suzuri_jp)  return 'suzuri_jp';
      var keys = Object.keys(map);
      return keys[0] || null;
    }}

    function renderProviders(){{
      provs.innerHTML = '';
      var map = VARIANT_PRICES[state.kind] || {{}};
      PROVIDERS.forEach(function(p){{
        var available = !!map[p.id];
        var sel = state.provider === p.id;
        var el = document.createElement('label');
        el.className = 'bm-prov' + (sel?' selected':'') + (available?'':' disabled');
        el.innerHTML =
          '<input type="radio" name="bm-provider" value="'+p.id+'"'+(sel?' checked':'')+(available?'':' disabled')+'>' +
          '<div class="p-name">'+p.name+'</div>' +
          '<div class="p-meta">'+p.region+'<br>'+p.ship+'</div>';
        if (available){{
          el.addEventListener('click', function(){{
            state.provider = p.id;
            // Default fabric to first available for the new provider.
            var fabrics = (VARIANT_PRICES[state.kind]||{{}})[state.provider] || [];
            state.fabric = fabrics[0] ? fabrics[0].id : null;
            renderProviders();
            renderFabrics();
            updateTotal();
          }});
        }}
        provs.appendChild(el);
      }});
    }}

    function renderFabrics(){{
      var fabrics = ((VARIANT_PRICES[state.kind]||{{}})[state.provider]) || [];
      if (!fabrics.length){{
        fabricSec.style.display = 'none';
        fabricSel.innerHTML = '';
        return;
      }}
      fabricSec.style.display = '';
      fabricSel.innerHTML = '';
      fabrics.forEach(function(f){{
        var o = document.createElement('option');
        o.value = f.id;
        o.textContent = f.label + ' · ' + fmtJPY(f.price);
        if (state.fabric === f.id) o.selected = true;
        fabricSel.appendChild(o);
      }});
      if (!state.fabric && fabrics[0]) state.fabric = fabrics[0].id;
    }}

    function renderSizes(){{
      if (WEAR_KINDS.indexOf(state.kind) < 0){{
        sizeSec.style.display = 'none';
        state.size = null;
        return;
      }}
      sizeSec.style.display = '';
      sizes.innerHTML = '';
      SIZE_LIST.forEach(function(s){{
        var b = document.createElement('button');
        b.type = 'button';
        b.className = 'bm-size' + (state.size === s ? ' selected' : '');
        b.textContent = s;
        b.addEventListener('click', function(){{
          state.size = s;
          renderSizes();
        }});
        sizes.appendChild(b);
      }});
    }}

    function currentUnitPrice(){{
      var fabrics = ((VARIANT_PRICES[state.kind]||{{}})[state.provider]) || [];
      var f = fabrics.find(function(x){{ return x.id === state.fabric; }});
      return f ? f.price : 0;
    }}

    function updateTotal(){{
      var q = Math.max(1, Math.min(5, parseInt(qty.value || '1', 10) || 1));
      totalEl.textContent = fmtJPY(currentUnitPrice() * q);
    }}

    fabricSel.addEventListener('change', function(){{
      state.fabric = fabricSel.value;
      updateTotal();
    }});
    qty.addEventListener('input', updateTotal);

    function openFor(btn){{
      state.product_id = parseInt(btn.dataset.productId || '0', 10) || null;
      state.kind       = (btn.dataset.kind || 'tee').toLowerCase();
      state.name       = btn.dataset.name || 'MU SKU';
      state.img        = btn.dataset.img || '';
      state.provider   = pickInitialProvider(state.kind);
      var fabrics = ((VARIANT_PRICES[state.kind]||{{}})[state.provider]) || [];
      state.fabric = fabrics[0] ? fabrics[0].id : null;
      state.size   = WEAR_KINDS.indexOf(state.kind) >= 0 ? 'M' : null;
      qty.value = 1;
      err.classList.remove('show'); err.textContent = '';
      cta.disabled = false; cta.textContent = 'Stripe で買う →';
      title.textContent = state.name;
      sub.textContent   = state.kind.toUpperCase();
      if (state.img){{ img.src = state.img; img.style.display=''; }} else {{ img.style.display='none'; }}
      renderProviders();
      renderFabrics();
      renderSizes();
      updateTotal();
      if (typeof dlg.showModal === 'function') dlg.showModal(); else dlg.setAttribute('open','');
    }}

    document.querySelectorAll('.card .buy[data-action="open-modal"]').forEach(function(btn){{
      btn.addEventListener('click', function(){{ openFor(btn); }});
    }});

    closeBtn.addEventListener('click', function(){{ dlg.close(); }});
    dlg.addEventListener('click', function(e){{ if (e.target === dlg) dlg.close(); }});

    form.addEventListener('submit', async function(e){{
      e.preventDefault();
      if (!state.product_id){{ return; }}
      if (!state.provider || !state.fabric){{
        err.classList.add('show');
        err.textContent = '配送元と生地を選んでください。';
        return;
      }}
      var q = Math.max(1, Math.min(5, parseInt(qty.value || '1', 10) || 1));
      var body = {{
        product_id: state.product_id,
        quantity:   q,
        variant_type: state.kind,
        pod_provider: state.provider
      }};
      if (state.size)         body.size  = state.size;
      var em = (email.value || '').trim();
      if (em && em.indexOf('@') > 0) body.email = em;
      cta.disabled = true; cta.textContent = '読み込み中 …'; err.classList.remove('show');
      try {{
        var r = await fetch('/api/checkout', {{
          method:'POST', headers:{{'Content-Type':'application/json'}},
          body: JSON.stringify(body)
        }});
        var j = await r.json().catch(function(){{ return {{}}; }});
        if (r.ok && j.url) {{ window.location.href = j.url; return; }}
        err.classList.add('show');
        err.textContent = '購入ページを開けませんでした (HTTP ' + r.status + ')。 ' + (j.error || '');
      }} catch (e2) {{
        err.classList.add('show');
        err.textContent = '通信エラー: ' + e2.message;
      }} finally {{
        cta.disabled = false; cta.textContent = 'Stripe で買う →';
      }}
    }});
  }})();
  (function(){{
    var form  = document.getElementById('extras-form-{slug}');
    var btn   = document.getElementById('extras-submit-{slug}');
    var inp   = document.getElementById('extras-email-{slug}');
    var out   = document.getElementById('extras-result-{slug}');
    if (!form) return;
    form.addEventListener('submit', async function(e){{
      e.preventDefault();
      var email = (inp.value || '').trim();
      if (!email || email.indexOf('@') < 0) {{
        out.className='result err'; out.textContent='valid email required'; return;
      }}
      btn.disabled = true; out.className='result'; out.textContent='submitting …';
      try {{
        var r = await fetch('/api/proposal/{slug}/extras/order', {{
          method:'POST',
          headers:{{'Content-Type':'application/json'}},
          body: JSON.stringify({{email: email, qty: 30, notify_email: true}}),
        }});
        var j = await r.json();
        if (r.ok && j.ok !== false) {{
          out.className='result ok';
          out.innerHTML = '✓ queued · job_id=<code>'+(j.job_id||'?')+'</code> · cost=<code>'+(j.cost||0)+' pt</code>' + (j.free_applied?' (free_30 applied)':'') + ' — 完了で <code>'+email+'</code> 宛にメール通知。';
        }} else {{
          out.className='result err';
          out.textContent = '✗ ' + (j.error || ('HTTP '+r.status));
        }}
      }} catch (err) {{
        out.className='result err'; out.textContent = '✗ ' + err.message;
      }} finally {{ btn.disabled = false; }}
    }});
  }})();
  </script>
  <footer>
    <p>© 株式会社イネブラ / MU · <a href="https://wearmu.com">wearmu.com</a> · IP owner: {ip_owner} · <a href="/api-keys">API key を発行</a></p>
    <p>自分のブランドを立ち上げる: <a href="/api-keys">/api-keys</a> → email でログイン → 30 pt / SKU で公開販売可。</p>
    <p style="opacity:0.6;margin-top:12px">このページは <code>proposals</code> + <code>proposal_skus</code> テーブルから動的に生成されています。静的ファイルなし。</p>
  </footer>
</div>
</body></html>"#,
        display_name = html_escape(&display_name),
        tagline = html_escape(&tagline),
        h1 = h1,
        subtitle = html_escape(&subtitle),
        lede = lede,
        why_md = why_md,
        accent = accent,
        accent_rgba = accent_rgba,
        status_label = status_label,
        n_sku = n_sku,
        total_jpy = format_jpy(total_jpy),
        hero_kv_html = hero_kv_html,
        use_cases_html = use_cases_html,
        mu_intro_html = mu_intro_html,
        mechanism_html = mechanism_html,
        options_html = options_html,
        terms_html = terms_html,
        timeline_html = timeline_html,
        cards_html = cards_html,
        ip_owner = html_escape(ip_owner),
        slug = slug,
        robots_meta = robots_meta,
        canonical_url_localized = html_attr_escape(&canonical_url_localized),
        hreflang_links = hreflang_links,
        html_lang_attr = html_lang_attr,
        og_locale_primary = og_locale_primary,
        og_locale_alt = og_locale_alt,
        title_suffix = title_suffix,
        meta_desc_text_esc = html_attr_escape(&meta_desc_text),
        og_desc_lp_esc = html_attr_escape(&og_desc_lp),
        og_image_lp_esc = html_attr_escape(&og_image_lp),
    )
}

#[derive(Deserialize)]
struct ProposalApproveBody {
    approver_name: String,
    approver_email: String,
    #[serde(default)] plan_tier: String,
    #[serde(default)] note: String,
}

/// POST /api/proposal/:slug/approve — admin-gated.
async fn proposal_generic_approve(
    State(db): State<Db>,
    axum::extract::Path(slug): axum::extract::Path<String>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(body): Json<ProposalApproveBody>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), &format!("/api/proposal/{}/approve", slug)).await { return r; }
    let name = body.approver_name.trim();
    let email = body.approver_email.trim().to_lowercase();
    if name.is_empty() || !email.contains('@') {
        return (StatusCode::BAD_REQUEST, "approver_name + valid approver_email required").into_response();
    }
    let plan = match body.plan_tier.trim().to_lowercase().as_str() {
        "starter" | "growth" | "enterprise" => body.plan_tier.trim().to_lowercase(),
        _ => "starter".into(),
    };
    let ip = client_ip(&headers);
    let now = chrono_now();
    let (activated, total) = {
        let conn = db.lock().unwrap();
        if proposal_row(&conn, &slug).is_none() {
            return (StatusCode::NOT_FOUND, "unknown proposal slug").into_response();
        }
        let _ = conn.execute(
            "UPDATE proposals SET
                approved_at=?, approver_name=?, approver_email=?, approver_ip=?,
                plan_tier=?, note=?, revoked_at=NULL
             WHERE slug=?",
            params![now, name, email, ip, plan, body.note.trim(), slug],
        );
        let activated = conn.execute(
            "UPDATE products SET active=1 WHERE brand LIKE ?||'%' AND active=0",
            params![format!("{}_", slug)],
        ).unwrap_or(0);
        let total: i64 = conn.query_row(
            "SELECT COUNT(*) FROM proposal_skus WHERE slug=?",
            params![slug], |r| r.get(0),
        ).unwrap_or(0);
        (activated, total)
    };
    let alert = format!(
        "━◯━ {} collab APPROVED\napprover: {} <{}>\nplan: {}\nproducts activated: {}/{}\nat: {}\nnext: 全 SKU が公式販売中 (https://wearmu.com/proposals/{})",
        slug, name, email, plan, activated, total, now, slug,
    );
    tokio::spawn(async move { send_telegram_message(&alert).await; });
    Json(serde_json::json!({
        "ok": true, "slug": slug, "approved_at": now,
        "products_activated": activated, "products_total": total, "plan_tier": plan,
    })).into_response()
}

/// POST /api/proposal/:slug/revoke — admin-gated.
async fn proposal_generic_revoke(
    State(db): State<Db>,
    axum::extract::Path(slug): axum::extract::Path<String>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), &format!("/api/proposal/{}/revoke", slug)).await { return r; }
    let now = chrono_now();
    let deactivated = {
        let conn = db.lock().unwrap();
        if proposal_row(&conn, &slug).is_none() {
            return (StatusCode::NOT_FOUND, "unknown proposal slug").into_response();
        }
        let _ = conn.execute(
            "UPDATE proposals SET revoked_at=? WHERE slug=?",
            params![now, slug],
        );
        conn.execute(
            "UPDATE products SET active=0 WHERE brand LIKE ?||'%' AND active=1",
            params![format!("{}_", slug)],
        ).unwrap_or(0)
    };
    Json(serde_json::json!({
        "ok": true, "slug": slug, "revoked_at": now, "products_deactivated": deactivated,
    })).into_response()
}

// ───────────────────────────────────────────────────────────────────────
// Partner self-serve consent: OK → 即販売開始 / NG → 見送り記録。
// admin master token は partner に渡さない。proposal ごとの capability token
// (meta_json.consent_token) を発行し、decide ページ URL に載せて partner に
// 送る。「権利侵害しない限り」= 公開されるのは MU オリジナル意匠のみ。商標・
// ロゴ・肖像の利用を含む提案 (meta.uses_partner_ip=true) はワンクリック公開を
// 禁止し、書面合意のうえ管理者承認に倒す。
// ───────────────────────────────────────────────────────────────────────

/// Constant-time string compare for capability tokens (no timing oracle).
fn ct_eq_str(a: &str, b: &str) -> bool {
    let (a, b) = (a.as_bytes(), b.as_bytes());
    if a.len() != b.len() { return false; }
    let mut diff = 0u8;
    for i in 0..a.len() { diff |= a[i] ^ b[i]; }
    diff == 0
}

fn proposal_meta_value(conn: &rusqlite::Connection, slug: &str) -> serde_json::Value {
    let s: Option<String> = conn.query_row(
        "SELECT meta_json FROM proposals WHERE slug=?",
        params![slug], |r| r.get(0),
    ).ok().flatten();
    s.as_deref()
        .and_then(|s| serde_json::from_str(s).ok())
        .unwrap_or_else(|| serde_json::json!({}))
}

fn proposal_set_meta(conn: &rusqlite::Connection, slug: &str, meta: &serde_json::Value) {
    let _ = conn.execute(
        "UPDATE proposals SET meta_json=? WHERE slug=?",
        params![meta.to_string(), slug],
    );
}

/// Ensure (and return) a per-proposal consent capability token. None if the
/// proposal slug doesn't exist.
fn proposal_ensure_consent_token(conn: &rusqlite::Connection, slug: &str) -> Option<String> {
    if proposal_row(conn, slug).is_none() { return None; }
    let mut meta = proposal_meta_value(conn, slug);
    if let Some(t) = meta.get("consent_token").and_then(|v| v.as_str()) {
        if !t.is_empty() { return Some(t.to_string()); }
    }
    let token = mypage_random_token();
    if let Some(obj) = meta.as_object_mut() {
        obj.insert("consent_token".into(), serde_json::json!(token));
    }
    proposal_set_meta(conn, slug, &meta);
    Some(token)
}

/// GET /api/admin/proposal/:slug/consent_link — admin-gated. Mints (or returns
/// the existing) consent token + the partner-facing decide URL to send out.
async fn admin_proposal_consent_link(
    State(db): State<Db>,
    axum::extract::Path(slug): axum::extract::Path<String>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(),
        &format!("/api/admin/proposal/{}/consent_link", slug)).await { return r; }
    let token = {
        let conn = db.lock().unwrap();
        match proposal_ensure_consent_token(&conn, &slug) {
            Some(t) => t,
            None => return (StatusCode::NOT_FOUND, "unknown proposal slug").into_response(),
        }
    };
    let url = format!("https://wearmu.com/proposal/{}/decide?t={}", slug, token);
    Json(serde_json::json!({
        "ok": true, "slug": slug, "decide_url": url, "consent_token": token,
    })).into_response()
}

/// GET /proposal/:slug/decide?t=<consent_token> — partner-facing decision page.
/// Capability-gated: invalid/missing token → 404 (no existence leak).
async fn proposal_decide_page(
    State(db): State<Db>,
    axum::extract::Path(slug): axum::extract::Path<String>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let t = q.get("t").map(|s| s.trim()).unwrap_or("");
    let not_found = || (StatusCode::NOT_FOUND, axum::response::Html(
        "<!doctype html><meta charset=utf-8><title>404</title><body style='background:#0a0a0a;color:#888;font-family:system-ui;text-align:center;padding:20vh'>404</body>".to_string()
    )).into_response();

    let (name, approved, declined, uses_partner_ip, n_sku, total_jpy, accent) = {
        let conn = db.lock().unwrap();
        let row = match proposal_row(&conn, &slug) { Some(r) => r, None => return not_found() };
        let meta = proposal_meta_value(&conn, &slug);
        let stored = meta.get("consent_token").and_then(|v| v.as_str()).unwrap_or("");
        if stored.is_empty() || t.is_empty() || !ct_eq_str(t, stored) { return not_found(); }
        let approved = row.2.is_some() && row.6.is_none();
        let declined = meta.get("declined_at").and_then(|v| v.as_str()).map(|s| !s.is_empty()).unwrap_or(false);
        let uses_partner_ip = meta.get("uses_partner_ip").and_then(|v| v.as_bool()).unwrap_or(false);
        let n_sku: i64 = conn.query_row("SELECT COUNT(*) FROM proposal_skus WHERE slug=?", params![slug], |r| r.get(0)).unwrap_or(0);
        let total_jpy: i64 = conn.query_row("SELECT COALESCE(SUM(price_jpy),0) FROM proposal_skus WHERE slug=?", params![slug], |r| r.get(0)).unwrap_or(0);
        let accent = meta.get("accent_hex").and_then(|v| v.as_str()).filter(|s| s.starts_with('#') && s.len() <= 7).unwrap_or("#7be57b").to_string();
        (row.0, approved, declined, uses_partner_ip, n_sku, total_jpy, accent)
    };

    let title = html_escape(&name);
    let safe_line = "公開されるのは <b>MU オリジナル意匠のみ</b>。貴社の商標・ロゴ・肖像・楽曲等は使用しません。";
    let terms_line = "「OK」を押すと、上記 SKU が即座に wearmu.com で販売開始されます（在庫リスクゼロのオンデマンド製造）。いつでも管理者連絡で停止できます。";

    let body_main = if approved {
        format!("<div class='card'><div class='badge'>● 販売中</div><h1>{title}</h1><p>この提案は承認済みで、現在 wearmu.com で販売中です。</p><a class='btn ok' href='/{slug}'>商品ページを開く →</a></div>",
            title=title, slug=html_attr_escape(&slug))
    } else if declined {
        format!("<div class='card'><div class='badge gray'>見送り</div><h1>{title}</h1><p>この提案は「見送り」として記録済みです。再検討の際は mail@yukihamada.jp までご連絡ください。</p></div>", title=title)
    } else {
        let ok_block = if uses_partner_ip {
            "<button class='btn ok' disabled>OK（書面合意が必要）</button><p class='note'>この提案は商標・ロゴ等の利用を含むため、ワンクリック公開はできません。書面合意のうえ管理者が公開します。</p>".to_string()
        } else {
            "<button class='btn ok' onclick=\"decide('ok')\">OK・販売を開始する</button>".to_string()
        };
        format!(
            "<div class='card'>\
             <div class='badge'>提案の確認</div>\
             <h1>{title}</h1>\
             <p class='lede'>{n} 型 / 合計 ¥{total}（バンドル）</p>\
             <div class='consent'>{safe}</div>\
             <p class='terms'>{terms}</p>\
             <div class='fields'>\
               <input id='nm' placeholder='お名前・ご担当者名' value='{namev}'>\
               <input id='em' placeholder='メール（任意）' type='email'>\
             </div>\
             <div id='actions'>{ok}\
               <button class='btn ng' onclick=\"decide('ng')\">今回は見送る</button>\
             </div>\
            </div>",
            title=title, n=n_sku, total=fmt_jpy(total_jpy), safe=safe_line, terms=terms_line,
            namev=html_attr_escape(&name), ok=ok_block,
        )
    };

    let css = r#"<style>
*{box-sizing:border-box}
body{margin:0;background:#0a0a0a;color:#f2f2ee;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;line-height:1.7;display:flex;flex-direction:column;min-height:100vh;align-items:center;justify-content:center;padding:24px}
.card{max-width:460px;width:100%;background:#121212;border:1px solid #262626;border-radius:18px;padding:32px}
.badge{display:inline-block;font-size:12px;letter-spacing:.08em;color:var(--a);border:1px solid var(--a);border-radius:999px;padding:3px 12px;margin-bottom:18px}
.badge.gray{color:#888;border-color:#444}
h1{font-size:24px;margin:0 0 8px;font-weight:700}
.lede{color:#bdbdb6;margin:0 0 18px}
.consent{background:rgba(255,255,255,.04);border:1px solid #2a2a2a;border-radius:12px;padding:14px 16px;font-size:14px;color:#dcdcd6;margin-bottom:14px}
.terms{font-size:12.5px;color:#9a9a92;margin:0 0 20px}
.fields{display:flex;flex-direction:column;gap:10px;margin-bottom:18px}
input{background:#0e0e0e;border:1px solid #303030;border-radius:10px;padding:12px 14px;color:#f2f2ee;font-size:15px}
#actions{display:flex;flex-direction:column;gap:10px}
.btn{display:block;text-align:center;text-decoration:none;border:none;border-radius:12px;padding:15px;font-size:16px;font-weight:700;cursor:pointer}
.btn.ok{background:var(--a);color:#0a0a0a}
.btn.ng{background:transparent;color:#bbb;border:1px solid #3a3a3a}
.btn:disabled{opacity:.4;cursor:not-allowed}
.note{font-size:12.5px;color:#c9a24a;margin:8px 0 0}
#result{max-width:460px;margin:16px auto 0;text-align:center;color:#cfcfc8}
</style>"#;

    let script = r#"<script>
const SLUG=document.body.dataset.slug, T=document.body.dataset.t;
async function decide(d){
  const btns=document.querySelectorAll('#actions button'); btns.forEach(b=>b.disabled=true);
  const name=(document.getElementById('nm')||{}).value||'';
  const email=(document.getElementById('em')||{}).value||'';
  const reason= d==='ng' ? (prompt('差し支えなければ理由を一言（任意）')||'') : '';
  let r,j;
  try{ r=await fetch(`/api/proposal/${SLUG}/consent`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({t:T,decision:d,name,email,reason})}); j=await r.json(); }
  catch(e){ document.getElementById('result').innerHTML='<p style="color:#ff8a8a">通信エラー</p>'; btns.forEach(b=>b.disabled=false); return; }
  const box=document.getElementById('result');
  if(r.ok && j.ok){
    document.getElementById('actions').style.display='none';
    if(d==='ok'){ box.innerHTML='<h2>✓ 販売を開始しました</h2><p>ありがとうございます。商品ページを開きます…</p>'; setTimeout(()=>location.href=(j.redirect||('/'+SLUG)),1500); }
    else { box.innerHTML='<h2>承りました</h2><p>今回は見送りとして記録しました。ご検討ありがとうございました。</p>'; }
  } else {
    box.innerHTML='<p style="color:#ff8a8a">'+((j&&j.error)||('エラー ('+r.status+')'))+'</p>'; btns.forEach(b=>b.disabled=false);
  }
}
</script>"#;

    let html = format!(
        "<!doctype html><html lang=ja><head><meta charset=utf-8><meta name=viewport content='width=device-width,initial-scale=1'><meta name=robots content='noindex,nofollow'><title>{title} — 確認</title><style>:root{{--a:{accent}}}</style>{css}</head><body data-slug=\"{slug}\" data-t=\"{tok}\">{body_main}<div id=result></div>{script}</body></html>",
        title=title, accent=html_attr_escape(&accent), css=css, slug=html_attr_escape(&slug),
        tok=html_attr_escape(t), body_main=body_main, script=script,
    );
    axum::response::Html(html).into_response()
}

#[derive(Deserialize)]
struct ProposalConsentBody {
    #[serde(default)] t: String,
    #[serde(default)] decision: String,
    #[serde(default)] name: String,
    #[serde(default)] email: String,
    #[serde(default)] reason: String,
}

/// POST /api/proposal/:slug/consent — partner self-serve OK/NG. Capability-
/// gated by the per-proposal consent token; light IP rate limit. OK flips the
/// proposal to approved + activates all SKUs (即販売開始). NG records a decline
/// and keeps everything non-public. Products that would touch a third party's
/// rights never auto-publish (uses_partner_ip guard → 409).
async fn proposal_consent(
    State(db): State<Db>,
    axum::extract::Path(slug): axum::extract::Path<String>,
    headers: HeaderMap,
    Json(body): Json<ProposalConsentBody>,
) -> Response {
    let ip = { let s = client_ip(&headers); if s.is_empty() { "unknown".to_string() } else { s } };
    let now_s: i64 = chrono_now().parse().unwrap_or(0);
    let hour_bucket = now_s / 3600;
    let rl_key = format!("consent:{}", ip);
    {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "INSERT INTO blog_rate_limit (ip, hour_bucket, hits) VALUES (?,?,1)
             ON CONFLICT(ip, hour_bucket) DO UPDATE SET hits = hits + 1",
            params![rl_key, hour_bucket]);
        let hits: i64 = conn.query_row(
            "SELECT hits FROM blog_rate_limit WHERE ip=? AND hour_bucket=?",
            params![rl_key, hour_bucket], |r| r.get(0)).unwrap_or(0);
        if hits > 30 {
            return (StatusCode::TOO_MANY_REQUESTS,
                Json(serde_json::json!({"error":"しばらく経ってから再度お試しください"}))).into_response();
        }
    }

    let decision = body.decision.trim().to_lowercase();
    if decision != "ok" && decision != "ng" {
        return (StatusCode::BAD_REQUEST,
            Json(serde_json::json!({"error":"decision must be ok|ng"}))).into_response();
    }
    let name = { let n = body.name.trim(); if n.is_empty() { "partner (self-serve)".to_string() } else { n.to_string() } };
    let email = body.email.trim().to_lowercase();
    let reason = body.reason.trim().to_string();
    let now = chrono_now();

    enum Outcome { Ok(i64), Ng, RightsHold, Reject }
    let outcome = {
        let conn = db.lock().unwrap();
        if proposal_row(&conn, &slug).is_none() {
            Outcome::Reject
        } else {
            let mut meta = proposal_meta_value(&conn, &slug);
            let stored = meta.get("consent_token").and_then(|v| v.as_str()).unwrap_or("").to_string();
            if stored.is_empty() || body.t.trim().is_empty() || !ct_eq_str(body.t.trim(), &stored) {
                Outcome::Reject
            } else if decision == "ok" {
                if meta.get("uses_partner_ip").and_then(|v| v.as_bool()).unwrap_or(false) {
                    Outcome::RightsHold
                } else {
                    let _ = conn.execute(
                        "UPDATE proposals SET approved_at=?, approver_name=?, approver_email=?, approver_ip=?, plan_tier=COALESCE(NULLIF(plan_tier,''),'starter'), revoked_at=NULL WHERE slug=?",
                        params![now, name, email, ip, slug]);
                    let activated = conn.execute(
                        "UPDATE products SET active=1 WHERE brand LIKE ?||'%' AND active=0",
                        params![format!("{}_", slug)]).unwrap_or(0) as i64;
                    if let Some(o) = meta.as_object_mut() {
                        o.insert("consented_via".into(), serde_json::json!("partner_link"));
                        o.insert("consented_at".into(), serde_json::json!(now));
                        o.remove("declined_at");
                    }
                    proposal_set_meta(&conn, &slug, &meta);
                    Outcome::Ok(activated)
                }
            } else {
                if let Some(o) = meta.as_object_mut() {
                    o.insert("declined_at".into(), serde_json::json!(now));
                    o.insert("declined_by".into(), serde_json::json!(name));
                    if !reason.is_empty() { o.insert("declined_reason".into(), serde_json::json!(reason)); }
                }
                proposal_set_meta(&conn, &slug, &meta);
                let _ = conn.execute("UPDATE products SET active=0 WHERE brand LIKE ?||'%' AND active=1", params![format!("{}_", slug)]);
                let _ = conn.execute("UPDATE proposals SET revoked_at=? WHERE slug=? AND approved_at IS NOT NULL", params![now, slug]);
                Outcome::Ng
            }
        }
    };

    match outcome {
        Outcome::Reject => (StatusCode::NOT_FOUND, Json(serde_json::json!({"error":"not found"}))).into_response(),
        Outcome::RightsHold => (StatusCode::CONFLICT, Json(serde_json::json!({
            "error":"この提案は商標・ロゴ等の利用を含むため、ワンクリック公開できません。書面合意のうえ管理者が公開します。"}))).into_response(),
        Outcome::Ok(activated) => {
            let alert = format!("━◯━ {} 提案を partner が自己承認 (OK)\nby: {} <{}>\nIP: {}\nactivated: {} SKU\n→ 即販売開始 https://wearmu.com/{}", slug, name, email, ip, activated, slug);
            tokio::spawn(async move { send_telegram_message(&alert).await; });
            Json(serde_json::json!({"ok":true,"decision":"ok","slug":slug,"products_activated":activated,"redirect":format!("/{}", slug)})).into_response()
        }
        Outcome::Ng => {
            let alert = format!("✕ {} 提案を partner が見送り (NG)\nby: {}\nreason: {}", slug, name, if reason.is_empty(){"—".to_string()}else{reason.clone()});
            tokio::spawn(async move { send_telegram_message(&alert).await; });
            Json(serde_json::json!({"ok":true,"decision":"ng","slug":slug})).into_response()
        }
    }
}

#[derive(Deserialize)]
struct ProposalCreateBody {
    slug: String,
    name: String,
    #[serde(default)] ip_owner: String,
    #[serde(default)] meta: Option<serde_json::Value>,
    skus: Vec<ProposalCreateSku>,
}
#[derive(Deserialize)]
struct ProposalCreateSku {
    letter: String,
    drop_num: i64,
    price_jpy: i64,
    label: String,
    kind: String,
    design_slug: String,
    #[serde(default)] design_url: Option<String>,
}

/// POST /admin/proposal — create a new brand in one call. Admin-gated.
/// Seeds proposals + proposal_skus rows + matching products rows. Idempotent
/// on slug — re-running upserts the SKU list. Does NOT auto-approve.
async fn proposal_generic_create(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(body): Json<ProposalCreateBody>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/admin/proposal").await { return r; }
    let slug = body.slug.trim().to_lowercase();
    if slug.is_empty() || !slug.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit() || c == '_') {
        return (StatusCode::BAD_REQUEST, "slug must be [a-z0-9_]+").into_response();
    }
    if body.name.trim().is_empty() {
        return (StatusCode::BAD_REQUEST, "name required").into_response();
    }
    if body.skus.is_empty() {
        return (StatusCode::BAD_REQUEST, "at least one SKU required").into_response();
    }
    let ip_owner = if body.ip_owner.trim().is_empty() { body.name.clone() } else { body.ip_owner.clone() };
    let meta_json: Option<String> = body.meta.as_ref().map(|m| m.to_string());
    let now = chrono_now();
    let mut inserted = 0i64;
    {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "INSERT INTO proposals (slug, name, ip_owner, created_at, meta_json)
             VALUES (?, ?, ?, ?, ?)
             ON CONFLICT(slug) DO UPDATE SET
                name=excluded.name,
                ip_owner=excluded.ip_owner,
                meta_json=COALESCE(excluded.meta_json, proposals.meta_json)",
            params![slug, body.name.trim(), ip_owner, now, meta_json],
        );
        for s in &body.skus {
            let letter = s.letter.trim().to_lowercase();
            let kind = s.kind.trim();
            let design_slug = s.design_slug.trim();
            if letter.is_empty() || kind.is_empty() || design_slug.is_empty() { continue; }
            let _ = conn.execute(
                "INSERT INTO proposal_skus (slug, letter, drop_num, price_jpy, label, kind, design_slug, design_url)
                 VALUES (?,?,?,?,?,?,?,?)
                 ON CONFLICT(slug, letter) DO UPDATE SET
                    drop_num=excluded.drop_num, price_jpy=excluded.price_jpy,
                    label=excluded.label, kind=excluded.kind,
                    design_slug=excluded.design_slug,
                    design_url=COALESCE(excluded.design_url, proposal_skus.design_url)",
                params![slug, letter, s.drop_num, s.price_jpy, s.label.trim(), kind, design_slug, s.design_url],
            );
            // Seed the matching products row.
            let brand = proposal_brand_for_kind(&slug, kind);
            let exists: bool = conn.query_row(
                "SELECT 1 FROM products WHERE brand=? AND drop_num=? LIMIT 1",
                params![brand, s.drop_num], |r| r.get::<_, i64>(0),
            ).is_ok();
            if !exists {
                let design_url = s.design_url.clone().unwrap_or_else(|| {
                    format!("https://wearmu.com/static/proposals/{}-design-{}.png", slug, design_slug)
                });
                let mockup_url = format!("https://wearmu.com/static/proposals/{}-mockup-{}.png", slug, letter);
                let _ = conn.execute(
                    "INSERT INTO products
                        (brand, drop_num, name, design_url, mockup_url, price_jpy, inventory, active, created_at, weather_data)
                     VALUES (?,?,?,?,?,?,?,?,?,?)",
                    params![
                        brand, s.drop_num,
                        format!("━◯━ MU × {} · {} · {}", ip_owner, letter.to_uppercase(), s.label.trim()),
                        design_url, mockup_url, s.price_jpy, 50, 1, now,
                        serde_json::json!({
                            "kind": format!("{}_{}", slug, kind),
                            "design_slug": design_slug,
                            "license_status": "pending",
                            "ip_owner": ip_owner,
                        }).to_string(),
                    ],
                );
                inserted += 1;
            } else if let Some(new_url) = s.design_url.as_deref().map(|u| u.trim()).filter(|u| !u.is_empty()) {
                // Always sync products.design_url to the latest from the upsert
                // when a non-empty design_url is supplied. Previously this only
                // ran for legacy `/proposals/design-%` paths, which left stale
                // placeholders in products.design_url and caused SUZURI publish
                // to upload the wrong (= often identical placeholder) design
                // across drops sharing the seeded placeholder URL.
                let _ = conn.execute(
                    "UPDATE products SET design_url = ?
                     WHERE brand=? AND drop_num=? AND COALESCE(design_url,'') != ?",
                    params![new_url, brand, s.drop_num, new_url],
                );
            } else {
                // No design_url supplied on this upsert — only backfill legacy
                // `/proposals/design-%` 404 paths so we don't clobber a good URL.
                let _ = conn.execute(
                    "UPDATE products SET
                        design_url = ?,
                        mockup_url = COALESCE(NULLIF(mockup_url, ''), ?)
                     WHERE brand=? AND drop_num=?
                       AND (design_url IS NULL OR design_url='' OR design_url LIKE 'https://wearmu.com/proposals/design-%')",
                    params![
                        format!("https://wearmu.com/static/proposals/{}-design-{}.png", slug, design_slug),
                        format!("https://wearmu.com/static/proposals/{}-mockup-{}.png", slug, letter),
                        brand, s.drop_num,
                    ],
                );
            }
        }
    }
    Json(serde_json::json!({
        "ok": true, "slug": slug, "name": body.name.trim(),
        "skus_total": body.skus.len(), "products_inserted": inserted,
        "next": format!("POST /api/proposal/{}/approve to activate sales", slug),
    })).into_response()
}

/// GET /ls — admin-gated HTML dashboard listing every proposal in DB with
/// approve / revoke toggles and live preview links. Single page so the admin
/// (mail@yukihamada.jp by default; ADMIN_EMAIL env overrides) can see and
/// switch every brand from one place. All state comes from `proposals`.
async fn admin_ls_page(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/ls").await { return r; }
    let admin_email = std::env::var("ADMIN_EMAIL").unwrap_or_else(|_| "mail@yukihamada.jp".into());
    let rows: Vec<(String, String, Option<String>, Option<String>, Option<String>, i64)> = {
        let conn = db.lock().unwrap();
        let mut out = Vec::new();
        if let Ok(mut stmt) = conn.prepare(
            "SELECT p.slug, p.name, p.approved_at, p.revoked_at, p.plan_tier,
                    (SELECT COUNT(*) FROM proposal_skus s WHERE s.slug=p.slug)
             FROM proposals p ORDER BY p.approved_at IS NULL DESC, p.created_at DESC",
        ) {
            if let Ok(it) = stmt.query_map([], |r| Ok((
                r.get::<_,String>(0)?, r.get::<_,String>(1)?,
                r.get::<_,Option<String>>(2)?, r.get::<_,Option<String>>(3)?,
                r.get::<_,Option<String>>(4)?, r.get::<_,i64>(5)?,
            ))) {
                for x in it.flatten() { out.push(x); }
            }
        }
        out
    };
    // Auth mode: prefer cookie session (no token in URL). If admin reached
    // /ls via legacy ?admin_token=… we keep propagating it onto preview links
    // so they still bypass the public gate from the dashboard.
    let session_email = is_admin_email_session(&db, &headers);
    let token = if session_email.is_some() {
        String::new()
    } else {
        q.get("admin_token").or_else(|| q.get("token")).cloned()
            .or_else(|| headers.get("authorization")
                .and_then(|v| v.to_str().ok())
                .and_then(|s| s.strip_prefix("Bearer ").or_else(|| s.strip_prefix("bearer ")))
                .map(String::from))
            .or_else(|| headers.get("x-admin-token").and_then(|v| v.to_str().ok()).map(String::from))
            .unwrap_or_default()
    };
    let tok_q = if token.is_empty() { String::new() } else { format!("?admin_token={}", html_attr_escape(&token)) };
    let auth_mode = if session_email.is_some() { "cookie" } else { "token" };
    let session_email_display = session_email.clone().unwrap_or_else(|| admin_email.clone());

    let mut tbody = String::new();
    let mut n_approved = 0i64;
    let mut n_total = 0i64;
    for (slug, name, approved_at, revoked_at, plan_tier, sku_count) in &rows {
        n_total += 1;
        let approved = approved_at.is_some() && revoked_at.is_none();
        if approved { n_approved += 1; }
        let status = if approved {
            format!("<span class=\"ok\">LIVE</span> · {}", html_escape(plan_tier.as_deref().unwrap_or("—")))
        } else if revoked_at.is_some() {
            "<span class=\"warn\">REVOKED</span>".into()
        } else {
            "<span class=\"gate\">GATED</span>".into()
        };
        tbody.push_str(&format!(
            "<tr data-slug=\"{slug}\">\
              <td><a class=\"slug\" href=\"/{slug}{tok}\" target=\"_blank\">{slug}</a></td>\
              <td>{name}</td>\
              <td>{sku} SKU</td>\
              <td>{status}</td>\
              <td class=\"row-actions\">\
                <button class=\"act approve\" data-act=\"approve\" data-slug=\"{slug}\" {ap_disabled}>approve</button>\
                <button class=\"act revoke\" data-act=\"revoke\" data-slug=\"{slug}\" {rv_disabled}>revoke</button>\
                <a class=\"act preview\" href=\"/{slug}{tok}\" target=\"_blank\">preview ↗</a>\
                <a class=\"act api\" href=\"/api/proposal/{slug}/state\" target=\"_blank\">state</a>\
              </td>\
             </tr>",
            slug = html_escape(slug),
            tok = tok_q,
            name = html_escape(name),
            sku = sku_count,
            status = status,
            ap_disabled = if approved { "disabled" } else { "" },
            rv_disabled = if !approved { "disabled" } else { "" },
        ));
    }

    let html = format!(r#"<!doctype html>
<html lang="ja"><head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="robots" content="noindex,nofollow">
<title>/ls — admin dashboard</title>
<style>
:root{{--bg:#0a0a0a;--fg:#f5f5f5;--mute:#888;--line:#222;--accent:#ff5a36;--ok:#7be57b;--warn:#ff6464}}
*{{box-sizing:border-box}}
body{{background:var(--bg);color:var(--fg);font-family:'Helvetica Neue',Arial,sans-serif;margin:0;line-height:1.6;font-size:14px}}
.wrap{{max-width:1180px;margin:0 auto;padding:32px 24px}}
.head{{display:flex;justify-content:space-between;align-items:baseline;border-bottom:1px solid var(--line);padding-bottom:12px;margin-bottom:24px;flex-wrap:wrap;gap:12px}}
h1{{font-size:22px;margin:0;font-weight:800;letter-spacing:-0.01em}}
.head .meta{{color:var(--mute);font-size:12px;letter-spacing:0.06em}}
.head .admin{{color:var(--accent);font-weight:600}}
.stats{{display:flex;gap:24px;margin-bottom:24px;font-size:12px;color:var(--mute);letter-spacing:0.08em;text-transform:uppercase}}
.stats b{{color:var(--fg);font-size:16px;display:block;font-family:inherit}}
table{{width:100%;border-collapse:collapse;font-size:13px}}
th{{text-align:left;font-weight:600;color:var(--mute);font-size:11px;letter-spacing:0.16em;text-transform:uppercase;padding:8px 10px;border-bottom:1px solid var(--line)}}
td{{padding:10px;border-bottom:1px solid var(--line);vertical-align:middle}}
a.slug{{color:var(--accent);text-decoration:none;font-weight:700;font-family:'SF Mono',monospace}}
a.slug:hover{{text-decoration:underline}}
.ok{{color:var(--ok);font-weight:700;font-size:11px;letter-spacing:0.1em}}
.warn{{color:var(--warn);font-weight:700;font-size:11px;letter-spacing:0.1em}}
.gate{{color:var(--mute);font-weight:700;font-size:11px;letter-spacing:0.1em}}
.row-actions{{white-space:nowrap}}
.act{{display:inline-block;background:#181818;border:1px solid var(--line);color:var(--fg);font-family:inherit;font-size:11px;padding:6px 10px;border-radius:3px;cursor:pointer;text-decoration:none;margin-right:4px;letter-spacing:0.04em}}
.act.approve{{border-color:var(--ok);color:var(--ok)}}
.act.revoke{{border-color:var(--warn);color:var(--warn)}}
.act:hover:not(:disabled){{filter:brightness(1.25)}}
.act:disabled{{opacity:0.3;cursor:not-allowed}}
.toast{{position:fixed;bottom:24px;right:24px;background:#181818;border:1px solid var(--line);padding:12px 16px;border-radius:4px;font-size:12px;max-width:380px;opacity:0;transition:opacity 0.2s;pointer-events:none}}
.toast.show{{opacity:1;pointer-events:auto}}
.toast.ok{{border-color:var(--ok)}}
.toast.err{{border-color:var(--warn)}}
</style></head><body>
<div class="wrap">
  <div class="head">
    <div>
      <h1>━◯━ /ls — proposal admin</h1>
      <div class="meta">all proposals in <code>proposals</code> table · DB-driven · auth: <code>{auth_mode}</code></div>
    </div>
    <div class="admin">{session_email_display}</div>
  </div>
  <div class="stats">
    <div>total<b>{n_total}</b></div>
    <div>approved<b>{n_approved}</b></div>
    <div>gated<b>{n_gated}</b></div>
  </div>
  <table>
    <thead><tr>
      <th>slug</th><th>name</th><th>skus</th><th>status</th><th>actions</th>
    </tr></thead>
    <tbody>{tbody}</tbody>
  </table>
</div>
<div id="toast" class="toast"></div>
<script>
(function(){{
  var TOKEN = {token_js};
  var toast = document.getElementById('toast');
  function show(msg, ok){{
    toast.textContent = msg;
    toast.className = 'toast show ' + (ok===false?'err':'ok');
    setTimeout(function(){{ toast.className = 'toast'; }}, 4000);
  }}
  function approverBody(){{
    return {{ approver_name: 'admin-/ls', approver_email: 'mail@yukihamada.jp', plan_tier: 'starter', note: '/ls toggle' }};
  }}
  document.querySelectorAll('button.act').forEach(function(btn){{
    btn.addEventListener('click', async function(){{
      var slug = btn.dataset.slug, act = btn.dataset.act;
      btn.disabled = true;
      try {{
        var url = '/api/proposal/'+encodeURIComponent(slug)+'/'+act
                + (TOKEN ? ('?admin_token='+encodeURIComponent(TOKEN)) : '');
        var r = await fetch(url, {{
          method:'POST',
          credentials:'same-origin',
          headers:{{'Content-Type':'application/json'}},
          body: act==='approve' ? JSON.stringify(approverBody()) : '{{}}',
        }});
        var j = await r.json();
        if (r.ok && j.ok !== false) {{
          show('✓ '+act+' '+slug, true);
          setTimeout(function(){{ location.reload(); }}, 600);
        }} else {{ show('✗ '+(j.error || ('HTTP '+r.status)), false); btn.disabled=false; }}
      }} catch(e) {{ show('✗ '+e.message, false); btn.disabled=false; }}
    }});
  }});
}})();
</script>
</body></html>"#,
        session_email_display = html_escape(&session_email_display),
        auth_mode = auth_mode,
        n_total = n_total,
        n_approved = n_approved,
        n_gated = n_total - n_approved,
        tbody = tbody,
        token_js = serde_json::to_string(&token).unwrap_or_else(|_| "\"\"".into()),
    );
    Html(html).into_response()
}

/// GET /admin/proposals — admin-gated. Lists every proposal + state.
async fn proposal_generic_list(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/admin/proposals").await { return r; }
    let conn = db.lock().unwrap();
    let mut stmt = match conn.prepare(
        "SELECT p.slug, p.name, p.ip_owner, p.approved_at, p.revoked_at,
                (SELECT COUNT(*) FROM proposal_skus s WHERE s.slug=p.slug) AS sku_count,
                (SELECT COUNT(*) FROM products pr WHERE pr.brand LIKE p.slug||'_%' AND pr.active=1) AS active
         FROM proposals p ORDER BY p.created_at ASC",
    ) { Ok(s) => s, Err(_) => return (StatusCode::INTERNAL_SERVER_ERROR, "db").into_response() };
    let rows: Vec<serde_json::Value> = stmt.query_map([], |r| {
        Ok(serde_json::json!({
            "slug": r.get::<_, String>(0)?,
            "name": r.get::<_, String>(1)?,
            "ip_owner": r.get::<_, String>(2)?,
            "approved_at": r.get::<_, Option<String>>(3)?,
            "revoked_at": r.get::<_, Option<String>>(4)?,
            "sku_count": r.get::<_, i64>(5)?,
            "products_active": r.get::<_, i64>(6)?,
        }))
    }).map(|i| i.flatten().collect()).unwrap_or_default();
    Json(serde_json::json!({ "proposals": rows })).into_response()
}

/// GET /api/admin/collabs/dashboard — admin-gated single-pane summary of
/// every collab brand: name/ip_owner, current AI prompt template (from
/// proposals.meta_json.ai_prompt), generation cadence
/// (meta_json.cadence_hours, default 24), and up to 8 latest product
/// thumbnails (joined from products on brand LIKE slug||'_%').
///
/// `?include_personal=1` keeps the per-email `personal-*` slugs in the
/// response (default behaviour: include them, so the admin sees every
/// brand). `?approved=1` filters to approved+non-revoked rows only.
///
/// Cron-actual cadence (hours between scheduled runs) is reported per-slug
/// when the brand has a known cron entry — used by the UI to warn when the
/// admin-set cadence drifts from what's actually scheduled. Mapping is a
/// hardcoded snapshot of cron.sh (cron.sh lives outside the Docker build
/// context, so we can't include_str it).
async fn admin_collabs_dashboard(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/api/admin/collabs/dashboard").await { return r; }
    let approved_only = q.get("approved").map(|s| s == "1").unwrap_or(false);
    let include_personal = q.get("include_personal").map(|s| s != "0").unwrap_or(true);
    let conn = db.lock().unwrap();
    let mut sql = String::from(
        "SELECT p.slug, p.name, p.ip_owner, p.approved_at, p.revoked_at,
                p.meta_json,
                (SELECT COUNT(*) FROM proposal_skus s WHERE s.slug=p.slug) AS sku_count,
                (SELECT COUNT(*) FROM products pr WHERE pr.brand LIKE p.slug||'_%' AND pr.active=1) AS active
         FROM proposals p WHERE 1=1"
    );
    if approved_only {
        sql.push_str(" AND p.approved_at IS NOT NULL AND p.revoked_at IS NULL");
    }
    if !include_personal {
        sql.push_str(" AND p.slug NOT LIKE 'personal-%'");
    }
    sql.push_str(" ORDER BY COALESCE(p.approved_at, p.created_at) DESC");
    let mut stmt = match conn.prepare(&sql) {
        Ok(s) => s,
        Err(_) => return (StatusCode::INTERNAL_SERVER_ERROR, "db prep").into_response(),
    };
    let base_rows: Vec<(String, String, String, Option<String>, Option<String>, Option<String>, i64, i64)> =
        stmt.query_map([], |r| {
            Ok((
                r.get::<_, String>(0)?,
                r.get::<_, String>(1)?,
                r.get::<_, String>(2)?,
                r.get::<_, Option<String>>(3)?,
                r.get::<_, Option<String>>(4)?,
                r.get::<_, Option<String>>(5)?,
                r.get::<_, i64>(6)?,
                r.get::<_, i64>(7)?,
            ))
        }).map(|i| i.flatten().collect()).unwrap_or_default();
    drop(stmt);

    let mut out: Vec<serde_json::Value> = Vec::with_capacity(base_rows.len());
    for (slug, name, ip_owner, approved_at, revoked_at, meta_str, sku_count, active) in base_rows {
        // Parse meta_json.
        let meta: serde_json::Map<String, serde_json::Value> = meta_str.as_deref()
            .and_then(|s| serde_json::from_str(s).ok())
            .unwrap_or_default();
        let ai_prompt = meta.get("ai_prompt").and_then(|v| v.as_str()).unwrap_or("").to_string();
        let cadence_hours = meta.get("cadence_hours").and_then(|v| v.as_i64()).unwrap_or(24);
        let cadence_label = meta.get("cadence_label").and_then(|v| v.as_str()).unwrap_or("every 24h").to_string();
        // Sample products (up to 8): active first, then by sold + id DESC.
        let brand_like = format!("{}_%", slug);
        let mut samples: Vec<serde_json::Value> = Vec::new();
        if let Ok(mut sstmt) = conn.prepare(
            "SELECT id, name, mockup_url, design_url, lifestyle_url,
                    COALESCE(sold,0) AS sold, COALESCE(active,0) AS active
             FROM products
             WHERE brand LIKE ?
             ORDER BY active DESC, sold DESC, id DESC
             LIMIT 8"
        ) {
            let it = sstmt.query_map(params![brand_like], |r| {
                Ok(serde_json::json!({
                    "id": r.get::<_, i64>(0)?,
                    "name": r.get::<_, String>(1)?,
                    "mockup_url": r.get::<_, Option<String>>(2)?,
                    "design_url": r.get::<_, Option<String>>(3)?,
                    "lifestyle_url": r.get::<_, Option<String>>(4)?,
                    "sold": r.get::<_, i64>(5)?,
                    "active": r.get::<_, i64>(6)? == 1,
                }))
            });
            if let Ok(rows) = it {
                samples = rows.flatten().collect();
            }
        }
        let products_total: i64 = conn.query_row(
            "SELECT COUNT(*) FROM products WHERE brand LIKE ?",
            params![brand_like], |r| r.get(0),
        ).unwrap_or(0);

        let (cron_actual_hours, cron_actual_label) = cron_actual_for_slug(&slug);
        out.push(serde_json::json!({
            "slug": slug,
            "name": name,
            "ip_owner": ip_owner,
            "approved_at": approved_at,
            "revoked_at": revoked_at,
            "approved": approved_at.is_some() && revoked_at.is_none(),
            "sku_count": sku_count,
            "products_active": active,
            "products_total": products_total,
            "ai_prompt": ai_prompt,
            "ai_prompt_suggested": suggest_ai_prompt(&slug),
            "cadence_hours": cadence_hours,
            "cadence_label": cadence_label,
            "cron_actual_hours": cron_actual_hours,
            "cron_actual_label": cron_actual_label,
            "product_samples": samples,
        }));
    }
    let total = out.len();
    Json(serde_json::json!({
        "collabs": out,
        "total": total,
    })).into_response()
}

/// Hardcoded snapshot of cron.sh: maps a collab slug (or brand prefix) to
/// the actual cadence the m5 cron is configured for. Returns
/// (hours, label). hours=0 means "no scheduled run — manual only".
///
/// Keep in sync with cron.sh when schedules change. cron.sh isn't in the
/// Docker build context, so we can't include_str! it.
fn cron_actual_for_slug(slug: &str) -> (i64, String) {
    let s = slug.to_lowercase();
    if s == "mugen" { return (1, "every hour".to_string()); }
    if s == "muon" { return (24, "daily".to_string()); }
    if s == "ma" { return (720, "monthly".to_string()); }
    if s == "nouns_mugen" || s == "nouns-mugen" { return (168, "weekly Mon".to_string()); }
    if s == "nouns_muon" || s == "nouns-muon" { return (24, "daily".to_string()); }
    if s == "nouns_ma" || s == "nouns-ma" { return (720, "monthly 15th".to_string()); }
    if s == "nouns" { return (24, "daily (mugen/muon/ma fan-out)".to_string()); }
    // No dedicated cron — PRODUCT-CREATOR runs every 2h and picks brands by
    // signal, so brand-agnostic collabs get touched on that cadence.
    (0, "manual / signal-driven (PRODUCT-CREATOR @2h)".to_string())
}

/// Per-collab AI prompt template suggestion. Used as a placeholder on the
/// /admin/collabs editor textarea so partners get something editable on
/// day 1. The admin can keep or edit it; saving persists into
/// proposals.meta_json.ai_prompt via PATCH /api/admin/proposal/:slug/meta.
fn suggest_ai_prompt(slug: &str) -> String {
    let s = slug.to_lowercase();
    let t: &str = match s.as_str() {
        "reversal" =>
            "rvddw R-in-circle + 月相 (lunar phase glyph), minimal monoline on white tee, no logotype, centered front print, black ink only",
        "amami" =>
            "奄美大島 motif (波/森/海/イルカ silhouette), monoline ink wash, soft blue + jungle green palette, centered print, no text",
        "atsume" =>
            "atsume.io 集合 motif: scattered dots condensing into a single mark, minimal monoline, black on natural tee",
        "ryozo" =>
            "ryozo 焼肉古今系 motif: charcoal grill mark + smoke curl monoline, deep red + black, centered front print",
        "jiufight" | "jf" =>
            "JIU FIGHT × MU: 柔術 gi lapel grip silhouette + 月 (moon) mark, monoline ink, black on white",
        "asoview" =>
            "asoview 体験 motif: 山/波/星 silhouette stacked monoline, soft outdoor palette, centered front print",
        "elsoul" =>
            "elsoul: ambient sound wave + 魂 (soul) glyph monoline, deep indigo, centered front print",
        "ele" =>
            "ELE: 雷 (lightning) bolt + 月 minimal monoline, gold on black tee",
        "nojimahal" =>
            "nojima hall: 円形 stage outline + spotlight ray monoline, warm amber palette, centered print",
        "kichinan" =>
            "kichinan 吉南: 吉 character deconstructed into monoline strokes, black on natural tee",
        "blank" =>
            "BLANK MU: pure 無 (mu) glyph centered, single line ink, no other element",
        "nihon-kotsu" | "nihon_kotsu" =>
            "日本交通: taxi 行灯 silhouette + 月 mark monoline, black on white, centered front print",
        "nouns" =>
            "Nouns DAO × MU: noggle glasses + 月 (moon) mark, simple monoline, primary noun palette",
        "kokon" =>
            "焼肉古今 (kokon.tokyo): charcoal grill + 古今 glyph monoline, deep red + black, centered print",
        "sweep" =>
            "MU × SIIIEEP BJJ (internal): gi belt sweep motion line + 月 mark, monoline ink, black on white",
        _ => ""
    };
    if !t.is_empty() { return t.to_string(); }
    format!("{slug}: minimal monoline 月 (moon) + brand glyph on white tee, single ink color, centered front print, no logotype",
        slug = slug)
}

/// GET /admin/collabs — admin-gated HTML dashboard. Lists every collab
