async fn extras_balance(
    State(db): State<Db>,
    Json(body): Json<ExtrasEmailBody>,
) -> Response {
    let email = match validate_email(&body.email) {
        Ok(e) => e,
        Err(m) => return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok": false, "error": m}))).into_response(),
    };
    let conn = db.lock().unwrap();
    let (balance, free_used) = points_balance(&conn, &email);
    Json(serde_json::json!({
        "ok": true,
        "email": email,
        "balance": balance,
        "free_30_eligible": !free_used,
        "points_per_sku": EXTRAS_POINTS_PER_SKU,
        // MU claim is variable (100% of yen paid). Floor is the brand's
        // base price (¥7,800 for MUGEN/MUON, ¥18,000 for MA). Kept here
        // as a UI hint only — not the actual grant amount.
        "mu_claim_floor_jpy": EXTRAS_POINTS_PER_MUGEN_FLOOR,
    })).into_response()
}

// ── Public-developer API (MU API key = collab_users.session_token) ─────
// Self-serve: log in via /api/collab/auth/{start,verify} (or visit /api-keys)
// to mint a session_token, then use it as `Authorization: Bearer <token>`
// or `?api_key=<token>` for the endpoints below.

#[derive(Deserialize)]
struct SkuCreateBody {
    /// Target proposal slug. Defaults to the caller's personal sandbox
    /// (`personal-<hash(email)>`) if omitted or empty.
    #[serde(default)] slug: String,
    label: String,
    kind: String,                 // tee / hoodie / mug / longsleeve / ...
    design_url: String,           // absolute URL to a PNG hosted anywhere
    #[serde(default)] price_jpy: Option<i64>,
}

/// POST /api/v1/sku/create — auth: Bearer <api_key> (or ?api_key=).
/// Creates one new SKU in the caller's chosen slug for 30 pt (free for
/// the first 30 SKUs per email). Mirrors collab_partner_sku_add but
/// is gated on the API key, not the per-slug manage token.
async fn api_v1_sku_create(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(body): Json<SkuCreateBody>,
) -> Response {
    let email = match bearer_or_session_email(&db, &headers, Some(&q)) {
        Some(e) => e,
        None => return (StatusCode::UNAUTHORIZED, Json(serde_json::json!({
            "ok": false, "error": "missing or invalid api_key (Authorization: Bearer <key> or ?api_key=)"
        }))).into_response(),
    };
    let label = body.label.trim();
    let kind  = body.kind.trim();
    let url   = body.design_url.trim();
    if label.is_empty() || kind.is_empty() || url.is_empty() {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({
            "ok": false, "error": "label, kind, design_url required"
        }))).into_response();
    }
    if !url.starts_with("http://") && !url.starts_with("https://") {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({
            "ok": false, "error": "design_url must be absolute http(s) URL"
        }))).into_response();
    }
    let slug = if body.slug.trim().is_empty() {
        let conn = db.lock().unwrap();
        ensure_personal_proposal(&conn, &email)
    } else {
        body.slug.trim().to_lowercase()
    };

    let final_price: i64 = body.price_jpy.unwrap_or_else(|| match kind {
        "tee" => 4_900, "longsleeve" => 6_400, "tank_top" => 4_800,
        "hoodie" => 9_800, "crewneck" => 8_400, "zip_hoodie" => 10_800,
        "cap" => 5_800, "beanie" => 3_800, "tote" => 4_200,
        "drawstring" => 2_800, "mug" => 2_400, "socks" => 1_800,
        "sticker" => 980, "pin" => 880, "magnet" => 980, "postcard" => 480,
        "notebook" => 2_800, "phonecase" => 3_400, "kids_tee" => 4_200,
        _ => 4_900,
    });

    // Charge 30 pt unless free-30 still available.
    let (cost, free_applied) = {
        let conn = db.lock().unwrap();
        extras_compute_cost(&conn, &email, 1)
    };
    let now = chrono_now();
    let (letter, drop_num, sku_id) = {
        let conn = db.lock().unwrap();
        if !free_applied {
            if let Err(e) = points_mutate(&conn, &email, -cost, "sku_create", None, Some(&slug)) {
                return (StatusCode::PAYMENT_REQUIRED, Json(serde_json::json!({
                    "ok": false, "error": e, "cost_pt": cost,
                    "topup_url": "https://wearmu.com/extras/my"
                }))).into_response();
            }
        } else {
            // Burn the free-30 entitlement on first call.
            let _ = conn.execute(
                "INSERT OR IGNORE INTO proposal_points (email, balance, free_30_used, updated_at)
                 VALUES (?, 0, 0, ?)",
                params![normalize_email(&email), now],
            );
            let _ = conn.execute(
                "UPDATE proposal_points SET free_30_used=1, updated_at=? WHERE email=?",
                params![now, normalize_email(&email)],
            );
        }
        // Auto-assign letter (m001, m002, …).
        let n: i64 = conn.query_row(
            "SELECT COUNT(*) FROM proposal_skus WHERE slug=? AND letter LIKE 'm%'",
            params![slug], |r| r.get(0),
        ).unwrap_or(0);
        let letter = format!("m{:03}", n + 1);
        let max_manual: i64 = conn.query_row(
            "SELECT COALESCE(MAX(drop_num),7_999_999) FROM proposal_skus
             WHERE slug=? AND drop_num BETWEEN 8_000_000 AND 8_999_999",
            params![slug], |r| r.get(0),
        ).unwrap_or(7_999_999);
        let drop_num = max_manual + 1;
        let _ = conn.execute(
            "INSERT INTO proposal_extras_skus
              (job_id, slug, letter, label, kind, price_jpy, image_url,
               approval_status, reviewed_at, created_at)
             VALUES (0, ?, ?, ?, ?, ?, ?, 'approved', ?, ?)",
            params![slug, letter, label, kind, final_price, url, now, now],
        );
        let sku_id = conn.last_insert_rowid();
        let _ = conn.execute(
            "INSERT OR IGNORE INTO proposal_skus
                (slug, letter, drop_num, price_jpy, label, kind, design_slug, design_url)
             VALUES (?, ?, ?, ?, ?, ?, 'api-v1', ?)",
            params![slug, letter, drop_num, final_price, label, kind, url],
        );
        // Mirror into products so PATCH/DELETE/SUZURI publish find the row.
        // Same shape as /sku/quick and seed_partners_from_spec_dir.
        let brand = proposal_brand_for_kind(&slug, kind);
        let _ = conn.execute(
            "INSERT INTO products
                (brand, drop_num, name, design_url, mockup_url, price_jpy, inventory, active, created_at, weather_data)
             VALUES (?,?,?,?,?,?,?,?,?,?)",
            params![
                brand, drop_num,
                format!("━◯━ MU × {} · {} · {}", slug, letter.to_uppercase(), label),
                url, url, final_price, 50, 1, now,
                serde_json::json!({
                    "kind": format!("{}_{}", slug, kind),
                    "source": "api-v1-sku-create",
                    "design_slug": "api-v1",
                    "license_status": "self_serve",
                }).to_string(),
            ],
        );
        (letter, drop_num, sku_id)
    };

    Json(serde_json::json!({
        "ok": true,
        "sku_id": sku_id,
        "slug": slug,
        "letter": letter,
        "drop_num": drop_num,
        "price_jpy": final_price,
        "cost_pt": if free_applied { 0 } else { cost },
        "free_applied": free_applied,
        "lp_url": format!("https://wearmu.com/{}", slug),
        "next": "approve sales: POST /api/v1/proposal/{slug}/approve",
    })).into_response()
}

/// Returns Ok(email) if the caller (via Bearer/cookie/api_key) owns the slug,
/// else Err(response). Ownership = proposals.owner_email match, OR the slug
/// is the caller's personal sandbox (`personal-<hash(email)>`).
fn require_slug_owner(
    db: &Db, headers: &HeaderMap,
    query: Option<&std::collections::HashMap<String, String>>,
    slug: &str,
) -> Result<String, Response> {
    let email = match bearer_or_session_email(db, headers, query) {
        Some(e) => e,
        None => return Err((StatusCode::UNAUTHORIZED, Json(serde_json::json!({
            "ok": false, "error": "missing or invalid api_key"
        }))).into_response()),
    };
    if slug == personal_slug_for(&email) { return Ok(email); }
    let conn = db.lock().unwrap();
    let owner: Option<String> = conn.query_row(
        "SELECT owner_email FROM proposals WHERE slug=?",
        params![slug], |r| r.get(0),
    ).ok().flatten();
    match owner {
        Some(o) if o.to_lowercase() == email => Ok(email),
        Some(_) => Err((StatusCode::FORBIDDEN, Json(serde_json::json!({
            "ok": false, "error": "this slug is owned by another email"
        }))).into_response()),
        None => Err((StatusCode::FORBIDDEN, Json(serde_json::json!({
            "ok": false,
            "error": "slug has no owner; POST /api/v1/proposal first to claim it"
        }))).into_response()),
    }
}

#[derive(Deserialize)]
struct ProposalUpsertBody {
    slug: String,
    #[serde(default)] name: String,
    #[serde(default)] ip_owner: String,
    #[serde(default)] meta: Option<serde_json::Value>,
}

/// POST /api/v1/proposal — upsert a brand under the caller. Claims the slug
/// if it has no owner; updates name/ip_owner/meta if already owned. Forbidden
/// when the slug is owned by a different email.
async fn api_v1_proposal_upsert(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(body): Json<ProposalUpsertBody>,
) -> Response {
    let email = match bearer_or_session_email(&db, &headers, Some(&q)) {
        Some(e) => e,
        None => return (StatusCode::UNAUTHORIZED, Json(serde_json::json!({
            "ok": false, "error": "missing or invalid api_key"
        }))).into_response(),
    };
    let slug = body.slug.trim().to_lowercase();
    if slug.is_empty() || !slug.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit() || c == '_' || c == '-') {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({
            "ok": false, "error": "slug must be [a-z0-9_-]+"
        }))).into_response();
    }
    let name = if body.name.trim().is_empty() { slug.clone() } else { body.name.trim().to_string() };
    let ip_owner = if body.ip_owner.trim().is_empty() { name.clone() } else { body.ip_owner.trim().to_string() };
    let meta_json: Option<String> = body.meta.as_ref().map(|m| m.to_string());

    let conn = db.lock().unwrap();
    // Check existing ownership.
    let existing: Option<(String, Option<String>)> = conn.query_row(
        "SELECT name, owner_email FROM proposals WHERE slug=?",
        params![slug], |r| Ok((r.get(0)?, r.get(1)?)),
    ).ok();
    let allow_personal = slug == personal_slug_for(&email);
    if let Some((_, Some(owner))) = &existing {
        if owner.to_lowercase() != email && !allow_personal {
            return (StatusCode::FORBIDDEN, Json(serde_json::json!({
                "ok": false, "error": "this slug is owned by another email"
            }))).into_response();
        }
    }
    let now = chrono_now();
    let _ = conn.execute(
        "INSERT INTO proposals (slug, name, ip_owner, created_at, meta_json, owner_email)
         VALUES (?, ?, ?, ?, ?, ?)
         ON CONFLICT(slug) DO UPDATE SET
            name = excluded.name,
            ip_owner = excluded.ip_owner,
            meta_json = COALESCE(excluded.meta_json, proposals.meta_json),
            owner_email = COALESCE(proposals.owner_email, excluded.owner_email)",
        params![slug, name, ip_owner, now, meta_json, email],
    );
    Json(serde_json::json!({
        "ok": true,
        "slug": slug,
        "name": name,
        "owner_email": email,
        "created": existing.is_none(),
        "next": {
            "create_sku":     format!("POST /api/v1/sku/create  body: {{\"slug\":\"{}\",\"label\":...}}", slug),
            "approve_public": format!("POST /api/v1/proposal/{}/approve", slug),
            "view_lp":        format!("https://wearmu.com/{}", slug),
        },
    })).into_response()
}

/// POST /api/v1/proposal/:slug/approve — owner-gated. Same effect as the
/// admin endpoint: sets approved_at + clears revoked_at, activating the
/// public LP at /<slug>.
async fn api_v1_proposal_approve(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Path(slug): axum::extract::Path<String>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let email = match require_slug_owner(&db, &headers, Some(&q), &slug) {
        Ok(e) => e, Err(r) => return r,
    };
    let now = chrono_now();
    {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "UPDATE proposals SET
                approved_at=?, approver_name=?, approver_email=?,
                plan_tier='self-serve', revoked_at=NULL
             WHERE slug=?",
            params![now, email, email, slug],
        );
        let _ = conn.execute(
            "UPDATE products SET active=1 WHERE brand LIKE ?||'%' AND active=0",
            params![format!("{}_", slug)],
        );
    }
    Json(serde_json::json!({
        "ok": true, "slug": slug, "approved_at": now, "approver_email": email,
        "public_url": format!("https://wearmu.com/{}", slug),
    })).into_response()
}

/// POST /api/v1/proposal/:slug/revoke — owner-gated. Hides /<slug> from
/// the public; SKUs remain in DB.
async fn api_v1_proposal_revoke(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Path(slug): axum::extract::Path<String>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let _email = match require_slug_owner(&db, &headers, Some(&q), &slug) {
        Ok(e) => e, Err(r) => return r,
    };
    let now = chrono_now();
    {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "UPDATE proposals SET revoked_at=? WHERE slug=?",
            params![now, slug],
        );
    }
    Json(serde_json::json!({"ok": true, "slug": slug, "revoked_at": now})).into_response()
}

#[derive(Deserialize)]
struct SkuPatchBody {
    #[serde(default)] label: Option<String>,
    #[serde(default)] price_jpy: Option<i64>,
    #[serde(default)] design_url: Option<String>,
}

/// PATCH /api/v1/sku/:slug/:letter — owner-gated. Update label / price /
/// design_url. Mirrors to products table.
async fn api_v1_sku_patch(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Path((slug, letter)): axum::extract::Path<(String, String)>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(body): Json<SkuPatchBody>,
) -> Response {
    let _ = match require_slug_owner(&db, &headers, Some(&q), &slug) {
        Ok(e) => e, Err(r) => return r,
    };
    let letter = letter.to_lowercase();
    let conn = db.lock().unwrap();
    // Ensure SKU exists.
    let kind: String = match conn.query_row(
        "SELECT kind FROM proposal_skus WHERE slug=? AND letter=?",
        params![slug, letter], |r| r.get(0),
    ) {
        Ok(k) => k,
        Err(_) => return (StatusCode::NOT_FOUND, Json(serde_json::json!({
            "ok": false, "error": "no such (slug, letter)"
        }))).into_response(),
    };
    let brand = proposal_brand_for_kind(&slug, &kind);
    let mut sets_ps: Vec<String> = Vec::new();
    let mut sets_p:  Vec<String> = Vec::new();
    let mut vals: Vec<rusqlite::types::Value> = Vec::new();
    if let Some(l) = body.label.as_deref().map(|s| s.trim()).filter(|s| !s.is_empty()) {
        sets_ps.push("label=?".into()); sets_p.push("name=?".into());
        vals.push(l.to_string().into());
        vals.push(format!("━◯━ MU × {} · {} · {}", slug, letter.to_uppercase(), l).into());
    }
    if let Some(p) = body.price_jpy.filter(|p| *p > 0) {
        sets_ps.push("price_jpy=?".into()); sets_p.push("price_jpy=?".into());
        vals.push(p.into()); vals.push(p.into());
    }
    if let Some(u) = body.design_url.as_deref().map(|s| s.trim()).filter(|s| !s.is_empty()) {
        sets_ps.push("design_url=?".into()); sets_p.push("design_url=?".into());
        vals.push(u.to_string().into()); vals.push(u.to_string().into());
    }
    if sets_ps.is_empty() {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({
            "ok": false, "error": "supply at least one of label/price_jpy/design_url"
        }))).into_response();
    }
    // Emit per-field updates (simpler than dynamic param binding).
    let _ = (sets_ps, sets_p, vals);
    drop(conn);
    let conn = db.lock().unwrap();
    let mut affected_ps = 0i64;
    let mut affected_p = 0i64;
    if let Some(l) = body.label.as_deref().map(|s| s.trim()).filter(|s| !s.is_empty()) {
        affected_ps += conn.execute("UPDATE proposal_skus SET label=? WHERE slug=? AND letter=?",
            params![l, slug, letter]).unwrap_or(0) as i64;
        affected_p += conn.execute(
            "UPDATE products SET name=? WHERE brand=? AND drop_num IN (SELECT drop_num FROM proposal_skus WHERE slug=? AND letter=?)",
            params![format!("━◯━ MU × {} · {} · {}", slug, letter.to_uppercase(), l), brand, slug, letter]
        ).unwrap_or(0) as i64;
    }
    if let Some(p) = body.price_jpy.filter(|p| *p > 0) {
        affected_ps += conn.execute("UPDATE proposal_skus SET price_jpy=? WHERE slug=? AND letter=?",
            params![p, slug, letter]).unwrap_or(0) as i64;
        affected_p += conn.execute(
            "UPDATE products SET price_jpy=? WHERE brand=? AND drop_num IN (SELECT drop_num FROM proposal_skus WHERE slug=? AND letter=?)",
            params![p, brand, slug, letter]
        ).unwrap_or(0) as i64;
    }
    if let Some(u) = body.design_url.as_deref().map(|s| s.trim()).filter(|s| !s.is_empty()) {
        affected_ps += conn.execute("UPDATE proposal_skus SET design_url=? WHERE slug=? AND letter=?",
            params![u, slug, letter]).unwrap_or(0) as i64;
        affected_p += conn.execute(
            "UPDATE products SET design_url=? WHERE brand=? AND drop_num IN (SELECT drop_num FROM proposal_skus WHERE slug=? AND letter=?)",
            params![u, brand, slug, letter]
        ).unwrap_or(0) as i64;
    }
    Json(serde_json::json!({
        "ok": true, "slug": slug, "letter": letter,
        "rows_proposal_skus_updated": affected_ps,
        "rows_products_updated": affected_p,
    })).into_response()
}

/// DELETE /api/v1/sku/:slug/:letter — owner-gated soft delete. Removes
/// the proposal_skus row and deactivates products.active=0. Hard-deletes
/// the proposal_extras_skus row only if approval_status was 'pending'.
async fn api_v1_sku_delete(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Path((slug, letter)): axum::extract::Path<(String, String)>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let _ = match require_slug_owner(&db, &headers, Some(&q), &slug) {
        Ok(e) => e, Err(r) => return r,
    };
    let letter = letter.to_lowercase();
    let conn = db.lock().unwrap();
    let row: Option<(i64, String)> = conn.query_row(
        "SELECT drop_num, kind FROM proposal_skus WHERE slug=? AND letter=?",
        params![slug, letter], |r| Ok((r.get(0)?, r.get(1)?)),
    ).ok();
    let (drop_num, kind) = match row {
        Some(r) => r,
        None => return (StatusCode::NOT_FOUND, Json(serde_json::json!({
            "ok": false, "error": "no such (slug, letter)"
        }))).into_response(),
    };
    let brand = proposal_brand_for_kind(&slug, &kind);
    let deleted_ps = conn.execute("DELETE FROM proposal_skus WHERE slug=? AND letter=?",
        params![slug, letter]).unwrap_or(0);
    let deactivated_p = conn.execute(
        "UPDATE products SET active=0 WHERE brand=? AND drop_num=?",
        params![brand, drop_num]).unwrap_or(0);
    let _ = conn.execute(
        "UPDATE proposal_extras_skus SET approval_status='deleted'
         WHERE slug=? AND letter=? AND approval_status IN ('approved','pending')",
        params![slug, letter]);
    Json(serde_json::json!({
        "ok": true, "slug": slug, "letter": letter,
        "proposal_skus_deleted": deleted_ps,
        "products_deactivated": deactivated_p,
    })).into_response()
}

#[derive(Deserialize)]
struct MockupRegenBody {
    slug: String,
    letter: String,
}

/// POST /api/v1/mockup/regen — owner-gated Printful mockup regen.
/// Triggers regen_product_mockup as a background tokio task so the
/// caller doesn't block on the full Printful poll (~2 min). Returns
/// immediately with status='regenerating'.
async fn api_v1_mockup_regen(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(body): Json<MockupRegenBody>,
) -> Response {
    let _ = match require_slug_owner(&db, &headers, Some(&q), &body.slug) {
        Ok(e) => e, Err(r) => return r,
    };
    let letter = body.letter.to_lowercase();
    let row: Option<(i64, String, Option<String>)> = {
        let conn = db.lock().unwrap();
        let kind: String = match conn.query_row(
            "SELECT kind FROM proposal_skus WHERE slug=? AND letter=?",
            params![body.slug, letter], |r| r.get(0),
        ) { Ok(k) => k, Err(_) => return (StatusCode::NOT_FOUND, Json(serde_json::json!({
            "ok": false, "error": "no such (slug, letter)"
        }))).into_response() };
        let brand = proposal_brand_for_kind(&body.slug, &kind);
        conn.query_row(
            "SELECT id, brand, design_url FROM products
             WHERE brand=? ORDER BY drop_num DESC LIMIT 1",
            params![brand], |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?)),
        ).ok()
    };
    let (pid, brand, design_url) = match row {
        Some((p, b, Some(d))) if !d.is_empty() => (p, b, d),
        Some(_) => return (StatusCode::BAD_REQUEST, Json(serde_json::json!({
            "ok": false, "error": "product has no design_url"
        }))).into_response(),
        None => return (StatusCode::NOT_FOUND, Json(serde_json::json!({
            "ok": false, "error": "no products row for this slug/letter"
        }))).into_response(),
    };
    let db2 = db.clone();
    tokio::spawn(async move { regen_product_mockup(pid, brand, design_url, db2).await; });
    Json(serde_json::json!({
        "ok": true, "status": "regenerating",
        "product_id": pid, "slug": body.slug, "letter": letter,
        "note": "Printful task takes ~30-90s. Poll GET /api/admin/products?search=<slug>&no_summary=1 for mockup_url.",
    })).into_response()
}

#[derive(Deserialize)]
struct SuzuriPublishApiBody {
    slug: String,
    letter: String,
    /// Comma-separated SUZURI item ids. Default: 100 (ビッグシルエットTシャツ).
    /// e.g. "100,152,8" for tee + hoodie + full-graphic.
    #[serde(default)] items: Option<String>,
}

/// POST /api/v1/suzuri/publish — owner-gated. Publishes one of the owner's
/// SKUs to SUZURI with optional multi-item variant list.
async fn api_v1_suzuri_publish(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(body): Json<SuzuriPublishApiBody>,
) -> Response {
    let _email = match require_slug_owner(&db, &headers, Some(&q), &body.slug) {
        Ok(e) => e, Err(r) => return r,
    };
    // Look up the products.id for this slug+letter.
    let pid: i64 = {
        let conn = db.lock().unwrap();
        let kind: String = match conn.query_row(
            "SELECT kind FROM proposal_skus WHERE slug=? AND letter=?",
            params![body.slug, body.letter], |r| r.get(0),
        ) {
            Ok(k) => k,
            Err(_) => return (StatusCode::NOT_FOUND, Json(serde_json::json!({
                "ok": false, "error": "no such (slug, letter)"
            }))).into_response(),
        };
        let brand = proposal_brand_for_kind(&body.slug, &kind);
        match conn.query_row(
            "SELECT id FROM products WHERE brand=? ORDER BY drop_num DESC LIMIT 1",
            params![brand], |r| r.get::<_, i64>(0),
        ) {
            Ok(p) => p,
            Err(_) => return (StatusCode::NOT_FOUND, Json(serde_json::json!({
                "ok": false, "error": format!("no products row for brand={}", brand)
            }))).into_response(),
        }
    };
    let items: Vec<u32> = body.items.as_deref().unwrap_or("")
        .split(',').filter_map(|s| s.trim().parse::<u32>().ok()).collect();
    let result = if items.is_empty() {
        suzuri_publish_drop(db.clone(), pid, true).await
    } else {
        suzuri_publish_drop_with_items(db.clone(), pid, true, items).await
    };
    match result {
        Ok((mid, spid, url)) => Json(serde_json::json!({
            "ok": true, "product_id": pid,
            "suzuri_material_id": mid,
            "suzuri_product_id": spid,
            "suzuri_url": url,
        })).into_response(),
        Err(e) => (StatusCode::BAD_GATEWAY, Json(serde_json::json!({
            "ok": false, "error": e
        }))).into_response(),
    }
}

#[derive(Deserialize)]
struct SkuQuickBody {
    /// Target slug. Defaults to caller's personal sandbox.
    #[serde(default)] slug: String,
    /// Optional: pin a specific kind (tee / hoodie / longsleeve / mug / …).
    /// If empty, picked randomly from `extras_categories_for(slug)`.
    #[serde(default)] kind: String,
    /// Optional label override. If empty, generated from partner_name + kind.
    #[serde(default)] label: String,
}

/// POST /api/v1/sku/quick — SYNCHRONOUS generate + publish.
/// Auth via Bearer / cookie / ?api_key=. Charges 30 pt (free first 30
/// per email). Blocks for ~10-30 s while Gemini renders the design and
/// the bytes are pushed to R2. On success the SKU is INSERTED with
/// approval_status='approved' so it's immediately visible at
/// GET /api/proposal/<slug>/skus and on /<slug> if the slug is approved.
///
/// Difference vs /api/proposal/:slug/extras/order: that endpoint queues a
/// job + sends email when done; this one runs inline and returns the new
/// SKU's URL in the response — for "+1 button → すぐに出てくる" UX.
async fn api_v1_sku_quick(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
    Json(body): Json<SkuQuickBody>,
) -> Response {
    let email = match bearer_or_session_email(&db, &headers, Some(&q)) {
        Some(e) => e,
        None => return (StatusCode::UNAUTHORIZED, Json(serde_json::json!({
            "ok": false, "error": "missing or invalid api_key (Authorization: Bearer <key> or ?api_key=)"
        }))).into_response(),
    };
    let slug = if body.slug.trim().is_empty() {
        let conn = db.lock().unwrap();
        ensure_personal_proposal(&conn, &email)
    } else { body.slug.trim().to_lowercase() };

    // Pick category. Allow caller to pin a kind; otherwise rotate.
    let cats = extras_categories_for(&slug);
    if cats.is_empty() {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({
            "ok": false, "error": "no allowed categories for this slug"
        }))).into_response();
    }
    let (kind, label_tmpl, default_price): (&str, &str, i64) = if !body.kind.trim().is_empty() {
        match cats.iter().find(|(k, _, _)| *k == body.kind.trim()) {
            Some(c) => *c,
            None => return (StatusCode::BAD_REQUEST, Json(serde_json::json!({
                "ok": false, "error": format!("kind '{}' not allowed for this slug", body.kind.trim()),
                "allowed": cats.iter().map(|(k, _, _)| k.to_string()).collect::<Vec<_>>(),
            }))).into_response(),
        }
    } else {
        use std::time::{SystemTime, UNIX_EPOCH};
        let idx = (SystemTime::now().duration_since(UNIX_EPOCH).map(|d| d.as_micros()).unwrap_or(0) as usize) % cats.len();
        cats[idx]
    };

    // Charge or burn free-30.
    let (cost, free_applied) = {
        let conn = db.lock().unwrap();
        extras_compute_cost(&conn, &email, 1)
    };
    let now = chrono_now();
    {
        let conn = db.lock().unwrap();
        if !free_applied {
            if let Err(e) = points_mutate(&conn, &email, -cost, "sku_quick", None, Some(&slug)) {
                return (StatusCode::PAYMENT_REQUIRED, Json(serde_json::json!({
                    "ok": false, "error": e, "cost_pt": cost,
                    "topup_url": "https://wearmu.com/extras/my",
                }))).into_response();
            }
        } else {
            let _ = conn.execute(
                "INSERT OR IGNORE INTO proposal_points (email, balance, free_30_used, updated_at)
                 VALUES (?, 0, 0, ?)",
                params![normalize_email(&email), now],
            );
            let _ = conn.execute(
                "UPDATE proposal_points SET free_30_used=1, updated_at=? WHERE email=?",
                params![now, normalize_email(&email)],
            );
        }
    }

    // Resolve partner display name.
    let partner_name: String = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT COALESCE(name, slug) FROM proposals WHERE slug=?",
            params![slug], |r| r.get::<_, String>(0),
        ).ok().unwrap_or_else(|| match slug.as_str() {
            "sweep"   => "SIIIEEP".to_string(),
            "kokon"   => "kokon.tokyo".to_string(),
            "jiuflow" => "JiuFlow".to_string(),
            "jiufight" => "JIUFIGHT × MU".to_string(),
            other     => other.to_string(),
        })
    };
    let label = if !body.label.trim().is_empty() {
        body.label.trim().to_string()
    } else {
        format!("MU × {} — {}", partner_name, label_tmpl)
    };

    // INLINE Gemini generation.
    let seed = format!("quick-{}-{}", now.chars().filter(|c| c.is_ascii_alphanumeric()).take(10).collect::<String>(), email.chars().take(3).collect::<String>());
    let tagline = "quiet, premium, 1着 = 1 シグナル".to_string();
    let brief = gemini::PartnerSkuBrief {
        partner_display: &partner_name, partner_tagline: &tagline,
        kind, label: &label, seed: &seed,
    };
    let img = match gemini::generate_partner_sku(&brief).await {
        Ok(g) => g,
        Err(e) => {
            // Refund the charge if generation failed and free wasn't used.
            if !free_applied {
                let conn = db.lock().unwrap();
                let _ = points_mutate(&conn, &email, cost, "sku_quick_refund", None, Some(&slug));
            }
            return (StatusCode::BAD_GATEWAY, Json(serde_json::json!({
                "ok": false, "error": format!("gemini: {}", e.chars().take(160).collect::<String>()),
                "refunded": !free_applied,
            }))).into_response();
        }
    };

    // Upload to R2.
    let r2 = match r2_config() {
        Some(c) => c,
        None => return (StatusCode::SERVICE_UNAVAILABLE, Json(serde_json::json!({
            "ok": false, "error": "R2 not configured server-side"
        }))).into_response(),
    };
    let ts = now.chars().filter(|c| c.is_ascii_alphanumeric()).collect::<String>();
    let key = format!("extras/{}/quick-{}-{}.{}", slug, ts, seed,
        if img.mime.contains("png") { "png" } else { "jpg" });
    let ct = if img.mime.contains("png") { "image/png" } else { "image/jpeg" };
    let public_url = match r2.bucket.put_object_with_content_type(&key, &img.bytes, ct).await {
        Ok(r) if r.status_code() == 200 => format!("{}/{}", r2.public_base.trim_end_matches('/'), key),
        Ok(r) => return (StatusCode::BAD_GATEWAY, Json(serde_json::json!({
            "ok": false, "error": format!("r2 upload failed: {} {}", r.status_code(), String::from_utf8_lossy(r.bytes()).chars().take(160).collect::<String>())
        }))).into_response(),
        Err(e) => return (StatusCode::BAD_GATEWAY, Json(serde_json::json!({
            "ok": false, "error": format!("r2 upload err: {}", e)
        }))).into_response(),
    };

    // Insert as APPROVED — visible immediately.
    let (letter, drop_num, sku_id, pid_opt) = {
        let conn = db.lock().unwrap();
        let n: i64 = conn.query_row(
            "SELECT COUNT(*) FROM proposal_skus WHERE slug=? AND letter LIKE 'q%'",
            params![slug], |r| r.get(0),
        ).unwrap_or(0);
        let letter = format!("q{:03}", n + 1);
        let max_q: i64 = conn.query_row(
            "SELECT COALESCE(MAX(drop_num), 5_999_999) FROM proposal_skus
             WHERE slug=? AND drop_num BETWEEN 6_000_000 AND 6_999_999",
            params![slug], |r| r.get(0),
        ).unwrap_or(5_999_999);
        let drop_num = max_q + 1;
        let _ = conn.execute(
            "INSERT INTO proposal_extras_skus
              (job_id, slug, letter, label, kind, price_jpy, image_url,
               approval_status, reviewed_at, created_at)
             VALUES (0, ?, ?, ?, ?, ?, ?, 'approved', ?, ?)",
            params![slug, letter, label, kind, default_price, public_url, now, now],
        );
        let sku_id = conn.last_insert_rowid();
        let _ = conn.execute(
            "INSERT OR IGNORE INTO proposal_skus
                (slug, letter, drop_num, price_jpy, label, kind, design_slug, design_url)
             VALUES (?, ?, ?, ?, ?, ?, 'api-quick', ?)",
            params![slug, letter, drop_num, default_price, label, kind, public_url],
        );
        // Mirror into products so SUZURI publish (and the rest of the
        // POD pipeline) can find this SKU. design_url = the generated
        // image; mockup_url left equal to it until a Printful mockup is
        // regenerated separately.
        let brand = proposal_brand_for_kind(&slug, kind);
        let _ = conn.execute(
            "INSERT INTO products
                (brand, drop_num, name, design_url, mockup_url, price_jpy, inventory, active, created_at, weather_data)
             VALUES (?,?,?,?,?,?,?,?,?,?)",
            params![
                brand, drop_num,
                format!("━◯━ MU × {} · {} · {}", partner_name, letter.to_uppercase(), label),
                public_url, public_url, default_price, 50, 1, now,
                serde_json::json!({
                    "kind": format!("{}_{}", slug, kind),
                    "source": "api-v1-sku-quick",
                    "design_slug": "api-quick",
                    "license_status": "self_serve",
                    "ip_owner": partner_name,
                }).to_string(),
            ],
        );
        let pid = conn.last_insert_rowid();
        (letter, drop_num, sku_id, Some(pid))
    };
    let (suzuri_url, suzuri_err): (Option<String>, Option<String>) = match pid_opt {
        Some(pid) => match suzuri_publish_drop_with_items(
            db.clone(), pid, true, SUZURI_DEFAULT_ITEMS.to_vec()
        ).await {
            Ok((_mid, _spid, url)) => (Some(url), None),
            Err(e) => (None, Some(e)),
        },
        None => (None, Some("no products row found for this SKU".to_string())),
    };

    Json(serde_json::json!({
        "ok": true,
        "sku_id": sku_id,
        "slug": slug,
        "letter": letter,
        "drop_num": drop_num,
        "kind": kind,
        "label": label,
        "design_url": public_url,
        "price_jpy": default_price,
        "cost_pt": if free_applied { 0 } else { cost },
        "free_applied": free_applied,
        "suzuri_url": suzuri_url,
        "suzuri_items": SUZURI_DEFAULT_ITEMS,
        "suzuri_error": suzuri_err,
        "skus_api": format!("https://wearmu.com/api/proposal/{}/skus", slug),
        "lp_url": format!("https://wearmu.com/{}", slug),
    })).into_response()
}

/// GET /api/me — auth: Bearer/cookie. Returns the caller's email, API key,
/// points balance, and a quickstart curl example.
async fn api_v1_me(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let email = match bearer_or_session_email(&db, &headers, Some(&q)) {
        Some(e) => e,
        None => return (StatusCode::UNAUTHORIZED, Json(serde_json::json!({
            "ok": false, "error": "not authenticated; POST /api/collab/auth/start with {email} to begin"
        }))).into_response(),
    };
    let (api_key, balance, free_used, personal): (String, i64, bool, String) = {
        let conn = db.lock().unwrap();
        let row: (String,) = conn.query_row(
            "SELECT COALESCE(session_token,'') FROM collab_users WHERE email=?",
            params![email], |r| Ok((r.get(0)?,)),
        ).unwrap_or((String::new(),));
        let (bal, free) = points_balance(&conn, &email);
        let p = ensure_personal_proposal(&conn, &email);
        (row.0, bal, free, p)
    };
    Json(serde_json::json!({
        "ok": true,
        "email": email,
        "api_key": api_key,
        "points_balance": balance,
        "free_30_used": free_used,
        "personal_slug": personal,
        "endpoints": {
            "create_sku": "POST /api/v1/sku/create",
            "list_skus":  "GET  /api/proposal/<slug>/skus",
            "state":      "GET  /api/proposal/<slug>/state",
        },
        "pricing": {
            "per_sku_pt": EXTRAS_POINTS_PER_SKU,
            "free_first_n_skus": EXTRAS_FREE_SKUS,
            "topup": "https://wearmu.com/extras/my",
        },
        "quickstart_curl": format!(
            "curl -X POST https://wearmu.com/api/v1/sku/create \\\n  -H 'Authorization: Bearer {}' \\\n  -H 'Content-Type: application/json' \\\n  -d '{{\"label\":\"My first tee\",\"kind\":\"tee\",\"design_url\":\"https://example.com/design.png\"}}'",
            if api_key.is_empty() { "<your_api_key>".into() } else { api_key.clone() }
        ),
    })).into_response()
}

