/// POST /api/proposal/extras/job/:job_id/approve-all — bulk approve every
/// still-pending SKU in a job. Same auth (email matches the job).
async fn extras_job_approve_all(
    State(db): State<Db>,
    axum::extract::Path(job_id): axum::extract::Path<i64>,
    Json(body): Json<ExtrasReviewBody>,
) -> Response {
    let email = match validate_email(&body.email) {
        Ok(e) => e,
        Err(m) => return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok": false, "error": m}))).into_response(),
    };
    let conn = db.lock().unwrap();
    let job_email: String = match conn.query_row(
        "SELECT email FROM proposal_extras_jobs WHERE id=?",
        params![job_id], |r| r.get(0),
    ) {
        Ok(e) => e,
        Err(_) => return (StatusCode::NOT_FOUND, Json(serde_json::json!({"ok": false, "error": "unknown job"}))).into_response(),
    };
    if normalize_email(&job_email) != email {
        return (StatusCode::FORBIDDEN, Json(serde_json::json!({"ok": false, "error": "email does not match the job"}))).into_response();
    }
    // Mirror all pending SKUs to proposal_skus, then flip them to approved.
    let now = chrono_now();
    let mut approved_count: i64 = 0;
    let pending: Vec<(i64, String, String, String, String, i64, String)> = {
        let mut st = match conn.prepare(
            "SELECT id, slug, letter, label, kind, price_jpy, COALESCE(image_url,'')
             FROM proposal_extras_skus
             WHERE job_id=? AND approval_status='pending' AND image_url IS NOT NULL AND image_url <> ''"
        ) { Ok(s) => s, Err(_) => return (StatusCode::INTERNAL_SERVER_ERROR, "prepare").into_response() };
        let rows = st.query_map(params![job_id], |r| Ok((
            r.get::<_, i64>(0)?, r.get::<_, String>(1)?, r.get::<_, String>(2)?,
            r.get::<_, String>(3)?, r.get::<_, String>(4)?, r.get::<_, i64>(5)?,
            r.get::<_, String>(6)?,
        )));
        match rows { Ok(it) => it.flatten().collect(), Err(_) => Vec::new() }
    };
    for (id, slug, letter, label, kind, price_jpy, image_url) in pending.iter() {
        let drop_num = 9_000_000 + id;
        let _ = conn.execute(
            "INSERT OR IGNORE INTO proposal_skus
                (slug, letter, drop_num, price_jpy, label, kind, design_slug, design_url)
             VALUES (?,?,?,?,?,?,?,?)",
            params![slug, letter, drop_num, price_jpy, label, kind, "extras", image_url],
        );
        let _ = conn.execute(
            "UPDATE proposal_extras_skus SET approval_status='approved', reviewed_at=? WHERE id=?",
            params![now, id],
        );
        approved_count += 1;
    }
    Json(serde_json::json!({
        "ok": true, "job_id": job_id, "approved": approved_count,
    })).into_response()
}

/// POST /api/proposal/extras/job/:job_id/stop — partner cancels mid-run.
/// If still 'pending' (worker hasn't picked it up), we finalize immediately
/// (refund + reset free_30). If 'processing', we flip to 'cancelling' and
/// the worker exits on its next iteration; finalize_extras_job stamps it
/// 'cancelled' and handles refund.
async fn extras_job_stop(
    State(db): State<Db>,
    axum::extract::Path(job_id): axum::extract::Path<i64>,
    Json(body): Json<ExtrasReviewBody>,
) -> Response {
    let email = match validate_email(&body.email) {
        Ok(e) => e,
        Err(m) => return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok": false, "error": m}))).into_response(),
    };
    let row = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT slug, email, qty, free_applied, points_charged, status, done_count
             FROM proposal_extras_jobs WHERE id=?",
            params![job_id],
            |r| Ok((r.get::<_, String>(0)?, r.get::<_, String>(1)?, r.get::<_, i64>(2)?,
                    r.get::<_, i64>(3)? != 0, r.get::<_, i64>(4)?, r.get::<_, String>(5)?,
                    r.get::<_, i64>(6)?)),
        )
    };
    let (slug, job_email, qty, free_applied, points_charged, status, done) = match row {
        Ok(v) => v,
        Err(_) => return (StatusCode::NOT_FOUND, Json(serde_json::json!({"ok": false, "error": "unknown job"}))).into_response(),
    };
    if normalize_email(&job_email) != email {
        return (StatusCode::FORBIDDEN, Json(serde_json::json!({"ok": false, "error": "email does not match the job"}))).into_response();
    }
    match status.as_str() {
        "completed" | "partial" | "failed" | "cancelled" => {
            return Json(serde_json::json!({"ok": true, "already": true, "status": status, "job_id": job_id})).into_response();
        }
        "cancelling" => {
            return Json(serde_json::json!({"ok": true, "already": true, "status": "cancelling", "job_id": job_id})).into_response();
        }
        "pending" => {
            // Worker hasn't started — finalize directly. Refund happens via
            // the standard finalize_extras_job path (which also flips
            // free_30 back). We synthesise a result of (0, "cancelled before
            // start") so it follows the same code path.
            let _ = {
                let conn = db.lock().unwrap();
                conn.execute(
                    "UPDATE proposal_extras_jobs SET status='cancelling' WHERE id=? AND status='pending'",
                    params![job_id],
                )
            };
            finalize_extras_job(&db, job_id, &email, qty, free_applied, points_charged,
                                &slug, (done, Some("cancelled before start".to_string())));
            return Json(serde_json::json!({"ok": true, "status": "cancelled", "job_id": job_id})).into_response();
        }
        "processing" => {
            let conn = db.lock().unwrap();
            let _ = conn.execute(
                "UPDATE proposal_extras_jobs SET status='cancelling' WHERE id=? AND status='processing'",
                params![job_id],
            );
            return Json(serde_json::json!({"ok": true, "status": "cancelling", "job_id": job_id})).into_response();
        }
        _ => {
            return (StatusCode::CONFLICT, Json(serde_json::json!({"ok": false, "error": format!("unknown status: {}", status)}))).into_response();
        }
    }
}

/// POST /api/proposal/extras/sku/:sku_id/regenerate — re-roll a single SKU.
/// Always costs EXTRAS_POINTS_PER_SKU (no free). Inserts a NEW pending row
/// into proposal_extras_skus (preserving the original for audit), then
/// fires off a tokio task that runs the Gemini + R2 dance. Frontend polls
/// /job/:job_id and the new card appears once image_url is set.
async fn extras_sku_regenerate(
    State(db): State<Db>,
    axum::extract::Path(sku_id): axum::extract::Path<i64>,
    Json(body): Json<ExtrasReviewBody>,
) -> Response {
    let email = match validate_email(&body.email) {
        Ok(e) => e,
        Err(m) => return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok": false, "error": m}))).into_response(),
    };
    // Lookup original SKU + parent job
    let row: Result<(i64, String, String, String, i64, String), &'static str> = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT s.job_id, s.slug, s.kind, s.label, s.price_jpy, j.email
             FROM proposal_extras_skus s
             JOIN proposal_extras_jobs j ON j.id = s.job_id
             WHERE s.id = ?",
            params![sku_id],
            |r| Ok((r.get::<_, i64>(0)?, r.get::<_, String>(1)?, r.get::<_, String>(2)?,
                    r.get::<_, String>(3)?, r.get::<_, i64>(4)?, r.get::<_, String>(5)?)),
        ).map_err(|_| "sku not found")
    };
    let (job_id, slug, kind, label, price_jpy, job_email) = match row {
        Ok(v) => v,
        Err(m) => return (StatusCode::NOT_FOUND, Json(serde_json::json!({"ok": false, "error": m}))).into_response(),
    };
    if normalize_email(&job_email) != email {
        return (StatusCode::FORBIDDEN, Json(serde_json::json!({"ok": false, "error": "email does not match the job"}))).into_response();
    }
    // Charge 10pt unconditionally (regen is always paid — free quota is for
    // initial batches, not retries).
    let new_balance = {
        let conn = db.lock().unwrap();
        match points_mutate(&conn, &email, -EXTRAS_POINTS_PER_SKU, "extras_regen",
                            Some(&sku_id.to_string()), Some(&slug)) {
            Ok(b) => b,
            Err(e) => return (StatusCode::PAYMENT_REQUIRED, Json(serde_json::json!({"ok": false, "error": e}))).into_response(),
        }
    };
    // Insert placeholder row.
    let now = chrono_now();
    let new_id = {
        let conn = db.lock().unwrap();
        let letter = format!("x{}r{}", job_id, sku_id);
        let _ = conn.execute(
            "INSERT INTO proposal_extras_skus
                (job_id, slug, letter, label, kind, price_jpy, image_url, prompt,
                 approval_status, created_at)
             VALUES (?,?,?,?,?,?,NULL,NULL,'pending',?)",
            params![job_id, slug, letter, label, kind, price_jpy, now],
        );
        conn.last_insert_rowid()
    };
    // Fire-and-forget generation.
    let db2 = db.clone();
    let slug_owned = slug.clone();
    let label_owned = label.clone();
    let kind_owned = kind.clone();
    let email_owned = email.clone();
    tokio::spawn(async move {
        regenerate_sku_task(db2, new_id, slug_owned, kind_owned, label_owned, price_jpy, email_owned).await;
    });
    Json(serde_json::json!({
        "ok": true, "new_sku_id": new_id, "old_sku_id": sku_id,
        "job_id": job_id, "balance": new_balance,
    })).into_response()
}

async fn regenerate_sku_task(
    db: Db, sku_id: i64, slug: String, kind: String,
    label: String, price_jpy: i64, email: String,
) {
    let partner_name: String = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT COALESCE(name, slug) FROM proposals WHERE slug=?",
            params![slug], |r| r.get::<_, String>(0),
        ).ok().unwrap_or_else(|| match slug.as_str() {
            "sweep"   => "SIIIEEP".to_string(),
            "kokon"   => "kokon.tokyo".to_string(),
            "jiuflow" => "JiuFlow".to_string(),
            other     => other.to_string(),
        })
    };
    let seed = format!("regen-{}-{}", sku_id, chrono_now().chars().filter(|c| c.is_ascii_alphanumeric()).take(8).collect::<String>());
    let tagline = "quiet, premium, 1着 = 1 シグナル".to_string();
    let brief = gemini::PartnerSkuBrief {
        partner_display: &partner_name,
        partner_tagline: &tagline,
        kind: &kind, label: &label, seed: &seed,
    };
    let cfg = match r2_config() {
        Some(c) => c,
        None => {
            refund_regen(&db, &email, sku_id, &slug, "r2-not-configured");
            return;
        }
    };
    let img = match gemini::generate_partner_sku(&brief).await {
        Ok(g) => g,
        Err(e) => {
            eprintln!("[extras-regen] sku={} gemini fail: {}", sku_id, e);
            refund_regen(&db, &email, sku_id, &slug, "gemini-failed");
            return;
        }
    };
    let key = format!("extras/{}/regen-{}.{}", slug, sku_id,
        if img.mime.contains("png") { "png" } else { "jpg" });
    let ct = if img.mime.contains("png") { "image/png" } else { "image/jpeg" };
    let url = match cfg.bucket.put_object_with_content_type(&key, &img.bytes, ct).await {
        Ok(r) if r.status_code() == 200 => format!("{}/{}", cfg.public_base.trim_end_matches('/'), key),
        Ok(r) => {
            eprintln!("[extras-regen] sku={} r2 status={}", sku_id, r.status_code());
            refund_regen(&db, &email, sku_id, &slug, "r2-upload-failed");
            return;
        }
        Err(e) => {
            eprintln!("[extras-regen] sku={} r2 err: {}", sku_id, e);
            refund_regen(&db, &email, sku_id, &slug, "r2-error");
            return;
        }
    };
    let now = chrono_now();
    let _ = {
        let conn = db.lock().unwrap();
        conn.execute(
            "UPDATE proposal_extras_skus SET image_url=?, prompt=? WHERE id=?",
            params![url, gemini::build_partner_sku_prompt(&brief), sku_id],
        )
    };
    let _ = price_jpy; // already stored; no-op
    let _ = now;
}

fn refund_regen(db: &Db, email: &str, sku_id: i64, slug: &str, reason: &str) {
    let conn = db.lock().unwrap();
    // Delete the placeholder row.
    let _ = conn.execute("DELETE FROM proposal_extras_skus WHERE id=?", params![sku_id]);
    // Refund the 10pt charge.
    let _ = points_mutate(&conn, email, EXTRAS_POINTS_PER_SKU, "extras_regen_refund",
                          Some(&format!("{}:{}", sku_id, reason)), Some(slug));
}

// ── Direct pt purchase ───────────────────────────────────────────────────
// Partners who don't want a MUGEN tee can buy points straight via Stripe.
// Returns a Payment Link; webhook below credits the email on settle.

#[derive(Deserialize)]
struct ExtrasBuyPointsBody {
    #[serde(default)] email: String,
    /// Yen amount; must match one of EXTRAS_POINT_PACKS.
    amount_yen: i64,
    /// Optional proposal slug for the after-completion redirect.
    #[serde(default)] slug: String,
}

fn extras_resolve_pack(amount_yen: i64) -> Option<(i64, i64, i64)> {
    EXTRAS_POINT_PACKS.iter().copied().find(|(a, _, _)| *a == amount_yen)
}

/// POST /api/proposal/extras/buy-points → Stripe Payment Link URL.
#[derive(Deserialize)]
struct ExtrasFeedbackBody {
    #[serde(default)] slug: String,
    #[serde(default)] email: String,
    #[serde(default)] text: String,
}

// ── Universal pt gate (もっと見るには30pt) ─────────────────────────────
// Reusable paywall for any page/section. Cost defaults to EXTRAS_POINTS_PER_SKU (30pt).
// First-time visitors get the free 30pt grant automatically (free_30_used flag).
// Once unlocked, the (email, target) row in proposal_points_unlocks persists forever.

#[derive(Deserialize)]
struct PointsUnlockBody {
    email: String,
    /// Stable gate id, e.g. "kokon:section-2", "jiuflow:deep-dive". Letters/digits/:-_ only.
    target: String,
    /// Cost in pt. Defaults to 30 if 0 or missing.
    #[serde(default)] cost: i64,
}

fn sanitize_pt_target(t: &str) -> String {
    t.chars().filter(|c| c.is_ascii_alphanumeric() || matches!(*c, '-'|'_'|':'|'.')).take(80).collect()
}

/// GET /api/points/balance?email=X
async fn points_balance_api(
    State(db): State<Db>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let email = match q.get("email").and_then(|e| validate_email(e).ok()) {
        Some(e) => e,
        None => return Json(serde_json::json!({"ok": false, "error": "email required"})).into_response(),
    };
    let conn = db.lock().unwrap();
    let (balance, free_used) = points_balance(&conn, &email);
    let free_remaining = if free_used { 0 } else { EXTRAS_FREE_SKUS };
    Json(serde_json::json!({
        "ok": true, "email": email, "balance": balance,
        "free_used": free_used, "free_remaining": free_remaining,
        "pt_per_unlock": EXTRAS_POINTS_PER_SKU,
    })).into_response()
}

/// GET /api/points/unlocked?email=X[&target=Y] — list (or single check) of unlocks.
async fn points_unlocked_api(
    State(db): State<Db>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let email = match q.get("email").and_then(|e| validate_email(e).ok()) {
        Some(e) => e,
        None => return Json(serde_json::json!({"ok": false, "error": "email required"})).into_response(),
    };
    let target = q.get("target").map(|s| sanitize_pt_target(s));
    let conn = db.lock().unwrap();
    if let Some(t) = target.as_deref() {
        let ok: i64 = conn.query_row(
            "SELECT COUNT(*) FROM proposal_points_unlocks WHERE email=? AND target=?",
            params![normalize_email(&email), t], |r| r.get(0),
        ).unwrap_or(0);
        return Json(serde_json::json!({"ok": true, "unlocked": ok > 0, "target": t})).into_response();
    }
    let mut stmt = match conn.prepare(
        "SELECT target, cost, free_used, created_at FROM proposal_points_unlocks WHERE email=? ORDER BY created_at DESC LIMIT 200"
    ) { Ok(s) => s, Err(_) => return Json(serde_json::json!({"ok": true, "unlocks": []})).into_response() };
    let rows: Vec<serde_json::Value> = stmt.query_map(params![normalize_email(&email)], |r| {
        Ok(serde_json::json!({
            "target": r.get::<_, String>(0)?, "cost": r.get::<_, i64>(1)?,
            "free_used": r.get::<_, i64>(2)? != 0, "at": r.get::<_, String>(3)?,
        }))
    }).map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default();
    Json(serde_json::json!({"ok": true, "unlocks": rows})).into_response()
}

/// POST /api/points/unlock — spend points (or free 30) to unlock target content.
/// Returns {ok:true, balance, free_used} on success.
/// Returns {ok:false, need_buy:true, balance, shortfall, buy_url} if insufficient.
async fn points_unlock_api(
    State(db): State<Db>,
    Json(body): Json<PointsUnlockBody>,
) -> Response {
    let email = match validate_email(&body.email) {
        Ok(e) => e,
        Err(m) => return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok": false, "error": m}))).into_response(),
    };
    let target = sanitize_pt_target(&body.target);
    if target.is_empty() {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok": false, "error": "target required"}))).into_response();
    }
    let cost = if body.cost <= 0 { EXTRAS_POINTS_PER_SKU } else { body.cost.min(10_000) };
    let conn = db.lock().unwrap();
    let em = normalize_email(&email);
    // Idempotent: already unlocked?
    let already: i64 = conn.query_row(
        "SELECT COUNT(*) FROM proposal_points_unlocks WHERE email=? AND target=?",
        params![em, target], |r| r.get(0),
    ).unwrap_or(0);
    if already > 0 {
        let (bal, free_used) = points_balance(&conn, &email);
        return Json(serde_json::json!({
            "ok": true, "already_unlocked": true, "balance": bal, "free_used": free_used,
            "target": target,
        })).into_response();
    }
    let (balance, free_used) = points_balance(&conn, &email);
    let use_free = !free_used && cost <= EXTRAS_FREE_SKUS;
    if !use_free && balance < cost {
        // Insufficient → return buy_url for ¥1000 = 1000pt pack
        let shortfall = cost - balance;
        let buy_url = format!("https://wearmu.com/?need_pt={}&email={}", shortfall, urlencoding::encode(&email));
        return Json(serde_json::json!({
            "ok": false, "need_buy": true, "balance": balance, "cost": cost,
            "shortfall": shortfall, "buy_url": buy_url,
            "free_used": free_used,
        })).into_response();
    }
    let now = chrono_now();
    if use_free {
        mark_free_30_used(&conn, &email);
        let _ = conn.execute(
            "INSERT INTO proposal_point_events (email, delta, reason, ref, slug, balance_after, created_at)
             VALUES (?,0,'pt_gate_unlock_free',?,?,?,?)",
            params![em, target, target.split(':').next().unwrap_or(""), balance, now],
        );
    } else {
        // Charge balance
        if let Err(e) = points_mutate(&conn, &email, -cost, "pt_gate_unlock", Some(&target), Some(target.split(':').next().unwrap_or(""))) {
            return (StatusCode::PAYMENT_REQUIRED, Json(serde_json::json!({"ok": false, "error": e}))).into_response();
        }
    }
    let _ = conn.execute(
        "INSERT OR IGNORE INTO proposal_points_unlocks (email, target, cost, free_used, created_at)
         VALUES (?,?,?,?,?)",
        params![em, target, if use_free {0} else {cost}, if use_free {1} else {0}, now],
    );
    let (new_bal, new_free_used) = points_balance(&conn, &email);
    Json(serde_json::json!({
        "ok": true, "unlocked": true, "balance": new_bal, "free_used": new_free_used,
        "target": target, "cost_charged": if use_free {0} else {cost}, "used_free": use_free,
    })).into_response()
}

/// POST /api/proposal/extras/feedback — free-form feedback from a sandbox
/// or proposal page visitor. Stored in proposal_feedback (existing table)
/// + forwarded to Telegram so yuki sees it in real time.
async fn extras_feedback(
    State(db): State<Db>,
    headers: HeaderMap,
    Json(body): Json<ExtrasFeedbackBody>,
) -> Response {
    let text = body.text.trim();
    if text.is_empty() || text.len() > 4000 {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok": false, "error": "text required (1-4000 chars)"}))).into_response();
    }
    let slug = if body.slug.is_empty() { "_general".to_string() }
               else { body.slug.chars().filter(|c| c.is_ascii_alphanumeric() || *c == '-' || *c == '_').take(40).collect() };
    let email = validate_email(&body.email).ok();
    let ip = headers.get("fly-client-ip")
        .or_else(|| headers.get("x-forwarded-for"))
        .and_then(|v| v.to_str().ok())
        .map(|s| s.split(',').next().unwrap_or("").trim().to_string());
    let now = chrono_now();
    {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "INSERT INTO proposal_feedback
                (slug, design_letter, action, comment, voter_email, voter_ip, voter_pseudonym, created_at)
             VALUES (?, '', 'comment', ?, ?, ?, NULL, ?)",
            params![slug, text, email, ip, now],
        );
    }
    // Telegram alert (best-effort, fire-and-forget).
    let tg_token = env::var("TELEGRAM_BOT_TOKEN").unwrap_or_default();
    let tg_chat  = env::var("TELEGRAM_CHAT_ID").unwrap_or_else(|_| "1136442501".into());
    if !tg_token.is_empty() {
        let msg = format!(
            "💬 sandbox feedback\n\nslug: {}\nemail: {}\n\n{}",
            slug, email.as_deref().unwrap_or("(anon)"), text.chars().take(2000).collect::<String>(),
        );
        tokio::spawn(async move {
            let _ = reqwest::Client::new()
                .post(format!("https://api.telegram.org/bot{}/sendMessage", tg_token))
                .json(&serde_json::json!({"chat_id": tg_chat, "text": msg, "disable_web_page_preview": true}))
                .timeout(std::time::Duration::from_secs(8))
                .send().await;
        });
    }
    Json(serde_json::json!({"ok": true})).into_response()
}

async fn extras_buy_points(
    State(_db): State<Db>,
    Json(body): Json<ExtrasBuyPointsBody>,
) -> Response {
    let email = match validate_email(&body.email) {
        Ok(e) => e,
        Err(m) => return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok": false, "error": m}))).into_response(),
    };
    let (yen, pts, bonus) = match extras_resolve_pack(body.amount_yen) {
        Some(p) => p,
        None => return (StatusCode::BAD_REQUEST, Json(serde_json::json!({
            "ok": false, "error": "amount_yen must be one of 1000 / 3000 / 10000 / 30000",
        }))).into_response(),
    };
    let stripe_key = env::var("STRIPE_SECRET_KEY").unwrap_or_default();
    if stripe_key.is_empty() {
        return (StatusCode::SERVICE_UNAVAILABLE, "stripe key missing").into_response();
    }
    let slug_clean: String = body.slug.chars().filter(|c| c.is_ascii_alphanumeric() || *c == '-' || *c == '_').take(40).collect();
    let redirect_url = if slug_clean.is_empty() {
        "https://wearmu.com/?points=ok".to_string()
    } else {
        format!("https://wearmu.com/proposals/{}?points=ok", slug_clean)
    };
    let client = reqwest::Client::new();
    let bonus_label = if bonus > 0 { format!(" +{}% bonus", bonus) } else { String::new() };
    let product_name = format!("MU Collab — {} pt 購入 (¥{}{})", pts, yen, bonus_label);
    let price_form: Vec<(&str, String)> = vec![
        ("currency", "jpy".into()),
        ("unit_amount", yen.to_string()),
        ("product_data[name]", product_name),
    ];
    let raw_resp = match client.post("https://api.stripe.com/v1/prices")
        .basic_auth(&stripe_key, Some("")).form(&price_form).send().await {
        Ok(r) => {
            let s = r.status();
            let b = r.text().await.unwrap_or_default();
            if !s.is_success() {
                return (StatusCode::BAD_GATEWAY, format!("stripe {}: {}", s, b.chars().take(300).collect::<String>())).into_response();
            }
            b
        }
        Err(e) => return (StatusCode::BAD_GATEWAY, format!("stripe price http: {}", e)).into_response(),
    };
    let price_id: String = serde_json::from_str::<serde_json::Value>(&raw_resp)
        .ok().and_then(|v| v.get("id").and_then(|x| x.as_str()).map(String::from)).unwrap_or_default();
    if price_id.is_empty() {
        return (StatusCode::BAD_GATEWAY, "stripe returned no price id").into_response();
    }
    let pl_form: Vec<(&str, String)> = vec![
        ("line_items[0][price]", price_id),
        ("line_items[0][quantity]", "1".into()),
        ("allow_promotion_codes", "true".into()),
        ("after_completion[type]", "redirect".into()),
        ("after_completion[redirect][url]", redirect_url.clone()),
        ("metadata[kind]", "extras_points".into()),
        ("metadata[email]", email.clone()),
        ("metadata[slug]", slug_clean.clone()),
        ("metadata[amount_yen]", yen.to_string()),
        ("metadata[pts]", pts.to_string()),
        ("metadata[bonus_pct]", bonus.to_string()),
    ];
    match client.post("https://api.stripe.com/v1/payment_links")
        .basic_auth(&stripe_key, Some("")).form(&pl_form).send().await
    {
        Ok(r) => {
            let v: serde_json::Value = r.json().await.unwrap_or(serde_json::Value::Null);
            if let Some(u) = v.get("url").and_then(|x| x.as_str()) {
                Json(serde_json::json!({
                    "ok": true, "url": u, "email": email,
                    "amount_yen": yen, "pts": pts, "bonus_pct": bonus,
                })).into_response()
            } else {
                (StatusCode::BAD_GATEWAY, format!("payment_link: {}", v.to_string().chars().take(300).collect::<String>())).into_response()
            }
        }
        Err(e) => (StatusCode::BAD_GATEWAY, format!("stripe: {}", e)).into_response(),
    }
}

/// POST /api/proposal/extras/claim — claim MU-tee purchase as pt grant.
/// Eligible brands: mugen / muon / ma. Grants 100% of the actual yen paid
/// (from mu_purchases.amount_jpy; falls back to products.price_jpy for
/// legacy rows that pre-date the column). Idempotent per purchase id.
async fn extras_claim_mu(
    State(db): State<Db>,
    Json(body): Json<ExtrasClaimMuBody>,
) -> Response {
    let email = match validate_email(&body.email) {
        Ok(e) => e,
        Err(m) => return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok": false, "error": m}))).into_response(),
    };
    let token = body.mu_purchase.trim();
    if token.is_empty() {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({"ok": false, "error": "missing mu_purchase id or session"}))).into_response();
    }
    // Resolve token → mu_purchases row (id, brand, email, paid amount).
    // amount_jpy may be NULL for legacy rows — fall back to products.price_jpy.
    let (purchase_id, brand, purchase_email, amount_jpy): (i64, String, String, i64) = {
        let conn = db.lock().unwrap();
        let sql = "SELECT mp.id, mp.brand, mp.email,
                          COALESCE(mp.amount_jpy, (SELECT p.price_jpy FROM products p WHERE p.id = mp.product_id), 0)
                   FROM mu_purchases mp
                   WHERE";
        let row = if let Ok(id) = token.parse::<i64>() {
            conn.query_row(
                &format!("{} mp.id=?", sql),
                params![id],
                |r| Ok((r.get::<_, i64>(0)?, r.get::<_, String>(1)?, r.get::<_, String>(2)?, r.get::<_, i64>(3)?)),
            )
        } else {
            conn.query_row(
                &format!("{} mp.session_id=?", sql),
                params![token],
                |r| Ok((r.get::<_, i64>(0)?, r.get::<_, String>(1)?, r.get::<_, String>(2)?, r.get::<_, i64>(3)?)),
            )
        };
        match row {
            Ok(v) => v,
            Err(_) => return (StatusCode::NOT_FOUND, Json(serde_json::json!({"ok": false, "error": "purchase not found — check the order id from your MU receipt"}))).into_response(),
        }
    };
    if !extras_brand_is_claimable(&brand) {
        return (StatusCode::BAD_REQUEST, Json(serde_json::json!({
            "ok": false, "error": format!("brand={} is not eligible (only mugen/muon/ma purchases grant points)", brand),
        }))).into_response();
    }
    if normalize_email(&purchase_email) != email {
        return (StatusCode::FORBIDDEN, Json(serde_json::json!({"ok": false, "error": "email does not match the purchase"}))).into_response();
    }
    // Floor guard: skip if we can't resolve a positive amount (e.g. amount_jpy
    // is NULL and products.price_jpy is 0 for some reason). Better to fail
    // loudly than silently grant 0.
    if amount_jpy <= 0 {
        return (StatusCode::CONFLICT, Json(serde_json::json!({
            "ok": false, "error": "could not resolve purchase amount; contact info@wearmu.com",
        }))).into_response();
    }
    let conn = db.lock().unwrap();
    let already: bool = conn.query_row(
        "SELECT 1 FROM proposal_mugen_claims WHERE mu_purchase_id=?",
        params![purchase_id], |_| Ok(true),
    ).unwrap_or(false);
    if already {
        let (balance, _) = points_balance(&conn, &email);
        return Json(serde_json::json!({
            "ok": false, "error": "this purchase has already been claimed",
            "balance": balance,
        })).into_response();
    }
    let now = chrono_now();
    let reason = format!("{}_claim", brand);
    let new_balance = match points_mutate(&conn, &email, amount_jpy, &reason,
                                          Some(&purchase_id.to_string()), None) {
        Ok(b) => b,
        Err(e) => return (StatusCode::INTERNAL_SERVER_ERROR, Json(serde_json::json!({"ok": false, "error": e}))).into_response(),
    };
    let _ = conn.execute(
        "INSERT INTO proposal_mugen_claims (mu_purchase_id, email, slug, points_added, claimed_at)
         VALUES (?,?,NULL,?,?)",
        params![purchase_id, email, amount_jpy, now],
    );
    Json(serde_json::json!({
        "ok": true, "added": amount_jpy, "brand": brand,
        "balance": new_balance, "mu_purchase_id": purchase_id,
    })).into_response()
}

// ── Proposal extras worker (background Gemini SKU generator) ─────────────
//
// Picks one pending job at a time, marks it 'processing', generates `qty`
// SKU mockups, uploads each to R2 under extras/<slug>/<job>-<idx>.jpg, and
// inserts a row into proposal_extras_skus + proposal_skus. On per-image
// failure, refunds the unused fraction of points (when the job was paid).
//
// Polls every 30s; back-off on empty queue.

/// 30 categories × colour rotation. Cycled by (idx % CATEGORIES.len()) so
/// 50 and 100-piece runs naturally spread across the same palette.
const EXTRAS_CATEGORIES: &[(&str, &str, i64)] = &[
    ("tee",        "heavy cotton T-shirt, black, half-body on model",                 4900),
    ("tee",        "lightweight T-shirt, off-white, half-body on model",              4900),
    ("longsleeve", "long-sleeve tee, faded olive, half-body on model",                6200),
    ("longsleeve", "long-sleeve tee, deep navy, half-body on model",                  6200),
    ("hoodie",     "heavy loop-back hoodie, charcoal, candid lifestyle",              9800),
    ("hoodie",     "heavy loop-back hoodie, sand, candid lifestyle",                  9800),
    ("zip-hoodie", "zip-up hoodie, black cotton blend, half-body on model",          10800),
    ("crewneck",   "fleece crewneck sweatshirt, off-white, half-body on model",       8900),
    ("cap",        "5-panel strapback cap, charcoal grey, front-view product shot",   4200),
    ("cap",        "flat-brim snapback, solid black wool, front-view product shot",   4500),
    ("beanie",     "ribbed knit beanie, deep navy, plinth product shot",              3900),
    ("bucket-hat", "bucket hat, black canvas, candid portrait on model",              4500),
    ("tote",       "raw canvas tote, natural off-white, hanging product shot",        3800),
    ("duffle",     "duffle bag, black with subtle all-over wordmark, rack shot",      9800),
    ("backpack",   "mid-size daypack, white with subtle all-over wordmark, floor",   11800),
    ("fanny-pack", "fanny pack, white with subtle pattern, cross-body on model",      4900),
    ("iphone-case","clear iPhone 15 case, brand wordmark on back panel, desk macro",  3800),
    ("mug",        "black glossy ceramic mug, wordmark sublimated white, table",      2900),
    ("bottle",     "matte black stainless 17oz bottle, plinth product shot",          4200),
    ("stickers",   "sticker sheet with wordmark variants, flat-lay on concrete",      1200),
    ("tank",       "athletic tank top, solid black cotton, half-body on model",       4500),
    ("joggers",    "recycled poly joggers, white with tonal pattern, lower-half",     6800),
    ("shorts",     "cotton shorts, solid black with faint pattern, lower-half",       5200),
    ("windbreaker","pull-over nylon windbreaker, matte black, candid on model",       9800),
    ("bomber",     "all-over print bomber, white satin shell, 3/4 view on model",    14800),
    ("track-jkt",  "track jacket, off-white with tonal pattern, half-body on model",  9800),
    ("jersey",     "button-front baseball jersey, white with tonal pattern, model",   8900),
    ("socks",      "crew socks 3-pack, white/black/grey, stacked product shot",       2400),
    ("spats",      "compression grappling spats, matte black, action half-body",      6800),
    ("fight-shorts","MMA fight shorts, all-black with subtle side line, athlete",     6800),
];

/// Categories that are BJJ / combat-sports specific. We hide these from
/// partners whose mood does not match (F&B, hospitality, lifestyle brands).
const EXTRAS_BJJ_ONLY_KINDS: &[&str] = &["spats", "fight-shorts"];

/// True iff this partner is allowed to receive BJJ-flavoured categories.
fn partner_allows_bjj(slug: &str) -> bool {
    matches!(slug,
        "sweep" | "jiuflow" | "jiufight" | "ryozo" | "nojimahal"
        // any future BJJ partners can be appended here without DB changes
    )
}

/// Returns the categories to rotate through for `slug`. BJJ-only kinds
/// are stripped for non-BJJ partners so e.g. kokon never gets fight-shorts.
fn extras_categories_for(slug: &str) -> Vec<(&'static str, &'static str, i64)> {
    if partner_allows_bjj(slug) {
        return EXTRAS_CATEGORIES.to_vec();
    }
    EXTRAS_CATEGORIES.iter()
        .filter(|(kind, _, _)| !EXTRAS_BJJ_ONLY_KINDS.contains(kind))
        .copied()
        .collect()
}

async fn proposal_extras_worker(db: Db) {
    // Honour a kill switch so the worker can be disabled on Fly via env.
    if env::var("PROPOSAL_EXTRAS_DISABLED").ok().as_deref() == Some("1") {
        eprintln!("[extras-worker] PROPOSAL_EXTRAS_DISABLED=1 — exiting");
        return;
    }
    loop {
        let job = pick_one_pending_extras_job(&db);
        match job {
            Some((id, slug, email, qty, free_applied, points_charged)) => {
                let res = process_extras_job(db.clone(), id, slug.clone(), email.clone(), qty).await;
                finalize_extras_job(&db, id, &email, qty, free_applied, points_charged, &slug, res);
            }
            None => {
                tokio::time::sleep(std::time::Duration::from_secs(30)).await;
            }
        }
    }
}

fn pick_one_pending_extras_job(db: &Db) -> Option<(i64, String, String, i64, bool, i64)> {
    let conn = db.lock().unwrap();
    let row = conn.query_row(
        "SELECT id, slug, email, qty, free_applied, points_charged
         FROM proposal_extras_jobs WHERE status='pending'
         ORDER BY id ASC LIMIT 1",
        [],
        |r| Ok((r.get::<_, i64>(0)?, r.get::<_, String>(1)?, r.get::<_, String>(2)?,
                r.get::<_, i64>(3)?, r.get::<_, i64>(4)? != 0, r.get::<_, i64>(5)?)),
    ).ok()?;
    let now = chrono_now();
    let _ = conn.execute(
        "UPDATE proposal_extras_jobs SET status='processing', started_at=? WHERE id=? AND status='pending'",
        params![now, row.0],
    );
    Some(row)
}

/// Returns (succeeded_count, last_error). last_error is Some only if at
/// least one image failed; succeeded_count is the number of SKUs actually
/// inserted into proposal_extras_skus.
async fn process_extras_job(
    db: Db, job_id: i64, slug: String, _email: String, qty: i64,
) -> (i64, Option<String>) {
    // Look up partner display name. Fall back to a hand-curated map for the
    // legacy sweep/kokon brands that don't have a proposals row.
    let partner_name: String = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT COALESCE(name, slug) FROM proposals WHERE slug=?",
            params![slug], |r| r.get::<_, String>(0),
        ).ok().unwrap_or_else(|| match slug.as_str() {
            "sweep"   => "SIIIEEP".to_string(),
            "kokon"   => "kokon.tokyo".to_string(),
            "jiuflow" => "JiuFlow".to_string(),
            other     => other.to_string(),
        })
    };
    // Offset to keep generated letters unique within proposal_skus(slug, letter)
    // — use 'x' + job_id + idx so even if two jobs interleave we don't clash.
    let r2 = r2_config();
    if r2.is_none() {
        return (0, Some("R2 not configured — set R2_ENDPOINT/R2_BUCKET/R2_ACCESS_KEY_ID/R2_SECRET_ACCESS_KEY".to_string()));
    }
    let cfg = r2.unwrap();
    let now_seed = chrono_now();
    let mut succeeded: i64 = 0;
    let mut last_err: Option<String> = None;
    let categories = extras_categories_for(&slug);
    if categories.is_empty() {
        return (0, Some("no allowed categories for this partner".to_string()));
    }
    for i in 0..qty {
        // P2.1: honour partner-initiated cancel mid-run. Status flips to
        // 'cancelling' via the /stop endpoint; we bail out and let
        // finalize_extras_job mark it 'cancelled' + refund unused pt.
        let cancelled: bool = {
            let conn = db.lock().unwrap();
            conn.query_row(
                "SELECT status FROM proposal_extras_jobs WHERE id=?",
                params![job_id], |r| r.get::<_, String>(0),
            ).map(|s| s == "cancelling" || s == "cancelled").unwrap_or(false)
        };
        if cancelled {
            last_err = Some(format!("cancelled by partner at {}/{}", succeeded, qty));
            break;
        }
        let (kind, label_tmpl, price_jpy) = categories[(i as usize) % categories.len()];
        let label = format!("MU × {} — {}", partner_name, label_tmpl);
        let seed = format!("job{}-{}-{}", job_id, i, now_seed.chars().filter(|c| c.is_ascii_alphanumeric()).take(8).collect::<String>());
        let tagline = format!("quiet, premium, 1着 = 1 シグナル");
        let brief = gemini::PartnerSkuBrief {
            partner_display: &partner_name,
            partner_tagline: &tagline,
            kind, label: &label, seed: &seed,
        };
        let img = match gemini::generate_partner_sku(&brief).await {
            Ok(g) => g,
            Err(e) => {
                eprintln!("[extras-worker] job={} idx={} gemini fail: {}", job_id, i, e);
                last_err = Some(format!("gemini #{}: {}", i, e.chars().take(120).collect::<String>()));
                continue;
            }
        };
        let key = format!("extras/{}/{}-{:03}.{}", slug, job_id, i,
            if img.mime.contains("png") { "png" } else { "jpg" });
        let ct = if img.mime.contains("png") { "image/png" } else { "image/jpeg" };
        let url = match cfg.bucket.put_object_with_content_type(&key, &img.bytes, ct).await {
            Ok(r) if r.status_code() == 200 => format!("{}/{}", cfg.public_base.trim_end_matches('/'), key),
            Ok(r) => {
                eprintln!("[extras-worker] job={} idx={} r2 status={}: {}",
                    job_id, i, r.status_code(), String::from_utf8_lossy(r.bytes()));
                last_err = Some(format!("r2 #{}: status {}", i, r.status_code()));
                continue;
            }
            Err(e) => {
                eprintln!("[extras-worker] job={} idx={} r2 err: {}", job_id, i, e);
                last_err = Some(format!("r2 #{}: {}", i, e.to_string().chars().take(120).collect::<String>()));
                continue;
            }
        };
        let letter = format!("x{}{:03}", job_id, i);
        let now = chrono_now();
        let conn = db.lock().unwrap();
        // Only the extras audit table is written during generation. The
        // partner's LP (proposal_skus) is only populated on approve — this
        // is the approval-gate fix from the persona review (P0.1).
        let _ = conn.execute(
            "INSERT INTO proposal_extras_skus
                (job_id, slug, letter, label, kind, price_jpy, image_url, prompt,
                 approval_status, created_at)
             VALUES (?,?,?,?,?,?,?,?, 'pending', ?)",
            params![job_id, slug, letter, label, kind, price_jpy, url,
                    gemini::build_partner_sku_prompt(&brief), now],
        );
        let _ = conn.execute(
            "UPDATE proposal_extras_jobs SET done_count=done_count+1 WHERE id=?",
            params![job_id],
        );
        succeeded += 1;
    }
    (succeeded, last_err)
}

fn finalize_extras_job(
    db: &Db, job_id: i64, email: &str, qty: i64,
    free_applied: bool, points_charged: i64, slug: &str,
    res: (i64, Option<String>),
) {
    let (succeeded, last_err) = res;
    let (was_cancelling, notify_email): (bool, bool) = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT status, notify_email FROM proposal_extras_jobs WHERE id=?",
            params![job_id], |r| Ok((r.get::<_, String>(0)? == "cancelling",
                                     r.get::<_, i64>(1)? != 0)),
        ).unwrap_or((false, false))
    };
    let status = if was_cancelling { "cancelled" }
                 else if succeeded == qty { "completed" }
                 else if succeeded == 0 { "failed" }
                 else { "partial" };
    let conn = db.lock().unwrap();
    let now = chrono_now();
    let _ = conn.execute(
        "UPDATE proposal_extras_jobs
         SET status=?, completed_at=?, last_error=COALESCE(?, last_error)
         WHERE id=?",
        params![status, now, last_err.as_deref(), job_id],
    );
    // Refund unused points on partial/failed jobs (only when actually paid).
    if !free_applied && succeeded < qty && points_charged > 0 {
        let failed = qty - succeeded;
        let refund = failed * EXTRAS_POINTS_PER_SKU;
        if refund > 0 {
            let _ = points_mutate(&conn, email, refund, "extras_refund",
                                  Some(&job_id.to_string()), Some(slug));
        }
    }
    // P1.3 fix from persona review: the free 30-pack is only consumed when
    // the run is fully successful (30/30). Any partial/total fail returns
    // the free token so the partner can try again. Worst case: we eat the
    // cost of a few extra Gemini calls — fairer than burning the freebie
    // on a half-broken batch.
    if free_applied && succeeded < qty {
        let _ = conn.execute(
            "UPDATE proposal_points SET free_30_used=0, updated_at=? WHERE email=?",
            params![now, normalize_email(email)],
        );
    }
    drop(conn);
    // P2.3: optional completion email via Resend. Fire-and-forget so a
    // mail failure never blocks finalize.
    if notify_email {
        let email_owned = email.to_string();
        let slug_owned = slug.to_string();
        let status_owned = status.to_string();
        tokio::spawn(async move {
            send_extras_completion_email(&email_owned, &slug_owned, job_id,
                                         &status_owned, succeeded, qty).await;
        });
    }
}

/// Sends a one-shot completion mail. Silent no-op if RESEND_API_KEY is unset.
async fn send_extras_completion_email(
    email: &str, slug: &str, job_id: i64,
    status: &str, succeeded: i64, qty: i64,
) {
    let resend_key = env::var("RESEND_API_KEY").unwrap_or_default();
    if resend_key.is_empty() {
        tracing::info!("[extras-notify] RESEND_API_KEY unset — skipping notification for job {}", job_id);
        return;
    }
    let subj_state = match status {
        "completed" => "完了",
        "partial"   => "部分完了",
        "cancelled" => "キャンセル",
        _           => "終了",
    };
    let subj = format!("MU × {} · 拡張 SKU 生成 {}", slug.to_uppercase(), subj_state);
    let url = format!("https://wearmu.com/proposals/{}", slug);
    let html = format!(
        r#"<div style="font-family:'Helvetica Neue',Arial,sans-serif;line-height:1.7;color:#222;max-width:520px">
        <h2 style="font-size:18px;font-weight:500">━◯━ ジョブ #{job} が {state} しました</h2>
        <p style="font-size:14px">生成: <strong>{succ}</strong> / {qty}<br>partner: <strong>{slug}</strong></p>
        <p style="font-size:14px">プロポーザル LP で各 SKU を <strong>✓ 承認</strong> または <strong>✗ 却下</strong> してください。 ✓ を押した SKU だけが LP に並びます。</p>
        <p style="margin:18px 0"><a href="{url}" style="background:#0a0a0a;color:#e6c449;text-decoration:none;padding:10px 18px;border-radius:3px;font-size:13px;letter-spacing:0.04em">→ {url}</a></p>
        <p style="font-size:11px;color:#888;margin-top:24px">free 枠で開始し失敗・キャンセルした場合、 無料 30 個の権利は自動で復元されています。<br>— MU / 株式会社イネブラ</p>
        </div>"#,
        job = job_id, state = subj_state, succ = succeeded, qty = qty,
        slug = slug, url = url,
    );
    let _ = send_extras_email(&resend_key, email, &subj, &html).await;
}

/// Thin Resend wrapper. Single source of truth for the from-address and
/// timeout — used by every extras-related notification.
async fn send_extras_email(resend_key: &str, to: &str, subject: &str, html: &str) -> bool {
    let r = reqwest::Client::new()
        .post("https://api.resend.com/emails")
        .bearer_auth(resend_key)
        .json(&serde_json::json!({
            "from": "━◯━ MU <info@wearmu.com>",
            "to": [to.to_string()],
            "subject": subject,
            "html": html,
            "reply_to": "info@wearmu.com",
        }))
        .timeout(std::time::Duration::from_secs(15))
        .send().await;
    matches!(r, Ok(rr) if rr.status().is_success())
}

/// Daily cron: nudge wallets that have been idle for 90+ days but still
/// have a meaningful balance. Points NEVER expire — this is purely a
/// "you have credit, don't forget" reminder. At most one mail per 180d.
const EXTRAS_REMINDER_INACTIVE_DAYS: i64 = 90;
const EXTRAS_REMINDER_COOLDOWN_DAYS: i64 = 180;
const EXTRAS_REMINDER_MIN_BALANCE: i64 = 300; // <10 SKUs not worth nudging

async fn proposal_extras_reminder_cron(db: Db) {
    let resend_key = env::var("RESEND_API_KEY").unwrap_or_default();
    if resend_key.is_empty() {
        tracing::info!("[extras-reminder] RESEND_API_KEY unset — skipping");
        return;
    }
    // Timestamps in the DB are unix-secs strings (chrono_now()). Compare
    // lexicographically since unix-secs strings of equal length sort
    // correctly. We pad to 10 chars below to stay correct past 2001-2286.
    use std::time::{SystemTime, UNIX_EPOCH};
    let now_secs = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs() as i64;
    let cutoff_activity_s = format!("{}", now_secs - EXTRAS_REMINDER_INACTIVE_DAYS * 86_400);
    let cutoff_remind_s   = format!("{}", now_secs - EXTRAS_REMINDER_COOLDOWN_DAYS * 86_400);
    let rows: Vec<(String, i64)> = {
        let conn = db.lock().unwrap();
        let mut st = match conn.prepare(
            "SELECT email, balance FROM proposal_points
             WHERE balance >= ?
               AND COALESCE(last_activity_at, updated_at) < ?
               AND (last_reminder_sent_at IS NULL OR last_reminder_sent_at < ?)
             ORDER BY balance DESC LIMIT 200"
        ) { Ok(s) => s, Err(_) => return };
        let it = st.query_map(params![EXTRAS_REMINDER_MIN_BALANCE, cutoff_activity_s, cutoff_remind_s],
            |r| Ok((r.get::<_, String>(0)?, r.get::<_, i64>(1)?)));
        match it { Ok(rs) => rs.flatten().collect(), Err(_) => Vec::new() }
    };
    let n = rows.len();
    if n == 0 {
        tracing::info!("[extras-reminder] no idle wallets to nudge");
        return;
    }
    tracing::info!("[extras-reminder] sending {} nudge emails", n);
    for (email, balance) in rows {
        let my_url = extras_my_url(&email);
        let html = format!(
            r##"<div style="font-family:'Helvetica Neue','Hiragino Sans',Arial,sans-serif;line-height:1.75;color:#222;max-width:520px;margin:0 auto;padding:8px">
<p style="font-size:14px">{email} さん、 こんにちは。 MU の濱田です。</p>
<p style="font-size:14px">前にお渡しした AI 試作用ポイント、 <strong>{bal_fmt} pt (¥{bal_fmt}) がまだ残っています</strong>。 失効はありませんが、 90 日以上触れてなさそうだったので念のため。</p>
<p style="margin:24px 0;text-align:center">
  <a href="{my_url}" style="background:#0a0a0a;color:#e6c449;text-decoration:none;padding:13px 26px;font-weight:700;border-radius:4px;letter-spacing:0.06em;font-size:13px;display:inline-block">🎨 sandbox を開く →</a>
</p>
<p style="font-size:13px;color:#555">気が向いたら触ってみてください。 1 SKU = 30 pt = ¥30 で、 自分のブランドの雰囲気で AI 生成 → 良いやつだけ ✓ で選別、 という使い方です。</p>
<p style="font-size:13px;color:#555;margin-top:18px"><strong>「使わなさそう」「忘れてた」「興味なくなった」</strong> どれでも素直な感想あったらメール返信ください。 次の改善に活かします。</p>
<p style="font-size:14px;margin-top:28px">— 濱田 優貴</p>
<p style="font-size:11px;color:#aaa;margin-top:28px;border-top:1px solid #eee;padding-top:12px">配信停止: <a href="mailto:info@wearmu.com" style="color:#aaa">info@wearmu.com</a><br>MU / 株式会社イネブラ</p>
</div>"##,
            email = html_escape(&email), bal_fmt = fmt_jpy(balance), my_url = html_attr_escape(&my_url),
        );
        let ok = send_extras_email(&resend_key, &email, "MU Collab — まだ残ってるポイントのこと", &html).await;
        if ok {
            let conn = db.lock().unwrap();
            let _ = conn.execute(
                "UPDATE proposal_points SET last_reminder_sent_at=? WHERE email=?",
                params![chrono_now(), email],
            );
        }
        tokio::time::sleep(std::time::Duration::from_millis(700)).await;
    }
}

