/// Bytes of profile + banner PNGs (embedded at compile time).
const X_PROFILE_PNG: &[u8] = include_bytes!("../static/x/profile.png");
const X_BANNER_PNG:  &[u8] = include_bytes!("../static/x/banner.png");

/// POST /admin/x/rebrand-once — one-shot: profile + pinned tweet + 3-tweet thread.
async fn admin_x_rebrand_once(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/admin/x/rebrand-once").await { return r; }
    let mut result = serde_json::Map::new();

    // 1. Profile fields.
    let bio = "北海道弟子屈の気象 × AI が、世界に 1 人のための T シャツを毎日描く。\nHokkaido weather → AI → 1/1 T-shirt. Autopilot apparel.\n/collab /bounty /you · Enabler Inc.";
    match x_update_profile(Some("MU / wearmu.com"), Some(bio), Some("https://wearmu.com"), Some("弟子屈 / Tokyo")).await {
        Ok(_) => { result.insert("profile".into(), serde_json::Value::from("updated")); }
        Err(e) => { result.insert("profile_err".into(), serde_json::Value::from(e)); }
    }

    // 1b. Profile image.
    match x_update_profile_image(X_PROFILE_PNG).await {
        Ok(()) => { result.insert("profile_image".into(), serde_json::Value::from("updated")); }
        Err(e) => { result.insert("profile_image_err".into(), serde_json::Value::from(e)); }
    }

    // 1c. Profile banner.
    match x_update_profile_banner(X_BANNER_PNG).await {
        Ok(()) => { result.insert("profile_banner".into(), serde_json::Value::from("updated")); }
        Err(e) => { result.insert("profile_banner_err".into(), serde_json::Value::from(e)); }
    }

    // 2. Rebrand tweet (head of thread).
    let t1 = "はじめまして、@wearMUcom です。\n\n「自動運転のアパレル」をやってます:\n\n🌡️ 北海道弟子屈の気象を AI が毎日読む\n🎨 1日1着、世界に1人のためのTシャツを生成\n📦 Printful 直接発注、7-10日でお届け\n🔗 Solana 永続記録、布が消えても記録は残る\n🤖 メール文面まで AI が自分で書き直す\n\n人間 0 人で動く apparel ブランド、はじめます。\n→ wearmu.com";
    let t1_id = match x_post_tweet_v2(&db, t1, None).await {
        Ok(id) => { result.insert("tweet1".into(), serde_json::Value::from(id.clone())); Some(id) }
        Err(e) => { result.insert("tweet1_err".into(), serde_json::Value::from(e)); None }
    };

    // 3. Pin tweet 1.
    if let Some(id) = &t1_id {
        match x_pin_tweet(&db, id).await {
            Ok(()) => { result.insert("pinned".into(), serde_json::Value::from(true)); }
            Err(e) => { result.insert("pin_err".into(), serde_json::Value::from(e)); }
        }
    }

    // 4. Thread tweet 2 (reply to 1).
    let t2 = "1/ MU の中身を全部公開してます。\n\nなぜ自動運転?\n人間0人で動く apparel ブランドを作ってる。デザイン生成、価格調整、カスタマーサポート、メール文面の改善、すべて AI agent が回す。\n\n濱田 (元 Mercari CPO) が監査だけする。";
    let t2_id = if let Some(rid) = &t1_id {
        match x_post_tweet_v2(&db, t2, Some(rid)).await {
            Ok(id) => { result.insert("tweet2".into(), serde_json::Value::from(id.clone())); Some(id) }
            Err(e) => { result.insert("tweet2_err".into(), serde_json::Value::from(e)); None }
        }
    } else { None };

    // 5. Thread tweet 3 (reply to 2).
    let t3 = "2/ 仕組みは全部 open:\n\n- agent_email_critic: 4 ペルソナ (Musk/Bezos/Jobs/Buyer) が毎日採点\n- agent_email_rewriter: 0.7 以下を Gemini Pro が書き直し\n- agent_bounty_triage: バグ報告を AI が 1 次仕分け\n- agent_price_micro: 価格を ±¥200 で自動調整\n- agent_strategist: 週次戦略を Gemini Pro が提案";
    let t3_id = if let Some(rid) = &t2_id {
        match x_post_tweet_v2(&db, t3, Some(rid)).await {
            Ok(id) => { result.insert("tweet3".into(), serde_json::Value::from(id.clone())); Some(id) }
            Err(e) => { result.insert("tweet3_err".into(), serde_json::Value::from(e)); None }
        }
    } else { None };

    // 6. Thread tweet 4 (reply to 3) — new features.
    let t4 = "3/ 今日 live になった追加機能:\n\n✅ /mypage — email リンクログイン + NFT 受け取り\n✅ /buyer/:token — 各オーナーの公開プロフィール\n✅ Resend Inbound — info@wearmu.com → AI 自動分類\n✅ 13 種 × A/B = 26 メールテンプレ自動運用\n\n服が届くまで体験を作ってる。\n→ wearmu.com";
    if let Some(rid) = &t3_id {
        match x_post_tweet_v2(&db, t4, Some(rid)).await {
            Ok(id) => { result.insert("tweet4".into(), serde_json::Value::from(id)); }
            Err(e) => { result.insert("tweet4_err".into(), serde_json::Value::from(e)); }
        }
    }

    Json(serde_json::Value::Object(result)).into_response()
}

/// POST /admin/x/delete?token=…&tweet_id=… — delete a tweet from @wearMUcom.
async fn admin_x_delete(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/admin/x/delete").await { return r; }
    let tweet_id = match q.get("tweet_id") {
        Some(t) if !t.is_empty() => t.clone(),
        _ => return (StatusCode::BAD_REQUEST, "missing ?tweet_id=").into_response(),
    };
    match x_delete_tweet_v2(&db, &tweet_id).await {
        Ok(()) => Json(serde_json::json!({"ok": true, "deleted": tweet_id})).into_response(),
        Err(e) => Json(serde_json::json!({"ok": false, "tweet_id": tweet_id, "err": e})).into_response(),
    }
}

/// "Cultural moment" daily cron — JST 12:00. Asks Gemini if there's an
/// observation MU should make today that lands cleanly with the brand voice
/// (fashion week timing, season turn, AI industry milestone, weather extreme,
/// etc.). If Gemini returns something, enqueue. Empty response = silence.
async fn run_cultural_moment_cron(db: Db) {
    if autopilot_skip("cultural-moment") { return; }
    // Skip if already enqueued today.
    let today = jst_today_str();
    let already: bool = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT 1 FROM sns_post_queue
             WHERE trigger_kind='cultural' AND DATE(created_at) = DATE(?)",
            params![chrono_now()], |r| r.get::<_, i64>(0),
        ).is_ok()
    };
    if already {
        tracing::info!("[cultural] already posted today, skipping");
        return;
    }
    // Build context: today's weather, recent drops, current ISO week.
    let weather_data: Option<String> = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT weather_data FROM products
             WHERE brand='muon' AND DATE(created_at) = DATE(?)
             ORDER BY created_at DESC LIMIT 1",
            params![chrono_now()], |r| r.get::<_, String>(0),
        ).ok()
    };
    let recent_sales: i64 = {
        let conn = db.lock().unwrap();
        conn.query_row(
            "SELECT COUNT(*) FROM mu_purchases WHERE DATE(created_at) >= DATE('now','-7 days')",
            [], |r| r.get::<_, i64>(0),
        ).unwrap_or(0)
    };
    let context = format!(
        "Today: {today}\n\
         Today's Hokkaido weather (MUON oracle): {weather}\n\
         Sales last 7 days: {sales}\n\
         Recent fashion-industry events to consider only if relevant:\n\
         - Paris/Milan/Tokyo Fashion Week happens twice a year (Feb-Mar, Sep-Oct)\n\
         - Met Gala is first Monday of May\n\
         - Black Friday late November (we ignore it, but readers know)\n\
         - Christmas, New Year, golden week, summer solstice\n\
         AI events:\n\
         - Major model releases, open-source LLM news\n\
         - AI x art debates ongoing\n\
         \n\
         If today calls for an observation MU should make, write it as a tweet.\n\
         If today is just an ordinary day with no clean angle, return EMPTY STRING.\n\
         Don't force a take. Silence is fine.",
        today = today,
        weather = weather_data.as_deref().unwrap_or("(none today)"),
        sales = recent_sales,
    );
    let composed = compose_x_tweet_via_gemini("cultural", &context).await;
    match composed {
        Some(text) if !text.trim().is_empty() => {
            let conn = db.lock().unwrap();
            let id = enqueue_sns_post(&conn, "x", "cultural", None, None, &text, None);
            tracing::info!("[cultural] enqueued #{}: {}", id, text.chars().take(60).collect::<String>());
        }
        _ => {
            tracing::info!("[cultural] no observation today, staying silent");
        }
    }
}

/// Background worker that drains sns_post_queue every 60s and posts to X.
/// Idempotent (sets posted_at on success, error on failure).
async fn x_post_worker(db: Db) {
    loop {
        tokio::time::sleep(std::time::Duration::from_secs(60)).await;
        if !autopilot_on() { continue; }
        // Skip if X not yet linked. Two paths satisfy "linked":
        //   1. OAuth 1.0a creds set as env vars (preferred — no expiry)
        //   2. OAuth 2.0 PKCE row in x_oauth_tokens (from /admin/x/auth)
        let has_oauth1 = ["X_CONSUMER_KEY","X_CONSUMER_SECRET","X_ACCESS_TOKEN","X_ACCESS_TOKEN_SECRET"]
            .iter().all(|k| env::var(k).map(|v| !v.is_empty()).unwrap_or(false));
        let linked = if has_oauth1 { true } else {
            let conn = db.lock().unwrap();
            conn.query_row(
                "SELECT 1 FROM x_oauth_tokens WHERE id=1",
                [], |r| r.get::<_, i64>(0),
            ).is_ok()
        };
        if !linked { continue; }
        // Age-filter so a long-paused worker (e.g. X OAuth unset for a week)
        // doesn't burst-post stale content when auth is reconnected. Anything
        // older than 7 days gets marked expired and skipped. Constitution
        // principle #14: preserve negative space — skip a day rather than fill.
        let week_ago = chrono_now().parse::<i64>().unwrap_or(0) - 7 * 86_400;
        let pending: Vec<(i64, String)> = {
            let conn = db.lock().unwrap();
            // Expire any rows older than 7d that never posted.
            let _ = conn.execute(
                "UPDATE sns_post_queue
                 SET error = COALESCE(NULLIF(error,''), 'expired_too_old')
                 WHERE network='x' AND posted_at IS NULL
                   AND CAST(COALESCE(created_at,'0') AS INTEGER) < ?",
                params![week_ago],
            );
            // Constitution §3 ("Quiet by default"). 1 post per 60s tick =
            // catch-up backlog at 1/min, natural cadence at 1/tick. Was 5/tick
            // which posted 5 tweets in ~5s and risked X spam-flagging the
            // account (observed live 2026-05-12T10:27:25Z–10:27:46Z).
            let result = match conn.prepare(
                "SELECT id, text FROM sns_post_queue
                 WHERE network='x' AND posted_at IS NULL
                   AND (error IS NULL OR error = '')
                   AND CAST(COALESCE(created_at,'0') AS INTEGER) >= ?
                 ORDER BY created_at ASC LIMIT 1"
            ) {
                Ok(mut stmt) => stmt.query_map(params![week_ago], |r| {
                    Ok((r.get::<_, i64>(0)?, r.get::<_, String>(1)?))
                }).map(|it| it.filter_map(|r| r.ok()).collect::<Vec<_>>())
                  .unwrap_or_default(),
                Err(_) => Vec::new(),
            };
            result
        };
        for (id, text) in pending {
            // Trim to 280 chars (X v2 limit).
            let posted = if text.chars().count() > 280 {
                text.chars().take(279).collect::<String>() + "…"
            } else { text };
            match x_post_tweet(&posted).await {
                Ok(Some(tweet_id)) => {
                    let conn = db.lock().unwrap();
                    let _ = conn.execute(
                        "UPDATE sns_post_queue SET posted_at=?, external_id=? WHERE id=?",
                        params![chrono_now(), tweet_id, id],
                    );
                    tracing::info!("[x-worker] posted queue#{} → tweet {}", id, tweet_id);
                }
                Ok(None) => {
                    // X not configured — leave row pending, stop loop.
                    break;
                }
                Err(e) => {
                    let conn = db.lock().unwrap();
                    let _ = conn.execute(
                        "UPDATE sns_post_queue SET posted_at=?, error=? WHERE id=?",
                        params![chrono_now(), e, id],
                    );
                    tracing::warn!("[x-worker] queue#{} failed: persisted as error", id);
                }
            }
            // Rate limit: 1 post per 5s within batch.
            tokio::time::sleep(std::time::Duration::from_secs(5)).await;
        }
    }
}

#[derive(Deserialize)]
struct BlogPublishBody {
    admin_token: String,
    title: String,
    body_md: String,
    /// Optional. Defaults to "gemini-2.5-flash-via-actions" if unset.
    #[serde(default)]
    model: Option<String>,
    /// Echoed back into auto_blog_posts.stats_json for audit. Optional.
    #[serde(default)]
    stats_used: Option<serde_json::Value>,
    /// If set, override slug; defaults to `auto-{jst_today}`. Lets Actions
    /// back-fill a missed day.
    #[serde(default)]
    slug: Option<String>,
    /// Tag for the auto_blog_posts.origin audit column.
    /// Expected values: "actions", "fly", "manual".
    #[serde(default)]
    origin: Option<String>,
    /// Number of retries it took Actions to reach a good response.
    #[serde(default)]
    retry_count: Option<i64>,
    /// If true, skip email digest + X cross-post + Telegram notify.
    /// Used for dry-run / backfill scenarios.
    #[serde(default)]
    quiet: bool,
}

async fn admin_blog_publish(
    State(db): State<Db>,
    Json(body): Json<BlogPublishBody>,
) -> impl IntoResponse {
    if let Err(r) = require_admin_token(Some(&body.admin_token)) { return r; }
    if !autopilot_on() {
        return (StatusCode::SERVICE_UNAVAILABLE,
            "autopilot disabled (MU_AUTOPILOT=0)").into_response();
    }
    // Input validation — defend against Gemini returning garbage or empty.
    let title = body.title.trim();
    let body_md = body.body_md.trim();
    if title.is_empty() || title.chars().count() > 120 {
        return (StatusCode::BAD_REQUEST,
            "title must be 1-120 chars").into_response();
    }
    if body_md.len() < 200 || body_md.len() > 8000 {
        return (StatusCode::BAD_REQUEST,
            "body_md must be 200-8000 bytes").into_response();
    }
    // Soft refusal detector — common Gemini failure patterns.
    let lower = body_md.to_lowercase();
    if lower.contains("i can't") || (lower.contains("申し訳") && body_md.len() < 600) {
        return (StatusCode::BAD_REQUEST,
            "body looks like a refusal / placeholder").into_response();
    }
    let slug = body.slug.clone().unwrap_or_else(|| format!("auto-{}", jst_today_str()));
    let model = body.model.clone().unwrap_or_else(|| format!("{}-via-actions", BLOG_GEMINI_MODEL));
    let origin = body.origin.clone().unwrap_or_else(|| "actions".to_string());
    let retry_count = body.retry_count.unwrap_or(0);
    let body_html = md_to_html_simple(body_md);
    let stats_json = body.stats_used
        .as_ref()
        .map(|v| v.to_string())
        .unwrap_or_else(|| "{}".to_string());
    let (inserted, already): (bool, bool) = {
        let conn = db.lock().unwrap();
        let already: bool = conn.query_row(
            "SELECT 1 FROM auto_blog_posts WHERE slug=?",
            params![slug], |r| r.get::<_, i64>(0),
        ).is_ok();
        if already {
            (false, true)
        } else {
            let n = conn.execute(
                "INSERT OR IGNORE INTO auto_blog_posts
                    (slug, title, body_html, body_md, model, stats_json,
                     origin, retry_count, published, created_at)
                 VALUES (?,?,?,?,?,?,?,?,1,?)",
                params![slug, title, body_html, body_md, model, stats_json,
                        origin, retry_count, chrono_now()],
            ).unwrap_or(0);
            (n > 0, false)
        }
    };

    // 2-pass review — informational only; we don't block publish on critic
    // feedback. Just log + include in response so Actions can surface. The
    // verdict is also persisted in ai_decisions for the Learning Loop.
    let review = if inserted && !body.quiet {
        let verdict = critic_check(body_md, "blog", MU_VOICE_RULES).await;
        if let Some(v) = &verdict {
            let conn = db.lock().unwrap();
            let _ = log_ai_decision(
                &conn,
                "review",
                &serde_json::json!({"slug": slug, "content_kind": "blog"}),
                &serde_json::json!({
                    "pass": v.pass, "score": v.score,
                    "reason": v.reason, "flags": v.flags,
                }),
                "gemini-2.5-flash",
                0,
            );
        }
        verdict.map(|v| (v.pass, v.reason))
    } else { None };

    // Email digest to /you subscribers + X cross-post + Telegram notify —
    // only on fresh insert, not idempotent re-publish, and not in quiet mode.
    let (digest_sent, x_posted): (i64, bool) = if inserted && !body.quiet {
        let digest_sent = match send_blog_digest(&db, &slug, title, body_md).await {
            Ok(n) => n,
            Err(e) => { eprintln!("[blog-digest] {e}"); 0 }
        };
        let x_posted = cross_post_x(&slug, title).await.unwrap_or(false);
        // Mark audit columns + enqueue SNS post (drained by Actions worker)
        {
            let conn = db.lock().unwrap();
            if digest_sent > 0 || x_posted {
                let _ = conn.execute(
                    "UPDATE auto_blog_posts SET
                        digest_sent_at = CASE WHEN ? > 0 THEN ? ELSE digest_sent_at END,
                        cross_post_x_at = CASE WHEN ?  THEN ? ELSE cross_post_x_at END
                     WHERE slug=?",
                    params![digest_sent, chrono_now(), x_posted, chrono_now(), slug],
                );
            }
        }
        // Compose tweet text via Gemini (brand voice) — fallback to plain
        // template if compose fails. Done OUTSIDE the lock since it's async.
        let blog_context = format!(
            "Blog title: {title}\n\
             Slug: {slug}\n\
             URL: https://wearmu.com/blog/{slug}\n\
             First 240 chars of body: {preview}\n\
             Note: This is MU's daily Field log — operational diary the AI itself writes each morning.",
            title = title,
            slug = slug,
            preview = body_md.chars().take(240).collect::<String>());
        let blog_tweet = compose_x_tweet_via_gemini("blog", &blog_context).await
            .unwrap_or_else(|| format!("📓 {} — MU Field log\nhttps://wearmu.com/blog/{slug}", title));
        {
            let conn = db.lock().unwrap();
            enqueue_sns_post(&conn, "x", "blog", None, Some(&slug), &blog_tweet, None);
        }
        // Telegram success notification (best-effort, fail-open).
        if let (Ok(tg_token), tg_chat) = (
            env::var("TELEGRAM_BOT_TOKEN"),
            env::var("TELEGRAM_CHAT_ID").unwrap_or_else(|_| "1136442501".into()),
        ) {
            let review_line = match &review {
                Some((pass, reason)) if *pass => format!("✓ review pass: {reason}"),
                Some((_, reason))             => format!("⚠ review flag: {reason}"),
                None                          => "review skipped".to_string(),
            };
            let msg = format!(
                "📓 Blog published — {}\n{}\norigin={origin} retries={retry_count}\n\
                 digest sent → {digest_sent} subs\nX cross-post: {}\n{review_line}\n\
                 https://wearmu.com/blog/{slug}",
                title,
                if x_posted { "✓" } else { "—" },
                if x_posted { "yes" } else { "no" },
            );
            let _ = reqwest::Client::new()
                .post(format!("https://api.telegram.org/bot{}/sendMessage", tg_token))
                .json(&serde_json::json!({
                    "chat_id": tg_chat, "text": msg, "disable_web_page_preview": false,
                }))
                .send().await;
        }
        (digest_sent, x_posted)
    } else {
        (0, false)
    };

    Json(serde_json::json!({
        "ok": true,
        "published": inserted,
        "already_existed": already,
        "slug": slug,
        "url": format!("https://wearmu.com/blog/{slug}"),
        "digest_sent": digest_sent,
        "x_posted": x_posted,
        "review_pass": review.as_ref().map(|(p,_)| *p),
        "review_reason": review.as_ref().map(|(_,r)| r.clone()),
    })).into_response()
}

#[derive(Deserialize)]
struct BlogUpdateBody {
    admin_token: String,
    slug: String,
    /// New title (1-120 chars). Optional — if omitted, title is preserved.
    #[serde(default)]
    title: Option<String>,
    /// New markdown body (200-8000 bytes). Required.
    body_md: String,
    /// Tag for the auto_blog_posts.model audit column. Optional.
    /// Used when rewriting older posts under a stronger model.
    #[serde(default)]
    model: Option<String>,
}

/// POST /api/admin/blog_update — overwrite body_md / body_html / title / model
/// on an existing slug. Does NOT trigger email digest / X cross-post / Telegram
/// (this is a rewrite, not a publish). Idempotent if the new body equals the old.
async fn admin_blog_update(
    State(db): State<Db>,
    Json(body): Json<BlogUpdateBody>,
) -> impl IntoResponse {
    if let Err(r) = require_admin_token(Some(&body.admin_token)) { return r; }
    let slug = body.slug.trim();
    if slug.is_empty() || slug.len() > 200 {
        return (StatusCode::BAD_REQUEST, "slug required").into_response();
    }
    let body_md = body.body_md.trim();
    if body_md.len() < 200 || body_md.len() > 8000 {
        return (StatusCode::BAD_REQUEST, "body_md must be 200-8000 bytes").into_response();
    }
    let new_title = body.title.as_deref().map(str::trim).filter(|s| !s.is_empty());
    if let Some(t) = new_title {
        if t.chars().count() > 120 {
            return (StatusCode::BAD_REQUEST, "title must be ≤120 chars").into_response();
        }
    }
    let body_html = md_to_html_simple(body_md);
    let n = {
        let conn = db.lock().unwrap();
        match (new_title, body.model.as_deref()) {
            (Some(t), Some(m)) => conn.execute(
                "UPDATE auto_blog_posts SET title=?, body_md=?, body_html=?, model=?
                 WHERE slug=?",
                params![t, body_md, body_html, m, slug],
            ).unwrap_or(0),
            (Some(t), None) => conn.execute(
                "UPDATE auto_blog_posts SET title=?, body_md=?, body_html=? WHERE slug=?",
                params![t, body_md, body_html, slug],
            ).unwrap_or(0),
            (None, Some(m)) => conn.execute(
                "UPDATE auto_blog_posts SET body_md=?, body_html=?, model=? WHERE slug=?",
                params![body_md, body_html, m, slug],
            ).unwrap_or(0),
            (None, None) => conn.execute(
                "UPDATE auto_blog_posts SET body_md=?, body_html=? WHERE slug=?",
                params![body_md, body_html, slug],
            ).unwrap_or(0),
        }
    };
    if n == 0 {
        return (StatusCode::NOT_FOUND, "slug not found").into_response();
    }
    Json(serde_json::json!({
        "ok": true,
        "slug": slug,
        "rows_updated": n,
        "url": format!("https://wearmu.com/blog/auto/{}", slug),
    })).into_response()
}

#[derive(Deserialize)]
struct BlogUnpublishBody {
    admin_token: String,
    slug: String,
}

/// POST /api/admin/blog_unpublish — flip an existing auto_blog_posts row to
/// published=0 so /blog/auto/:slug returns 404 and /blog listing hides it.
/// Idempotent: returns ok=true even if row was already unpublished.
async fn admin_blog_unpublish(
    State(db): State<Db>,
    Json(body): Json<BlogUnpublishBody>,
) -> impl IntoResponse {
    if let Err(r) = require_admin_token(Some(&body.admin_token)) { return r; }
    let slug = body.slug.trim();
    if slug.is_empty() || slug.len() > 200 {
        return (StatusCode::BAD_REQUEST, "slug required").into_response();
    }
    let (found, updated): (bool, bool) = {
        let conn = db.lock().unwrap();
        let exists: bool = conn.query_row(
            "SELECT 1 FROM auto_blog_posts WHERE slug=?",
            params![slug], |r| r.get::<_, i64>(0),
        ).is_ok();
        if !exists { (false, false) }
        else {
            let n = conn.execute(
                "UPDATE auto_blog_posts SET published=0 WHERE slug=? AND published=1",
                params![slug],
            ).unwrap_or(0);
            (true, n > 0)
        }
    };
    if !found {
        return (StatusCode::NOT_FOUND, "slug not found").into_response();
    }
    Json(serde_json::json!({
        "ok": true,
        "slug": slug,
        "was_published": updated,
    })).into_response()
}

/// GET /api/admin/funnel/top_paths?token=…&days=7 — page-level traffic
/// summary for the funnel_events table. yuki uses this to decide which
/// pages to invest copy/design effort in.
async fn admin_funnel_top_paths(
    State(db): State<Db>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = require_admin_token(q.get("token")) { return r; }
    let days: i64 = q.get("days").and_then(|s| s.parse().ok()).unwrap_or(7).clamp(1, 90);
    let limit: i64 = q.get("limit").and_then(|s| s.parse().ok()).unwrap_or(40).clamp(1, 200);
    let conn = db.lock().unwrap();
    let mut stmt = match conn.prepare(
        "SELECT path,
                COUNT(*) AS pv,
                COUNT(DISTINCT visitor_id) AS uv
         FROM funnel_events
         WHERE event='pageview'
           AND CAST(created_at AS INTEGER) > strftime('%s','now')-?1*86400
         GROUP BY path
         ORDER BY pv DESC
         LIMIT ?2"
    ) { Ok(s) => s, Err(e) => return (StatusCode::INTERNAL_SERVER_ERROR, format!("db: {}", e)).into_response() };
    let rows: Vec<serde_json::Value> = stmt.query_map(params![days, limit], |r| {
        Ok(serde_json::json!({
            "path": r.get::<_, String>(0)?,
            "pv":   r.get::<_, i64>(1)?,
            "uv":   r.get::<_, i64>(2)?,
        }))
    }).map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default();
    // Referrer breakdown
    let mut ref_stmt = match conn.prepare(
        "SELECT
            CASE
                WHEN referrer IS NULL OR referrer = '' THEN '(direct)'
                WHEN referrer LIKE '%t.co%' OR referrer LIKE '%twitter.com%' OR referrer LIKE '%x.com%' THEN 'X / Twitter'
                WHEN referrer LIKE '%google%' THEN 'Google'
                WHEN referrer LIKE '%threads%' THEN 'Threads'
                WHEN referrer LIKE '%instagram%' THEN 'Instagram'
                WHEN referrer LIKE '%news.ycombinator.com%' THEN 'Hacker News'
                WHEN referrer LIKE '%reddit%' THEN 'Reddit'
                WHEN referrer LIKE '%producthunt%' THEN 'Product Hunt'
                ELSE referrer
            END AS source,
            COUNT(*) AS pv
         FROM funnel_events
         WHERE event='pageview'
           AND CAST(created_at AS INTEGER) > strftime('%s','now')-?1*86400
         GROUP BY source ORDER BY pv DESC LIMIT 20"
    ) { Ok(s) => s, Err(e) => return (StatusCode::INTERNAL_SERVER_ERROR, format!("db: {}", e)).into_response() };
    let refs: Vec<serde_json::Value> = ref_stmt.query_map(params![days], |r| Ok(serde_json::json!({
        "source": r.get::<_, String>(0)?,
        "pv":     r.get::<_, i64>(1)?,
    }))).map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default();
    Json(serde_json::json!({
        "window_days": days,
        "paths": rows,
        "referrers": refs,
    })).into_response()
}

/// POST /api/admin/collab/refresh_mockups?token=…&partner=kokon[&dry_run=1]
/// For each collab_products row of `partner`, fetches the official Printful
/// variant image via /v1/products/variants/{id} and stores it as image_url.
/// Skips rows without printful_variant_id. Returns per-slug status JSON.
async fn admin_collab_refresh_mockups(
    State(db): State<Db>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = require_admin_token(q.get("token")) { return r; }
    let partner = q.get("partner").cloned().unwrap_or_default();
    if partner.is_empty() {
        return (StatusCode::BAD_REQUEST, "?partner=… required").into_response();
    }
    let dry = q.get("dry_run").map(|s| s == "1").unwrap_or(false);
    let key = env::var("PRINTFUL_API_KEY").unwrap_or_default();
    if key.is_empty() {
        return (StatusCode::FAILED_DEPENDENCY, "PRINTFUL_API_KEY unset").into_response();
    }
    let rows: Vec<(String, Option<i64>)> = {
        let conn = db.lock().unwrap();
        let mut stmt = match conn.prepare(
            "SELECT slug, printful_variant_id FROM collab_products
             WHERE partner=? AND active=1
             ORDER BY id"
        ) { Ok(s) => s, Err(e) => return (StatusCode::INTERNAL_SERVER_ERROR, format!("db: {}", e)).into_response() };
        stmt.query_map(params![partner], |r| Ok((r.get::<_, String>(0)?, r.get::<_, Option<i64>>(1)?)))
            .map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default()
    };
    let client = reqwest::Client::new();
    let mut results: Vec<serde_json::Value> = Vec::with_capacity(rows.len());
    for (slug, variant_id_opt) in rows {
        let Some(variant_id) = variant_id_opt else {
            results.push(serde_json::json!({"slug": slug, "ok": false, "reason": "no printful_variant_id"}));
            continue;
        };
        let url = format!("https://api.printful.com/v2/catalog-variants/{}", variant_id);
        let resp = match client.get(&url).bearer_auth(&key).send().await {
            Ok(r) => r,
            Err(e) => {
                results.push(serde_json::json!({"slug": slug, "ok": false, "reason": format!("http err: {}", e)}));
                continue;
            }
        };
        if !resp.status().is_success() {
            // v2 may 404 for some catalog rows — try v1 product-variants as fallback.
            let url_v1 = format!("https://api.printful.com/products/variant/{}", variant_id);
            let r1 = match client.get(&url_v1).bearer_auth(&key).send().await {
                Ok(r) => r,
                Err(e) => {
                    results.push(serde_json::json!({"slug": slug, "ok": false, "reason": format!("v1 http err: {}", e)}));
                    continue;
                }
            };
            if !r1.status().is_success() {
                results.push(serde_json::json!({"slug": slug, "ok": false, "reason": format!("printful {} / v1 {}", resp.status(), r1.status())}));
                continue;
            }
            let j: serde_json::Value = match r1.json().await { Ok(v) => v, Err(_) => { results.push(serde_json::json!({"slug": slug, "ok": false, "reason": "v1 json parse"})); continue; } };
            let image = j["result"]["variant"]["image"].as_str()
                .or_else(|| j["result"]["product"]["image"].as_str())
                .unwrap_or("").to_string();
            if image.is_empty() {
                results.push(serde_json::json!({"slug": slug, "ok": false, "reason": "v1 no image field"}));
                continue;
            }
            if dry {
                results.push(serde_json::json!({"slug": slug, "ok": true, "image": image, "via": "v1", "dry_run": true}));
                continue;
            }
            let conn = db.lock().unwrap();
            let n = conn.execute("UPDATE collab_products SET image_url=? WHERE slug=?", params![image, slug]).unwrap_or(0);
            results.push(serde_json::json!({"slug": slug, "ok": n > 0, "image": image, "via": "v1"}));
            continue;
        }
        let j: serde_json::Value = match resp.json().await { Ok(v) => v, Err(_) => { results.push(serde_json::json!({"slug": slug, "ok": false, "reason": "v2 json parse"})); continue; } };
        // v2 catalog-variants returns image at data.image (Printful API v2 docs).
        let image = j["data"]["image"].as_str()
            .or_else(|| j["result"]["image"].as_str())
            .unwrap_or("").to_string();
        if image.is_empty() {
            results.push(serde_json::json!({"slug": slug, "ok": false, "reason": "v2 no image field"}));
            continue;
        }
        if dry {
            results.push(serde_json::json!({"slug": slug, "ok": true, "image": image, "via": "v2", "dry_run": true}));
            continue;
        }
        let conn = db.lock().unwrap();
        let n = conn.execute("UPDATE collab_products SET image_url=? WHERE slug=?", params![image, slug]).unwrap_or(0);
        results.push(serde_json::json!({"slug": slug, "ok": n > 0, "image": image, "via": "v2"}));
    }
    Json(serde_json::json!({
        "partner": partner,
        "count":   results.len(),
        "results": results,
    })).into_response()
}

/// POST /api/admin/chronicle/vote/announce?token=…[&dry_run=1][&include_you=1]
/// Sends the Sibling Chronicle DAO vote announcement to every past
/// third-party buyer (mu_purchases, cs_live_*, excluding yuki dogfood).
///
/// Default mode = dry_run: returns the recipient list + the rendered HTML
/// without sending anything. Pass dry_run=0 to actually fire emails.
/// Idempotent: each email is recorded in cv_config so a re-run skips
/// previously notified addresses (audit + safety against double-send).
async fn admin_chronicle_vote_announce(
    State(db): State<Db>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = require_admin_token(q.get("token")) { return r; }
    let dry_run = q.get("dry_run").map(|s| s != "0").unwrap_or(true);
    let include_you = q.get("include_you").map(|s| s == "1").unwrap_or(false);

    let yuki = ("yuki@hamada.tokyo", "mail@yukihamada.jp");
    let recipients: Vec<(String, i64)> = {
        let conn = db.lock().unwrap();
        let mut stmt = match conn.prepare(
            "SELECT LOWER(email) AS e, COUNT(*) AS n
             FROM mu_purchases
             WHERE session_id LIKE 'cs_live_%'
               AND LOWER(email) NOT IN (?, ?)
             GROUP BY e
             ORDER BY MIN(id) ASC"
        ) { Ok(s) => s, Err(e) => return (StatusCode::INTERNAL_SERVER_ERROR, format!("db: {}", e)).into_response() };
        let mut buyers: Vec<(String, i64)> = stmt.query_map(params![yuki.0, yuki.1], |r| Ok((
            r.get::<_, String>(0)?, r.get::<_, i64>(1)?,
        ))).map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default();

        if include_you {
            let mut s2 = match conn.prepare(
                "SELECT LOWER(email) FROM you_users
                 WHERE unsubscribed_at IS NULL
                   AND LOWER(email) NOT IN (?, ?)
                   AND LOWER(email) NOT IN (SELECT LOWER(email) FROM mu_purchases WHERE session_id LIKE 'cs_live_%')"
            ) { Ok(s) => s, Err(_) => return (StatusCode::INTERNAL_SERVER_ERROR, "db you").into_response() };
            let you_emails: Vec<String> = s2.query_map(params![yuki.0, yuki.1], |r| r.get::<_, String>(0))
                .map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default();
            for em in you_emails { buyers.push((em, 0)); }
        }
        buyers
    };

    // Filter out already-notified recipients (idempotency).
    let recipients: Vec<(String, i64, bool)> = {
        let conn = db.lock().unwrap();
        recipients.into_iter().map(|(em, n)| {
            let key = format!("chronicle_vote_notified:{}", em);
            let already = cv_get(&conn, &key, "") == "1";
            (em, n, already)
        }).collect()
    };

    let body_template = |email: &str, purchases: i64, is_you_only: bool| -> String {
        let buyer_id = purchase_pseudonym(email);
        let lifetime_line = if is_you_only {
            "あなたは /you 登録者として参加できます。".to_string()
        } else {
            format!("あなたはこれまで <strong>{}</strong> 着 MU を購入してくださいました。", purchases)
        };
        format!(
            r#"<div style="font-family:'Helvetica Neue','Hiragino Sans',sans-serif;font-size:14.5px;line-height:1.85;color:#222;max-width:560px;margin:0 auto;padding:32px 24px">
  <p style="font-size:11px;letter-spacing:0.3em;text-transform:uppercase;color:#A67843;opacity:0.85;margin-bottom:16px">MU · Sibling Chronicle · DAO 投票</p>
  <h1 style="font-size:22px;font-weight:300;letter-spacing:0.02em;line-height:1.4;margin:0 0 18px">同じデザインを着る人たちの「年代記」、入れていいですか?</h1>
  <p>{lifetime}</p>
  <p>
    新しい仕組みを設計しました: 同じデザインを N 着刷る商品 (MUON 等) の N 番目を買うと、シャツに小さな QR + 番号がプリントされます。
    スキャンすると、これまでの注文日時 + 匿名 ID が表示され、後から買う人もリストに自動で追記されていく。<br>
    実名・メール・住所は一切載せず、SHA-256 由来の <code style="background:#f6f4ee;color:#A67843;padding:1px 5px">MU-XXXX</code> 形式の匿名 ID のみ。
  </p>
  <p style="margin-top:18px">QR を <strong>どこに焼くか</strong> を、過去に MU を着てくださった皆さまの投票で決めます:</p>
  <ol style="padding-left:20px;margin:0 0 18px">
    <li style="margin-bottom:8px"><strong>front design に合成</strong> — Printful の placement は 1 つのまま、追加費用 ¥0。デザインの隅に QR が入る trade-off</li>
    <li style="margin-bottom:8px"><strong>首裏下に専用印刷</strong> — デザインは無傷、Printful 追加配置 +$2/着 (¥300)、margin -15%</li>
    <li><strong>実装しない</strong> — feature flag OFF のまま</li>
  </ol>
  <p style="margin-top:16px">
    <a href="https://wearmu.com/chronicle-vote" style="display:inline-block;background:#A67843;color:#fff;text-decoration:none;padding:14px 28px;font-size:12px;letter-spacing:0.25em;text-transform:uppercase;font-weight:600;border-radius:2px">投票ページへ →</a>
  </p>
  <p style="font-size:12px;color:#666;margin-top:16px">
    投票方式: メールアドレスに magic link を送り、リンクをクリックで確定。1 人 1 票、24 時間以内に有効。<br>
    クォーラム = 5 票 + 60% 賛成で<strong>自動デプロイ</strong>。yuki が判断するのではなく、コードと投票結果が判断します。
  </p>
  <p style="font-size:11px;color:#999;margin-top:24px;line-height:1.7">
    あなたの匿名 ID: <code style="background:#f6f4ee;color:#A67843;padding:1px 5px">{buyer_id}</code><br>
    これは <a href="https://wearmu.com/transparency" style="color:#A67843">/transparency</a> ページに最近の購入として既に表示されている (PII 安全な) ID です。<br>
    本メールが不要な場合は <a href="mailto:info@wearmu.com" style="color:#A67843">info@wearmu.com</a> までご連絡ください。<br>
    — yuki (1 human operator) · 28 agents · 株式会社イネブラ (Enabler Inc.)
  </p>
</div>"#,
            lifetime = lifetime_line,
            buyer_id = buyer_id,
        )
    };

    if dry_run {
        let sample = recipients.first()
            .map(|(em, n, _)| body_template(em, *n, *n == 0))
            .unwrap_or_default();
        return Json(serde_json::json!({
            "ok": true,
            "dry_run": true,
            "total_recipients": recipients.len(),
            "would_send": recipients.iter().filter(|(_,_,already)| !already).count(),
            "already_notified": recipients.iter().filter(|(_,_,already)| *already).count(),
            "recipients": recipients.iter().map(|(em, n, already)| serde_json::json!({
                "email_masked": mask_email(em),
                "purchases": n,
                "already_notified": already,
            })).collect::<Vec<_>>(),
            "sample_html": sample,
            "note": "Pass dry_run=0 to actually send. include_you=1 adds /you signups that haven't bought yet.",
        })).into_response();
    }

    // Production send.
    let resend_key = env::var("RESEND_API_KEY").unwrap_or_default();
    if resend_key.is_empty() {
        return (StatusCode::FAILED_DEPENDENCY, "RESEND_API_KEY unset").into_response();
    }
    let client = reqwest::Client::new();
    let mut sent = 0i64;
    let mut errs: Vec<serde_json::Value> = Vec::new();
    for (email, purchases, already) in &recipients {
        if *already { continue; }
        let body = body_template(email, *purchases, *purchases == 0);
        let resp = client.post("https://api.resend.com/emails")
            .bearer_auth(&resend_key)
            .json(&serde_json::json!({
                "from": "━◯━ MU Vote <noreply@wearmu.com>",
                "to": [email.clone()],
                "subject": "[MU] 「年代記」を入れていいですか? DAO 投票のお願い",
                "html": body,
                "reply_to": "info@wearmu.com",
            }))
            .send().await;
        match resp {
            Ok(r) if r.status().is_success() => {
                sent += 1;
                {
                    let conn = db.lock().unwrap();
                    let key = format!("chronicle_vote_notified:{}", email);
                    cv_set(&conn, &key, "1", "chronicle_vote_announce");
                }
                tokio::time::sleep(std::time::Duration::from_millis(200)).await;
            }
            Ok(r) => {
                let s = r.status();
                let b = r.text().await.unwrap_or_default();
                errs.push(serde_json::json!({"email": mask_email(email), "status": s.as_u16(), "body": b.chars().take(200).collect::<String>()}));
            }
            Err(e) => {
                errs.push(serde_json::json!({"email": mask_email(email), "err": e.to_string()}));
            }
        }
    }
    send_telegram_message(&format!(
        "📬 chronicle vote announce: sent={} errors={} total_recipients={}",
        sent, errs.len(), recipients.len()
    )).await;
    Json(serde_json::json!({
        "ok": true,
        "dry_run": false,
        "sent": sent,
        "errors": errs,
        "total_recipients": recipients.len(),
    })).into_response()
}

#[derive(Deserialize)]
struct AdminTokenOnly { admin_token: String }

#[derive(Deserialize)]
struct AdminXEnqueueBody {
    admin_token: String,
    text: String,
    #[serde(default)]
    image_url: Option<String>,
    /// Free-form tag for audit (e.g. "manual-yuki" or "campaign-2026-05").
    #[serde(default)]
    trigger_kind: Option<String>,
}

/// POST /api/admin/x_enqueue — push a hand-written X post into sns_post_queue.
/// The x_post_worker drains 1/min, so a manual post lands in ~60s. Bypasses
/// the growth agent's 24h rate limit (which only governs auto-generation).
/// Idempotent on text within last 24h to prevent dup-fire.
async fn admin_x_enqueue(
    State(db): State<Db>,
    Json(body): Json<AdminXEnqueueBody>,
) -> impl IntoResponse {
    if let Err(r) = require_admin_token(Some(&body.admin_token)) { return r; }
    let text = body.text.trim();
    if text.is_empty() || text.chars().count() > 280 {
        return (StatusCode::BAD_REQUEST, "text must be 1-280 chars").into_response();
    }
    let trigger_kind = body.trigger_kind.as_deref().unwrap_or("manual");
    let image_url = body.image_url.as_deref();
    let day_ago: i64 = chrono_now().parse::<i64>().unwrap_or(0) - 86_400;
    let (queue_id, was_duplicate): (i64, bool) = {
        let conn = db.lock().unwrap();
        let existing: Option<i64> = conn.query_row(
            "SELECT id FROM sns_post_queue
             WHERE network='x' AND text=? AND CAST(created_at AS INTEGER) > ?",
            params![text, day_ago], |r| r.get(0),
        ).ok();
        match existing {
            Some(id) => (id, true),
            None => {
                let id = enqueue_sns_post(&conn, "x", trigger_kind, None, None, text, image_url);
                (id, false)
            }
        }
    };
    Json(serde_json::json!({
        "ok": true,
        "queue_id": queue_id,
        "duplicate": was_duplicate,
        "note": if was_duplicate {
            "same text enqueued within last 24h — returned existing row"
        } else {
            "x_post_worker drains 1/min — expect post within ~60s"
        },
    })).into_response()
}

/// POST /api/admin/products_reconcile_sold — set every active product's `sold`
/// column to the actual count from mu_purchases (joined on product_id + brand).
/// Fixes the lie where seed data had sold=24 for products never bought.
///
/// Returns: { updated: <total rows>, before_sum: i64, after_sum: i64 }
async fn admin_products_reconcile_sold(
    State(db): State<Db>,
    Json(body): Json<AdminTokenOnly>,
) -> impl IntoResponse {
    if let Err(r) = require_admin_token(Some(&body.admin_token)) { return r; }
    let (updated, before_sum, after_sum): (i64, i64, i64) = {
        let conn = db.lock().unwrap();
        let before: i64 = conn.query_row(
            "SELECT COALESCE(SUM(sold), 0) FROM products WHERE active=1",
            [], |r| r.get(0)).unwrap_or(0);
        // brand-aware: brand='you' doesn't have a products row to update.
        // Other brands: set products.sold = real cs_live_* count joined on (id, brand).
        let n = conn.execute(
            "UPDATE products SET sold = (
                SELECT COUNT(*) FROM mu_purchases mp
                WHERE mp.product_id = products.id
                  AND mp.brand = products.brand
                  AND mp.session_id LIKE 'cs_live_%'
             ) WHERE active=1",
            [],
        ).unwrap_or(0) as i64;
        let after: i64 = conn.query_row(
            "SELECT COALESCE(SUM(sold), 0) FROM products WHERE active=1",
            [], |r| r.get(0)).unwrap_or(0);
        (n, before, after)
    };
    Json(serde_json::json!({
        "ok": true,
        "updated_rows": updated,
        "before_total_sold": before_sum,
        "after_total_sold": after_sum,
        "delta": after_sum - before_sum,
    })).into_response()
}

#[derive(Deserialize)]
struct DeactivateBrandBody {
    admin_token: String,
    brand: String,
    reason: Option<String>,
}

/// POST /api/admin/deactivate_brand — flip `active=0` for every product of a
/// given brand. Used to hide a brand (e.g. NOUNS) from the public catalog
/// without dropping rows. Reversible by an UPDATE products SET active=1.
async fn admin_deactivate_brand(
    State(db): State<Db>,
    Json(body): Json<DeactivateBrandBody>,
) -> impl IntoResponse {
    if let Err(r) = require_admin_token(Some(&body.admin_token)) { return r; }
    let brand = body.brand.trim().to_lowercase();
    if brand.is_empty() || brand.len() > 32 {
        return (StatusCode::BAD_REQUEST, "brand required").into_response();
    }
    // Constitution §21: `active=0` flips are T1 only — this endpoint requires
    // admin_token which is the human-approval gate.
    let reason = body.reason.unwrap_or_else(|| "admin_deactivate_brand".into());
    let n = {
        let conn = db.lock().unwrap();
        let n = conn.execute(
            "UPDATE products SET active=0, retired_at=?, retire_reason=?
             WHERE brand=? AND active=1",
            params![chrono_now(), reason, brand],
        ).unwrap_or(0);
        n as i64
    };
    Json(serde_json::json!({
        "ok": true,
        "brand": brand,
        "rows_deactivated": n,
    })).into_response()
}

