/// GET /api/pass/by_email?email=X
/// Returns the passes (membership tokens) associated with the given email.
/// Used by the /pass page's "are you already a member?" check and by
/// pt_gate.js to grant free-unlock to holders.
async fn pass_by_email_api(
    State(db): State<Db>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    use serde_json::json;
    let email = q.get("email").map(|s| s.trim().to_lowercase()).unwrap_or_default();
    if email.is_empty() || !email.contains('@') {
        return (axum::http::StatusCode::BAD_REQUEST, Json(json!({"error": "email required"}))).into_response();
    }
    let conn = match db.lock() { Ok(c) => c, Err(_) => return Json(json!({"passes": []})).into_response() };
    let rows: Vec<serde_json::Value> = conn
        .prepare("SELECT edition, brand, sku_id, mint_status, mint_tx, created_at FROM mu_passes WHERE email = ? ORDER BY edition ASC")
        .and_then(|mut s| {
            s.query_map([&email], |r| {
                Ok(json!({
                    "edition":      r.get::<_, i64>(0)?,
                    "brand":        r.get::<_, String>(1)?,
                    "sku_id":       r.get::<_, Option<String>>(2)?,
                    "mint_status":  r.get::<_, String>(3)?,
                    "mint_tx":      r.get::<_, Option<String>>(4)?,
                    "created_at":   r.get::<_, String>(5)?,
                }))
            }).map(|it| it.filter_map(|r| r.ok()).collect())
        }).unwrap_or_default();

    let mut resp = Json(json!({ "passes": rows })).into_response();
    let h = resp.headers_mut();
    h.insert("Access-Control-Allow-Origin", HeaderValue::from_static("*"));
    h.insert("Cache-Control", HeaderValue::from_static("private, max-age=30"));
    resp
}

/// POST /api/pass/claim {email}
/// For genesis lot: if the email matches a past customer (Stripe order),
/// assign the next edition number. Idempotent: re-calling returns existing.
/// For new purchases, the Stripe webhook calls this server-side.
async fn pass_claim_api(
    State(db): State<Db>,
    Json(body): Json<serde_json::Value>,
) -> Response {
    use serde_json::json;
    let email = body.get("email")
        .and_then(|v| v.as_str())
        .map(|s| s.trim().to_lowercase())
        .unwrap_or_default();
    let brand = body.get("brand").and_then(|v| v.as_str()).unwrap_or("mugen").to_string();
    let sku_id = body.get("sku_id").and_then(|v| v.as_str()).map(|s| s.to_string());
    let order_ref = body.get("order_ref").and_then(|v| v.as_str()).map(|s| s.to_string());

    if email.is_empty() || !email.contains('@') {
        return (axum::http::StatusCode::BAD_REQUEST, Json(json!({"error": "email required"}))).into_response();
    }

    let conn = match db.lock() { Ok(c) => c, Err(_) => return (axum::http::StatusCode::INTERNAL_SERVER_ERROR, Json(json!({"error": "db lock"}))).into_response() };

    // Idempotency: if this order_ref already issued a pass, return it.
    if let Some(ref oref) = order_ref {
        if let Ok(edition) = conn.query_row(
            "SELECT edition FROM mu_passes WHERE order_ref = ?",
            [oref],
            |r| r.get::<_, i64>(0),
        ) {
            return Json(json!({ "ok": true, "edition": edition, "duplicate": true })).into_response();
        }
    }

    let next_edition: i64 = conn.query_row(
        "SELECT COALESCE(MAX(edition), 0) + 1 FROM mu_passes",
        [],
        |r| r.get(0),
    ).unwrap_or(1);

    let now = chrono_now();
    let res = conn.execute(
        "INSERT INTO mu_passes (edition, email, brand, sku_id, order_ref, mint_status, created_at)
         VALUES (?, ?, ?, ?, ?, 'pending', ?)",
        rusqlite::params![next_edition, &email, &brand, &sku_id, &order_ref, &now],
    );
    match res {
        Ok(_) => Json(json!({ "ok": true, "edition": next_edition, "duplicate": false })).into_response(),
        Err(e) => (axum::http::StatusCode::INTERNAL_SERVER_ERROR, Json(json!({"error": e.to_string()}))).into_response(),
    }
}

/// GET /api/pass/stats — public counter for the LP ticker.
async fn pass_stats_api(State(db): State<Db>) -> Response {
    use serde_json::json;
    let conn = match db.lock() { Ok(c) => c, Err(_) => return Json(json!({"total": 0})).into_response() };
    let total: i64 = conn.query_row("SELECT COUNT(*) FROM mu_passes", [], |r| r.get(0)).unwrap_or(0);
    let minted: i64 = conn.query_row("SELECT COUNT(*) FROM mu_passes WHERE mint_status = 'minted'", [], |r| r.get(0)).unwrap_or(0);
    let recent: Vec<serde_json::Value> = conn
        .prepare("SELECT edition, email FROM mu_passes ORDER BY edition DESC LIMIT 8")
        .and_then(|mut s| {
            s.query_map([], |r| {
                let em: String = r.get::<_, String>(1)?;
                let mask = mask_email_for_ticker(&em);
                Ok(json!({ "edition": r.get::<_, i64>(0)?, "owner": mask }))
            }).map(|it| it.filter_map(|r| r.ok()).collect())
        }).unwrap_or_default();
    let mut resp = Json(json!({ "total": total, "minted": minted, "recent": recent })).into_response();
    resp.headers_mut().insert("Cache-Control", HeaderValue::from_static("public, max-age=60"));
    resp
}

/// POST /api/admin/pass/backfill
/// Walk every collab_orders row (chronological) and gift a MU Pass to each
/// unique buyer email that doesn't yet have one. Editions are assigned by
/// purchase order; mint_status starts 'pending'. Idempotent — re-running
/// only inserts new rows for new buyers.
///
/// Body: {"admin_token": "...", "dry_run": true}
async fn pass_backfill_api(
    State(db): State<Db>,
    Json(body): Json<serde_json::Value>,
) -> Response {
    use serde_json::json;
    let token = body.get("admin_token").and_then(|v| v.as_str()).unwrap_or("");
    let expected = std::env::var("ADMIN_TOKEN").unwrap_or_default();
    if expected.is_empty() || token != expected {
        return (axum::http::StatusCode::FORBIDDEN, Json(json!({"error": "admin token required"}))).into_response();
    }
    let dry_run = body.get("dry_run").and_then(|v| v.as_bool()).unwrap_or(false);
    let conn = match db.lock() { Ok(c) => c, Err(_) => return (axum::http::StatusCode::INTERNAL_SERVER_ERROR, Json(json!({"error": "db lock"}))).into_response() };

    // Pull every paid order with a usable email, chronologically.
    let rows: Vec<(String, String, String, Option<String>)> = conn
        .prepare("SELECT email, slug, stripe_session, created_at FROM collab_orders
                  WHERE email IS NOT NULL AND email != '' AND status != 'failed'
                  ORDER BY created_at ASC")
        .and_then(|mut s| {
            s.query_map([], |r| {
                Ok((
                    r.get::<_, String>(0)?.to_lowercase(),
                    r.get::<_, String>(1)?,
                    r.get::<_, String>(2)?,
                    r.get::<_, Option<String>>(3)?,
                ))
            }).map(|it| it.filter_map(|r| r.ok()).collect())
        }).unwrap_or_default();

    let mut next_edition: i64 = conn.query_row(
        "SELECT COALESCE(MAX(edition), 0) FROM mu_passes",
        [],
        |r| r.get(0),
    ).unwrap_or(0);

    let mut inserted = 0i64;
    let mut skipped_dup = 0i64;
    let mut sample = Vec::new();

    for (email, slug, stripe_session, _ts) in rows {
        // Skip if this stripe_session already minted a pass.
        let already: i64 = conn.query_row(
            "SELECT COUNT(*) FROM mu_passes WHERE order_ref = ?",
            [&stripe_session],
            |r| r.get(0),
        ).unwrap_or(0);
        if already > 0 { skipped_dup += 1; continue; }

        next_edition += 1;
        let now = chrono_now();
        if !dry_run {
            let _ = conn.execute(
                "INSERT INTO mu_passes (edition, email, brand, sku_id, order_ref, mint_status, created_at)
                 VALUES (?, ?, ?, NULL, ?, 'pending', ?)",
                rusqlite::params![next_edition, &email, &slug, &stripe_session, &now],
            );
        }
        inserted += 1;
        if sample.len() < 5 {
            sample.push(json!({ "edition": next_edition, "email": mask_email_for_ticker(&email), "brand": slug }));
        }
    }

    Json(json!({
        "ok": true,
        "dry_run": dry_run,
        "inserted": inserted,
        "skipped_dup": skipped_dup,
        "sample": sample,
        "highest_edition": next_edition,
    })).into_response()
}

/// POST /api/admin/pass/mint
/// Mints the cNFT for a specific pass edition via Crossmint API.
/// Crossmint handles email→custodial-wallet, cNFT compression, and chain
/// submission. We just call one POST and poll status.
///
/// Body: {"admin_token": "...", "edition": 1}
/// Env required: CROSSMINT_API_KEY, CROSSMINT_COLLECTION_ID
///   (CROSSMINT_ENV = "production" | "staging", default "staging")
async fn pass_mint_api(
    State(db): State<Db>,
    Json(body): Json<serde_json::Value>,
) -> Response {
    use serde_json::json;
    let token = body.get("admin_token").and_then(|v| v.as_str()).unwrap_or("");
    let expected = std::env::var("ADMIN_TOKEN").unwrap_or_default();
    if expected.is_empty() || token != expected {
        return (axum::http::StatusCode::FORBIDDEN, Json(json!({"error": "admin token required"}))).into_response();
    }
    let edition = body.get("edition").and_then(|v| v.as_i64()).unwrap_or(0);
    if edition <= 0 {
        return (axum::http::StatusCode::BAD_REQUEST, Json(json!({"error": "edition required"}))).into_response();
    }

    // Env check first — fail loud if Crossmint isn't configured yet (so the
    // endpoint can ship safely without auto-burning SOL the moment it deploys).
    let api_key = std::env::var("CROSSMINT_API_KEY").unwrap_or_default();
    let collection_id = std::env::var("CROSSMINT_COLLECTION_ID").unwrap_or_default();
    let env_label = std::env::var("CROSSMINT_ENV").unwrap_or_else(|_| "staging".to_string());
    if api_key.is_empty() || collection_id.is_empty() {
        return Json(json!({
            "ok": false,
            "error": "Crossmint not configured",
            "needed_env": ["CROSSMINT_API_KEY", "CROSSMINT_COLLECTION_ID", "CROSSMINT_ENV"],
            "hint": "Get a server-side API key at crossmint.com → Console → API keys",
        })).into_response();
    }

    // Pull the row + the brand's display image (for cNFT metadata).
    let (email, brand, sku_id, status, image_url): (String, String, Option<String>, String, Option<String>) = {
        let conn = match db.lock() { Ok(c) => c, Err(_) => return (axum::http::StatusCode::INTERNAL_SERVER_ERROR, Json(json!({"error": "db lock"}))).into_response() };
        let row = conn.query_row(
            "SELECT p.email, p.brand, p.sku_id, p.mint_status,
                    (SELECT image_url FROM collab_products WHERE slug = p.brand LIMIT 1)
             FROM mu_passes p WHERE p.edition = ?",
            [edition],
            |r| Ok((r.get::<_, String>(0)?, r.get::<_, String>(1)?, r.get::<_, Option<String>>(2)?, r.get::<_, String>(3)?, r.get::<_, Option<String>>(4)?)),
        );
        match row {
            Ok(r) => r,
            Err(_) => return (axum::http::StatusCode::NOT_FOUND, Json(json!({"error": "edition not found"}))).into_response(),
        }
    };
    if status == "minted" {
        return Json(json!({"ok": true, "already_minted": true})).into_response();
    }

    // Mark as minting (so concurrent calls don't double-mint).
    {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "UPDATE mu_passes SET mint_status = 'minting' WHERE edition = ? AND mint_status != 'minted'",
            [edition],
        );
    }

    // Crossmint API call. Recipient format: "email:user@example.com:solana"
    // for email-custodial Solana wallets. compressed=true → cNFT.
    let host = if env_label == "production" {
        "https://www.crossmint.com"
    } else {
        "https://staging.crossmint.com"
    };
    let url = format!("{}/api/2022-06-09/collections/{}/nfts", host, collection_id);
    let image = image_url.unwrap_or_else(|| "https://mockups.wearmu.com/hero.png".to_string());
    let edition_pad = format!("{:03}", edition);
    let req_body = json!({
        "recipient": format!("email:{}:solana", email),
        "metadata": {
            "name": format!("MU Pass #{}", edition_pad),
            "description": format!("MU community membership · genesis edition #{}. \
                Holder of this pass has permanent access to /vault, voting rights, \
                and a share of the §28 Community fund's discretionary送金.", edition_pad),
            "image": image,
            "attributes": [
                {"trait_type": "Edition", "value": edition_pad},
                {"trait_type": "Brand", "value": brand},
                {"trait_type": "Sku", "value": sku_id.unwrap_or_default()},
                {"trait_type": "Issued", "value": chrono_now()}
            ]
        },
        "compressed": true,
    });

    let resp = reqwest::Client::new()
        .post(&url)
        .header("x-api-key", &api_key)
        .header("content-type", "application/json")
        .json(&req_body)
        .send().await;

    match resp {
        Ok(r) => {
            let status = r.status();
            let body_json: serde_json::Value = r.json().await.unwrap_or(serde_json::Value::Null);
            if status.is_success() {
                let asset_id = body_json.get("id").and_then(|v| v.as_str()).unwrap_or("").to_string();
                let chain_tx = body_json.pointer("/onChain/mintHash").and_then(|v| v.as_str()).unwrap_or("").to_string();
                {
                    let conn = db.lock().unwrap();
                    let _ = conn.execute(
                        "UPDATE mu_passes SET mint_status='minted', mint_asset=?, mint_tx=? WHERE edition=?",
                        params![asset_id, chain_tx, edition],
                    );
                }
                Json(json!({"ok": true, "edition": edition, "mint_asset": asset_id, "mint_tx": chain_tx, "raw": body_json})).into_response()
            } else {
                // Revert mint_status so we can retry safely.
                {
                    let conn = db.lock().unwrap();
                    let _ = conn.execute(
                        "UPDATE mu_passes SET mint_status='failed' WHERE edition=?",
                        [edition],
                    );
                }
                (axum::http::StatusCode::BAD_GATEWAY, Json(json!({"ok": false, "edition": edition, "crossmint_status": status.as_u16(), "crossmint_body": body_json}))).into_response()
            }
        }
        Err(e) => {
            let conn = db.lock().unwrap();
            let _ = conn.execute(
                "UPDATE mu_passes SET mint_status='failed' WHERE edition=?",
                [edition],
            );
            (axum::http::StatusCode::BAD_GATEWAY, Json(json!({"ok": false, "error": e.to_string()}))).into_response()
        }
    }
}

/// POST /api/admin/pass/mint_batch
/// Mint up to N (default 5) pending passes. Use this from a cron after the
/// first 2 manual tests pass.
async fn pass_mint_batch_api(
    State(db): State<Db>,
    Json(body): Json<serde_json::Value>,
) -> Response {
    use serde_json::json;
    let token = body.get("admin_token").and_then(|v| v.as_str()).unwrap_or("");
    let expected = std::env::var("ADMIN_TOKEN").unwrap_or_default();
    if expected.is_empty() || token != expected {
        return (axum::http::StatusCode::FORBIDDEN, Json(json!({"error": "admin token required"}))).into_response();
    }
    let limit = body.get("limit").and_then(|v| v.as_i64()).unwrap_or(5).clamp(1, 50);

    let pending: Vec<i64> = {
        let conn = db.lock().unwrap();
        conn.prepare("SELECT edition FROM mu_passes WHERE mint_status IN ('pending','failed') ORDER BY edition ASC LIMIT ?")
            .and_then(|mut s| s.query_map([limit], |r| r.get::<_, i64>(0)).map(|it| it.filter_map(|r| r.ok()).collect()))
            .unwrap_or_default()
    };

    let mut results = Vec::new();
    for ed in pending {
        let single = serde_json::json!({"admin_token": token, "edition": ed});
        let resp = pass_mint_api(State(db.clone()), Json(single)).await;
        let status = resp.status().as_u16();
        results.push(json!({"edition": ed, "status": status}));
        // Be polite to Crossmint's rate limits.
        tokio::time::sleep(std::time::Duration::from_millis(500)).await;
    }
    Json(json!({"ok": true, "processed": results.len(), "results": results})).into_response()
}

fn mask_email_for_ticker(em: &str) -> String {
    let parts: Vec<&str> = em.splitn(2, '@').collect();
    if parts.len() < 2 { return "anon".to_string(); }
    let local = parts[0];
    let visible = if local.len() <= 3 { local.to_string() } else { local.chars().take(3).collect::<String>() };
    format!("{}…@{}", visible, parts[1])
}

/// GET /api/admin/pass/list?admin_token=…
/// All pass rows for the mint tool to iterate.
async fn pass_list_admin_api(
    State(db): State<Db>,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    use serde_json::json;
    let token = q.get("admin_token").map(|s| s.as_str()).unwrap_or("");
    let expected = std::env::var("ADMIN_TOKEN").unwrap_or_default();
    if expected.is_empty() || token != expected {
        return (axum::http::StatusCode::FORBIDDEN, Json(json!({"error": "admin token required"}))).into_response();
    }
    let conn = match db.lock() { Ok(c) => c, Err(_) => return (axum::http::StatusCode::INTERNAL_SERVER_ERROR, Json(json!({"error": "db lock"}))).into_response() };
    let rows: Vec<serde_json::Value> = conn
        .prepare("SELECT p.edition, p.email, p.brand, p.sku_id, p.mint_status, p.mint_asset, p.mint_tx,
                         (SELECT image_url FROM collab_products WHERE slug = p.brand LIMIT 1) AS image_url
                  FROM mu_passes p ORDER BY p.edition ASC")
        .and_then(|mut s| {
            s.query_map([], |r| {
                Ok(json!({
                    "edition": r.get::<_, i64>(0)?,
                    "email": r.get::<_, String>(1)?,
                    "brand": r.get::<_, String>(2)?,
                    "sku_id": r.get::<_, Option<String>>(3)?,
                    "mint_status": r.get::<_, String>(4)?,
                    "mint_asset": r.get::<_, Option<String>>(5)?,
                    "mint_tx": r.get::<_, Option<String>>(6)?,
                    "image_url": r.get::<_, Option<String>>(7)?,
                }))
            }).map(|it| it.filter_map(|r| r.ok()).collect())
        }).unwrap_or_default();
    Json(json!({"passes": rows})).into_response()
}

/// POST /api/admin/pass/record_mint
/// External mint tool reports back to DB after a successful on-chain mint.
async fn pass_record_mint_api(
    State(db): State<Db>,
    Json(body): Json<serde_json::Value>,
) -> Response {
    use serde_json::json;
    let token = body.get("admin_token").and_then(|v| v.as_str()).unwrap_or("");
    let expected = std::env::var("ADMIN_TOKEN").unwrap_or_default();
    if expected.is_empty() || token != expected {
        return (axum::http::StatusCode::FORBIDDEN, Json(json!({"error": "admin token required"}))).into_response();
    }
    let edition = body.get("edition").and_then(|v| v.as_i64()).unwrap_or(0);
    let mint_tx = body.get("mint_tx").and_then(|v| v.as_str()).unwrap_or("");
    let mint_asset = body.get("mint_asset").and_then(|v| v.as_str()).unwrap_or("");
    if edition <= 0 || mint_tx.is_empty() {
        return (axum::http::StatusCode::BAD_REQUEST, Json(json!({"error": "edition + mint_tx required"}))).into_response();
    }
    let conn = match db.lock() { Ok(c) => c, Err(_) => return (axum::http::StatusCode::INTERNAL_SERVER_ERROR, Json(json!({"error": "db lock"}))).into_response() };
    let n = conn.execute(
        "UPDATE mu_passes SET mint_status='minted', mint_tx=?, mint_asset=? WHERE edition=?",
        params![mint_tx, mint_asset, edition],
    ).unwrap_or(0);
    Json(json!({"ok": true, "rows": n})).into_response()
}

/// GET /api/pass/metadata/:edition
/// Public metadata JSON for a pass — consumed by Bubblegum cNFT URI.
async fn pass_metadata_api(
    State(db): State<Db>,
    axum::extract::Path(edition_str): axum::extract::Path<String>,
) -> Response {
    use serde_json::json;
    let edition: i64 = edition_str.trim_end_matches(".json").parse().unwrap_or(0);
    if edition <= 0 {
        return (axum::http::StatusCode::BAD_REQUEST, Json(json!({"error": "bad edition"}))).into_response();
    }
    let conn = match db.lock() { Ok(c) => c, Err(_) => return Json(json!({})).into_response() };
    let row = conn.query_row(
        "SELECT p.brand, p.created_at,
                (SELECT image_url FROM collab_products WHERE slug = p.brand LIMIT 1)
         FROM mu_passes p WHERE p.edition = ?",
        [edition],
        |r| Ok((r.get::<_, String>(0)?, r.get::<_, String>(1)?, r.get::<_, Option<String>>(2)?)),
    );
    let (brand, created_at, image_url) = match row {
        Ok(r) => r,
        Err(_) => return (axum::http::StatusCode::NOT_FOUND, Json(json!({"error": "edition not found"}))).into_response(),
    };
    let edition_pad = format!("{:03}", edition);
    let image = image_url.unwrap_or_else(|| "https://mockups.wearmu.com/hero.png".to_string());

    let mut resp = Json(json!({
        "name": format!("MU Pass #{}", edition_pad),
        "symbol": "MUPASS",
        "description": "MU community membership pass. Holder gets permanent /vault access, voting rights in next-drop selection, and a share of the §28 Community fund's discretionary送金. Issued on purchase of a MU shirt; transferable (residual revshare承継 limited to 90 days post-transfer); burnable by holder only — Yuki cannot revoke.",
        "image": image,
        "external_url": format!("https://wearmu.com/pass#{}", edition_pad),
        "attributes": [
            {"trait_type": "Edition", "value": edition_pad},
            {"trait_type": "Genesis Lot", "value": if edition <= 20 { "yes" } else { "no" }},
            {"trait_type": "Brand", "value": brand},
            {"trait_type": "Issued", "value": created_at}
        ],
        "properties": {
            "category": "image",
            "files": [{"uri": image, "type": "image/png"}]
        }
    })).into_response();
    resp.headers_mut().insert("Cache-Control", HeaderValue::from_static("public, max-age=300"));
    resp
}

/// GET /jiufight — public sales page for the SUPER YAWARA SWEEP CUP collab.
/// Serves a static HTML file generated by `scripts/gen_collab_static_page.py`
/// from the bulk-publish results — keeps Rust code unchanged when new
/// designs are added (just rerun the script + redeploy or hot-reload static).
async fn show_jiufight_page() -> Response {
    let html = std::fs::read_to_string("static/jiufight/index.html")
        .unwrap_or_else(|_| {
            "<!doctype html><meta charset=utf-8><title>JIUFIGHT</title>\
             <body style='font-family:sans-serif;padding:40px'>\
             <h1>JIUFIGHT</h1><p>shop page warming up…</p></body>".to_string()
        });
    axum::response::Html(html).into_response()
}

/// GET /jiufight/preview — design candidate picker (private review page).
/// noindex; generated by scripts/gen_preview_gallery.py. Embedded via
/// include_str! so the page survives Docker layer-cache quirks where new
/// files under static/ occasionally fail to appear in the running container.
async fn show_jiufight_preview() -> Response {
    axum::response::Html(include_str!("../static/jiufight/preview.html")).into_response()
}

async fn jiuflow_sample_checkout(
    State(db): State<Db>,
    headers: HeaderMap,
    Json(body): Json<SampleCheckoutBody>,
) -> impl IntoResponse {
    sample_checkout(db, "jiuflow", "/jiuflow/proposal", "MU×JiuFlow sample", headers, body).await
}

