fn fmt_jpy(n: i64) -> String {
    let s = n.to_string();
    let bytes = s.as_bytes();
    let mut out = String::with_capacity(s.len() + s.len() / 3);
    for (i, b) in bytes.iter().enumerate() {
        if i > 0 && (bytes.len() - i) % 3 == 0 { out.push(','); }
        out.push(*b as char);
    }
    out
}
fn jst_now_str() -> String {
    let now: i64 = chrono_now().parse().unwrap_or(0);
    let jst = now + 9 * 3600;
    let day = jst / 86400;
    let h = (jst % 86400) / 3600;
    let m = (jst % 3600) / 60;
    let s = jst % 60;
    let (y, mo, d) = days_to_ymd(day);
    format!("{:04}-{:02}-{:02} {:02}:{:02}:{:02} JST", y, mo, d, h, m, s)
}
fn days_to_ymd(days_since_epoch: i64) -> (i64, i64, i64) {
    // 1970-01-01 → days = 0
    let mut y = 1970i64;
    let mut d = days_since_epoch;
    loop {
        let leap = (y % 4 == 0 && y % 100 != 0) || (y % 400 == 0);
        let dy = if leap { 366 } else { 365 };
        if d < dy { break; }
        d -= dy; y += 1;
    }
    let leap = (y % 4 == 0 && y % 100 != 0) || (y % 400 == 0);
    let mdays = if leap { [31,29,31,30,31,30,31,31,30,31,30,31] }
                else    { [31,28,31,30,31,30,31,31,30,31,30,31] };
    let mut m = 0usize;
    while d >= mdays[m] as i64 { d -= mdays[m] as i64; m += 1; }
    (y, (m + 1) as i64, d + 1)
}

/// Send one A/B-variant template via Resend. Persists to email_sends.
/// Honors DRY_RUN_PRODUCTION_WATCHER.
async fn send_buyer_email(
    db: &Db,
    to: &str,
    kind: &str,
    ctx: &EmailContext,
    extra: serde_json::Value,
) -> Result<String, String> {
    if is_test_email(to) { return Err("test_email".into()); }
    let variant = assign_email_variant(to, kind);
    let (subject, html) = match (kind, variant) {
        ("received",   v) => template_received(ctx, v),
        ("production", v) => template_production(ctx, v,
            extra.get("facility").and_then(|x| x.as_str()).unwrap_or(""),
            extra.get("printful_order_id").and_then(|x| x.as_str()).unwrap_or("")),
        ("shipped",    v) => template_shipped(ctx, v,
            extra.get("tracking").and_then(|x| x.as_str()).unwrap_or(""),
            extra.get("carrier").and_then(|x| x.as_str()).unwrap_or("")),
        ("cohort30",   v) => template_cohort30(ctx, v,
            extra.get("cohort_size").and_then(|x| x.as_i64()).unwrap_or(1)),
        ("nft_mint",   v) => template_nft_mint(ctx, v,
            extra.get("mint_address").and_then(|x| x.as_str()).unwrap_or("")),
        ("nft_login",  v) => template_nft_login(ctx, v),
        ("mu_x_you",   v) => template_mu_x_you(ctx, v),
        ("drop_preview", v) => template_drop_preview(ctx, v),
        ("quarter",    v) => template_quarter(ctx, v),
        ("referral",         v) => template_referral(ctx, v,
            extra.get("ref_code").and_then(|x| x.as_str()).unwrap_or("MU-REF")),
        ("silent_disappear", v) => template_silent_disappear(ctx, v,
            extra.get("days_silent").and_then(|x| x.as_i64()).unwrap_or(60)),
        ("council",          v) => template_council(ctx, v,
            extra.get("tier").and_then(|x| x.as_str()).unwrap_or("Council")),
        ("anniversary",      v) => template_anniversary(ctx, v,
            extra.get("year_n").and_then(|x| x.as_i64()).unwrap_or(1)),
        _ => return Err(format!("unknown kind: {}", kind)),
    };

    // Auto-UTM every wearmu.com link in the body so we can attribute pageviews
    // back to which email kind/variant brought the click. Idempotent (re-tags
    // are safe since we only inject when no utm_source= present).
    let html = utm_tag_email_body(&html, kind, variant);

    let is_dry = dry_run_active("production_watcher");
    if is_dry {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "INSERT INTO email_sends (to_email, kind, variant, subject, order_id, sent_at, dry_run)
             VALUES (?,?,?,?,?,?,1)",
            params![to, kind, variant, subject, ctx.order_id, chrono_now()],
        );
        return Ok(format!("DRY_RUN variant={}", variant));
    }
    let resend_key = env::var("RESEND_API_KEY").map_err(|_| "RESEND_API_KEY missing".to_string())?;
    let resp = reqwest::Client::new()
        .post("https://api.resend.com/emails")
        .bearer_auth(&resend_key)
        .json(&serde_json::json!({
            "from": "━◯━ MU Autopilot <mu-autopilot@wearmu.com>",
            "to": [to],
            "subject": subject,
            "html": html,
            "headers": {"X-MU-Variant": variant, "X-MU-Kind": kind},
            "tags": [
                {"name":"kind","value":kind},
                {"name":"variant","value":variant}
            ],
            "reply_to": "info@wearmu.com",
        }))
        .send().await.map_err(|e| e.to_string())?;
    if !resp.status().is_success() {
        let s = resp.status();
        let t = resp.text().await.unwrap_or_default();
        return Err(format!("resend {}: {}", s, t.chars().take(200).collect::<String>()));
    }
    let j: serde_json::Value = resp.json().await.unwrap_or_default();
    let resend_id = j["id"].as_str().unwrap_or("").to_string();
    {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "INSERT INTO email_sends (to_email, kind, variant, subject, resend_id, order_id, sent_at)
             VALUES (?,?,?,?,?,?,?)",
            params![to, kind, variant, subject, resend_id, ctx.order_id, chrono_now()],
        );
    }
    Ok(resend_id)
}

// ── Agent: production_watcher ───────────────────────────────────────────
// 30 min. Drives the 4-email A/B cohort:
//   1. received  — new collab_orders <24h without a 'received' email_sends row
//   2. production — Printful API says status moved into in_production/inprocess
//   3. shipped    — Printful status moved into fulfilled/shipped + tracking
//   4. cohort30   — orders aged 30–31d without a 'cohort30' email_sends row
async fn agent_production_watcher(db: Db) -> Result<AgentReport, String> {
    let mut obs = serde_json::Map::new();
    let mut actions: Vec<serde_json::Value> = Vec::new();
    let mut decisions: Vec<serde_json::Value> = Vec::new();
    let is_dry = dry_run_active("production_watcher");
    obs.insert("dry_run".into(), serde_json::Value::from(is_dry));

    let now_s: i64 = chrono_now().parse().unwrap_or(0);
    let h24 = now_s - 24 * 3600;
    let d30 = now_s - 30 * 86_400;
    let d31 = now_s - 31 * 86_400;

    // ── 1. received ───────────────────────────────────────────────────
    let new_orders: Vec<(i64, String, String, i64)> = {
        let conn = db.lock().unwrap();
        let mut stmt = match conn.prepare(
            "SELECT o.id, COALESCE(o.email,''), COALESCE(o.slug,''), COALESCE(o.amount_jpy,0)
             FROM collab_orders o
             WHERE CAST(COALESCE(o.created_at,'0') AS INTEGER) > ?
               AND NOT EXISTS (SELECT 1 FROM email_sends e WHERE e.order_id = o.id AND e.kind = 'received')
             ORDER BY o.id ASC LIMIT 10"
        ) { Ok(s) => s, Err(_) => return Ok(AgentReport::idle("schema not ready")) };
        stmt.query_map(params![h24], |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?)))
            .map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default()
    };
    let mut sent_received = 0i64;
    for (oid, email, slug, amount) in &new_orders {
        if is_test_email(email) { continue; }
        let ctx = {
            let conn = db.lock().unwrap();
            build_email_context(&conn, *oid, slug, *amount)
        };
        match send_buyer_email(&db, email, "received", &ctx, serde_json::json!({})).await {
            Ok(_) => { sent_received += 1; }
            Err(e) => {
                decisions.push(serde_json::json!({"type":"received_fail","order_id":oid,"error":e}));
            }
        }
    }
    obs.insert("sent_received".into(), serde_json::Value::from(sent_received));

    // ── 2 + 3. production / shipped via Printful API ──────────────────
    let printful_key = env::var("PRINTFUL_API_KEY").unwrap_or_default();
    let mut sent_production = 0i64;
    let mut sent_shipped = 0i64;
    if !printful_key.is_empty() {
        let opens: Vec<(i64, String, String, String, String)> = {
            let conn = db.lock().unwrap();
            let mut stmt = match conn.prepare(
                "SELECT o.id, COALESCE(o.email,''), COALESCE(o.printful_order_id,''),
                        COALESCE(o.slug,''), COALESCE(ps.last_status,'')
                 FROM collab_orders o
                 LEFT JOIN production_status ps ON ps.collab_order_id = o.id
                 WHERE o.printful_order_id IS NOT NULL AND length(o.printful_order_id) > 0
                   AND (ps.last_status IS NULL OR ps.last_status NOT IN ('fulfilled','canceled','shipped'))
                 ORDER BY o.id DESC LIMIT 20"
            ) { Ok(s) => s, Err(_) => return Ok(AgentReport::idle("schema not ready")) };
            stmt.query_map([], |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?, r.get(4)?)))
                .map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default()
        };
        for (oid, email, pf_id, slug, last_status) in &opens {
            let url = format!("https://api.printful.com/orders/{}", pf_id);
            let r = match reqwest::Client::new().get(&url).bearer_auth(&printful_key).send().await {
                Ok(r) if r.status().is_success() => r,
                _ => continue,
            };
            let j: serde_json::Value = match r.json().await { Ok(v) => v, _ => continue };
            let pf_status = j["result"]["status"].as_str().unwrap_or("").to_string();
            let tracking = j["result"]["shipments"][0]["tracking_number"].as_str().unwrap_or("").to_string();
            let carrier  = j["result"]["shipments"][0]["service"].as_str().unwrap_or("").to_string();
            {
                let conn = db.lock().unwrap();
                let _ = conn.execute(
                    "INSERT INTO production_status (collab_order_id, printful_order_id, last_status, tracking_number, carrier, created_at, updated_at)
                     VALUES (?,?,?,?,?,?,?)
                     ON CONFLICT(collab_order_id) DO UPDATE SET
                         last_status = excluded.last_status,
                         tracking_number = excluded.tracking_number,
                         carrier = excluded.carrier,
                         updated_at = excluded.updated_at",
                    params![oid, pf_id, pf_status, tracking, carrier, chrono_now(), chrono_now()],
                );
            }
            if &pf_status == last_status { continue; }
            if is_test_email(email) { continue; }
            let (kind, extra) = match pf_status.as_str() {
                "inprocess" | "in_production" => ("production",
                    serde_json::json!({"facility":"", "printful_order_id":pf_id})),
                "fulfilled" | "shipped" => ("shipped",
                    serde_json::json!({"tracking":tracking, "carrier":carrier})),
                _ => continue,
            };
            let ctx = {
                let conn = db.lock().unwrap();
                build_email_context(&conn, *oid, slug, 0)
            };
            match send_buyer_email(&db, email, kind, &ctx, extra).await {
                Ok(_) => if kind == "production" { sent_production += 1 } else { sent_shipped += 1 },
                Err(e) => decisions.push(serde_json::json!({"type":format!("{}_fail",kind),"order_id":oid,"error":e})),
            }
        }
    }
    obs.insert("sent_production".into(), serde_json::Value::from(sent_production));
    obs.insert("sent_shipped".into(),    serde_json::Value::from(sent_shipped));

    // ── 4. cohort30 ───────────────────────────────────────────────────
    let cohort: Vec<(i64, String, String)> = {
        let conn = db.lock().unwrap();
        let mut stmt = match conn.prepare(
            "SELECT o.id, COALESCE(o.email,''), COALESCE(o.slug,'')
             FROM collab_orders o
             WHERE CAST(COALESCE(o.created_at,'0') AS INTEGER) BETWEEN ? AND ?
               AND NOT EXISTS (SELECT 1 FROM email_sends e WHERE e.order_id = o.id AND e.kind = 'cohort30')
             ORDER BY o.id ASC LIMIT 5"
        ) { Ok(s) => s, Err(_) => return Ok(AgentReport::idle("schema not ready")) };
        stmt.query_map(params![d31, d30], |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?)))
            .map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default()
    };
    let mut sent_cohort = 0i64;
    for (oid, email, slug) in &cohort {
        if is_test_email(email) { continue; }
        let cohort_size: i64 = {
            let conn = db.lock().unwrap();
            conn.query_row(
                "SELECT COUNT(DISTINCT email) FROM collab_orders
                 WHERE DATE(created_at,'unixepoch') = (SELECT DATE(created_at,'unixepoch') FROM collab_orders WHERE id=?)",
                params![oid], |r| r.get(0),
            ).unwrap_or(1)
        };
        let ctx = {
            let conn = db.lock().unwrap();
            build_email_context(&conn, *oid, slug, 0)
        };
        match send_buyer_email(&db, email, "cohort30", &ctx,
            serde_json::json!({"cohort_size": cohort_size})).await
        {
            Ok(_) => { sent_cohort += 1; }
            Err(e) => decisions.push(serde_json::json!({"type":"cohort30_fail","order_id":oid,"error":e})),
        }
    }
    obs.insert("sent_cohort30".into(), serde_json::Value::from(sent_cohort));

    // ── 5. Day-N follow-ups (forgetting curve: 3 / 14 / 60 / 90) ──────
    //   day_3   → nft_mint     (Scarcity + Liking)
    //   day_14  → nft_login    (Consistency)
    //   day_60  → drop_preview (Liking + Reciprocity)
    //   day_90  → quarter      (Consistency)
    async fn day_n_kind(
        db: &Db, kind: &str, day: i64
    ) -> Result<i64, String> {
        let now_s: i64 = chrono_now().parse().unwrap_or(0);
        let lo = now_s - (day + 1) * 86_400;
        let hi = now_s - day * 86_400;
        let rows: Vec<(i64, String, String)> = {
            let conn = db.lock().unwrap();
            let mut stmt = match conn.prepare(
                "SELECT o.id, COALESCE(o.email,''), COALESCE(o.slug,'')
                 FROM collab_orders o
                 WHERE CAST(COALESCE(o.created_at,'0') AS INTEGER) BETWEEN ? AND ?
                   AND NOT EXISTS (SELECT 1 FROM email_sends e
                                   WHERE e.order_id = o.id AND e.kind = ?)
                 ORDER BY o.id ASC LIMIT 5"
            ) { Ok(s) => s, Err(_) => return Ok(0) };
            stmt.query_map(params![lo, hi, kind], |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?)))
                .map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default()
        };
        let mut n = 0i64;
        for (oid, email, slug) in &rows {
            if is_test_email(email) { continue; }
            let ctx = {
                let conn = db.lock().unwrap();
                build_email_context(&conn, *oid, slug, 0)
            };
            // For nft_mint, look up the actual mint address from products
            // by joining slug. (Falls back to empty string for collab SKUs
            // without an NFT — the template renders gracefully.)
            let mint_addr: String = {
                let conn = db.lock().unwrap();
                conn.query_row(
                    "SELECT COALESCE(nft_mint,'') FROM products WHERE slug=?",
                    params![slug], |r| r.get::<_, String>(0),
                ).unwrap_or_default()
            };
            let extra = serde_json::json!({"mint_address": mint_addr});
            if send_buyer_email(db, email, kind, &ctx, extra).await.is_ok() {
                n += 1;
            }
        }
        Ok(n)
    }

    let sent_nft_mint     = day_n_kind(&db, "nft_mint",     3).await.unwrap_or(0);
    let sent_mu_x_you     = day_n_kind(&db, "mu_x_you",     7).await.unwrap_or(0);
    let sent_nft_login    = day_n_kind(&db, "nft_login",   14).await.unwrap_or(0);
    let sent_drop_preview = day_n_kind(&db, "drop_preview",60).await.unwrap_or(0);
    let sent_quarter      = day_n_kind(&db, "quarter",     90).await.unwrap_or(0);
    obs.insert("sent_nft_mint".into(),     serde_json::Value::from(sent_nft_mint));
    obs.insert("sent_mu_x_you".into(),     serde_json::Value::from(sent_mu_x_you));
    obs.insert("sent_nft_login".into(),    serde_json::Value::from(sent_nft_login));
    obs.insert("sent_drop_preview".into(), serde_json::Value::from(sent_drop_preview));
    obs.insert("sent_quarter".into(),      serde_json::Value::from(sent_quarter));

    actions.push(serde_json::json!({"received": sent_received, "production": sent_production, "shipped": sent_shipped, "cohort30": sent_cohort, "nft_mint": sent_nft_mint, "mu_x_you": sent_mu_x_you, "nft_login": sent_nft_login, "drop_preview": sent_drop_preview, "quarter": sent_quarter}));
    let total = sent_received + sent_production + sent_shipped + sent_cohort
              + sent_nft_mint + sent_mu_x_you + sent_nft_login + sent_drop_preview + sent_quarter;
    let summary = format!("watcher: {} sent (recv={}, prod={}, ship={}, c30={}, dry={})",
        total, sent_received, sent_production, sent_shipped, sent_cohort, is_dry);
    Ok(AgentReport {
        observations: serde_json::Value::Object(obs),
        decisions, actions, summary,
        notable: total > 0,
    })
}

/// POST /webhooks/resend — receive open/click events from Resend.
/// No HMAC verification for v1 (Resend uses Svix; defer signing). The webhook
/// is idempotent at the DB level via COALESCE.
async fn webhook_resend(
    State(db): State<Db>,
    Json(body): Json<serde_json::Value>,
) -> Response {
    let event_type = body["type"].as_str().unwrap_or("");
    let resend_id  = body["data"]["email_id"].as_str().unwrap_or("");
    if resend_id.is_empty() { return StatusCode::OK.into_response(); }
    let column = match event_type {
        "email.opened"    => "opened_at",
        "email.clicked"   => "clicked_at",
        "email.bounced"   => return StatusCode::OK.into_response(),
        "email.complained"=> return StatusCode::OK.into_response(),
        _ => return StatusCode::OK.into_response(),
    };
    let conn = db.lock().unwrap();
    let _ = conn.execute(
        &format!("UPDATE email_sends SET {col} = COALESCE({col}, ?) WHERE resend_id = ?", col = column),
        params![chrono_now(), resend_id],
    );
    StatusCode::OK.into_response()
}

/// GET /admin/email-preview?token=…&kind=&variant=
/// Render an email template with synthetic context (no send). Visual QA tool.
async fn admin_email_preview(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/admin/email-preview").await { return r; }
    let kind = q.get("kind").map(String::as_str).unwrap_or("received").to_string();
    let variant = q.get("variant").map(String::as_str).unwrap_or("A").to_string();
    let tok = q.get("token").map(String::as_str).unwrap_or("").to_string();
    let ctx = {
        let conn = db.lock().unwrap();
        build_email_context(&conn, 42, "mugen-0042-charcoal-m", 6_000)
    };
    let (subject, html) = match (kind.as_str(), variant.as_str()) {
        ("received",         v) => template_received(&ctx, v),
        ("production",       v) => template_production(&ctx, v, "Printful Charlotte, NC", "PF-12345678"),
        ("shipped",          v) => template_shipped(&ctx, v, "9405511899223344556677", "USPS First-Class International"),
        ("cohort30",         v) => template_cohort30(&ctx, v, 1),
        ("nft_mint",         v) => template_nft_mint(&ctx, v, "ENaiMint1234567890SoulboundSample"),
        ("nft_login",        v) => template_nft_login(&ctx, v),
        ("mu_x_you",         v) => template_mu_x_you(&ctx, v),
        ("drop_preview",     v) => template_drop_preview(&ctx, v),
        ("quarter",          v) => template_quarter(&ctx, v),
        ("referral",         v) => template_referral(&ctx, v, "MU-REF-0042-SAMPLE"),
        ("silent_disappear", v) => template_silent_disappear(&ctx, v, 87),
        ("council",          v) => template_council(&ctx, v, "Council"),
        ("anniversary",      v) => template_anniversary(&ctx, v, 1),
        _ => ("(unknown)".into(), "<p>unknown</p>".into()),
    };
    let tok_attr = html_attr_escape(&tok);
    let mut nav = String::new();
    for k in ["received","nft_mint","production","nft_login","shipped","mu_x_you","cohort30","drop_preview","quarter","referral","silent_disappear","council","anniversary"] {
        for v in ["A","B"] {
            nav.push_str(&format!(
                r#"<a href="?token={t}&kind={k}&variant={v}" style="color:#9bd;margin-right:8px;">{k}/{v}</a>"#,
                t = &tok_attr, k = k, v = v));
        }
    }
    let wrapped = format!(
        r#"<div style="background:#222;color:#999;padding:10px 16px;font:12px ui-monospace,Menlo,monospace;border-bottom:1px solid #444;">PREVIEW · subject=<b>{}</b><br>{}</div>{}"#,
        html_escape(&subject), nav, html);
    Html(wrapped).into_response()
}

/// POST /admin/email-test-send?token=&to=&kind=
/// Actually send 1 email via Resend to the specified address. Use to verify
/// design renders in real inbox. admin-only; not gated by is_test_email so
/// you can send to your own address even if it matches test patterns.
async fn admin_email_test_send(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/admin/email-test-send").await { return r; }
    let to = q.get("to").cloned().unwrap_or_default();
    let kind = q.get("kind").cloned().unwrap_or("received".into());
    if to.is_empty() || !to.contains('@') {
        return (StatusCode::BAD_REQUEST, "missing or invalid ?to=").into_response();
    }
    let ctx = {
        let conn = db.lock().unwrap();
        build_email_context(&conn, 42, "mugen-0042-charcoal-m", 6_000)
    };
    // Optional ?variant=A|B override for QA (default: deterministic hash).
    let variant: &'static str = match q.get("variant").map(String::as_str) {
        Some("A") => "A",
        Some("B") => "B",
        _ => assign_email_variant(&to, &kind),
    };
    let (subject, html) = match (kind.as_str(), variant) {
        ("received",   v) => template_received(&ctx, v),
        ("production", v) => template_production(&ctx, v, "Printful Charlotte, NC", "PF-TEST-123"),
        ("shipped",    v) => template_shipped(&ctx, v, "9405511899223344556677", "USPS Intl"),
        ("cohort30",   v) => template_cohort30(&ctx, v, 1),
        ("nft_mint",   v) => template_nft_mint(&ctx, v, "ENaiMint1234567890SoulboundSample"),
        ("nft_login",  v) => template_nft_login(&ctx, v),
        ("mu_x_you",   v) => template_mu_x_you(&ctx, v),
        ("drop_preview", v) => template_drop_preview(&ctx, v),
        ("quarter",    v) => template_quarter(&ctx, v),
        _ => return (StatusCode::BAD_REQUEST, "unknown kind").into_response(),
    };
    let resend_key = match env::var("RESEND_API_KEY") {
        Ok(k) if !k.is_empty() => k,
        _ => return (StatusCode::SERVICE_UNAVAILABLE, "RESEND_API_KEY missing").into_response(),
    };
    let resp = reqwest::Client::new()
        .post("https://api.resend.com/emails")
        .bearer_auth(&resend_key)
        .json(&serde_json::json!({
            "from": "━◯━ MU Autopilot <mu-autopilot@wearmu.com>",
            "to": [to.clone()],
            "subject": format!("[TEST] {}", subject),
            "html": html,
            "headers": {"X-MU-Variant": variant, "X-MU-Kind": kind, "X-MU-Test": "1"},
        }))
        .send().await;
    match resp {
        Ok(r) if r.status().is_success() => {
            let j: serde_json::Value = r.json().await.unwrap_or_default();
            Json(serde_json::json!({
                "ok": true, "to": to, "kind": kind, "variant": variant,
                "subject": subject, "resend_id": j["id"].as_str().unwrap_or(""),
            })).into_response()
        }
        Ok(r) => {
            let s = r.status();
            let t = r.text().await.unwrap_or_default();
            (s, format!("resend: {}", t)).into_response()
        }
        Err(e) => (StatusCode::INTERNAL_SERVER_ERROR, format!("http: {e}")).into_response(),
    }
}

// ── Agent 24: email_critic ─────────────────────────────────────────────
// 4 personas (Musk / Bezos / Jobs / skeptical buyer) score each email
// template (subject + body) via Gemini Flash. Writes to email_critique.
// Cost: 9 kinds × 2 variants × 1 batched call/day ≈ 18 Flash calls/day.

const EMAIL_CRITIC_PROMPT: &str = r#"You are scoring a single email from MU
(a 0-human apparel brand) from FOUR personas. Each persona has its own
operating principles. Return STRICT JSON only (no fences).

The four personas:
1. "musk"  — Elon Musk. Cuts BS. Numbers, not adjectives. Speed obsessed.
            Scores HIGH only when message is data-dense, no fluff, ships fast.
            Scores LOW if it sounds like a marketing email.
2. "bezos" — Jeff Bezos. Customer obsession. Day 1 thinking.
            Scores HIGH when the email centers the buyer's actual experience
            and discloses the long-term thesis. LOW if seller-centric.
3. "jobs"  — Steve Jobs. Aesthetic + simplicity + emotional resonance.
            Scores HIGH when one sentence carries the whole point and the
            design serves the message. LOW for clutter, multiple CTAs,
            "everything but the kitchen sink".
4. "buyer" — A skeptical 28-year-old Tokyo customer who bought a single
            MUGEN shirt. Scores HIGH if reading it feels like the brand
            knows them and isn't trying to extract more money. LOW if it
            feels like spam, "BUY NOW", or guilt-tripping.

Each persona returns:
- score: 0.0..1.0 (be HARSH; default ~0.4–0.6, only excellent gets 0.85+)
- verdict: <=120 chars headline ("what this email is")
- suggestion: <=200 chars, ONE concrete change (rewrite/delete/add)

Output schema (exact keys, all four required):
{
  "musk":  {"score":0.0,"verdict":"...","suggestion":"..."},
  "bezos": {"score":0.0,"verdict":"...","suggestion":"..."},
  "jobs":  {"score":0.0,"verdict":"...","suggestion":"..."},
  "buyer": {"score":0.0,"verdict":"...","suggestion":"..."}
}
"#;

/// Strip HTML tags for a plain-text summary suitable for Gemini.
fn strip_html_tags(html: &str) -> String {
    let mut out = String::with_capacity(html.len());
    let mut in_tag = false;
    let mut last_was_space = true;
    for ch in html.chars() {
        match ch {
            '<' => in_tag = true,
            '>' => { in_tag = false; if !last_was_space { out.push(' '); last_was_space = true; } }
            c if in_tag => { let _ = c; }
            c if c.is_whitespace() => {
                if !last_was_space { out.push(' '); last_was_space = true; }
            }
            c => { out.push(c); last_was_space = false; }
        }
    }
    out.replace("&nbsp;", " ")
       .replace("&amp;", "&")
       .replace("&lt;", "<")
       .replace("&gt;", ">")
       .replace("&quot;", "\"")
       .replace("&#39;", "'")
       .trim().chars().take(1800).collect()
}

