/// GET /admin/email-ab?token=… — A/B test rollup per kind+variant.
async fn admin_email_ab(
    State(db): State<Db>,
    headers: HeaderMap,
    axum::extract::Query(q): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(r) = admin_auth(&headers, &q, db.clone(), "/admin/email-ab").await { return r; }
    let token = q.get("token").map(String::as_str).unwrap_or("");

    let rows: Vec<(String, String, i64, i64, i64)> = {
        let conn = db.lock().unwrap();
        let mut stmt = match conn.prepare(
            "SELECT kind, variant,
                    COUNT(*) AS sent,
                    SUM(CASE WHEN opened_at IS NOT NULL THEN 1 ELSE 0 END) AS opened,
                    SUM(CASE WHEN clicked_at IS NOT NULL THEN 1 ELSE 0 END) AS clicked
             FROM email_sends
             WHERE COALESCE(dry_run, 0) = 0
             GROUP BY kind, variant
             ORDER BY kind, variant"
        ) { Ok(s) => s, Err(_) => return (StatusCode::INTERNAL_SERVER_ERROR, "db").into_response() };
        stmt.query_map([], |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?, r.get(4)?)))
            .map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default()
    };

    let mut tbody = String::new();
    for (kind, variant, sent, opened, clicked) in &rows {
        let open_pct  = if *sent > 0 { *opened as f64 / *sent as f64 * 100.0 } else { 0.0 };
        let click_pct = if *sent > 0 { *clicked as f64 / *sent as f64 * 100.0 } else { 0.0 };
        tbody.push_str(&format!(
            r#"<tr><td><code>{kind}</code></td><td><b>{v}</b></td><td class=num>{s}</td><td class=num>{o} ({op:.0}%)</td><td class=num>{c} ({cp:.0}%)</td></tr>"#,
            kind = html_escape(kind), v = html_escape(variant),
            s = sent, o = opened, op = open_pct, c = clicked, cp = click_pct));
    }
    if tbody.is_empty() {
        tbody = "<tr><td colspan=5 class=dim>(no email_sends rows yet — production_watcher hasn't fired)</td></tr>".into();
    }

    Html(format!(r#"<!doctype html><html lang="ja"><head>
<meta charset=utf-8><meta name=viewport content="width=device-width,initial-scale=1">
<title>MU / Email A/B</title>
<style>
body{{font:14px/1.55 ui-monospace,Menlo,monospace;color:#eaeaea;background:#0b0b0b;padding:24px;max-width:980px;margin:0 auto}}
h1{{font-weight:500;margin-top:0}}
table{{width:100%;border-collapse:collapse;margin-top:12px}}
td,th{{padding:8px 10px;border-bottom:1px solid #222;text-align:left}}
.num{{text-align:right;font-variant-numeric:tabular-nums}} .dim{{color:#666}}
code{{background:#1a1a1a;padding:1px 6px;border-radius:4px;color:#e6c449}}
.nav a{{margin-right:14px;color:#9bd}} .nav{{margin-bottom:20px}}
</style></head><body>
<div class=nav>
  <a href="/admin/agents?token={tok}">Agents</a>
  <a href="/admin/insights?token={tok}">Insights</a>
  <a href="/admin/governance?token={tok}">Governance</a>
  <a href="/admin/audit?token={tok}">Audit</a>
  <a href="/admin/founders?token={tok}">Founders</a>
  <a href="/admin/email-ab?token={tok}">Email A/B</a>
</div>
<h1>Buyer email A/B rollup</h1>
<p class=dim>送信タグごとに variant A vs B の sent / opened / clicked。production_watcher が DRY_RUN_PRODUCTION_WATCHER=1 のとき send は db ログのみ (dry_run=1 行は除外)。</p>
<table><thead><tr><th>kind</th><th>variant</th><th>sent</th><th>opened</th><th>clicked</th></tr></thead>
<tbody>{tbody}</tbody></table>
</body></html>"#,
        tok = html_attr_escape(token), tbody = tbody)).into_response()
}

// ── Agent: checkout_health ─────────────────────────────────────────────
// Constitution: "purchase path is sacrosanct". Every 15 min, probe the user-
// facing endpoints customers actually use to buy. Any non-200 → governance T1
// + immediate Telegram (severity=critical). Probes are external HTTPS hits
// to wearmu.com so even Fly proxy issues are caught.
async fn agent_checkout_health(_db: Db) -> Result<AgentReport, String> {
    let mut obs = serde_json::Map::new();
    let mut decisions: Vec<serde_json::Value> = Vec::new();
    let mut critical: Vec<String> = Vec::new();

    let client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(10)).build()
        .map_err(|e| e.to_string())?;
    let probes: &[(&str, &str, Option<&str>)] = &[
        ("healthz",          "https://wearmu.com/healthz",                       Some("ok")),
        ("home",             "https://wearmu.com/",                              Some("MU")),
        ("you_landing",      "https://wearmu.com/you",                           None),
        ("sweep_signals",    "https://wearmu.com/api/sweep/signals",             None),
        ("collab_landing",   "https://wearmu.com/collab",                        None),
        ("product_detail",   "https://wearmu.com/products/sweep/sweep-cap",      None),
    ];
    for (name, url, must_contain) in probes {
        let started = std::time::Instant::now();
        let res = client.get(*url).send().await;
        let elapsed_ms = started.elapsed().as_millis() as i64;
        let (ok, status, body_check) = match res {
            Ok(r) => {
                let status = r.status().as_u16();
                let is_2xx = (200..=299).contains(&status);
                let body_ok = if let Some(needle) = must_contain {
                    r.text().await.map(|t| t.contains(needle)).unwrap_or(false)
                } else { is_2xx };
                (is_2xx && body_ok, status, body_ok)
            }
            Err(_) => (false, 0u16, false),
        };
        obs.insert(format!("{}_status", name), serde_json::Value::from(status as i64));
        obs.insert(format!("{}_ms", name),     serde_json::Value::from(elapsed_ms));
        obs.insert(format!("{}_ok", name),     serde_json::Value::from(ok));
        if !ok {
            critical.push(format!("{} {} status={} body_ok={} ({}ms)",
                name, url, status, body_check, elapsed_ms));
            decisions.push(serde_json::json!({
                "type":"probe_fail","name":name,"url":url,"status":status,"elapsed_ms":elapsed_ms,
            }));
        }
    }

    // Stripe webhook lag: if there are recent orders (last 24h) but no
    // successful webhook-processed row in same window, alert.
    // We use a proxy: collab_orders rows with non-null amount_jpy.
    let stripe_lag = {
        let now_s: i64 = chrono_now().parse().unwrap_or(0);
        let h24 = now_s - 24 * 3600;
        let conn = _db.lock().unwrap();
        let n: i64 = conn.query_row(
            "SELECT COUNT(*) FROM collab_orders
             WHERE CAST(COALESCE(created_at,'0') AS INTEGER) > ?",
            params![h24], |r| r.get(0),
        ).unwrap_or(0);
        n
    };
    obs.insert("orders_24h".into(), serde_json::Value::from(stripe_lag));

    // Constitution: critical means immediate Telegram, regardless of dedup.
    if !critical.is_empty() {
        let tg_token = env::var("TELEGRAM_BOT_TOKEN").unwrap_or_default();
        let tg_chat  = env::var("TELEGRAM_CHAT_ID").unwrap_or_else(|_| "1136442501".into());
        if !tg_token.is_empty() {
            let msg = format!(
                "🚨 CHECKOUT HEALTH FAIL\n\nMU の購入導線に問題:\n{}",
                critical.join("\n"));
            let _ = reqwest::Client::new()
                .post(format!("https://api.telegram.org/bot{}/sendMessage", tg_token))
                .json(&serde_json::json!({
                    "chat_id": tg_chat, "text": msg, "disable_web_page_preview": true,
                }))
                .send().await;
        }
        let conn = _db.lock().unwrap();
        let did = log_autonomy_decision(
            &conn, "checkout_health", "probe_critical_fail", "T1",
            &serde_json::json!({"failures": critical.clone()}),
            false, true, false,
        );
        let _ = enqueue_governance(
            &conn, did, "checkout_health",
            "CRITICAL: purchase path probes failed",
            &critical.join(" | "),
        );
    }

    let ok_count = probes.len() - critical.len();
    let summary = format!("checkout_health: {}/{} probes OK ({} orders 24h)",
        ok_count, probes.len(), stripe_lag);
    Ok(AgentReport {
        observations: serde_json::Value::Object(obs),
        decisions, actions: vec![],
        summary,
        notable: !critical.is_empty(),
    })
}

// ── Agent: funnel_anomaly ──────────────────────────────────────────────
// Looks at the last 24h funnel vs the 30d baseline. If CV rate dropped by
// >50% relative to baseline AND there were ≥20 pageviews today, T1 alert.
// Catches the silent "all customers see a broken Buy button" scenario.
async fn agent_funnel_anomaly(db: Db) -> Result<AgentReport, String> {
    let mut obs = serde_json::Map::new();
    let mut decisions: Vec<serde_json::Value> = Vec::new();

    let now_s: i64 = chrono_now().parse().unwrap_or(0);
    let h24 = now_s - 24 * 3600;
    let d30 = now_s - 30 * 86_400;

    let (pv_24h, paid_24h, pv_30d, paid_30d): (i64, i64, i64, i64) = {
        let conn = db.lock().unwrap();
        let q = |sql: &str, t: i64| -> i64 {
            conn.query_row(sql, params![t], |r| r.get(0)).unwrap_or(0)
        };
        (
            q("SELECT COUNT(*) FROM funnel_events WHERE event='pageview' AND CAST(COALESCE(created_at,'0') AS INTEGER) > ?", h24),
            q("SELECT COUNT(*) FROM funnel_events WHERE event='checkout_paid' AND CAST(COALESCE(created_at,'0') AS INTEGER) > ?", h24),
            q("SELECT COUNT(*) FROM funnel_events WHERE event='pageview' AND CAST(COALESCE(created_at,'0') AS INTEGER) > ?", d30),
            q("SELECT COUNT(*) FROM funnel_events WHERE event='checkout_paid' AND CAST(COALESCE(created_at,'0') AS INTEGER) > ?", d30),
        )
    };
    let cv_24h = if pv_24h > 0 { paid_24h as f64 / pv_24h as f64 } else { 0.0 };
    let cv_30d = if pv_30d > 0 { paid_30d as f64 / pv_30d as f64 } else { 0.0 };
    obs.insert("pageviews_24h".into(), pv_24h.into());
    obs.insert("paid_24h".into(),      paid_24h.into());
    obs.insert("cv_24h".into(),        serde_json::json!(cv_24h));
    obs.insert("cv_30d".into(),        serde_json::json!(cv_30d));

    if pv_24h < 20 || cv_30d == 0.0 {
        return Ok(AgentReport::idle("insufficient signal (need >=20 pageviews and a 30d baseline)"));
    }

    let drop_ratio = if cv_30d > 0.0 { (cv_30d - cv_24h) / cv_30d } else { 0.0 };
    if drop_ratio > 0.5 {
        decisions.push(serde_json::json!({
            "type":"cv_anomaly","drop_ratio":drop_ratio,"cv_24h":cv_24h,"cv_30d":cv_30d,
        }));
        let tg_token = env::var("TELEGRAM_BOT_TOKEN").unwrap_or_default();
        let tg_chat  = env::var("TELEGRAM_CHAT_ID").unwrap_or_else(|_| "1136442501".into());
        if !tg_token.is_empty() {
            let msg = format!(
                "📉 FUNNEL ANOMALY\nCV dropped {:.0}% vs 30d baseline\n24h: {} pv / {} paid (cv {:.2}%)\n30d: cv {:.2}%",
                drop_ratio * 100.0, pv_24h, paid_24h, cv_24h * 100.0, cv_30d * 100.0);
            let _ = reqwest::Client::new()
                .post(format!("https://api.telegram.org/bot{}/sendMessage", tg_token))
                .json(&serde_json::json!({"chat_id": tg_chat, "text": msg}))
                .send().await;
        }
        let conn = db.lock().unwrap();
        let did = log_autonomy_decision(
            &conn, "funnel_anomaly", "cv_drop", "T1",
            &serde_json::json!({"cv_24h": cv_24h, "cv_30d": cv_30d, "drop_ratio": drop_ratio}),
            false, true, false,
        );
        let _ = enqueue_governance(
            &conn, did, "funnel_anomaly",
            "Funnel CV dropped >50% vs 30d baseline",
            &format!("24h cv={:.2}%, 30d cv={:.2}%", cv_24h * 100.0, cv_30d * 100.0),
        );
    }

    let summary = format!("funnel: 24h cv={:.2}% vs 30d {:.2}% (drop {:.0}%)",
        cv_24h * 100.0, cv_30d * 100.0, drop_ratio * 100.0);
    Ok(AgentReport {
        observations: serde_json::Value::Object(obs),
        decisions, actions: vec![],
        summary, notable: drop_ratio > 0.5,
    })
}

// ── Agent 20: musk_review (founder persona) ────────────────────────────
async fn agent_musk_review(db: Db) -> Result<AgentReport, String> {
    founder_review(db, "musk", MUSK_PROMPT).await
}

// ── Agent: purchase_celebrate ───────────────────────────────────────────
// 新規 external 購入を検知し、Gemini Pro で「同じ文面の繰り返しなし / humor /
// FOMO」のお祝いツイートを生成して enqueue。同時に次の MUGEN ドロップ用の
// design_seed を cv_config('next_mugen_seed_prompt') に保存。
//
// 売れたから生まれる T シャツ、というファンループ:
//   purchase → tweet → 次 MUGEN drop のデザイン seed → 別の購入 → ...
//
// yuki 本人 (yuki@hamada.tokyo / mail@yukihamada.jp) の dogfood 購入は対象外。
// 10 分 cadence、idempotent (cv_config('last_celebrated_purchase_id'))。
async fn agent_purchase_celebrate(db: Db) -> Result<AgentReport, String> {
    let key = match env::var("GEMINI_API_KEY") {
        Ok(k) if !k.is_empty() => k,
        _ => return Ok(AgentReport::idle("GEMINI_API_KEY missing")),
    };
    let yuki_a = "yuki@hamada.tokyo";
    let yuki_b = "mail@yukihamada.jp";
    let (last_id, new_purchases): (i64, Vec<(i64, String, String, i64, String)>) = {
        let conn = db.lock().unwrap();
        let last: i64 = cv_get(&conn, "last_celebrated_purchase_id", "0").parse().unwrap_or(0);
        let mut stmt = match conn.prepare(
            "SELECT id, email, brand, drop_num, COALESCE(session_id,'') FROM mu_purchases
             WHERE id > ? AND session_id LIKE 'cs_live_%' AND email NOT IN (?,?)
             ORDER BY id ASC LIMIT 5"
        ) { Ok(s) => s, Err(_) => return Ok(AgentReport::idle("schema not ready")) };
        let rows: Vec<_> = stmt.query_map(params![last, yuki_a, yuki_b],
            |r| Ok((r.get::<_,i64>(0)?, r.get::<_,String>(1)?, r.get::<_,String>(2)?,
                    r.get::<_,i64>(3)?, r.get::<_,String>(4)?)))
            .map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default();
        (last, rows)
    };
    if new_purchases.is_empty() {
        return Ok(AgentReport::idle("no new external purchases"));
    }
    let mut decisions: Vec<serde_json::Value> = Vec::new();
    let mut actions: Vec<serde_json::Value> = Vec::new();
    let mut posted = 0i64;
    let mut max_id = last_id;
    for (pid, _email, brand, drop_num, _sess) in &new_purchases {
        let (tweet, seed) = match generate_purchase_celebration(&key, brand, *drop_num, &db).await {
            Ok(v) => v,
            Err(e) => {
                decisions.push(serde_json::json!({"type":"gemini_err","purchase_id":pid,"error":e}));
                max_id = *pid;
                continue;
            }
        };
        // Enqueue tweet + save next drop seed (atomic-ish)
        {
            let conn = db.lock().unwrap();
            let qid = enqueue_sns_post(&conn, "x", "purchase_celebrate", None, None, &tweet, None);
            cv_set(&conn, "next_mugen_seed_prompt", &seed, &format!("purchase_celebrate purchase_id={}", pid));
            actions.push(serde_json::json!({
                "purchase_id": pid, "brand": brand, "drop_num": drop_num,
                "queue_id": qid, "tweet_chars": tweet.chars().count(),
                "design_seed_preview": seed.chars().take(60).collect::<String>(),
            }));
        }
        posted += 1;
        max_id = *pid;
    }
    {
        let conn = db.lock().unwrap();
        cv_set(&conn, "last_celebrated_purchase_id", &max_id.to_string(), "purchase_celebrate");
    }

    // ── 2. Lifecycle transitions (production / shipped / delivered) ──
    // Poll Printful for all mu_purchases that have printful_order_id and
    // are not yet 'fulfilled'. Detect state changes vs last_printful_status,
    // fire a celebration tweet per transition (kind = production_started /
    // shipped / delivered), and update last_printful_status.
    let printful_key = env::var("PRINTFUL_API_KEY").unwrap_or_default();
    let mut lifecycle_posted = 0i64;
    if !printful_key.is_empty() {
        let opens: Vec<(i64, String, String, i64, String, String)> = {
            let conn = db.lock().unwrap();
            let mut stmt = match conn.prepare(
                "SELECT id, COALESCE(email,''), brand, drop_num,
                        COALESCE(printful_order_id,''), COALESCE(last_printful_status,'')
                 FROM mu_purchases
                 WHERE printful_order_id IS NOT NULL AND length(printful_order_id) > 0
                   AND (last_printful_status IS NULL
                        OR last_printful_status NOT IN ('fulfilled','delivered','canceled'))
                   AND email NOT IN (?,?)
                 ORDER BY id DESC LIMIT 20"
            ) { Ok(s) => s, Err(_) => return Ok(AgentReport {
                observations: serde_json::json!({"new_purchases": new_purchases.len(), "tweets_queued": posted}),
                decisions, actions, summary: format!("purchase_celebrate (no lifecycle): {} purchases", new_purchases.len()),
                notable: posted > 0,
            }) };
            stmt.query_map(params![yuki_a, yuki_b], |r| Ok((
                r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?, r.get(4)?, r.get(5)?,
            ))).map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default()
        };
        for (pid, _email, brand, drop_num, pf_id, prev_status) in &opens {
            let url = format!("https://api.printful.com/orders/{}", pf_id);
            let r = match reqwest::Client::new().get(&url).bearer_auth(&printful_key).send().await {
                Ok(r) if r.status().is_success() => r,
                _ => continue,
            };
            let j: serde_json::Value = match r.json().await { Ok(v) => v, _ => continue };
            let pf_status = j["result"]["status"].as_str().unwrap_or("").to_string();
            if pf_status == *prev_status || pf_status.is_empty() { continue; }
            // Map Printful status → our lifecycle kind.
            let kind: Option<&str> = match pf_status.as_str() {
                "inprocess" | "in_production" | "pending"      => Some("production_started"),
                "fulfilled" | "shipped"                         => Some("shipped"),
                "delivered"                                     => Some("delivered"),
                _ => None,
            };
            let Some(kind) = kind else {
                // Still update the recorded status even if we don't celebrate.
                let conn = db.lock().unwrap();
                let _ = conn.execute(
                    "UPDATE mu_purchases SET last_printful_status=?, last_status_at=? WHERE id=?",
                    params![pf_status, chrono_now(), pid],
                );
                continue;
            };
            let parent_seed = {
                let conn = db.lock().unwrap();
                cv_get(&conn, "next_mugen_seed_prompt", "")
            };
            let parent_opt = if parent_seed.is_empty() { None } else { Some(parent_seed.as_str()) };
            let (tweet, seed) = match generate_lifecycle_celebration(
                &key, kind, brand, *drop_num, &pf_status, parent_opt, &db,
            ).await {
                Ok(v) => v,
                Err(e) => {
                    decisions.push(serde_json::json!({"type":"lifecycle_err","kind":kind,"purchase_id":pid,"error":e}));
                    continue;
                }
            };
            {
                let conn = db.lock().unwrap();
                let qid = enqueue_sns_post(&conn, "x", &format!("celebrate_{}", kind), None, None, &tweet, None);
                cv_set(&conn, "next_mugen_seed_prompt", &seed, &format!("celebrate_{} purchase_id={}", kind, pid));
                let _ = conn.execute(
                    "UPDATE mu_purchases SET last_printful_status=?, last_status_at=? WHERE id=?",
                    params![pf_status, chrono_now(), pid],
                );
                actions.push(serde_json::json!({
                    "purchase_id": pid, "kind": kind, "pf_status": pf_status,
                    "queue_id": qid, "tweet_chars": tweet.chars().count(),
                }));
            }
            lifecycle_posted += 1;
        }
    }
    let total_posted = posted + lifecycle_posted;
    Ok(AgentReport {
        observations: serde_json::json!({
            "new_purchases": new_purchases.len(),
            "purchase_tweets": posted,
            "lifecycle_tweets": lifecycle_posted,
            "last_celebrated_id": max_id,
        }),
        decisions,
        actions,
        summary: format!(
            "purchase_celebrate: {} purchase + {} lifecycle tweets queued ({}+{} events)",
            posted, lifecycle_posted, new_purchases.len(), lifecycle_posted,
        ),
        notable: total_posted > 0,
    })
}

/// Lifecycle-aware celebration. `kind` ∈ {production_started, shipped, delivered}.
/// `parent_seed` is the previous design's seed prompt — included so each new
/// celebration design RIFFS on the original instead of being unrelated. ふぁ
/// ファンループ: 元のデザインがいろんな場面で派生する。
async fn generate_lifecycle_celebration(
    gemini_key: &str, kind: &str, brand: &str, drop_num: i64,
    pf_status: &str, parent_seed: Option<&str>, db: &Db,
) -> Result<(String, String), String> {
    // Avoid recent celebrations of the same lifecycle kind.
    let recent: Vec<String> = {
        let conn = db.lock().unwrap();
        let mut stmt = match conn.prepare(
            "SELECT text FROM sns_post_queue
             WHERE network='x' AND trigger_kind = ?
             ORDER BY created_at DESC LIMIT 4"
        ) { Ok(s) => s, Err(_) => return Err("db prep".into()) };
        stmt.query_map(params![format!("celebrate_{}", kind)], |r| r.get::<_,String>(0))
            .map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default()
    };
    let avoid_block = if recent.is_empty() { "(初回)".into() }
        else { recent.iter().enumerate().map(|(i,t)| format!("{}: {}", i+1, t.chars().take(120).collect::<String>())).collect::<Vec<_>>().join("\n") };
    let brand_url = match brand {
        "mugen" => "wearmu.com/mugen", "muon" => "wearmu.com/muon",
        "ma" => "wearmu.com/ma", "you" => "wearmu.com/you",
        _ => "wearmu.com",
    };
    let lifecycle_jp = match kind {
        "production_started" => "生産開始",
        "shipped"            => "発送",
        "delivered"          => "到着",
        _                    => kind,
    };
    let humor_angle = match kind {
        "production_started" => "プリンタが温まった瞬間 / インクが布に乗る前の静けさ / Printful の工場で何かが始まる",
        "shipped"            => "段ボールが travel する / 弟子屈から飛び立つ / トラックが知らない誰かの街へ",
        "delivered"          => "玄関のチャイム / クローゼットに 1 着追加 / 18°C の朝の温度が誰かの肩に着地",
        _                    => "",
    };
    let parent_hint = match parent_seed {
        Some(s) if !s.is_empty() => format!("\n# 元のデザインの seed (riff してね、無視せず)\n{}", s),
        _ => String::new(),
    };
    let learnings = active_feedback_insights(db, 5);
    let vision_pref = vision_compliant_prefix();
    let prompt = format!(r#"{vision_pref}
あなたは MU (北海道弟子屈町、無人 AI ファッションブランド) の SNS 担当 AI です。
{brand} #{drop_num} の lifecycle に変化: 「{lifecycle_jp}」 (Printful 状態: {pf_status})。
このイベントを X 投稿します。同時に次の MUGEN ドロップの design_seed も提案します。

# 場面の手触り
{humor_angle}

{parent_hint}

{learnings}

# tweet 必須条件
- 240 文字以内
- 末尾に {brand_url}
- ! は最大 1 個。🎉/🔥/CAPS 禁止。感謝連呼禁止。
- humor 必須: 短い ironic / 観察的 / 自虐的
- 「{lifecycle_jp}」の場面を fresh に描写、定型句なし
- 次の人が「自分も買いたい」と思える FOMO 要素

# avoid (直近の同 kind ツイート)
{avoid_block}

# 出力フォーマット
JSON のみ:
{{
  "tweet": "<上記条件を満たす日本語ツイート>",
  "design_seed": "<次 MUGEN T シャツの英語 prompt 30-80 字。元の seed を riff or 進化させる>"
}}"#,
        brand=brand, drop_num=drop_num, lifecycle_jp=lifecycle_jp, pf_status=pf_status,
        humor_angle=humor_angle, parent_hint=parent_hint, brand_url=brand_url, avoid_block=avoid_block,
    );
    let req = serde_json::json!({
        "contents": [{"parts": [{"text": prompt}]}],
        "generationConfig": {
            "temperature": 0.95, "maxOutputTokens": 8000,
            "responseMimeType": "application/json",
        },
    });
    let url = format!("https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-pro:generateContent?key={}", gemini_key);
    let resp = reqwest::Client::new().post(&url).json(&req).send().await
        .map_err(|e| format!("gemini http: {e}"))?;
    if !resp.status().is_success() {
        let s = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(format!("gemini {}: {}", s, &body[..body.len().min(200)]));
    }
    let body: serde_json::Value = resp.json().await.map_err(|e| format!("gemini json: {e}"))?;
    let text = body["candidates"][0]["content"]["parts"][0]["text"]
        .as_str().ok_or("no text")?.trim().to_string();
    let parsed: serde_json::Value = serde_json::from_str(&text)
        .map_err(|e| format!("parse: {e}"))?;
    let tweet = parsed["tweet"].as_str().ok_or("missing tweet")?.trim().to_string();
    let seed  = parsed["design_seed"].as_str().ok_or("missing design_seed")?.trim().to_string();
    if tweet.is_empty() || tweet.chars().count() > 280 { return Err(format!("tweet len {}", tweet.chars().count())); }
    if seed.is_empty() || seed.len() > 400 { return Err(format!("seed len {}", seed.len())); }
    let vs = validate_vision_hard(&tweet);
    if !vs.is_empty() { return Err(format!("vision violations in lifecycle tweet: [{}]", vs.join(", "))); }
    Ok((tweet, seed))
}

/// Gemini Pro で celebration tweet + 次 MUGEN ドロップ用 design_seed を生成。
/// temperature 高め (0.9) で variety 担保、recent tweets を avoid list として送る。
async fn generate_purchase_celebration(
    gemini_key: &str, brand: &str, drop_num: i64, db: &Db,
) -> Result<(String, String), String> {
    // Pull last 5 celebration tweets so Gemini can avoid repeating them.
    let recent: Vec<String> = {
        let conn = db.lock().unwrap();
        let mut stmt = match conn.prepare(
            "SELECT text FROM sns_post_queue
             WHERE network='x' AND trigger_kind='purchase_celebrate'
             ORDER BY created_at DESC LIMIT 5"
        ) { Ok(s) => s, Err(_) => return Err("db prep".into()) };
        stmt.query_map([], |r| r.get::<_, String>(0))
            .map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default()
    };
    // Weather snippet (best-effort).
    let temp = {
        let conn = db.lock().unwrap();
        cv_get(&conn, "weather_temp_c", "?")
    };
    let avoid_block = if recent.is_empty() {
        "(初回なので avoid なし)".into()
    } else {
        recent.iter().enumerate()
            .map(|(i, t)| format!("{}: {}", i+1, t.chars().take(120).collect::<String>()))
            .collect::<Vec<_>>().join("\n")
    };
    let brand_url = match brand {
        "mugen" => "wearmu.com/mugen",
        "muon"  => "wearmu.com/muon",
        "ma"    => "wearmu.com/ma",
        "you"   => "wearmu.com/you",
        _       => "wearmu.com",
    };
    let learnings = active_feedback_insights(db, 5);
    let vision_pref = vision_compliant_prefix();
    let prompt = format!(r#"{vision_pref}
あなたは MU (北海道弟子屈町、無人 AI ファッションブランド) の SNS 担当 AI です。
今、{brand} #{drop_num} が 1 着、外部のお客様に売れました。お祝い + FOMO + humor の X 投稿を書きます。

# 文脈
- 弟子屈の今の気温: {temp}°C (発行枚数のシード)
- 売れたブランド: {brand} / drop_num: {drop_num}
- URL: {brand_url}

{learnings}

# このタスクに特化した追加条件
- 240 文字以内
- 末尾に {brand_url}
- humor: 短い ironic な観察、または自虐
- FOMO: 「次の人を待ってる」「もう 1 枚しかない」「同じデザインは二度と」など、買い逃すと損する暗示
- お客様の実名・email を絶対に書かない (PII 保護)

# 避けるべき表現 (直近 5 件、同じ文体は drift)
{avoid_block}

# 出力フォーマット
JSON のみ。前置きや説明なし:
{{
  "tweet": "<上記条件を満たすツイート全文>",
  "design_seed": "<このツイートの世界観・トーンを反映した、次の MUGEN T シャツデザインのプロンプト英語 30-80 字。例: 'A single grain of static caught in 18°C morning air, sumi-e style'>"
}}"#,
        brand = brand, drop_num = drop_num, temp = temp,
        brand_url = brand_url, avoid_block = avoid_block,
    );
    let req = serde_json::json!({
        "contents": [{"parts": [{"text": prompt}]}],
        "generationConfig": {
            "temperature": 0.9,
            "maxOutputTokens": 8000,
            "responseMimeType": "application/json",
        },
    });
    let url = format!(
        "https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-pro:generateContent?key={}",
        gemini_key);
    let resp = reqwest::Client::new().post(&url).json(&req).send().await
        .map_err(|e| format!("gemini http: {e}"))?;
    if !resp.status().is_success() {
        let s = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(format!("gemini {}: {}", s, &body[..body.len().min(200)]));
    }
    let body: serde_json::Value = resp.json().await.map_err(|e| format!("gemini json: {e}"))?;
    let text = body["candidates"][0]["content"]["parts"][0]["text"]
        .as_str().ok_or("no text in gemini response")?.trim().to_string();
    let parsed: serde_json::Value = serde_json::from_str(&text)
        .map_err(|e| format!("parse json '{}': {}", text.chars().take(200).collect::<String>(), e))?;
    let tweet = parsed["tweet"].as_str().ok_or("missing tweet")?.trim().to_string();
    let seed  = parsed["design_seed"].as_str().ok_or("missing design_seed")?.trim().to_string();
    if tweet.is_empty() || tweet.chars().count() > 280 {
        return Err(format!("tweet length out of bounds: {}", tweet.chars().count()));
    }
    if seed.is_empty() || seed.len() > 400 {
        return Err(format!("design_seed length out of bounds: {}", seed.len()));
    }
    // Vision hard validation. Reject hype emoji / forbidden adjectives etc.
    let vs = validate_vision_hard(&tweet);
    if !vs.is_empty() {
        return Err(format!("vision violations in tweet: [{}]", vs.join(", ")));
    }
    Ok((tweet, seed))
}

// ── Agent: feedback_learner ─────────────────────────────────────────────
// Observe X reactions (mentions + own tweets' public_metrics) and let Gemini
// extract patterns about what resonates vs falls flat. Insights persist in
// feedback_insights table and are injected into next celebration tweets.
//
// Cadence: 6h (X API rate-limited; over-frequent = waste).
// Inputs: X mentions to @WEARMUCOM + last 20 posted tweets' metrics.
// Output: 3-7 short insights, e.g.
//   - "数字+humor 組合せが retweet を集める (signal 0.8 positive)"
//   - "ありがとう連呼ツイートは impressions 0 (signal 0.9 negative)"
//
// generate_purchase_celebration / generate_lifecycle_celebration both pull
// top-3 active insights and prepend them to the Gemini prompt as
// 「これまでの学び」 — so the system literally learns from reactions.
async fn agent_feedback_learner(db: Db) -> Result<AgentReport, String> {
    let gemini_key = match env::var("GEMINI_API_KEY") {
        Ok(k) if !k.is_empty() => k,
        _ => return Ok(AgentReport::idle("GEMINI_API_KEY missing")),
    };
    let bearer = env::var("X_BEARER_TOKEN").unwrap_or_default();
    if bearer.is_empty() {
        return Ok(AgentReport::idle("X_BEARER_TOKEN missing"));
    }
    // Fetch @WEARMUCOM user id (cached). Lock scope is sync-only, await
    // happens outside so the future stays Send.
    let cached_id: String = {
        let conn = db.lock().unwrap();
        cv_get(&conn, "wearmu_x_user_id", "")
    };
    let user_id: String = if !cached_id.is_empty() { cached_id } else {
        let url = "https://api.twitter.com/2/users/by/username/WEARMUCOM";
        let r = reqwest::Client::new().get(url).bearer_auth(&bearer).send().await
            .map_err(|e| format!("x user_id: {e}"))?;
        if !r.status().is_success() {
            return Ok(AgentReport::idle(&format!("X user lookup {}", r.status())));
        }
        let j: serde_json::Value = r.json().await.map_err(|e| format!("x user json: {e}"))?;
        let id = j["data"]["id"].as_str().unwrap_or("").to_string();
        if !id.is_empty() {
            let conn = db.lock().unwrap();
            cv_set(&conn, "wearmu_x_user_id", &id, "feedback_learner");
        }
        id
    };
    if user_id.is_empty() { return Ok(AgentReport::idle("no X user id")); }

    // Recent posted tweets with metrics (signal of what worked).
    let tweets_url = format!(
        "https://api.twitter.com/2/users/{}/tweets?max_results=20&tweet.fields=public_metrics,created_at,text",
        user_id);
    let tw_resp = reqwest::Client::new().get(&tweets_url).bearer_auth(&bearer).send().await
        .map_err(|e| format!("x tweets: {e}"))?;
    let tw_j: serde_json::Value = tw_resp.json().await.unwrap_or_default();
    let tweets: Vec<serde_json::Value> = tw_j["data"].as_array().cloned().unwrap_or_default();

    // Mentions: who's talking about us (proxy for resonance).
    let mentions_url = format!(
        "https://api.twitter.com/2/users/{}/mentions?max_results=20&tweet.fields=public_metrics,text,author_id",
        user_id);
    let m_resp = reqwest::Client::new().get(&mentions_url).bearer_auth(&bearer).send().await
        .map_err(|e| format!("x mentions: {e}"))?;
    let m_j: serde_json::Value = m_resp.json().await.unwrap_or_default();
    let mentions: Vec<serde_json::Value> = m_j["data"].as_array().cloned().unwrap_or_default();

    if tweets.is_empty() && mentions.is_empty() {
        return Ok(AgentReport::idle("no X data to analyze"));
    }

    // Compact serialization for Gemini.
    let tweets_compact: Vec<serde_json::Value> = tweets.iter().take(20).map(|t| {
        serde_json::json!({
            "text": t["text"].as_str().unwrap_or(""),
            "imp": t["public_metrics"]["impression_count"].as_i64().unwrap_or(0),
            "like": t["public_metrics"]["like_count"].as_i64().unwrap_or(0),
            "rt": t["public_metrics"]["retweet_count"].as_i64().unwrap_or(0),
            "rep": t["public_metrics"]["reply_count"].as_i64().unwrap_or(0),
        })
    }).collect();
    let mentions_compact: Vec<serde_json::Value> = mentions.iter().take(20).map(|t| {
        serde_json::json!({
            "text": t["text"].as_str().unwrap_or(""),
            "like": t["public_metrics"]["like_count"].as_i64().unwrap_or(0),
        })
    }).collect();

    let prompt = format!(r#"あなたは MU (北海道弟子屈町、無人 AI ファッションブランド) の X SNS analyst。
直近の @WEARMUCOM の投稿と外部 mention を見て、「何が機能していて、何が flat か」のパターンを抽出します。

# データ
## @WEARMUCOM の最近の投稿 (text + impressions/like/rt/replies):
{tweets_json}

## @WEARMUCOM への外部 mentions (text + like):
{mentions_json}

# 出力指示
JSON 配列で 3-7 件の learning insight を出して。各 insight は:
- theme: 短い label (40 char 以下)
- pattern: 何が起きてる / 何が刺さってる (240 char 以下、具体的に)
- polarity: 'positive' (続けるべき) | 'negative' (やめるべき) | 'neutral' (中立観察)
- signal_score: 0.0 to 1.0 (確信度。証拠が薄ければ 0.3 以下)

# 例 (出力フォーマットの参考、実データに合わせて差し替えること)
[
  {{"theme":"数字 hook 強い","pattern":"具体的な金額が書かれてるツイートが imp 平均 2x","polarity":"positive","signal_score":0.7}},
  {{"theme":"絵文字過多","pattern":"🎉 含むツイートは reply 0","polarity":"negative","signal_score":0.5}}
]

JSON 配列のみ出力。前置きや説明禁止。
"#,
        tweets_json = serde_json::to_string(&tweets_compact).unwrap_or_default(),
        mentions_json = serde_json::to_string(&mentions_compact).unwrap_or_default(),
    );

    let req = serde_json::json!({
        "contents": [{"parts": [{"text": prompt}]}],
        "generationConfig": {
            "temperature": 0.4, "maxOutputTokens": 8000,
            "responseMimeType": "application/json",
        },
    });
    let url = format!("https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-pro:generateContent?key={}", gemini_key);
    let resp = reqwest::Client::new().post(&url).json(&req).send().await
        .map_err(|e| format!("gemini http: {e}"))?;
    if !resp.status().is_success() {
        let s = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(format!("gemini {}: {}", s, &body[..body.len().min(200)]));
    }
    let body: serde_json::Value = resp.json().await.map_err(|e| format!("gemini json: {e}"))?;
    let text = body["candidates"][0]["content"]["parts"][0]["text"]
        .as_str().ok_or("no text")?.trim().to_string();
    let insights: Vec<serde_json::Value> = serde_json::from_str(&text)
        .map_err(|e| format!("parse: {e}: '{}'", text.chars().take(200).collect::<String>()))?;

    // Mark previous insights as superseded (active=0), then insert fresh.
    let now = chrono_now();
    let mut saved = 0i64;
    {
        let conn = db.lock().unwrap();
        let _ = conn.execute(
            "UPDATE feedback_insights SET active=0 WHERE scope='general' AND active=1",
            [],
        );
        for ins in insights.iter().take(7) {
            let theme = ins["theme"].as_str().unwrap_or("");
            let pattern = ins["pattern"].as_str().unwrap_or("");
            let polarity = ins["polarity"].as_str().unwrap_or("neutral");
            let score = ins["signal_score"].as_f64().unwrap_or(0.3);
            if theme.is_empty() || pattern.is_empty() { continue; }
            let evidence = serde_json::json!({
                "tweet_count": tweets.len(), "mention_count": mentions.len(),
            }).to_string();
            let n = conn.execute(
                "INSERT INTO feedback_insights
                    (learned_at, scope, theme, pattern, polarity, signal_score, evidence, active)
                 VALUES (?, 'general', ?, ?, ?, ?, ?, 1)",
                params![now, theme, pattern, polarity, score, evidence],
            ).unwrap_or(0);
            saved += n as i64;
        }
    }
    Ok(AgentReport {
        observations: serde_json::json!({
            "tweets_analyzed": tweets.len(),
            "mentions_analyzed": mentions.len(),
            "insights_saved": saved,
        }),
        decisions: vec![],
        actions: vec![serde_json::json!({"saved": saved})],
        summary: format!("feedback_learner: {} tweets + {} mentions → {} insights", tweets.len(), mentions.len(), saved),
        notable: saved > 0,
    })
}

/// Fetch top-N active feedback_insights to inject into generation prompts.
/// Bucketed: positive (do more), negative (avoid), neutral (observe).
fn active_feedback_insights(db: &Db, limit: usize) -> String {
    let conn = db.lock().unwrap();
    let mut stmt = match conn.prepare(
        "SELECT theme, pattern, polarity, signal_score
         FROM feedback_insights WHERE active=1 ORDER BY signal_score DESC LIMIT ?"
    ) { Ok(s) => s, Err(_) => return String::new() };
    let rows: Vec<(String, String, String, f64)> = stmt.query_map(params![limit as i64],
        |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?)))
        .map(|it| it.filter_map(|r| r.ok()).collect()).unwrap_or_default();
    if rows.is_empty() { return String::new(); }
    let mut out = String::from("# これまでの学び (feedback_learner より、優先度高い順)\n");
    for (theme, pattern, polarity, score) in rows {
        let mark = match polarity.as_str() {
            "positive" => "✓ 続ける",
            "negative" => "✗ 避ける",
            _          => "○ 観察",
        };
        out.push_str(&format!("- {} [{}, score {:.2}] {}: {}\n", mark, polarity, score, theme, pattern));
    }
    out
}

// ── Agent: self_review (umbrella over 4 daily inward-looking agents) ───
// 統合先: self_improvement + vision_drift + self_evolve + pr_writer
// → 1 daily run で 4 サブエージェントを直列実行し、結果を 1 つの AgentReport に
// merge。 個別 agent としても残存 (debug や個別 dry_run 用)、ただし
// AGENT_REGISTRY からは self_review のみ scheduled。
//
// Telegram は merged summary 1 通 (旧: 最大 4 通)。
// agent_journal は merged 1 行 (旧: 最大 4 行/日)。
async fn agent_self_review(db: Db) -> Result<AgentReport, String> {
    let mut merged_obs = serde_json::Map::new();
    let mut merged_decisions: Vec<serde_json::Value> = Vec::new();
    let mut merged_actions: Vec<serde_json::Value> = Vec::new();
    let mut summary_parts: Vec<String> = Vec::new();
    let mut any_notable = false;
    let stages: [(&str, fn(Db) -> std::pin::Pin<Box<dyn std::future::Future<Output = Result<AgentReport, String>> + Send>>); 4] = [
        ("self_improvement", |d| Box::pin(agent_self_improvement(d))),
        ("vision_drift",     |d| Box::pin(agent_vision_drift(d))),
        ("self_evolve",      |d| Box::pin(agent_self_evolve(d))),
        ("pr_writer",        |d| Box::pin(agent_pr_writer(d))),
    ];
    for (stage_name, run_fn) in stages {
        match run_fn(db.clone()).await {
            Ok(r) => {
                merged_obs.insert(stage_name.into(), r.observations.clone());
                for d in r.decisions { merged_decisions.push(serde_json::json!({"stage": stage_name, "decision": d})); }
                for a in r.actions   { merged_actions.push(serde_json::json!({"stage": stage_name, "action": a})); }
                if r.notable { any_notable = true; }
                summary_parts.push(format!("{}: {}", stage_name, r.summary));
            }
            Err(e) => {
                merged_obs.insert(stage_name.into(), serde_json::json!({"error": e.clone()}));
                summary_parts.push(format!("{}: error", stage_name));
            }
        }
    }
    Ok(AgentReport {
        observations: serde_json::Value::Object(merged_obs),
        decisions: merged_decisions,
        actions: merged_actions,
        summary: summary_parts.join(" | "),
        notable: any_notable,
    })
}

// ── Agent: drop_filler ─────────────────────────────────────────────────
// Detect missing MUGEN drop_num + MUON dates and surface them as actionable
// Telegram notifications. Fly app cannot execute generate.py (Python runs on
// m5 Mac cron). This agent prompts yuki with the exact command to backfill,
// so the 11+7 visible "ops gaps" close without a Python-in-Fly migration.
//
// Cadence: 6h. Notable=true only when gap_count > 0 AND last_nudge > 18h
// (dedup so we don't spam yuki).
async fn agent_drop_filler(db: Db) -> Result<AgentReport, String> {
    let (mugen_missing, muon_missing) = {
        let conn = db.lock().unwrap();
        let dm = detect_missing_drops(&conn);
        let mugen: Vec<i64> = dm["mugen_missing_drops"].as_array()
            .map(|a| a.iter().filter_map(|v| v.as_i64()).collect())
            .unwrap_or_default();
        let muon: Vec<String> = dm["muon_missing_dates"].as_array()
            .map(|a| a.iter().filter_map(|v| v.as_str().map(String::from)).collect())
            .unwrap_or_default();
        (mugen, muon)
    };
    let total_gaps = (mugen_missing.len() + muon_missing.len()) as i64;
    if total_gaps == 0 {
        return Ok(AgentReport::idle("no missing drops"));
    }
    let commands: Vec<String> = mugen_missing.iter().take(3)
        .map(|n| format!("python3 generate.py --mugen={}", n))
        .chain(muon_missing.iter().take(2)
            .map(|d| format!("python3 generate.py --muon={}", d)))
        .collect();
    let summary = format!(
        "drop_filler: MUGEN {} / MUON {} ホール検出。優先 {} 件のコマンド提示",
        mugen_missing.len(), muon_missing.len(), commands.len()
    );
    let observations = serde_json::json!({
        "mugen_missing_count": mugen_missing.len(),
        "muon_missing_count": muon_missing.len(),
        "mugen_first5": mugen_missing.iter().take(5).collect::<Vec<_>>(),
        "muon_first5": muon_missing.iter().take(5).collect::<Vec<_>>(),
    });
    let actions: Vec<serde_json::Value> = commands.iter().enumerate()
        .map(|(i, c)| serde_json::json!({"priority": i+1, "cmd": c}))
        .collect();
    Ok(AgentReport {
        observations,
        decisions: vec![serde_json::json!({
            "type": "backfill_nudge",
            "total_gaps": total_gaps,
            "cmds_proposed": commands.len(),
        })],
        actions,
        summary,
        notable: total_gaps > 0,
    })
}

// ── Agent 21: bezos_review (founder persona) ───────────────────────────
async fn agent_bezos_review(db: Db) -> Result<AgentReport, String> {
    founder_review(db, "bezos", BEZOS_PROMPT).await
}

